canvas_presets.script:
/**
 * Title: The Architect (Transparency Optimized)
 * Description: Matrix-style digital rain.
 */
const CONFIG = { fontSize: 16, fontFamily: 'monospace', textColor: '#0f0', fadeAmount: 0.08, dropSpeed: 1, chars: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%^&*()_+' };
let canvas, ctx, width, height, columns, drops = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        startAnimation();
    } else if (e.data.type === 'resize') resize(e.data.width, e.data.height);
};

function resize(w, h) {
    width = w; height = h; canvas.width = w; canvas.height = h;
    columns = Math.floor(width / CONFIG.fontSize);
    drops = Array(columns).fill(-100);
}

function startAnimation() {
    function render() {
        if (!ctx) return;
        ctx.globalCompositeOperation = 'destination-out';
        ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.fadeAmount})`;
        ctx.fillRect(0, 0, width, height);
        ctx.globalCompositeOperation = 'source-over';
        ctx.font = `${CONFIG.fontSize}px ${CONFIG.fontFamily}`;
        for (let i = 0; i < drops.length; i++) {
            ctx.fillStyle = CONFIG.textColor;
            ctx.fillText(CONFIG.chars.charAt(Math.floor(Math.random() * CONFIG.chars.length)), i * CONFIG.fontSize, drops[i] * CONFIG.fontSize);
            if (drops[i] * CONFIG.fontSize > height && Math.random() > 0.975) drops[i] = 0;
            drops[i] += CONFIG.dropSpeed;
        }
        requestAnimationFrame(render);
    }
    render();
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Aetheric Flow
 * Description: 2,000+ energy filaments in a dynamic noise field.
 */
const CONFIG = { particleCount: 2200, noiseScale: 0.003, fieldStrength: 0.12, baseSpeed: 1.2, fadeAmount: 0.06, hueRange: [180, 260], mouseInfluence: 150 };
let canvas, ctx, width, height, particles = [], mouse = { x: -1000, y: -1000 }, zOff = 0;

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        width = canvas.width = e.data.width; height = canvas.height = e.data.height;
        for (let i = 0; i < CONFIG.particleCount; i++) particles.push({ x: Math.random() * width, y: Math.random() * height, prevX: 0, prevY: 0, speed: Math.random() * CONFIG.baseSpeed + 0.5, hue: Math.random() * (CONFIG.hueRange[1] - CONFIG.hueRange[0]) + CONFIG.hueRange[0] });
        render();
    } else if (e.data.type === 'mousemove') { mouse.x = e.data.x; mouse.y = e.data.y; }
};

function render() {
    ctx.globalCompositeOperation = 'destination-out';
    ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.fadeAmount})`;
    ctx.fillRect(0, 0, width, height);
    ctx.globalCompositeOperation = 'source-over';
    zOff += 0.005;
    particles.forEach(p => {
        p.prevX = p.x; p.prevY = p.y;
        let angle = (Math.sin(p.x * CONFIG.noiseScale) + Math.cos(p.y * CONFIG.noiseScale + zOff)) * Math.PI * 2;
        let dx = mouse.x - p.x, dy = mouse.y - p.y, dist = Math.hypot(dx, dy);
        if (dist < CONFIG.mouseInfluence) angle -= (1 - dist / CONFIG.mouseInfluence) * 2;
        p.x += Math.cos(angle) * p.speed; p.y += Math.sin(angle) * p.speed;
        if (p.x < 0 || p.x > width || p.y < 0 || p.y > height) { p.x = p.prevX = Math.random() * width; p.y = p.prevY = Math.random() * height; }
        ctx.beginPath(); ctx.strokeStyle = `hsla(${p.hue}, 80%, 60%, 0.5)`; ctx.moveTo(p.prevX, p.prevY); ctx.lineTo(p.x, p.y); ctx.stroke();
    });
    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Geometric Singularity
 * Description: Recursive 3D wireframe lattice warping toward the mouse.
 */
const CONFIG = { gridDensity: 25, warpStrength: 1.8, rotationSpeed: 0.002, lineColor: '0, 255, 150', perspective: 800 };
let canvas, ctx, width, height, time = 0, mouse = { x: 0, y: 0 };

self.onmessage = (e) => {
    if (e.data.type === 'init') { canvas = e.data.canvas; ctx = canvas.getContext('2d'); width = canvas.width = e.data.width; height = canvas.height = e.data.height; mouse = { x: width/2, y: height/2 }; animate(); }
    else if (e.data.type === 'mousemove') { mouse.x = e.data.x; mouse.y = e.data.y; }
};

function project(x, y, z) {
    let scale = CONFIG.perspective / (CONFIG.perspective + z);
    return { x: x * scale + width / 2, y: y * scale + height / 2 };
}

function animate() {
    ctx.clearRect(0, 0, width, height);
    time += CONFIG.rotationSpeed;
    ctx.lineWidth = 0.6; ctx.strokeStyle = `rgba(${CONFIG.lineColor}, 0.3)`;
    const step = width / CONFIG.gridDensity, size = width * 1.5;
    for (let i = -size; i < size; i += step) {
        ctx.beginPath();
        for (let j = -size; j < size; j += step / 2) {
            let dM = Math.hypot(i - (mouse.x - width/2), j - (mouse.y - height/2));
            let z = Math.sin(i*0.002+time)*100 + Math.cos(j*0.002-time)*100 + (CONFIG.warpStrength*20000/(dM+100));
            let p = project(i, j, z);
            if (j === -size) ctx.moveTo(p.x, p.y); else ctx.lineTo(p.x, p.y);
        }
        ctx.stroke();
    }
    requestAnimationFrame(animate);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Aurora Borealis
 * Description: Flowing, undulating aurora-like ribbons of light with green, teal, and purple hues.
 *              Ribbons sway gently using sine waves and respond subtly to mouse position
 *              by shifting their flow direction.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let ribbons = [];

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

const RIBBON_COUNT = 5;

// Aurora color palette: greens, teals, purples
const PALETTE = [
	{ r: 50, g: 220, b: 130 }, // green
	{ r: 30, g: 200, b: 180 }, // teal
	{ r: 80, g: 180, b: 220 }, // cyan-teal
	{ r: 130, g: 80, b: 220 }, // purple
	{ r: 60, g: 240, b: 160 } // bright green
];

class Ribbon {
	constructor(index) {
		this.index = index;
		this.color = PALETTE[index % PALETTE.length];
		this.yBase = 0;
		this.amplitude = 0;
		this.frequency = 0;
		this.speed = 0;
		this.thickness = 0;
		this.phase = Math.random() * Math.PI * 2;
		this.opacity = 0;
		this.recalculate();
	}

	recalculate() {
		// Position ribbon in upper-to-middle area
		this.yBase = height * (0.15 + this.index * 0.12);
		this.amplitude = height * (0.04 + Math.random() * 0.06);
		this.frequency = 0.002 + Math.random() * 0.002;
		this.speed = 0.008 + Math.random() * 0.006;
		this.thickness = height * (0.06 + Math.random() * 0.08);
		this.opacity = 0.04 + Math.random() * 0.04;
	}

	draw(t) {
		const { r, g, b } = this.color;
		const segments = 80;
		const segWidth = (width + 40) / segments;

		// Mouse influence: shift the ribbon horizontally and vertically
		const mouseFractionX = mouse.x > -1000 ? mouse.x / width - 0.5 : 0;
		const mouseFractionY = mouse.y > -1000 ? mouse.y / height - 0.5 : 0;
		const mouseShiftX = mouseFractionX * 30;
		const mouseShiftY = mouseFractionY * 15;

		// Draw multiple layers for glow
		for (let layer = 0; layer < 3; layer++) {
			const layerOpacity = this.opacity * (1 - layer * 0.3);
			const layerThickness = this.thickness * (1 + layer * 0.8);

			ctx.beginPath();

			for (let i = 0; i <= segments; i++) {
				const x = -20 + i * segWidth;
				const xNorm = x / width;

				// Composite sine wave for organic motion
				const wave1 = Math.sin(x * this.frequency + t * this.speed + this.phase);
				const wave2 =
					Math.sin(x * this.frequency * 1.7 + t * this.speed * 0.6 + this.phase * 2.3) * 0.5;
				const wave3 = Math.sin(x * this.frequency * 0.5 + t * this.speed * 1.3) * 0.3;

				const y =
					this.yBase +
					(wave1 + wave2 + wave3) * this.amplitude +
					mouseShiftY * (1 - Math.abs(xNorm - 0.5) * 1.5) +
					Math.sin(xNorm * Math.PI) * mouseShiftX;

				if (i === 0) {
					ctx.moveTo(x, y);
				} else {
					ctx.lineTo(x, y);
				}
			}

			// Create a gradient stroke that fades at edges
			const grad = ctx.createLinearGradient(0, 0, width, 0);
			grad.addColorStop(0, `rgba(${r}, ${g}, ${b}, 0)`);
			grad.addColorStop(0.15, `rgba(${r}, ${g}, ${b}, ${layerOpacity})`);
			grad.addColorStop(0.5, `rgba(${r}, ${g}, ${b}, ${layerOpacity * 1.2})`);
			grad.addColorStop(0.85, `rgba(${r}, ${g}, ${b}, ${layerOpacity})`);
			grad.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			ctx.strokeStyle = grad;
			ctx.lineWidth = layerThickness;
			ctx.lineCap = 'round';
			ctx.lineJoin = 'round';
			ctx.stroke();
		}
	}
}

function initRibbons() {
	ribbons = [];
	for (let i = 0; i < RIBBON_COUNT; i++) {
		ribbons.push(new Ribbon(i));
	}
}

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time += 1;

		// Draw ribbons back to front
		for (const ribbon of ribbons) {
			ribbon.draw(time);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initRibbons();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			for (const ribbon of ribbons) {
				ribbon.recalculate();
			}
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Bioluminescence
 * Description: Deep sea bioluminescent flashes and drifting organisms. Soft glowing
 *   creatures pulse and drift through dark water, trailing tentacles. Mouse presence
 *   attracts nearby organisms with a gentle pull.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
	// -- Organisms --
	organismCount: 35,                        // Number of floating organisms (10-80)
	organismSizeMin: 3,                       // Minimum organism body radius in px (1-10)
	organismSizeMax: 12,                      // Maximum organism body radius in px (5-25)
	driftSpeed: 18,                           // Base drift speed in px/s (5-60)
	jitter: 0.4,                              // Organic motion jitter strength (0-2)

	// -- Flashing --
	flashFrequency: 0.08,                     // Probability per frame of an organism flashing (0-0.3)
	flashDuration: 60,                        // Flash duration in frames (20-120)
	flashMaxRadius: 60,                       // Maximum glow radius during a flash in px (20-150)
	flashColorPalette: [                      // Colors organisms can flash — array of rgba strings
		'rgba(0, 255, 200, 1)',                 //   cyan-green
		'rgba(80, 180, 255, 1)',                //   sky blue
		'rgba(150, 80, 255, 1)',                //   purple
		'rgba(0, 255, 120, 1)',                 //   green
		'rgba(255, 120, 200, 1)',               //   pink
	],

	// -- Ambient Glow --
	ambientGlowOpacity: 0.12,                // Resting glow opacity around each organism (0-0.4)
	pulseRate: 0.02,                          // Speed of the ambient breathing pulse (0.005-0.1)

	// -- Tentacles --
	tentacleEnabled: true,                    // Draw trailing tentacles behind organisms
	tentacleLength: 8,                        // Number of tentacle segments (3-20)
	tentacleOpacity: 0.25,                    // Base opacity of tentacle strands (0-1)
	tentacleWidth: 1.5,                       // Width of tentacle lines in px (0.5-4)

	// -- Mouse Interaction --
	mouseAttractionRadius: 250,               // Distance at which mouse attracts organisms in px (50-500)
	mouseAttractionForce: 40,                 // Strength of mouse pull in px/s (5-100)

	// -- Environment --
	backgroundTint: 'rgba(0, 5, 20, 0.08)',  // Subtle background overlay color per frame
	particleCount: 60,                        // Tiny ambient deep-sea particles (0-200)
	particleAlpha: 0.15,                      // Alpha of ambient particles (0-0.5)
	particleSize: 1.5,                        // Size of ambient particles in px (0.5-3)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let organisms = [];
let particles = [];
let frameCount = 0;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── ORGANISM CLASS ─────────────────────────────────────────────────────────
function createOrganism(x, y) {
	const size = CONFIG.organismSizeMin +
		Math.random() * (CONFIG.organismSizeMax - CONFIG.organismSizeMin);
	const colorIndex = Math.floor(Math.random() * CONFIG.flashColorPalette.length);
	return {
		x: x !== undefined ? x : Math.random() * width,
		y: y !== undefined ? y : Math.random() * height,
		vx: (Math.random() - 0.5) * CONFIG.driftSpeed,
		vy: (Math.random() - 0.5) * CONFIG.driftSpeed * 0.5 - CONFIG.driftSpeed * 0.3,
		size,
		baseSize: size,
		colorIndex,
		flashTimer: 0,
		flashColor: null,
		phaseOffset: Math.random() * Math.PI * 2,
		trail: [],        // tentacle history positions
		angle: Math.random() * Math.PI * 2,
		angularVel: (Math.random() - 0.5) * 0.02,
	};
}

function createParticle() {
	return {
		x: Math.random() * width,
		y: Math.random() * height,
		vx: (Math.random() - 0.5) * 4,
		vy: -Math.random() * 3 - 1,
		alpha: Math.random() * CONFIG.particleAlpha,
		size: Math.random() * CONFIG.particleSize + 0.5,
	};
}

// ─── INIT ────────────────────────────────────────────────────────────────────
function initAll() {
	organisms = [];
	particles = [];
	for (let i = 0; i < CONFIG.organismCount; i++) {
		organisms.push(createOrganism());
	}
	for (let i = 0; i < CONFIG.particleCount; i++) {
		particles.push(createParticle());
	}
}

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function parseRgba(str) {
	const m = str.match(/[\d.]+/g);
	if (!m || m.length < 3) return [255, 255, 255, 1];
	return [+m[0], +m[1], +m[2], m[3] !== undefined ? +m[3] : 1];
}

// ─── UPDATE ──────────────────────────────────────────────────────────────────
function updateOrganisms() {
	for (const org of organisms) {
		// Organic jitter
		org.vx += (Math.random() - 0.5) * CONFIG.jitter;
		org.vy += (Math.random() - 0.5) * CONFIG.jitter;

		// Gentle upward drift bias
		org.vy -= 0.05;

		// Mouse attraction
		const dx = mouse.x - org.x;
		const dy = mouse.y - org.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < CONFIG.mouseAttractionRadius && dist > 1) {
			const force = (1 - dist / CONFIG.mouseAttractionRadius) * CONFIG.mouseAttractionForce;
			org.vx += (dx / dist) * force * 0.016;
			org.vy += (dy / dist) * force * 0.016;
		}

		// Damping
		org.vx *= 0.98;
		org.vy *= 0.98;

		// Speed limit
		const speed = Math.sqrt(org.vx * org.vx + org.vy * org.vy);
		const maxSpeed = CONFIG.driftSpeed * 2;
		if (speed > maxSpeed) {
			org.vx = (org.vx / speed) * maxSpeed;
			org.vy = (org.vy / speed) * maxSpeed;
		}

		org.x += org.vx * 0.016;
		org.y += org.vy * 0.016;

		// Wrap around
		if (org.x < -50) org.x = width + 50;
		if (org.x > width + 50) org.x = -50;
		if (org.y < -50) org.y = height + 50;
		if (org.y > height + 50) org.y = -50;

		// Tentacle trail
		if (CONFIG.tentacleEnabled) {
			org.trail.unshift({ x: org.x, y: org.y });
			while (org.trail.length > CONFIG.tentacleLength + 1) {
				org.trail.pop();
			}
		}

		// Flash trigger
		if (org.flashTimer <= 0 && Math.random() < CONFIG.flashFrequency * 0.016) {
			org.flashTimer = CONFIG.flashDuration;
			org.flashColor = CONFIG.flashColorPalette[
				Math.floor(Math.random() * CONFIG.flashColorPalette.length)
			];
		}
		if (org.flashTimer > 0) org.flashTimer--;

		// Rotation
		org.angle += org.angularVel;
	}
}

function updateParticles() {
	for (const p of particles) {
		p.x += p.vx * 0.016;
		p.y += p.vy * 0.016;
		if (p.y < -10) { p.y = height + 10; p.x = Math.random() * width; }
		if (p.x < -10) p.x = width + 10;
		if (p.x > width + 10) p.x = -10;
	}
}

// ─── DRAW ────────────────────────────────────────────────────────────────────
function drawParticles() {
	for (const p of particles) {
		ctx.beginPath();
		ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(100, 180, 255, ${p.alpha})`;
		ctx.fill();
	}
}

function drawOrganisms() {
	for (const org of organisms) {
		const pulse = Math.sin(frameCount * CONFIG.pulseRate + org.phaseOffset) * 0.3 + 0.7;
		const isFlashing = org.flashTimer > 0;
		const flashProgress = isFlashing ? org.flashTimer / CONFIG.flashDuration : 0;
		const flashIntensity = Math.sin(flashProgress * Math.PI); // peaks mid-flash

		// Pick base color
		const colorStr = isFlashing ? org.flashColor :
			CONFIG.flashColorPalette[org.colorIndex];
		const rgba = parseRgba(colorStr);

		// Draw tentacles
		if (CONFIG.tentacleEnabled && org.trail.length > 1) {
			for (let i = 1; i < org.trail.length; i++) {
				const t = 1 - i / org.trail.length;
				const alpha = t * CONFIG.tentacleOpacity * pulse;
				ctx.beginPath();
				ctx.moveTo(org.trail[i - 1].x, org.trail[i - 1].y);
				ctx.lineTo(org.trail[i].x, org.trail[i].y);
				ctx.strokeStyle = `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${alpha.toFixed(3)})`;
				ctx.lineWidth = CONFIG.tentacleWidth * t;
				ctx.stroke();
			}
		}

		// Outer glow (ambient or flash)
		const glowRadius = isFlashing
			? org.size * 2 + flashIntensity * CONFIG.flashMaxRadius
			: org.size * 3 * pulse;
		const glowAlpha = isFlashing
			? flashIntensity * 0.5
			: CONFIG.ambientGlowOpacity * pulse;

		const grad = ctx.createRadialGradient(org.x, org.y, 0, org.x, org.y, glowRadius);
		grad.addColorStop(0, `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${glowAlpha.toFixed(3)})`);
		grad.addColorStop(0.4, `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${(glowAlpha * 0.3).toFixed(3)})`);
		grad.addColorStop(1, 'rgba(0, 0, 0, 0)');
		ctx.fillStyle = grad;
		ctx.beginPath();
		ctx.arc(org.x, org.y, glowRadius, 0, Math.PI * 2);
		ctx.fill();

		// Body
		const bodyAlpha = 0.6 + pulse * 0.4;
		const bodySize = org.size * (0.9 + pulse * 0.1);

		// Soft body shape (slightly elliptical)
		ctx.save();
		ctx.translate(org.x, org.y);
		ctx.rotate(org.angle);
		ctx.scale(1, 0.75);
		ctx.beginPath();
		ctx.arc(0, 0, bodySize, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${(bodyAlpha * 0.4).toFixed(3)})`;
		ctx.fill();

		// Inner nucleus
		ctx.beginPath();
		ctx.arc(0, 0, bodySize * 0.4, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${Math.min(255, rgba[0] + 80)}, ${Math.min(255, rgba[1] + 80)}, ${Math.min(255, rgba[2] + 80)}, ${(bodyAlpha * 0.8).toFixed(3)})`;
		ctx.fill();
		ctx.restore();

		// Flash burst ring
		if (isFlashing && flashIntensity > 0.1) {
			ctx.beginPath();
			ctx.arc(org.x, org.y, org.size + flashIntensity * CONFIG.flashMaxRadius * 0.3, 0, Math.PI * 2);
			ctx.strokeStyle = `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${(flashIntensity * 0.3).toFixed(3)})`;
			ctx.lineWidth = 1;
			ctx.stroke();
		}
	}
}

// ─── ANIMATION LOOP ─────────────────────────────────────────────────────────
function startAnimation() {
	function render() {
		if (!ctx) return;
		frameCount++;

		// Dark water background overlay (creates trail effect)
		ctx.fillStyle = CONFIG.backgroundTint;
		ctx.fillRect(0, 0, width, height);

		updateOrganisms();
		updateParticles();

		drawParticles();

		// Additive glow pass
		ctx.globalCompositeOperation = 'lighter';
		drawOrganisms();
		ctx.globalCompositeOperation = 'source-over';

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── MESSAGE HANDLER ─────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Bit-Stream Corruption
 * Description: A chaotic storm of digital artifacts and ASCII bits that scramble near the cursor.
 */

const CONFIG = {
    bitCount: 150,
    color: 'rgba(255, 255, 0, 0.4)',
    glitchColor: 'rgba(255, 255, 255, 0.8)',
    chars: ['0', '1', 'X', '_', '|', '§', 'Δ'],
    fontSize: 12,
    noiseForce: 0.5
};

let canvas, ctx, w, h;
let bits = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    bits = [];
    for (let i = 0; i < CONFIG.bitCount; i++) {
        bits.push({
            x: Math.random() * w, y: Math.random() * h,
            char: CONFIG.chars[Math.floor(Math.random() * CONFIG.chars.length)],
            vx: (Math.random() - 0.5) * 4,
            vy: (Math.random() - 0.5) * 4,
            life: Math.random() * 100
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.font = `${CONFIG.fontSize}px 'JetBrains Mono', monospace`;

    for (let b of bits) {
        let dx = mouse.x - b.x; let dy = mouse.y - b.y;
        let dist = Math.hypot(dx, dy);

        // Glitch Logic: Scramble positions near mouse
        if (dist < 200) {
            b.x += (Math.random() - 0.5) * 15;
            b.y += (Math.random() - 0.5) * 15;
            ctx.fillStyle = CONFIG.glitchColor;
        } else {
            b.x += b.vx; b.y += b.vy;
            ctx.fillStyle = CONFIG.color;
        }

        // Digital drift
        if (Math.random() > 0.98) b.char = CONFIG.chars[Math.floor(Math.random() * CONFIG.chars.length)];

        // Screen Wrap
        if (b.x < 0) b.x = w; if (b.x > w) b.x = 0;
        if (b.y < 0) b.y = h; if (b.y > h) b.y = 0;

        ctx.fillText(b.char, b.x, b.y);
    }
    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Blueprint Grid
 * Description: Animated technical blueprint with dimension lines, measurement
 *   annotations, scan line effect, and interactive crosshair targeting.
 *   Mouse creates a crosshair target point with live measurements.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Grid --
  gridSize: 20,                    // Minor grid cell size in px (10-50)
  majorGridInterval: 5,            // Major line every N minor cells (2-10)
  gridColor: 'rgba(30,100,200,0.12)',  // Minor grid line color
  majorGridColor: 'rgba(30,100,200,0.25)', // Major grid line color
  gridOpacity: 1.0,                // Overall grid opacity multiplier (0-1)

  // -- Dimension Lines --
  dimensionLineEnabled: true,      // Show animated dimension lines
  dimensionColor: 'rgba(100,180,255,0.5)', // Dimension line/arrow color
  measurementDensity: 6,           // Number of dimension annotations visible (2-15)

  // -- Annotations --
  annotationEnabled: true,         // Show text annotations
  annotationColor: 'rgba(100,200,255,0.7)', // Annotation text color
  annotationFontSize: 10,          // Font size in px (8-16)

  // -- Scan Line --
  scanLineEnabled: true,           // Enable horizontal scan line sweep
  scanLineSpeed: 1.5,              // Scan line speed (0.5-5.0)
  scanLineColor: 'rgba(0,180,255,0.15)', // Scan line glow color

  // -- Crosshair --
  crosshairEnabled: true,          // Show center crosshair
  crosshairColor: 'rgba(0,200,255,0.4)', // Crosshair line color

  // -- Mouse Interaction --
  // Mouse creates a crosshair target point with coordinate readout
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let dimensions = [];

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initDimensions() {
  dimensions = [];
  for (let i = 0; i < CONFIG.measurementDensity; i++) {
    dimensions.push(createDimension(i));
  }
}

function createDimension(index) {
  const isHoriz = Math.random() > 0.5;
  const gs = CONFIG.gridSize * CONFIG.majorGridInterval;
  const snap = (v) => Math.round(v / gs) * gs;
  if (isHoriz) {
    const y = snap(80 + Math.random() * (height - 160));
    const x1 = snap(40 + Math.random() * (width * 0.3));
    const x2 = snap(x1 + 100 + Math.random() * (width * 0.4));
    return { type: 'h', x1, x2, y, age: Math.random() * 200, lifespan: 300 + Math.random() * 400 };
  } else {
    const x = snap(80 + Math.random() * (width - 160));
    const y1 = snap(40 + Math.random() * (height * 0.3));
    const y2 = snap(y1 + 100 + Math.random() * (height * 0.4));
    return { type: 'v', x, y1, y2, age: Math.random() * 200, lifespan: 300 + Math.random() * 400 };
  }
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initDimensions();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initDimensions();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function startAnimation() {
  let scanY = 0;

  function render() {
    if (!ctx) return;
    time += 1;
    ctx.clearRect(0, 0, width, height);

    const gs = CONFIG.gridSize;
    const major = CONFIG.majorGridInterval;
    const opacity = CONFIG.gridOpacity;

    // ── Minor grid ──
    ctx.lineWidth = 0.5;
    ctx.strokeStyle = CONFIG.gridColor;
    ctx.globalAlpha = opacity;
    ctx.beginPath();
    for (let x = 0; x <= width; x += gs) {
      if ((x / gs) % major === 0) continue;
      ctx.moveTo(x, 0);
      ctx.lineTo(x, height);
    }
    for (let y = 0; y <= height; y += gs) {
      if ((y / gs) % major === 0) continue;
      ctx.moveTo(0, y);
      ctx.lineTo(width, y);
    }
    ctx.stroke();

    // ── Major grid ──
    ctx.lineWidth = 1;
    ctx.strokeStyle = CONFIG.majorGridColor;
    ctx.beginPath();
    for (let x = 0; x <= width; x += gs * major) {
      ctx.moveTo(x, 0);
      ctx.lineTo(x, height);
    }
    for (let y = 0; y <= height; y += gs * major) {
      ctx.moveTo(0, y);
      ctx.lineTo(width, y);
    }
    ctx.stroke();
    ctx.globalAlpha = 1.0;

    // ── Dimension lines ──
    if (CONFIG.dimensionLineEnabled) {
      ctx.lineWidth = 1;
      ctx.setLineDash([4, 3]);

      for (let i = 0; i < dimensions.length; i++) {
        const d = dimensions[i];
        d.age += 1;

        // Fade in/out
        let alpha = 1;
        if (d.age < 30) alpha = d.age / 30;
        else if (d.age > d.lifespan - 30) alpha = (d.lifespan - d.age) / 30;
        if (d.age > d.lifespan) {
          dimensions[i] = createDimension(i);
          continue;
        }
        alpha = Math.max(0, Math.min(1, alpha));

        ctx.strokeStyle = CONFIG.dimensionColor;
        ctx.globalAlpha = alpha;

        if (d.type === 'h') {
          const offset = 8;
          // Horizontal dimension line
          ctx.beginPath();
          ctx.moveTo(d.x1, d.y);
          ctx.lineTo(d.x2, d.y);
          ctx.stroke();
          // Tick marks
          ctx.beginPath();
          ctx.moveTo(d.x1, d.y - offset);
          ctx.lineTo(d.x1, d.y + offset);
          ctx.moveTo(d.x2, d.y - offset);
          ctx.lineTo(d.x2, d.y + offset);
          ctx.stroke();
          // Label
          if (CONFIG.annotationEnabled) {
            const dist = Math.abs(d.x2 - d.x1);
            const label = `${(dist / gs).toFixed(1)} u`;
            ctx.fillStyle = CONFIG.annotationColor;
            ctx.font = `${CONFIG.annotationFontSize}px monospace`;
            ctx.textAlign = 'center';
            ctx.fillText(label, (d.x1 + d.x2) / 2, d.y - 10);
          }
        } else {
          const offset = 8;
          ctx.beginPath();
          ctx.moveTo(d.x, d.y1);
          ctx.lineTo(d.x, d.y2);
          ctx.stroke();
          ctx.beginPath();
          ctx.moveTo(d.x - offset, d.y1);
          ctx.lineTo(d.x + offset, d.y1);
          ctx.moveTo(d.x - offset, d.y2);
          ctx.lineTo(d.x + offset, d.y2);
          ctx.stroke();
          if (CONFIG.annotationEnabled) {
            const dist = Math.abs(d.y2 - d.y1);
            const label = `${(dist / gs).toFixed(1)} u`;
            ctx.save();
            ctx.fillStyle = CONFIG.annotationColor;
            ctx.font = `${CONFIG.annotationFontSize}px monospace`;
            ctx.textAlign = 'center';
            ctx.translate(d.x - 12, (d.y1 + d.y2) / 2);
            ctx.rotate(-Math.PI / 2);
            ctx.fillText(label, 0, 0);
            ctx.restore();
          }
        }
        ctx.globalAlpha = 1.0;
      }
      ctx.setLineDash([]);
    }

    // ── Coordinate labels along edges ──
    if (CONFIG.annotationEnabled) {
      ctx.fillStyle = CONFIG.annotationColor;
      ctx.font = `${CONFIG.annotationFontSize - 1}px monospace`;
      ctx.globalAlpha = 0.4;
      ctx.textAlign = 'center';
      for (let x = gs * major; x < width; x += gs * major) {
        ctx.fillText(`${(x / gs).toFixed(0)}`, x, 12);
      }
      ctx.textAlign = 'left';
      for (let y = gs * major; y < height; y += gs * major) {
        ctx.fillText(`${(y / gs).toFixed(0)}`, 4, y - 3);
      }
      ctx.globalAlpha = 1.0;
    }

    // ── Scan line ──
    if (CONFIG.scanLineEnabled) {
      scanY = (scanY + CONFIG.scanLineSpeed) % height;
      const grad = ctx.createLinearGradient(0, scanY - 40, 0, scanY + 40);
      grad.addColorStop(0, 'rgba(0,0,0,0)');
      grad.addColorStop(0.5, CONFIG.scanLineColor);
      grad.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = grad;
      ctx.fillRect(0, scanY - 40, width, 80);
    }

    // ── Center crosshair ──
    if (CONFIG.crosshairEnabled) {
      const cx = width / 2, cy = height / 2;
      ctx.strokeStyle = CONFIG.crosshairColor;
      ctx.lineWidth = 0.5;
      ctx.setLineDash([8, 6]);
      ctx.beginPath();
      ctx.moveTo(cx, 0); ctx.lineTo(cx, height);
      ctx.moveTo(0, cy); ctx.lineTo(width, cy);
      ctx.stroke();
      ctx.setLineDash([]);

      // Small reticle
      const rSize = 12;
      ctx.strokeStyle = CONFIG.crosshairColor;
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.arc(cx, cy, rSize, 0, Math.PI * 2);
      ctx.stroke();
    }

    // ── Mouse target crosshair ──
    if (mouse.x > 0 && mouse.y > 0) {
      const mx = mouse.x, my = mouse.y;

      // Crosshair lines
      ctx.strokeStyle = 'rgba(255,100,100,0.5)';
      ctx.lineWidth = 0.5;
      ctx.setLineDash([4, 4]);
      ctx.beginPath();
      ctx.moveTo(mx, 0); ctx.lineTo(mx, height);
      ctx.moveTo(0, my); ctx.lineTo(width, my);
      ctx.stroke();
      ctx.setLineDash([]);

      // Target reticle
      ctx.strokeStyle = 'rgba(255,100,100,0.7)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.arc(mx, my, 8, 0, Math.PI * 2);
      ctx.stroke();

      // Coordinate readout
      ctx.fillStyle = 'rgba(255,150,150,0.8)';
      ctx.font = `${CONFIG.annotationFontSize}px monospace`;
      ctx.textAlign = 'left';
      const coordLabel = `(${(mx / gs).toFixed(1)}, ${(my / gs).toFixed(1)})`;
      ctx.fillText(coordLabel, mx + 14, my - 10);

      // Distance from center
      const dx = mx - width / 2, dy = my - height / 2;
      const dist = Math.sqrt(dx * dx + dy * dy);
      ctx.fillStyle = 'rgba(255,150,150,0.5)';
      ctx.fillText(`Δ ${(dist / gs).toFixed(1)}u`, mx + 14, my + 4);
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Cell Division
 * Description: Mitosis-like cells that grow, develop a cleavage furrow, and divide
 *   into daughter cells. Features nucleus, membrane, cytoplasm, collision detection,
 *   and mouse repulsion.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Cell Population --
  initialCells: 4,                        // Starting number of cells
  maxCells: 40,                           // Maximum cells before oldest die off
  divisionTime: 400,                      // Frames until a cell divides

  // -- Cell Appearance --
  cellMinRadius: 18,                      // Minimum cell radius in px
  cellMaxRadius: 35,                      // Maximum cell radius (at division time)
  membraneColor: 'rgba(100, 200, 180, 0.4)',  // Cell membrane stroke color
  membraneWidth: 2,                       // Membrane stroke width in px
  nucleusColor: 'rgba(80, 160, 220, 0.5)',    // Nucleus fill color
  nucleusSizeRatio: 0.3,                  // Nucleus radius as fraction of cell radius (0-1)
  cytoplasmColor: 'rgba(120, 220, 200, 0.08)', // Inner cell fill color

  // -- Animation --
  divisionSpeed: 1.0,                     // Division animation speed multiplier (0-3)
  jiggleAmount: 0.5,                      // Random cell movement jitter in px

  // -- Mouse Interaction --
  mouseRepelRadius: 150,                  // Mouse repulsion radius in px
  mouseRepelForce: 5,                     // Mouse repulsion strength (0-15)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let cells = [];

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

class Cell {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.vx = (Math.random() - 0.5) * 0.5;
    this.vy = (Math.random() - 0.5) * 0.5;
    this.age = 0;
    this.dividing = false;
    this.divideProgress = 0;
    this.divideAngle = Math.random() * Math.PI;
    this.wobble = Math.random() * Math.PI * 2;
  }

  get radius() {
    const growth = Math.min(1, this.age / (CONFIG.divisionTime * 0.7));
    return CONFIG.cellMinRadius + (CONFIG.cellMaxRadius - CONFIG.cellMinRadius) * growth;
  }

  update() {
    this.age += CONFIG.divisionSpeed;
    this.wobble += 0.02;

    // Start dividing
    if (!this.dividing && this.age >= CONFIG.divisionTime * 0.8) {
      this.dividing = true;
    }

    if (this.dividing) {
      this.divideProgress = Math.min(1, this.divideProgress + 0.008 * CONFIG.divisionSpeed);
    }

    // Jiggle
    this.vx += (Math.random() - 0.5) * CONFIG.jiggleAmount * 0.1;
    this.vy += (Math.random() - 0.5) * CONFIG.jiggleAmount * 0.1;

    // Mouse repulsion
    const dx = this.x - mouse.x;
    const dy = this.y - mouse.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < CONFIG.mouseRepelRadius && dist > 0) {
      const force = (1 - dist / CONFIG.mouseRepelRadius) * CONFIG.mouseRepelForce * 0.1;
      this.vx += (dx / dist) * force;
      this.vy += (dy / dist) * force;
    }

    // Damping
    this.vx *= 0.95;
    this.vy *= 0.95;
    this.x += this.vx;
    this.y += this.vy;

    // Boundary
    const r = this.radius;
    if (this.x < r) { this.x = r; this.vx *= -0.5; }
    if (this.x > width - r) { this.x = width - r; this.vx *= -0.5; }
    if (this.y < r) { this.y = r; this.vy *= -0.5; }
    if (this.y > height - r) { this.y = height - r; this.vy *= -0.5; }
  }

  draw() {
    const r = this.radius;
    const wobX = Math.sin(this.wobble) * 1.5;
    const wobY = Math.cos(this.wobble * 1.3) * 1.5;

    if (this.dividing && this.divideProgress > 0) {
      // Draw two separating daughter cells
      const sep = this.divideProgress * r * 1.2;
      const cos = Math.cos(this.divideAngle);
      const sin = Math.sin(this.divideAngle);
      const r1 = r * (0.6 + 0.4 * this.divideProgress);
      const r2 = r * (0.6 + 0.4 * this.divideProgress);

      for (let side = -1; side <= 1; side += 2) {
        const cx = this.x + cos * sep * side * 0.5 + wobX;
        const cy = this.y + sin * sep * side * 0.5 + wobY;
        const cr = side === -1 ? r1 : r2;

        // Cytoplasm
        ctx.beginPath();
        ctx.arc(cx, cy, cr * 0.95, 0, Math.PI * 2);
        ctx.fillStyle = CONFIG.cytoplasmColor;
        ctx.fill();

        // Membrane
        ctx.beginPath();
        ctx.arc(cx, cy, cr, 0, Math.PI * 2);
        ctx.strokeStyle = CONFIG.membraneColor;
        ctx.lineWidth = CONFIG.membraneWidth;
        ctx.stroke();

        // Nucleus
        ctx.beginPath();
        ctx.arc(cx, cy, cr * CONFIG.nucleusSizeRatio, 0, Math.PI * 2);
        ctx.fillStyle = CONFIG.nucleusColor;
        ctx.fill();
      }

      // Cleavage furrow line
      if (this.divideProgress < 0.8) {
        const furrLen = r * (1 - this.divideProgress) * 0.8;
        ctx.beginPath();
        ctx.moveTo(this.x - sin * furrLen, this.y + cos * furrLen);
        ctx.lineTo(this.x + sin * furrLen, this.y - cos * furrLen);
        ctx.strokeStyle = CONFIG.membraneColor;
        ctx.lineWidth = CONFIG.membraneWidth * 0.5;
        ctx.stroke();
      }
    } else {
      // Normal cell
      const cx = this.x + wobX;
      const cy = this.y + wobY;

      // Cytoplasm
      ctx.beginPath();
      ctx.arc(cx, cy, r * 0.95, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.cytoplasmColor;
      ctx.fill();

      // Membrane
      ctx.beginPath();
      ctx.arc(cx, cy, r, 0, Math.PI * 2);
      ctx.strokeStyle = CONFIG.membraneColor;
      ctx.lineWidth = CONFIG.membraneWidth;
      ctx.stroke();

      // Nucleus
      ctx.beginPath();
      ctx.arc(cx, cy, r * CONFIG.nucleusSizeRatio, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.nucleusColor;
      ctx.fill();
    }
  }

  shouldDivide() {
    return this.dividing && this.divideProgress >= 1;
  }

  createDaughters() {
    const sep = this.radius * 0.7;
    const cos = Math.cos(this.divideAngle);
    const sin = Math.sin(this.divideAngle);
    const d1 = new Cell(this.x + cos * sep, this.y + sin * sep);
    const d2 = new Cell(this.x - cos * sep, this.y - sin * sep);
    d1.vx = cos * 0.5;
    d1.vy = sin * 0.5;
    d2.vx = -cos * 0.5;
    d2.vy = -sin * 0.5;
    return [d1, d2];
  }
}

function collide(cells) {
  for (let i = 0; i < cells.length; i++) {
    for (let j = i + 1; j < cells.length; j++) {
      const a = cells[i], b = cells[j];
      const dx = b.x - a.x;
      const dy = b.y - a.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const minDist = a.radius + b.radius;
      if (dist < minDist && dist > 0) {
        const overlap = (minDist - dist) * 0.5;
        const nx = dx / dist;
        const ny = dy / dist;
        a.x -= nx * overlap * 0.5;
        a.y -= ny * overlap * 0.5;
        b.x += nx * overlap * 0.5;
        b.y += ny * overlap * 0.5;
        a.vx -= nx * 0.2;
        a.vy -= ny * 0.2;
        b.vx += nx * 0.2;
        b.vy += ny * 0.2;
      }
    }
  }
}

function initCells() {
  cells = [];
  for (let i = 0; i < CONFIG.initialCells; i++) {
    cells.push(new Cell(
      Math.random() * (width - 100) + 50,
      Math.random() * (height - 100) + 50,
    ));
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, width, height);

    // Update and collect new divisions
    const newCells = [];
    const toRemove = [];
    for (let i = 0; i < cells.length; i++) {
      cells[i].update();
      if (cells[i].shouldDivide()) {
        if (cells.length + newCells.length < CONFIG.maxCells) {
          newCells.push(...cells[i].createDaughters());
        }
        toRemove.push(i);
      }
    }

    // Remove divided cells
    for (let i = toRemove.length - 1; i >= 0; i--) {
      cells.splice(toRemove[i], 1);
    }
    cells.push(...newCells);

    // Trim excess
    while (cells.length > CONFIG.maxCells) {
      cells.shift();
    }

    collide(cells);

    // Draw
    for (const cell of cells) {
      cell.draw();
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initCells();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Chroma RGB Liquid Grid – Cyber-Neon Edition
 * Description: Elastic neon lattice that breathes, ripples and explodes into RGB when touched.
 */

let canvas, ctx, width, height;
let points = [];
let mouse = { x: -5000, y: -5000 };
let tick = 0;
let rgbPhase = 0;                // 0-360° hue rotator
let lastMouse = { x: 0, y: 0 };  // for velocity tracking

const CONFIG = {
    // VISUALS
    gridSpacing: 40,
    crossSize: 3,
    colorIdle: 'rgba(255,255,255,0.15)',
    mouseSize: 140,
    mouseForce: 0.7,
    tension: 0.16,
    friction: 0.86,
    breatheSpeed: 0.025,
    breatheDepth: 3,

    // RGB PARTY
    rgbSpeed: 4,               // hue rotation per frame
    rgbRadius: 180,          // how far the RGB wave travels
    rgbIntensity: 0.8,       // 0-1 saturation of RGB
    trailDecay: 0.92        // mouse-trail fade
};

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            startLoop();
            break;
        case 'resize':
            resize(e.data.width, e.data.height);
            break;
        case 'mousemove':
            lastMouse.x = mouse.x;
            lastMouse.y = mouse.y;
            mouse.x = e.data.x;
            mouse.y = e.data.y;
            break;
    }
};

function resize(w, h) {
    width = w;
    height = h;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
    }
    initGrid();
}

class Point {
    constructor(x, y) {
        this.ox = x;
        this.oy = y;
        this.x = x;
        this.y = y;
        this.vx = 0;
        this.vy = 0;
        this.glow = 0;       // 0-1 RGB glow
    }

    update() {
        // --- forces ---
        let dx = mouse.x - this.x;
        let dy = mouse.y - this.y;
        let dist = Math.hypot(dx, dy);

        // repulsion
        if (dist < CONFIG.mouseSize) {
            let ang = Math.atan2(dy, dx);
            let f = (CONFIG.mouseSize - dist) / CONFIG.mouseSize;
            let push = -f * CONFIG.mouseForce * 25;
            this.vx += Math.cos(ang) * push;
            this.vy += Math.sin(ang) * push;
        }

        // spring back
        let breathe = Math.sin(this.ox * 0.05 + tick) * CONFIG.breatheDepth;
        let dxSpring = this.ox - this.x;
        let dySpring = this.oy - this.y + breathe;
        this.vx += dxSpring * CONFIG.tension;
        this.vy += dySpring * CONFIG.tension;

        // friction
        this.vx *= CONFIG.friction;
        this.vy *= CONFIG.friction;
        this.x += this.vx;
        this.y += this.vy;

        // --- RGB glow ---
        let speed = Math.hypot(this.vx, this.vy);
        let disp = Math.hypot(this.x - this.ox, this.y - this.oy);
        let mouseVel = Math.hypot(mouse.x - lastMouse.x, mouse.y - lastMouse.y);
        let hotRadius = CONFIG.mouseSize + mouseVel * 2;
        let hot = Math.max(0, 1 - dist / hotRadius);
        this.glow = Math.min(1, hot + (speed > 0.3 || disp > 6 ? 0.7 : 0));
        this.glow *= CONFIG.rgbIntensity;
    }

    draw() {
        ctx.save();
        ctx.translate(this.x, this.y);

        // --- color logic ---
        let hue = (rgbPhase + (this.x + this.y) * 0.3) % 360;
        let rgb = `hsl(${hue},100%,${50 + this.glow * 40}%)`;
        let base = this.glow > 0.05 ? rgb : CONFIG.colorIdle;

        // --- crosshair ---
        ctx.strokeStyle = base;
        ctx.lineWidth = 1 + this.glow * 2;
        ctx.beginPath();
        let s = CONFIG.crossSize + this.glow * 3;
        ctx.moveTo(-s, 0); ctx.lineTo(s, 0);
        ctx.moveTo(0, -s); ctx.lineTo(0, s);
        ctx.stroke();

        // --- additive glow ---
        if (this.glow) {
            ctx.strokeStyle = `hsl(${hue},100%,70%)`;
            ctx.lineWidth = 1;
            ctx.globalAlpha = this.glow * 0.6;
            ctx.stroke();
            ctx.globalAlpha = 1;
        }
        ctx.restore();
    }
}

function initGrid() {
    points = [];
    for (let x = 0; x < width + CONFIG.gridSpacing; x += CONFIG.gridSpacing)
        for (let y = 0; y < height + CONFIG.gridSpacing; y += CONFIG.gridSpacing)
            points.push(new Point(x, y));
}

function startLoop() {
    function render() {
        if (!ctx) return;
        ctx.clearRect(0, 0, width, height);

        tick += CONFIG.breatheSpeed;
        rgbPhase = (rgbPhase + CONFIG.rgbSpeed) % 360;

        for (let p of points) {
            p.update();
            p.draw();
        }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

/**
 * Title: Circuit Board
 * Description: Animated circuit board traces drawn in real-time. Lines travel horizontally
 *   and vertically with 90-degree turns. Glowing nodes at junctions/endpoints.
 *   Mouse creates signal pulses that race along nearby traces. Subtle cyan/green palette.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

const GRID = 20; // grid spacing
const MAX_TRACES = 60;
const MAX_PULSES = 40;
const TRACE_COLOR = 'rgba(0, 180, 160, 0.2)';
const NODE_COLOR = 'rgba(0, 220, 180, 0.5)';
const PULSE_COLOR = 'rgba(0, 255, 200, 0.9)';

let traces = [];
let pulses = [];
let activeTraces = []; // traces currently being drawn
let lastPulseTime = 0;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			traces = [];
			activeTraces = [];
			pulses = [];
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function snapToGrid(v) {
	return Math.round(v / GRID) * GRID;
}

function init() {
	traces = [];
	activeTraces = [];
	pulses = [];
}

// A trace is a series of connected segments (polyline on the grid)
function spawnTrace() {
	const startX = snapToGrid(Math.random() * width);
	const startY = snapToGrid(Math.random() * height);
	// Direction: 0=right, 1=down, 2=left, 3=up
	const dir = Math.floor(Math.random() * 4);
	const segmentCount = 3 + Math.floor(Math.random() * 8);

	return {
		points: [{ x: startX, y: startY }],
		targetPoints: generatePath(startX, startY, dir, segmentCount),
		currentSegment: 0,
		progress: 0, // 0-1 along current segment
		speed: 0.02 + Math.random() * 0.03,
		complete: false,
		opacity: 0.15 + Math.random() * 0.15
	};
}

function generatePath(sx, sy, startDir, count) {
	const pts = [{ x: sx, y: sy }];
	let dir = startDir;
	let cx = sx,
		cy = sy;

	for (let i = 0; i < count; i++) {
		const len = (2 + Math.floor(Math.random() * 8)) * GRID;
		const dx = [1, 0, -1, 0][dir];
		const dy = [0, 1, 0, -1][dir];
		cx += dx * len;
		cy += dy * len;
		// Clamp to canvas
		cx = Math.max(0, Math.min(width, cx));
		cy = Math.max(0, Math.min(height, cy));
		pts.push({ x: cx, y: cy });
		// Turn 90 degrees (randomly left or right)
		dir = (dir + (Math.random() < 0.5 ? 1 : 3)) % 4;
	}
	return pts;
}

function spawnPulse(trace) {
	if (trace.targetPoints.length < 2) return;
	return {
		trace: trace,
		segment: 0,
		progress: 0,
		speed: 0.03 + Math.random() * 0.02,
		life: 1.0
	};
}

function startAnimation() {
	let frameCount = 0;

	function render(time) {
		if (!ctx) return;
		frameCount++;

		ctx.clearRect(0, 0, width, height);

		// Spawn new traces periodically
		if (frameCount % 30 === 0 && activeTraces.length < 3 && traces.length < MAX_TRACES) {
			activeTraces.push(spawnTrace());
		}

		// Update and draw active (growing) traces
		for (let i = activeTraces.length - 1; i >= 0; i--) {
			const t = activeTraces[i];

			if (t.currentSegment < t.targetPoints.length - 1) {
				t.progress += t.speed;
				if (t.progress >= 1) {
					t.progress = 0;
					t.currentSegment++;
					// Add completed point
					if (t.currentSegment < t.targetPoints.length) {
						t.points.push({
							x: t.targetPoints[t.currentSegment].x,
							y: t.targetPoints[t.currentSegment].y
						});
					}
				}
			} else {
				t.complete = true;
				traces.push(t);
				activeTraces.splice(i, 1);
			}
		}

		// Remove oldest traces if over limit
		while (traces.length > MAX_TRACES) {
			traces.shift();
		}

		// Draw all completed traces
		for (const t of traces) {
			drawTrace(t);
		}

		// Draw active traces (partially drawn)
		for (const t of activeTraces) {
			drawActiveTrace(t);
		}

		// Mouse pulse spawning — find nearby completed traces
		if (time - lastPulseTime > 300) {
			for (const t of traces) {
				if (pulses.length >= MAX_PULSES) break;
				for (const pt of t.targetPoints) {
					const dx = pt.x - mouse.x;
					const dy = pt.y - mouse.y;
					if (dx * dx + dy * dy < 150 * 150) {
						const p = spawnPulse(t);
						if (p) pulses.push(p);
						lastPulseTime = time;
						break;
					}
				}
			}
		}

		// Update and draw pulses
		for (let i = pulses.length - 1; i >= 0; i--) {
			const p = pulses[i];
			p.progress += p.speed;
			if (p.progress >= 1) {
				p.progress = 0;
				p.segment++;
			}
			p.life -= 0.005;

			if (p.segment >= p.trace.targetPoints.length - 1 || p.life <= 0) {
				pulses.splice(i, 1);
				continue;
			}

			// Interpolate pulse position
			const a = p.trace.targetPoints[p.segment];
			const b = p.trace.targetPoints[p.segment + 1];
			const px = a.x + (b.x - a.x) * p.progress;
			const py = a.y + (b.y - a.y) * p.progress;

			ctx.beginPath();
			ctx.arc(px, py, 3, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(0, 255, 200, ${p.life * 0.8})`;
			ctx.shadowColor = 'rgba(0, 255, 200, 0.6)';
			ctx.shadowBlur = 10;
			ctx.fill();
			ctx.shadowBlur = 0;
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

function drawTrace(t) {
	if (t.targetPoints.length < 2) return;

	ctx.beginPath();
	ctx.moveTo(t.targetPoints[0].x, t.targetPoints[0].y);
	for (let i = 1; i < t.targetPoints.length; i++) {
		ctx.lineTo(t.targetPoints[i].x, t.targetPoints[i].y);
	}
	ctx.strokeStyle = `rgba(0, 180, 160, ${t.opacity})`;
	ctx.lineWidth = 1.5;
	ctx.stroke();

	// Draw nodes at junctions
	for (let i = 0; i < t.targetPoints.length; i++) {
		const pt = t.targetPoints[i];
		// Glow brighter if mouse is near
		const dx = pt.x - mouse.x;
		const dy = pt.y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		const glow = dist < 120 ? 0.6 + (1 - dist / 120) * 0.4 : 0.3;

		ctx.beginPath();
		ctx.arc(pt.x, pt.y, 2.5, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(0, 220, 180, ${glow * t.opacity * 2})`;
		ctx.fill();
	}
}

function drawActiveTrace(t) {
	if (t.points.length < 1 || t.currentSegment >= t.targetPoints.length - 1) return;

	// Draw completed segments
	ctx.beginPath();
	ctx.moveTo(t.points[0].x, t.points[0].y);
	for (let i = 1; i < t.points.length; i++) {
		ctx.lineTo(t.points[i].x, t.points[i].y);
	}

	// Draw current segment (in progress)
	const a = t.targetPoints[t.currentSegment];
	const b = t.targetPoints[t.currentSegment + 1];
	const cx = a.x + (b.x - a.x) * t.progress;
	const cy = a.y + (b.y - a.y) * t.progress;
	ctx.lineTo(cx, cy);

	ctx.strokeStyle = `rgba(0, 220, 180, ${t.opacity * 1.5})`;
	ctx.lineWidth = 1.5;
	ctx.stroke();

	// Glowing tip
	ctx.beginPath();
	ctx.arc(cx, cy, 3, 0, Math.PI * 2);
	ctx.fillStyle = 'rgba(0, 255, 220, 0.8)';
	ctx.shadowColor = 'rgba(0, 255, 220, 0.6)';
	ctx.shadowBlur = 8;
	ctx.fill();
	ctx.shadowBlur = 0;

	// Draw completed nodes
	for (const pt of t.points) {
		ctx.beginPath();
		ctx.arc(pt.x, pt.y, 2, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(0, 220, 180, ${t.opacity * 2})`;
		ctx.fill();
	}
}

/**
 * Title: Comet Shower
 * Description: Comets streak diagonally across the sky with glowing heads and
 *   sparkling fading tails. Mouse gravity pulls nearby comets toward the cursor.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Comet Spawning --
  cometFrequency: 600,                    // Average ms between comet spawns
  cometFrequencyVariance: 400,            // ± random ms added to frequency
  maxComets: 15,                          // Maximum simultaneous comets on screen

  // -- Comet Appearance --
  cometSize: 3.5,                         // Head radius in px
  headGlowRadius: 18,                     // Glow halo around comet head in px
  headGlowOpacity: 0.6,                   // Head glow intensity (0-1)
  colorPalette: [                         // Array of comet head/tail colors
    'rgba(100, 180, 255, 1)',             //   Cool blue
    'rgba(255, 160, 80, 1)',              //   Warm orange
    'rgba(180, 120, 255, 1)',             //   Purple
    'rgba(100, 255, 200, 1)',             //   Teal
    'rgba(255, 255, 150, 1)',             //   Pale gold
  ],

  // -- Tail --
  tailLength: 45,                         // Number of trail points stored
  tailFade: 0.92,                         // Opacity decay per trail point (0-1)
  tailWidth: 2.5,                         // Base tail stroke width in px
  sparkleDensity: 0.4,                    // Chance per trail point to emit a sparkle (0-1)
  sparkleSize: 1.8,                       // Sparkle particle radius in px
  sparkleLife: 40,                        // Sparkle lifetime in frames

  // -- Motion --
  minSpeed: 4,                            // Minimum comet travel speed in px/frame
  maxSpeed: 9,                            // Maximum comet travel speed in px/frame
  angle: 225,                             // Travel direction in degrees (0=right, 90=down, 225=upper-right to lower-left)
  angleVariance: 20,                      // ± random degrees of angle spread

  // -- Mouse Interaction --
  mouseGravityRadius: 250,                // Radius of mouse gravity pull in px
  mouseGravityStrength: 3.5,              // Strength of gravitational pull toward mouse
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let comets = [];
let sparkles = [];
let lastSpawnTime = 0;
let nextSpawnDelay = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function parseRGBA(str) {
  const m = str.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  if (m) return { r: +m[1], g: +m[2], b: +m[3] };
  return { r: 200, g: 200, b: 255 };
}

function spawnComet() {
  const angleRad = (CONFIG.angle + (Math.random() - 0.5) * CONFIG.angleVariance * 2) * Math.PI / 180;
  const speed = CONFIG.minSpeed + Math.random() * (CONFIG.maxSpeed - CONFIG.minSpeed);
  const vx = Math.cos(angleRad) * speed;
  const vy = Math.sin(angleRad) * speed;

  // Spawn from the edge the comet is coming from
  let x, y;
  if (vx < 0) {
    x = width + 50;
  } else {
    x = -50;
  }
  if (vy < 0) {
    y = height + 50;
  } else {
    y = -50;
  }
  // Add randomness along the perpendicular axis
  x += (Math.random() - 0.3) * width * 0.6;
  y += (Math.random() - 0.3) * height * 0.4;

  const colorStr = CONFIG.colorPalette[Math.floor(Math.random() * CONFIG.colorPalette.length)];
  const color = parseRGBA(colorStr);

  comets.push({
    x, y, vx, vy, speed,
    color,
    colorStr,
    trail: [],
  });
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    const now = performance.now();

    ctx.clearRect(0, 0, width, height);

    // Spawn comets
    if (now - lastSpawnTime > nextSpawnDelay && comets.length < CONFIG.maxComets) {
      spawnComet();
      lastSpawnTime = now;
      nextSpawnDelay = CONFIG.cometFrequency + (Math.random() - 0.5) * 2 * CONFIG.cometFrequencyVariance;
    }

    // Update and draw comets
    for (let i = comets.length - 1; i >= 0; i--) {
      const c = comets[i];

      // Mouse gravity
      const dx = mouse.x - c.x;
      const dy = mouse.y - c.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONFIG.mouseGravityRadius && dist > 1) {
        const factor = (1 - dist / CONFIG.mouseGravityRadius);
        c.vx += (dx / dist) * CONFIG.mouseGravityStrength * factor * 0.1;
        c.vy += (dy / dist) * CONFIG.mouseGravityStrength * factor * 0.1;
      }

      c.x += c.vx;
      c.y += c.vy;

      // Store trail
      c.trail.unshift({ x: c.x, y: c.y });
      if (c.trail.length > CONFIG.tailLength) c.trail.pop();

      // Remove if off-screen
      const margin = 100;
      if (c.x < -margin || c.x > width + margin || c.y < -margin || c.y > height + margin) {
        comets.splice(i, 1);
        continue;
      }

      // Emit sparkles from trail
      for (let t = 1; t < c.trail.length; t++) {
        if (Math.random() < CONFIG.sparkleDensity * 0.1) {
          sparkles.push({
            x: c.trail[t].x + (Math.random() - 0.5) * 6,
            y: c.trail[t].y + (Math.random() - 0.5) * 6,
            life: CONFIG.sparkleLife,
            maxLife: CONFIG.sparkleLife,
            color: c.color,
          });
        }
      }

      // Draw tail
      if (c.trail.length > 1) {
        for (let t = 1; t < c.trail.length; t++) {
          const alpha = Math.pow(CONFIG.tailFade, t);
          if (alpha < 0.01) break;
          const w = CONFIG.tailWidth * (1 - t / c.trail.length);
          ctx.beginPath();
          ctx.moveTo(c.trail[t - 1].x, c.trail[t - 1].y);
          ctx.lineTo(c.trail[t].x, c.trail[t].y);
          ctx.strokeStyle = `rgba(${c.color.r}, ${c.color.g}, ${c.color.b}, ${alpha})`;
          ctx.lineWidth = Math.max(0.5, w);
          ctx.lineCap = 'round';
          ctx.stroke();
        }
      }

      // Draw head glow
      const headGrad = ctx.createRadialGradient(c.x, c.y, 0, c.x, c.y, CONFIG.headGlowRadius);
      headGrad.addColorStop(0, `rgba(${c.color.r}, ${c.color.g}, ${c.color.b}, ${CONFIG.headGlowOpacity})`);
      headGrad.addColorStop(1, `rgba(${c.color.r}, ${c.color.g}, ${c.color.b}, 0)`);
      ctx.fillStyle = headGrad;
      ctx.beginPath();
      ctx.arc(c.x, c.y, CONFIG.headGlowRadius, 0, Math.PI * 2);
      ctx.fill();

      // Draw head
      ctx.beginPath();
      ctx.arc(c.x, c.y, CONFIG.cometSize, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${Math.min(255, c.color.r + 60)}, ${Math.min(255, c.color.g + 60)}, ${Math.min(255, c.color.b + 60)}, 1)`;
      ctx.fill();
    }

    // Update and draw sparkles
    for (let i = sparkles.length - 1; i >= 0; i--) {
      const s = sparkles[i];
      s.life--;
      if (s.life <= 0) {
        sparkles.splice(i, 1);
        continue;
      }
      const alpha = (s.life / s.maxLife) * 0.8;
      ctx.beginPath();
      ctx.arc(s.x, s.y, CONFIG.sparkleSize * (s.life / s.maxLife), 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${s.color.r}, ${s.color.g}, ${s.color.b}, ${alpha})`;
      ctx.fill();
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Constellation Map
 * Description: Randomly placed stars that form connection lines (like constellation patterns)
 *              to nearby stars within a threshold distance. Stars slowly drift across the canvas.
 *              Mouse creates a gravitational pull that attracts nearby stars.
 *              Connection line opacity is based on inter-star distance.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let stars = [];

const STAR_COUNT = 120;
const CONNECTION_DIST = 150;
const MOUSE_RADIUS = 250;
const MOUSE_GRAVITY = 0.015;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Star {
	constructor() {
		this.init();
	}

	init() {
		this.x = Math.random() * width;
		this.y = Math.random() * height;
		this.vx = (Math.random() - 0.5) * 0.2;
		this.vy = (Math.random() - 0.5) * 0.2;
		this.size = 0.8 + Math.random() * 1.8;
		this.brightness = 0.3 + Math.random() * 0.7;
		// Subtle twinkle
		this.twinkleSpeed = 0.02 + Math.random() * 0.03;
		this.twinklePhase = Math.random() * Math.PI * 2;
		this.twinkleAmount = 0.1 + Math.random() * 0.3;
		// Slight color variation (white to pale blue/gold)
		const hueRoll = Math.random();
		if (hueRoll < 0.6) {
			this.color = { r: 220, g: 230, b: 255 }; // pale blue-white
		} else if (hueRoll < 0.8) {
			this.color = { r: 255, g: 240, b: 200 }; // warm white
		} else {
			this.color = { r: 200, g: 220, b: 255 }; // blue
		}
	}

	update(time) {
		// Gravitational pull from mouse
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const dist = Math.sqrt(dx * dx + dy * dy);

		if (dist < MOUSE_RADIUS && dist > 5) {
			const force = (1 - dist / MOUSE_RADIUS) * MOUSE_GRAVITY;
			this.vx += (dx / dist) * force;
			this.vy += (dy / dist) * force;
		}

		// Apply velocity with damping
		this.x += this.vx;
		this.y += this.vy;
		this.vx *= 0.995;
		this.vy *= 0.995;

		// Wrap around edges
		if (this.x < -20) this.x = width + 20;
		if (this.x > width + 20) this.x = -20;
		if (this.y < -20) this.y = height + 20;
		if (this.y > height + 20) this.y = -20;

		// Twinkle
		this.currentBrightness =
			this.brightness + Math.sin(time * this.twinkleSpeed + this.twinklePhase) * this.twinkleAmount;
		this.currentBrightness = Math.max(0.1, Math.min(1, this.currentBrightness));
	}

	draw() {
		const { r, g, b } = this.color;
		const alpha = this.currentBrightness * 0.8;

		// Star glow
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size * 3, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${alpha * 0.08})`;
		ctx.fill();

		// Star core
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${alpha})`;
		ctx.fill();
	}
}

function initStars() {
	stars = [];
	for (let i = 0; i < STAR_COUNT; i++) {
		stars.push(new Star());
	}
}

function drawConnections() {
	for (let i = 0; i < stars.length; i++) {
		// Limit connections per star to avoid visual clutter
		let connections = 0;
		for (let j = i + 1; j < stars.length; j++) {
			if (connections >= 3) break;

			const dx = stars[i].x - stars[j].x;
			const dy = stars[i].y - stars[j].y;
			const dist = Math.sqrt(dx * dx + dy * dy);

			if (dist < CONNECTION_DIST) {
				const opacity = (1 - dist / CONNECTION_DIST) * 0.15;
				ctx.beginPath();
				ctx.moveTo(stars[i].x, stars[i].y);
				ctx.lineTo(stars[j].x, stars[j].y);
				ctx.strokeStyle = `rgba(180, 200, 255, ${opacity})`;
				ctx.lineWidth = 0.5;
				ctx.stroke();
				connections++;
			}
		}
	}
}

function drawMouseConnections() {
	if (mouse.x < -1000) return;

	for (const star of stars) {
		const dx = star.x - mouse.x;
		const dy = star.y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);

		if (dist < MOUSE_RADIUS * 0.6) {
			const opacity = (1 - dist / (MOUSE_RADIUS * 0.6)) * 0.1;
			ctx.beginPath();
			ctx.moveTo(mouse.x, mouse.y);
			ctx.lineTo(star.x, star.y);
			ctx.strokeStyle = `rgba(160, 200, 255, ${opacity})`;
			ctx.lineWidth = 0.3;
			ctx.stroke();
		}
	}
}

let time = 0;

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time += 1;

		// Update all stars
		for (const star of stars) {
			star.update(time);
		}

		// Draw constellation lines
		drawConnections();
		drawMouseConnections();

		// Draw stars on top
		for (const star of stars) {
			star.draw();
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initStars();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initStars();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Coral Growth
 * Description: Fractal branching coral structures that slowly grow from seed points.
 *   Features recursive branching with configurable angles, natural sway, line tapering,
 *   and mouse wind effect. Multiple colonies grow simultaneously.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Branch Geometry --
  branchAngle: 25,                        // Branch spread angle in degrees (10-60)
  branchLength: 40,                       // Base branch length in pixels
  reductionRatio: 0.72,                   // Each sub-branch is this fraction of parent (0.5-0.9)
  maxDepth: 7,                            // Maximum recursion depth (4-10)

  // -- Growth --
  growthSpeed: 0.8,                       // Growth animation speed (0.1-3)
  growthPoints: 4,                        // Number of coral colonies

  // -- Appearance --
  colors: [                               // Color palette for branches (cycled by depth)
    'rgba(255, 120, 150, 0.5)',           // Pink
    'rgba(255, 180, 100, 0.4)',           // Coral orange
    'rgba(200, 100, 180, 0.45)',          // Mauve
    'rgba(100, 200, 200, 0.4)',           // Teal
    'rgba(255, 150, 120, 0.45)',          // Salmon
  ],
  lineWidth: 3,                           // Base line width in px (tapers with depth)
  lineTaper: true,                        // Taper line width with depth

  // -- Motion --
  swayAmount: 3,                          // Sway displacement in px (0-15)
  swaySpeed: 0.8,                         // Sway animation speed (0-3)
  fadeOldBranches: true,                  // Older branches fade slightly

  // -- Mouse --
  mouseWindStrength: 6,                   // Wind bending strength from mouse (0-15)
  mouseWindRadius: 250,                   // Mouse influence radius in px
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let colonies = [];
let time = 0;
let growthProgress = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initColonies() {
  colonies = [];
  for (let i = 0; i < CONFIG.growthPoints; i++) {
    colonies.push({
      x: width * (0.15 + 0.7 * (i / Math.max(1, CONFIG.growthPoints - 1))),
      y: height - 10,
      angle: -Math.PI / 2 + (Math.random() - 0.5) * 0.3,
      seed: Math.random() * 1000,
    });
  }
  growthProgress = 0;
}

function drawBranch(x, y, angle, length, depth, maxVisibleDepth, seed) {
  if (depth > CONFIG.maxDepth || depth > maxVisibleDepth) return;
  if (length < 2) return;

  const angleRad = CONFIG.branchAngle * Math.PI / 180;

  // Sway
  const swayOffset = Math.sin(time * CONFIG.swaySpeed + seed + depth * 0.7) * CONFIG.swayAmount * (depth / CONFIG.maxDepth);

  // Mouse wind
  let windOffset = 0;
  const dx = x - mouse.x;
  const dy = y - mouse.y;
  const dist = Math.sqrt(dx * dx + dy * dy);
  if (dist < CONFIG.mouseWindRadius && dist > 0) {
    const force = (1 - dist / CONFIG.mouseWindRadius) * CONFIG.mouseWindStrength;
    windOffset = (dx / dist) * force * (depth / CONFIG.maxDepth);
  }

  const endX = x + Math.cos(angle) * length + swayOffset + windOffset;
  const endY = y + Math.sin(angle) * length;

  // Line width
  let lw = CONFIG.lineWidth;
  if (CONFIG.lineTaper) {
    lw = CONFIG.lineWidth * (1 - depth / (CONFIG.maxDepth + 1)) * 0.8 + 0.5;
  }

  // Color
  const colorIdx = depth % CONFIG.colors.length;
  let color = CONFIG.colors[colorIdx];

  // Fade old branches
  if (CONFIG.fadeOldBranches && depth < maxVisibleDepth - 2) {
    color = color.replace(/[\d.]+\)$/, (0.2 + depth * 0.03).toFixed(2) + ')');
  }

  // Growth progress within this depth
  const depthProgress = maxVisibleDepth - depth;
  const branchGrowth = Math.min(1, depthProgress);
  const actualEndX = x + (endX - x) * branchGrowth;
  const actualEndY = y + (endY - y) * branchGrowth;

  // Draw
  ctx.beginPath();
  ctx.moveTo(x, y);
  ctx.lineTo(actualEndX, actualEndY);
  ctx.strokeStyle = color;
  ctx.lineWidth = lw;
  ctx.lineCap = 'round';
  ctx.stroke();

  // Node glow at tip for growing branches
  if (Math.abs(depthProgress - 1) < 0.5 && branchGrowth > 0.5) {
    ctx.beginPath();
    ctx.arc(actualEndX, actualEndY, lw * 1.5, 0, Math.PI * 2);
    ctx.fillStyle = color.replace(/[\d.]+\)$/, '0.3)');
    ctx.fill();
  }

  if (branchGrowth >= 1) {
    const newLength = length * CONFIG.reductionRatio;
    // Left branch
    drawBranch(actualEndX, actualEndY, angle - angleRad + (Math.random() - 0.5) * 0.15, newLength, depth + 1, maxVisibleDepth, seed + 1);
    // Right branch
    drawBranch(actualEndX, actualEndY, angle + angleRad + (Math.random() - 0.5) * 0.15, newLength, depth + 1, maxVisibleDepth, seed + 2);
    // Occasional center branch
    if (Math.sin(seed * 7 + depth * 3) > 0.5) {
      drawBranch(actualEndX, actualEndY, angle + (Math.random() - 0.5) * 0.2, newLength * 0.8, depth + 1, maxVisibleDepth, seed + 3);
    }
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 0.016;
    growthProgress += CONFIG.growthSpeed * 0.01;

    ctx.clearRect(0, 0, width, height);

    const maxVisible = Math.min(CONFIG.maxDepth, growthProgress * 1.5);

    for (const colony of colonies) {
      drawBranch(
        colony.x,
        colony.y,
        colony.angle,
        CONFIG.branchLength,
        0,
        maxVisible,
        colony.seed,
      );
    }

    // Reset growth cycle when fully grown
    if (growthProgress > CONFIG.maxDepth * 1.5) {
      growthProgress = CONFIG.maxDepth * 1.5;
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initColonies();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initColonies();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Cosmic Dust
 * Description: Thousands of tiny dust-like particles drifting very slowly in random directions
 *              with extremely subtle colors (near-white with very low opacity). Creates a living,
 *              breathing cosmic dust cloud effect. Mouse creates a gentle wind that pushes particles.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let particles = [];
let time = 0;

const PARTICLE_COUNT = 1800;
const MOUSE_RADIUS = 180;
const WIND_FORCE = 0.3;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Pre-allocate typed arrays for performance with large particle counts
let posX, posY, velX, velY, sizes, opacities, colorR, colorG, colorB, phases;

function initParticles() {
	posX = new Float32Array(PARTICLE_COUNT);
	posY = new Float32Array(PARTICLE_COUNT);
	velX = new Float32Array(PARTICLE_COUNT);
	velY = new Float32Array(PARTICLE_COUNT);
	sizes = new Float32Array(PARTICLE_COUNT);
	opacities = new Float32Array(PARTICLE_COUNT);
	colorR = new Uint8Array(PARTICLE_COUNT);
	colorG = new Uint8Array(PARTICLE_COUNT);
	colorB = new Uint8Array(PARTICLE_COUNT);
	phases = new Float32Array(PARTICLE_COUNT);

	for (let i = 0; i < PARTICLE_COUNT; i++) {
		posX[i] = Math.random() * width;
		posY[i] = Math.random() * height;
		velX[i] = (Math.random() - 0.5) * 0.08;
		velY[i] = (Math.random() - 0.5) * 0.06;
		sizes[i] = 0.3 + Math.random() * 1.0;
		phases[i] = Math.random() * Math.PI * 2;

		// Near-white with extremely subtle color tinting
		const tint = Math.random();
		if (tint < 0.4) {
			// Pure near-white
			colorR[i] = 230 + Math.floor(Math.random() * 25);
			colorG[i] = 230 + Math.floor(Math.random() * 25);
			colorB[i] = 235 + Math.floor(Math.random() * 20);
			opacities[i] = 0.03 + Math.random() * 0.06;
		} else if (tint < 0.6) {
			// Slightly warm white
			colorR[i] = 240 + Math.floor(Math.random() * 15);
			colorG[i] = 225 + Math.floor(Math.random() * 20);
			colorB[i] = 210 + Math.floor(Math.random() * 20);
			opacities[i] = 0.02 + Math.random() * 0.05;
		} else if (tint < 0.8) {
			// Slightly cool white
			colorR[i] = 210 + Math.floor(Math.random() * 20);
			colorG[i] = 220 + Math.floor(Math.random() * 20);
			colorB[i] = 240 + Math.floor(Math.random() * 15);
			opacities[i] = 0.02 + Math.random() * 0.05;
		} else {
			// Faint lavender
			colorR[i] = 220 + Math.floor(Math.random() * 20);
			colorG[i] = 210 + Math.floor(Math.random() * 20);
			colorB[i] = 240 + Math.floor(Math.random() * 15);
			opacities[i] = 0.02 + Math.random() * 0.04;
		}
	}
}

function startAnimation() {
	// Cached previous mouse for wind direction
	let prevMouseX = mouse.x;
	let prevMouseY = mouse.y;

	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time += 1;

		// Calculate mouse movement direction for wind effect
		const mouseMoveDX = mouse.x - prevMouseX;
		const mouseMoveDY = mouse.y - prevMouseY;
		prevMouseX = mouse.x;
		prevMouseY = mouse.y;

		// Batch draw for performance — group by similar opacity ranges
		for (let i = 0; i < PARTICLE_COUNT; i++) {
			// Subtle breathing via sine wave
			const breathe = Math.sin(time * 0.008 + phases[i]) * 0.3;

			// Apply velocity
			posX[i] += velX[i] + breathe * 0.02;
			posY[i] += velY[i] + breathe * 0.015;

			// Mouse wind push effect
			const dx = posX[i] - mouse.x;
			const dy = posY[i] - mouse.y;
			const dist = Math.sqrt(dx * dx + dy * dy);

			if (dist < MOUSE_RADIUS && dist > 0) {
				const force = (1 - dist / MOUSE_RADIUS) * WIND_FORCE;
				// Push away from mouse
				velX[i] += (dx / dist) * force * 0.05;
				velY[i] += (dy / dist) * force * 0.05;
				// Also add directional wind from mouse movement
				velX[i] += mouseMoveDX * 0.002 * force;
				velY[i] += mouseMoveDY * 0.002 * force;
			}

			// Dampen velocity to prevent runaway
			velX[i] *= 0.998;
			velY[i] *= 0.998;

			// Speed limit
			const speed = Math.sqrt(velX[i] * velX[i] + velY[i] * velY[i]);
			if (speed > 0.5) {
				velX[i] = (velX[i] / speed) * 0.5;
				velY[i] = (velY[i] / speed) * 0.5;
			}

			// Wrap around edges seamlessly
			if (posX[i] < -5) posX[i] = width + 5;
			if (posX[i] > width + 5) posX[i] = -5;
			if (posY[i] < -5) posY[i] = height + 5;
			if (posY[i] > height + 5) posY[i] = -5;

			// Draw particle
			const alpha = opacities[i] * (0.7 + breathe * 0.3);
			const size = sizes[i];

			ctx.beginPath();
			ctx.arc(posX[i], posY[i], size, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(${colorR[i]}, ${colorG[i]}, ${colorB[i]}, ${alpha})`;
			ctx.fill();
		}

		// Occasional brighter "glint" particles (draw a few sparkles)
		const glintCount = 8;
		for (let i = 0; i < glintCount; i++) {
			const idx = Math.floor((time * 7 + i * 231) % PARTICLE_COUNT);
			const glintPhase = Math.sin(time * 0.05 + idx);
			if (glintPhase > 0.95) {
				const glintAlpha = (glintPhase - 0.95) * 2.0; // 0 to 0.1
				ctx.beginPath();
				ctx.arc(posX[idx], posY[idx], sizes[idx] * 2, 0, Math.PI * 2);
				ctx.fillStyle = `rgba(255, 255, 255, ${glintAlpha})`;
				ctx.fill();
			}
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initParticles();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initParticles();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: CRT Monitor
 * Description: CRT monitor effect with scanlines, vignette, subtle flicker,
 *   phosphor glow, chromatic aberration, and curvature. Mouse position creates
 *   a magnetic distortion ripple.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Scanlines --
  scanlineSpacing: 3,                       // Pixels between each scanline (2-8)
  scanlineOpacity: 0.12,                    // Scanline darkness (0-0.5)
  scanlineColor: 'rgba(0, 0, 0, 1)',        // Scanline color (usually black)
  scanlineScrollSpeed: 0.3,                 // Slow downward scroll of scanlines (0-2)

  // -- Flicker --
  flickerIntensity: 0.03,                   // Brightness flicker amount (0-0.15)
  flickerSpeed: 8,                          // Flicker oscillation speed (1-30)

  // -- Vignette --
  vignetteStrength: 0.6,                    // How dark the edges get (0-1)
  vignetteColor: 'rgba(0, 0, 0, 1)',        // Vignette tint color
  vignetteRadius: 0.75,                     // Inner clear radius as fraction of screen (0.3-1)

  // -- CRT Curvature --
  curvatureAmount: 0.03,                    // Barrel distortion strength (0-0.1, 0 = flat)

  // -- Noise / Static --
  staticNoiseAmount: 0.04,                  // Amount of random noise grain (0-0.2)
  noiseGrainSize: 2,                        // Size of noise grain pixels (1-4)

  // -- Phosphor Glow --
  phosphorGlowColor: 'rgba(0, 255, 80, 0.03)', // Subtle green phosphor tint
  phosphorGlowBlur: 4,                     // Phosphor bloom blur radius (0-10)

  // -- Chromatic Aberration --
  chromaticAberrationOffset: 1.5,           // RGB channel split in pixels (0-5)

  // -- Mouse Distortion --
  mouseDistortionRadius: 120,               // Radius of mouse magnetic effect in px
  mouseDistortionStrength: 8,               // Intensity of magnetic warp (0-20)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let noiseImageData = null;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      generateNoise();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      generateNoise();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function generateNoise() {
  const grain = CONFIG.noiseGrainSize;
  const nw = Math.ceil(width / grain);
  const nh = Math.ceil(height / grain);
  noiseImageData = { width: nw, height: nh, grain };
}

function startAnimation() {
  function render(timestamp) {
    if (!ctx) return;
    time = timestamp * 0.001;

    ctx.clearRect(0, 0, width, height);

    // -- Flicker --
    const flicker = 1 + Math.sin(time * CONFIG.flickerSpeed * Math.PI) * CONFIG.flickerIntensity
      + Math.sin(time * CONFIG.flickerSpeed * 2.7) * CONFIG.flickerIntensity * 0.3;

    // -- Phosphor glow base --
    ctx.save();
    ctx.globalAlpha = flicker;
    ctx.fillStyle = CONFIG.phosphorGlowColor;
    ctx.fillRect(0, 0, width, height);
    ctx.restore();

    // -- Static noise --
    drawNoise();

    // -- Mouse magnetic distortion --
    drawMouseDistortion();

    // -- Scanlines --
    drawScanlines();

    // -- Chromatic aberration fringe --
    drawChromaticAberration();

    // -- Vignette --
    drawVignette();

    // -- Screen curvature overlay --
    drawCurvature();

    requestAnimationFrame(render);
  }

  requestAnimationFrame(render);
}

function drawScanlines() {
  const spacing = CONFIG.scanlineSpacing;
  const scrollOffset = (time * CONFIG.scanlineScrollSpeed * 60) % spacing;

  ctx.save();
  ctx.fillStyle = CONFIG.scanlineColor;
  ctx.globalAlpha = CONFIG.scanlineOpacity;

  for (let y = -spacing + scrollOffset; y < height; y += spacing) {
    ctx.fillRect(0, y, width, 1);
  }
  ctx.restore();
}

function drawNoise() {
  if (CONFIG.staticNoiseAmount <= 0) return;

  const grain = CONFIG.noiseGrainSize;
  const cols = Math.ceil(width / grain);
  const rows = Math.ceil(height / grain);

  ctx.save();
  ctx.globalAlpha = CONFIG.staticNoiseAmount;

  // Draw a sparse scattering of noise pixels for performance
  const count = Math.floor(cols * rows * 0.08);
  for (let i = 0; i < count; i++) {
    const x = Math.floor(Math.random() * cols) * grain;
    const y = Math.floor(Math.random() * rows) * grain;
    const brightness = Math.floor(Math.random() * 255);
    ctx.fillStyle = `rgb(${brightness},${brightness},${brightness})`;
    ctx.fillRect(x, y, grain, grain);
  }
  ctx.restore();
}

function drawVignette() {
  const cx = width / 2;
  const cy = height / 2;
  const maxDim = Math.max(width, height);
  const innerR = maxDim * CONFIG.vignetteRadius * 0.5;
  const outerR = maxDim * 0.85;

  const grad = ctx.createRadialGradient(cx, cy, innerR, cx, cy, outerR);
  grad.addColorStop(0, 'rgba(0,0,0,0)');
  grad.addColorStop(1, CONFIG.vignetteColor);

  ctx.save();
  ctx.globalAlpha = CONFIG.vignetteStrength;
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, width, height);
  ctx.restore();
}

function drawCurvature() {
  if (CONFIG.curvatureAmount <= 0) return;

  // Darken edges to simulate barrel distortion
  const c = CONFIG.curvatureAmount;
  ctx.save();
  ctx.globalAlpha = c * 5;

  // Top and bottom curves
  ctx.fillStyle = 'rgba(0,0,0,1)';
  ctx.beginPath();
  ctx.moveTo(0, 0);
  ctx.quadraticCurveTo(width / 2, height * c * 2, width, 0);
  ctx.lineTo(width, 0);
  ctx.lineTo(0, 0);
  ctx.fill();

  ctx.beginPath();
  ctx.moveTo(0, height);
  ctx.quadraticCurveTo(width / 2, height - height * c * 2, width, height);
  ctx.lineTo(width, height);
  ctx.lineTo(0, height);
  ctx.fill();

  // Left and right curves
  ctx.beginPath();
  ctx.moveTo(0, 0);
  ctx.quadraticCurveTo(width * c * 2, height / 2, 0, height);
  ctx.lineTo(0, height);
  ctx.lineTo(0, 0);
  ctx.fill();

  ctx.beginPath();
  ctx.moveTo(width, 0);
  ctx.quadraticCurveTo(width - width * c * 2, height / 2, width, height);
  ctx.lineTo(width, height);
  ctx.lineTo(width, 0);
  ctx.fill();

  ctx.restore();
}

function drawChromaticAberration() {
  const offset = CONFIG.chromaticAberrationOffset;
  if (offset <= 0) return;

  // Subtle colored edge fringe
  ctx.save();
  ctx.globalAlpha = 0.06;
  ctx.globalCompositeOperation = 'screen';

  // Red shift left
  ctx.fillStyle = 'rgba(255, 0, 0, 1)';
  ctx.fillRect(-offset, 0, width, height);

  // Blue shift right
  ctx.fillStyle = 'rgba(0, 0, 255, 1)';
  ctx.fillRect(offset, 0, width, height);

  ctx.restore();
}

function drawMouseDistortion() {
  if (mouse.x < 0 || mouse.y < 0) return;
  const r = CONFIG.mouseDistortionRadius;
  const strength = CONFIG.mouseDistortionStrength;
  if (strength <= 0) return;

  ctx.save();
  ctx.globalAlpha = 0.08;

  // Draw concentric distortion rings
  const ringCount = 5;
  for (let i = 0; i < ringCount; i++) {
    const t = (i + time * 2) % ringCount;
    const ringR = (t / ringCount) * r;
    const alpha = (1 - t / ringCount) * 0.15 * (strength / 10);

    ctx.globalAlpha = alpha;
    ctx.strokeStyle = CONFIG.phosphorGlowColor;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(mouse.x, mouse.y, ringR, 0, Math.PI * 2);
    ctx.stroke();
  }

  // Scanline bend near mouse
  ctx.globalAlpha = 0.05 * (strength / 10);
  ctx.fillStyle = 'rgba(255,255,255,1)';
  const bandH = strength * 0.5;
  ctx.fillRect(0, mouse.y - bandH, width, bandH * 2);

  ctx.restore();
}

/**
 * Title: Cymatics
 * Description: Chladni plate vibration pattern simulator. Mouse position controls
 *   the vibration frequency modes — X controls horizontal, Y controls vertical.
 *   Sand particles are pushed from vibrating antinodes toward still nodal lines,
 *   forming beautiful geometric patterns: crosses, stars, diamonds, and complex
 *   symmetries. Move the mouse to morph between patterns in real-time.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Particles --
  particleCount: 2500,                    // Number of sand grains (500-5000)
  particleSize: 1.5,                      // Grain size in px (0.8-3)
  particleColor: '#c4a46c',               // Sand grain color
  particleOpacity: 0.7,                   // Grain opacity (0.3-0.95)

  // -- Physics --
  pushForce: 2.0,                         // Antinode push strength (0.5-8)
  pushDamping: 0.94,                      // Particle damping (0.88-0.98)
  transitionSpeed: 0.06,                  // Pattern morph speed (0.01-0.2)

  // -- Frequency Modes --
  modeRangeX: 6,                          // Max horizontal mode number (2-12)
  modeRangeY: 6,                          // Max vertical mode number (2-12)

  // -- Plate Appearance --
  plateColor: [35, 30, 25],               // Surface plate color [r,g,b]
  plateTexture: true,                     // Subtle wood/metal texture
  borderEnabled: true,                    // Show plate border
  borderColor: '#554433',                 // Border color
  borderWidth: 3,                         // Border width (1-6)

  // -- Visual Effects --
  glowEnabled: true,                      // Glow along particle concentrations
  glowColor: '#ffdd88',                   // Glow color
  glowIntensity: 0.15,                    // Glow strength (0.05-0.5)
  vibrationVisible: true,                 // Show jitter at antinodes
  vibrationAmount: 1.5,                   // Jitter displacement (0.3-4)

  // -- Overlay --
  nodalLineHint: true,                    // Faintly show mathematical nodal lines
  nodalLineOpacity: 0.06,                 // Nodal line hint opacity (0.02-0.15)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let particles = [];
let currentN = 2, currentM = 3; // active modes (smooth interpolated)
let textureData = null;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }

// Chladni equation: value at (x,y) for modes (n,m)
// Nodes where cos(n*pi*x)*cos(m*pi*y) - cos(m*pi*x)*cos(n*pi*y) = 0
function chladniValue(x, y, n, m) {
  const nx = x * Math.PI;
  const ny = y * Math.PI;
  return Math.cos(n * nx) * Math.cos(m * ny) - Math.cos(m * nx) * Math.cos(n * ny);
}

// Gradient of Chladni function (direction particles are pushed)
function chladniGradient(x, y, n, m) {
  const h = 0.005;
  const dx = chladniValue(x + h, y, n, m) - chladniValue(x - h, y, n, m);
  const dy = chladniValue(x, y + h, n, m) - chladniValue(x, y - h, n, m);
  return { dx: dx / (2 * h), dy: dy / (2 * h) };
}

class SandGrain {
  constructor() {
    this.x = rand(0.02, 0.98);
    this.y = rand(0.02, 0.98);
    this.vx = 0;
    this.vy = 0;
    this.size = CONFIG.particleSize * rand(0.7, 1.3);
  }

  update(n, m) {
    const val = chladniValue(this.x, this.y, n, m);
    const absVal = Math.abs(val);

    // Push from antinodes toward nodes
    // Antinodes have high |val|, nodes have val≈0
    if (absVal > 0.01) {
      const grad = chladniGradient(this.x, this.y, n, m);
      const mag = Math.sqrt(grad.dx * grad.dx + grad.dy * grad.dy) + 0.001;
      // Push along gradient toward zero crossings
      const force = CONFIG.pushForce * 0.0003 * absVal;
      // Push toward nearest node = against gradient of |val|
      const sign = val > 0 ? 1 : -1;
      this.vx -= sign * (grad.dx / mag) * force;
      this.vy -= sign * (grad.dy / mag) * force;
    }

    // Vibration jitter at antinodes
    if (CONFIG.vibrationVisible && absVal > 0.3) {
      const jitter = absVal * CONFIG.vibrationAmount * 0.0005;
      this.vx += (Math.random() - 0.5) * jitter;
      this.vy += (Math.random() - 0.5) * jitter;
    }

    this.vx *= CONFIG.pushDamping;
    this.vy *= CONFIG.pushDamping;
    this.x += this.vx;
    this.y += this.vy;

    // Boundary (stay on plate)
    if (this.x < 0.01) { this.x = 0.01; this.vx *= -0.3; }
    if (this.x > 0.99) { this.x = 0.99; this.vx *= -0.3; }
    if (this.y < 0.01) { this.y = 0.01; this.vy *= -0.3; }
    if (this.y > 0.99) { this.y = 0.99; this.vy *= -0.3; }
  }
}

function generateTexture() {
  if (!CONFIG.plateTexture) return;
  const pc = CONFIG.plateColor;
  const id = ctx.createImageData(width, height);
  const d = id.data;
  for (let i = 0; i < d.length; i += 4) {
    const noise = (Math.random() - 0.5) * 8;
    d[i] = Math.max(0, Math.min(255, pc[0] + noise));
    d[i+1] = Math.max(0, Math.min(255, pc[1] + noise));
    d[i+2] = Math.max(0, Math.min(255, pc[2] + noise));
    d[i+3] = 255;
  }
  textureData = id;
}

function initParticles() {
  particles = [];
  for (let i = 0; i < CONFIG.particleCount; i++) particles.push(new SandGrain());
}

function startAnimation() {
  const pc = CONFIG.plateColor;
  const sc = hexRgb(CONFIG.particleColor);
  const gc = hexRgb(CONFIG.glowColor);

  function render() {
    if (!ctx) return;

    // -- Smoothly interpolate toward target modes from mouse --
    if (mouse.x >= 0 && mouse.y >= 0) {
      const targetN = 1 + (mouse.x / width) * (CONFIG.modeRangeX - 1);
      const targetM = 1 + (mouse.y / height) * (CONFIG.modeRangeY - 1);
      currentN += (targetN - currentN) * CONFIG.transitionSpeed;
      currentM += (targetM - currentM) * CONFIG.transitionSpeed;
    }

    // -- Background --
    if (textureData) {
      ctx.putImageData(textureData, 0, 0);
    } else {
      ctx.fillStyle = `rgb(${pc[0]},${pc[1]},${pc[2]})`;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Nodal line hints --
    if (CONFIG.nodalLineHint) {
      const step = 3;
      const n = currentN, m = currentM;
      ctx.fillStyle = `rgba(200,200,180,${CONFIG.nodalLineOpacity})`;
      for (let py = 0; py < height; py += step) {
        for (let px = 0; px < width; px += step) {
          const nx = px / width, ny = py / height;
          const v = Math.abs(chladniValue(nx, ny, n, m));
          if (v < 0.08) {
            ctx.fillRect(px, py, step, step);
          }
        }
      }
    }

    // -- Update particles --
    for (const p of particles) p.update(currentN, currentM);

    // -- Glow pass (draw dim glow first) --
    if (CONFIG.glowEnabled) {
      for (const p of particles) {
        const px = p.x * width, py = p.y * height;
        ctx.beginPath();
        ctx.arc(px, py, p.size * 4, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${gc[0]},${gc[1]},${gc[2]},${CONFIG.glowIntensity * 0.02})`;
        ctx.fill();
      }
    }

    // -- Draw particles --
    for (const p of particles) {
      const px = p.x * width, py = p.y * height;
      ctx.beginPath();
      ctx.arc(px, py, p.size, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${sc[0]},${sc[1]},${sc[2]},${CONFIG.particleOpacity})`;
      ctx.fill();
    }

    // -- Border --
    if (CONFIG.borderEnabled) {
      ctx.strokeStyle = CONFIG.borderColor;
      ctx.lineWidth = CONFIG.borderWidth;
      ctx.strokeRect(0, 0, width, height);
    }

    // -- Mode indicator --
    ctx.fillStyle = 'rgba(200,200,180,0.25)';
    ctx.font = '10px monospace';
    ctx.fillText(`n=${currentN.toFixed(1)} m=${currentM.toFixed(1)}`, 8, height - 8);

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initParticles();
      generateTexture();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initParticles();
      generateTexture();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Data Stream
 * Description: Horizontal streams of flowing data represented as small rectangles of varying
 *   lengths zipping across the screen. Like watching network traffic visualized.
 *   Dim blue/cyan palette. Mouse creates a vortex that curves nearby streams.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

const MAX_PARTICLES = 200;
const VORTEX_RADIUS = 180;
const VORTEX_STRENGTH = 3;

let particles = [];
let lanes = [];

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function init() {
	particles = [];
	// Create lanes at various y positions
	const laneCount = Math.floor(height / 12);
	lanes = [];
	for (let i = 0; i < laneCount; i++) {
		lanes.push({
			y: (i + 0.5) * (height / laneCount),
			baseSpeed: 0.5 + Math.random() * 2.5,
			direction: Math.random() < 0.7 ? 1 : -1 // mostly left-to-right
		});
	}

	// Pre-populate some particles
	for (let i = 0; i < MAX_PARTICLES * 0.6; i++) {
		spawnParticle(true);
	}
}

function spawnParticle(randomX) {
	if (particles.length >= MAX_PARTICLES) return;

	const lane = lanes[Math.floor(Math.random() * lanes.length)];
	const pWidth = 4 + Math.random() * 30; // rectangle width
	const pHeight = 1.5 + Math.random() * 2.5;

	// Color variation in blue/cyan spectrum
	const hue = 190 + Math.random() * 30; // 190-220 range (blue to cyan)
	const sat = 60 + Math.random() * 40;
	const light = 40 + Math.random() * 20;
	const alpha = 0.1 + Math.random() * 0.25;

	let x;
	if (randomX) {
		x = Math.random() * width;
	} else {
		x = lane.direction > 0 ? -pWidth : width + pWidth;
	}

	particles.push({
		x: x,
		y: lane.y + (Math.random() - 0.5) * 6, // slight y jitter within lane
		baseY: lane.y,
		w: pWidth,
		h: pHeight,
		vx: lane.baseSpeed * lane.direction * (0.7 + Math.random() * 0.6),
		vy: 0,
		color: `hsla(${hue}, ${sat}%, ${light}%, ${alpha})`,
		glowColor: `hsla(${hue}, ${sat}%, ${light + 20}%, ${alpha * 0.6})`,
		alpha: alpha
	});
}

function startAnimation() {
	function render(time) {
		if (!ctx) return;

		ctx.clearRect(0, 0, width, height);

		// Spawn new particles
		if (particles.length < MAX_PARTICLES && Math.random() < 0.3) {
			spawnParticle(false);
		}

		// Update and draw particles
		for (let i = particles.length - 1; i >= 0; i--) {
			const p = particles[i];

			// Vortex effect from mouse
			const dx = p.x - mouse.x;
			const dy = p.y - mouse.y;
			const dist = Math.sqrt(dx * dx + dy * dy);

			if (dist < VORTEX_RADIUS && dist > 1) {
				const force = (1 - dist / VORTEX_RADIUS) * VORTEX_STRENGTH;
				// Perpendicular force (creates swirl) + slight attraction
				const angle = Math.atan2(dy, dx);
				const perpX = -Math.sin(angle) * force;
				const perpY = Math.cos(angle) * force;
				p.vy += perpY * 0.1;
				p.vx += perpX * 0.05;
			}

			// Return to base Y (spring force)
			const yDiff = p.baseY - p.y;
			p.vy += yDiff * 0.01;
			p.vy *= 0.92; // damping

			// Move
			p.x += p.vx;
			p.y += p.vy;

			// Remove if off-screen
			if (
				(p.vx > 0 && p.x > width + p.w + 10) ||
				(p.vx < 0 && p.x < -p.w - 10) ||
				p.y < -50 ||
				p.y > height + 50
			) {
				particles.splice(i, 1);
				continue;
			}

			// Draw the data packet
			// Subtle glow
			ctx.shadowColor = p.glowColor;
			ctx.shadowBlur = 4;
			ctx.fillStyle = p.color;
			ctx.fillRect(p.x, p.y - p.h / 2, p.w, p.h);
			ctx.shadowBlur = 0;
		}

		// Draw faint lane lines for depth
		ctx.strokeStyle = 'rgba(0, 100, 140, 0.03)';
		ctx.lineWidth = 0.5;
		for (const lane of lanes) {
			ctx.beginPath();
			ctx.moveTo(0, lane.y);
			ctx.lineTo(width, lane.y);
			ctx.stroke();
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
