// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let allFish = [], bubbles = [], plants = [], particles = [], foodPellets = [];
let rocks = [], aerators = [];
let feedTimer = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }

// ════════════════════════════════════════════
// ██  FOOD PELLET
// ════════════════════════════════════════════
class Food {
  constructor(x) {
    this.x = x + rand(-8, 8);
    this.y = 5;
    this.vy = CONFIG.foodSinkSpeed * rand(0.7, 1.3);
    this.vx = rand(-0.15, 0.15);
    this.r = CONFIG.foodSize * rand(0.7, 1.2);
    this.eaten = false;
    this.phase = rand(0, Math.PI * 2);
    this.color = hexRgb(CONFIG.foodColor);
  }
  update() {
    if (this.eaten) return false;
    this.phase += 0.04;
    this.x += this.vx + Math.sin(this.phase) * 0.12;
    this.y += this.vy;
    this.vy *= 0.999; // slight deceleration
    const floor = height - CONFIG.sandHeight - this.r;
    if (this.y >= floor) { this.y = floor; this.vy = 0; this.vx = 0; }
    return true;
  }
  draw() {
    if (this.eaten) return;
    const c = this.color;
    // Glow
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r * 2.5, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},0.06)`;
    ctx.fill();
    // Pellet
    const g = ctx.createRadialGradient(this.x - this.r * 0.3, this.y - this.r * 0.3, 0, this.x, this.y, this.r);
    g.addColorStop(0, `rgba(${Math.min(255,c[0]+50)},${Math.min(255,c[1]+50)},${Math.min(255,c[2]+30)},0.9)`);
    g.addColorStop(1, `rgba(${c[0]},${c[1]},${c[2]},0.8)`);
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);
    ctx.fillStyle = g;
    ctx.fill();
  }
}

// ════════════════════════════════════════════
// ██  FISH
// ════════════════════════════════════════════
class Fish {
  constructor() {
    this.size = rand(CONFIG.fishMinSize, CONFIG.fishMaxSize);
    const palIdx = Math.floor(Math.random() * CONFIG.fishPalette.length);
    const pal = CONFIG.fishPalette[palIdx];
    this.bodyColor = hexRgb(pal[0]);
    this.finColor = hexRgb(pal[1]);
    this.stripeColor = pal[2] ? hexRgb(pal[2]) : this.bodyColor;
    this.x = rand(this.size * 2, width - this.size * 2);
    this.y = rand(50, height - CONFIG.sandHeight - this.size * 2);
    this.angle = rand(-Math.PI, Math.PI);
    this.targetAngle = this.angle;
    this.baseSpeed = rand(0.3, 0.7) * CONFIG.fishSpeed;
    this.speed = this.baseSpeed;
    this.phase = rand(0, Math.PI * 2);
    this.wanderTimer = rand(60, 200);
    this.wanderTarget = { x: this.x, y: this.y };
    this.turnRate = rand(0.025, 0.06);
    this.depth = rand(0, 1); // 0=far, 1=near
    this.depthScale = 0.7 + this.depth * 0.3;
    this.depthAlpha = 0.5 + this.depth * 0.5;
    this.vx = 0; this.vy = 0;
    this.chasing = null; // food target
    this.nibbleTimer = 0; // happy wiggle after eating
    this.stripeCount = Math.floor(rand(2, 4));
  }

  pickWanderTarget() {
    const m = this.size * 2;
    this.wanderTarget.x = rand(m, width - m);
    this.wanderTarget.y = rand(40, height - CONFIG.sandHeight - m - 20);
    this.wanderTimer = rand(100, 300);
  }

  findFood() {
    if (!CONFIG.feedingEnabled || foodPellets.length === 0) return null;
    let best = null, bestD = CONFIG.foodDetectRadius;
    for (const f of foodPellets) {
      if (f.eaten) continue;
      const d = Math.hypot(f.x - this.x, f.y - this.y);
      if (d < bestD) { bestD = d; best = f; }
    }
    return best;
  }

  update() {
    this.phase += 0.05;
    if (this.nibbleTimer > 0) this.nibbleTimer--;

    // Look for food
    const food = this.findFood();
    if (food && !food.eaten) {
      this.chasing = food;
      this.targetAngle = Math.atan2(food.y - this.y, food.x - this.x);
      this.speed = CONFIG.fishChaseSpeed * this.baseSpeed;
      this.turnRate = 0.08; // turn faster when chasing

      // Eat if close enough
      const ed = Math.hypot(food.x - this.x, food.y - this.y);
      if (ed < this.size * 0.6) {
        food.eaten = true;
        this.chasing = null;
        this.nibbleTimer = 40;
        this.speed = this.baseSpeed;
        this.turnRate = rand(0.025, 0.06);
      }
    } else {
      this.chasing = null;
      this.speed = this.baseSpeed;
      this.turnRate = rand(0.025, 0.06);

      this.wanderTimer--;
      if (this.wanderTimer <= 0) this.pickWanderTarget();
      this.targetAngle = Math.atan2(this.wanderTarget.y - this.y, this.wanderTarget.x - this.x);

      // Schooling
      if (CONFIG.schooling) {
        let cx = 0, cy = 0, n = 0;
        for (const o of allFish) {
          if (o === this) continue;
          if (Math.hypot(o.x - this.x, o.y - this.y) < 100) { cx += o.x; cy += o.y; n++; }
        }
        if (n > 0) {
          const sa = Math.atan2(cy / n - this.y, cx / n - this.x);
          this.targetAngle = this.targetAngle * 0.7 + sa * 0.3;
        }
      }
    }

    // Smooth turn
    let da = this.targetAngle - this.angle;
    while (da > Math.PI) da -= Math.PI * 2;
    while (da < -Math.PI) da += Math.PI * 2;
    this.angle += da * this.turnRate;

    // Mouse scatter (only below feed zone)
    const inFeedZone = mouse.y >= 0 && mouse.y < height * CONFIG.feedZoneHeight;
    if (!inFeedZone) {
      const mdx = this.x - mouse.x, mdy = this.y - mouse.y;
      const md = Math.sqrt(mdx * mdx + mdy * mdy);
      if (md < CONFIG.mouseScatterRadius && md > 0) {
        const f = (1 - md / CONFIG.mouseScatterRadius) * CONFIG.mouseScatterForce;
        this.vx += (mdx / md) * f;
        this.vy += (mdy / md) * f;
      }
    }

    // Nibble wiggle
    const wiggle = this.nibbleTimer > 0 ? Math.sin(this.nibbleTimer * 0.8) * 0.15 : 0;

    this.vx += Math.cos(this.angle + wiggle) * this.speed * 0.15;
    this.vy += Math.sin(this.angle + wiggle) * this.speed * 0.15;
    this.vx *= 0.93; this.vy *= 0.93;
    this.x += this.vx; this.y += this.vy;

    // Boundary
    const m = this.size * 1.5;
    if (this.x < m) { this.x = m; this.vx = Math.abs(this.vx); this.pickWanderTarget(); }
    if (this.x > width - m) { this.x = width - m; this.vx = -Math.abs(this.vx); this.pickWanderTarget(); }
    if (this.y < 15) { this.y = 15; this.vy = Math.abs(this.vy); }
    if (this.y > height - CONFIG.sandHeight - m) { this.y = height - CONFIG.sandHeight - m; this.vy = -Math.abs(this.vy); }
  }

  drawShadow() {
    if (!CONFIG.fishShadows) return;
    const sandY = height - CONFIG.sandHeight + 3;
    const shadowAlpha = Math.max(0.02, 0.06 * (1 - (sandY - this.y) / height));
    const shadowScale = 0.6 + (sandY - this.y) / height * 0.4;
    ctx.beginPath();
    ctx.ellipse(this.x, sandY, this.size * shadowScale, this.size * 0.15, 0, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(0,0,0,${shadowAlpha})`;
    ctx.fill();
  }

  draw() {
    const s = this.size * this.depthScale;
    const swimPhase = Math.sin(this.phase * CONFIG.fishTailSpeed);
    const und = CONFIG.fishUndulation;
    const tailWag = swimPhase * s * und * 0.7;
    const bw1 = Math.sin(this.phase * CONFIG.fishTailSpeed + 1) * s * und * 0.15;
    const bw2 = Math.sin(this.phase * CONFIG.fishTailSpeed + 2) * s * und * 0.08;

    ctx.save();
    ctx.globalAlpha = this.depthAlpha;
    ctx.translate(this.x, this.y);
    ctx.rotate(this.angle);

    // ── Tail ──
    ctx.beginPath();
    ctx.moveTo(-s * 0.4, 0);
    ctx.quadraticCurveTo(-s * 0.7, -s * 0.35 + tailWag * 0.3, -s * 0.95 + tailWag * 0.5, -s * 0.42 + tailWag);
    ctx.lineTo(-s * 0.5, tailWag * 0.15);
    ctx.lineTo(-s * 0.95 + tailWag * 0.5, s * 0.42 + tailWag);
    ctx.quadraticCurveTo(-s * 0.7, s * 0.35 + tailWag * 0.3, -s * 0.4, 0);
    ctx.fillStyle = `rgba(${this.finColor[0]},${this.finColor[1]},${this.finColor[2]},0.65)`;
    ctx.fill();

    // ── Body ──
    ctx.beginPath();
    ctx.moveTo(s * 0.52, 0);
    ctx.bezierCurveTo(s * 0.38, -s * 0.3 + bw2, 0, -s * 0.34 + bw1, -s * 0.35, -s * 0.13 + bw1);
    ctx.lineTo(-s * 0.42, 0);
    ctx.bezierCurveTo(-s * 0.35, s * 0.13 + bw1, 0, s * 0.34 + bw1, s * 0.38, s * 0.3 + bw2);
    ctx.closePath();
    const bc = this.bodyColor;
    const bg = ctx.createLinearGradient(0, -s * 0.3, 0, s * 0.3);
    bg.addColorStop(0, `rgba(${Math.min(255,bc[0]+50)},${Math.min(255,bc[1]+50)},${Math.min(255,bc[2]+50)},0.88)`);
    bg.addColorStop(0.45, `rgba(${bc[0]},${bc[1]},${bc[2]},0.92)`);
    bg.addColorStop(1, `rgba(${Math.max(0,bc[0]-35)},${Math.max(0,bc[1]-35)},${Math.max(0,bc[2]-35)},0.88)`);
    ctx.fillStyle = bg;
    ctx.fill();

    // ── Stripes ──
    if (CONFIG.fishStripes) {
      ctx.save();
      // Clip to body shape (re-draw path)
      ctx.beginPath();
      ctx.moveTo(s * 0.52, 0);
      ctx.bezierCurveTo(s * 0.38, -s * 0.3 + bw2, 0, -s * 0.34 + bw1, -s * 0.35, -s * 0.13 + bw1);
      ctx.lineTo(-s * 0.42, 0);
      ctx.bezierCurveTo(-s * 0.35, s * 0.13 + bw1, 0, s * 0.34 + bw1, s * 0.38, s * 0.3 + bw2);
      ctx.closePath();
      ctx.clip();
      const sc = this.stripeColor;
      ctx.fillStyle = `rgba(${sc[0]},${sc[1]},${sc[2]},0.25)`;
      const stripeW = s * 0.1;
      for (let i = 0; i < this.stripeCount; i++) {
        const sx = s * 0.2 - i * s * 0.25;
        ctx.fillRect(sx - stripeW / 2, -s * 0.5, stripeW, s);
      }
      ctx.restore();
    }

    // ── Dorsal fin ──
    const dw = Math.sin(this.phase * CONFIG.fishTailSpeed + 0.5) * s * und * 0.1;
    ctx.beginPath();
    ctx.moveTo(s * 0.18, -s * 0.28 + bw2);
    ctx.quadraticCurveTo(0, -s * 0.52 + dw, -s * 0.22, -s * 0.26 + bw1);
    ctx.fillStyle = `rgba(${this.finColor[0]},${this.finColor[1]},${this.finColor[2]},0.45)`;
    ctx.fill();

    // ── Pectoral fin ──
    const pp = Math.sin(this.phase * CONFIG.fishTailSpeed * 0.7 + 1);
    ctx.beginPath();
    ctx.moveTo(s * 0.1, s * 0.22);
    ctx.quadraticCurveTo(0, s * 0.44 + pp * s * 0.07, -s * 0.15, s * 0.3);
    ctx.fillStyle = `rgba(${this.finColor[0]},${this.finColor[1]},${this.finColor[2]},0.35)`;
    ctx.fill();

    // ── Eye ──
    const eyeX = s * 0.32, eyeY = -s * 0.05;
    ctx.beginPath();
    ctx.arc(eyeX, eyeY, s * 0.065, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255,255,255,0.92)';
    ctx.fill();
    ctx.beginPath();
    ctx.arc(eyeX + s * 0.02, eyeY, s * 0.035, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(5,5,5,0.95)';
    ctx.fill();
    // Eye glint
    ctx.beginPath();
    ctx.arc(eyeX + s * 0.04, eyeY - s * 0.02, s * 0.015, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255,255,255,0.7)';
    ctx.fill();

    // ── Mouth (opens when near food) ──
    if (this.chasing) {
      const md = Math.hypot(this.chasing.x - this.x, this.chasing.y - this.y);
      if (md < this.size * 2) {
        const open = Math.sin(this.phase * 12) * 0.5 + 0.5;
        ctx.beginPath();
        ctx.arc(s * 0.5, 0, s * 0.06 * (0.5 + open), 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${Math.max(0,bc[0]-60)},${Math.max(0,bc[1]-60)},${Math.max(0,bc[2]-60)},0.6)`;
        ctx.fill();
      }
    }

    // ── Happy flash after eating ──
    if (this.nibbleTimer > 20) {
      const flash = (this.nibbleTimer - 20) / 20;
      ctx.beginPath();
      ctx.ellipse(0, 0, s * 0.6, s * 0.35, 0, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(255,255,200,${flash * 0.12})`;
      ctx.fill();
    }

    ctx.restore();
  }
}

// ════════════════════════════════════════════
// ██  BUBBLE
// ════════════════════════════════════════════
class Bubble {
  constructor(x, y, sizeScale) {
    this.r = rand(CONFIG.bubbleMinSize, CONFIG.bubbleMaxSize) * (sizeScale || 1);
    this.x = x !== undefined ? x + rand(-3, 3) : rand(0, width);
    this.y = y !== undefined ? y : height + rand(0, 20);
    this.speed = rand(0.3, 0.7) * CONFIG.bubbleSpeed;
    this.wobblePhase = rand(0, Math.PI * 2);
    this.wobbleAmp = rand(0.2, 0.6);
  }
  update() {
    this.y -= this.speed;
    this.wobblePhase += 0.03;
    this.x += Math.sin(this.wobblePhase) * this.wobbleAmp;
    // Pop at surface with tiny chance
    return this.y + this.r > -5;
  }
  draw() {
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);
    ctx.strokeStyle = CONFIG.bubbleColor;
    ctx.lineWidth = 0.7;
    ctx.stroke();
    ctx.fillStyle = CONFIG.bubbleColor.replace(/[\d.]+\)$/, '0.06)');
    ctx.fill();
    if (CONFIG.bubbleShine && this.r > 2) {
      ctx.beginPath();
      ctx.arc(this.x - this.r * 0.25, this.y - this.r * 0.3, this.r * 0.25, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.3)';
      ctx.fill();
    }
  }
}

// ════════════════════════════════════════════
// ██  PLANT
// ════════════════════════════════════════════
class Plant {
  constructor(x) {
    this.x = x;
    this.baseY = height - CONFIG.sandHeight * 0.5;
    this.h = rand(CONFIG.plantMinHeight, CONFIG.plantMaxHeight);
    this.segs = CONFIG.plantSegments;
    const c = CONFIG.plantColors[Math.floor(Math.random() * CONFIG.plantColors.length)];
    this.color = hexRgb(c);
    this.phase = rand(0, Math.PI * 2);
    this.leafW = CONFIG.plantLeafWidth * rand(0.7, 1.3);
    this.depth = rand(0.4, 1); // depth dimming
  }
  draw() {
    const sway = CONFIG.plantSwayAmount;
    const sp = CONFIG.plantSwaySpeed;
    const segH = this.h / this.segs;
    const c = this.color;

    // Build spine points
    const pts = [{ x: this.x, y: this.baseY }];
    for (let i = 1; i <= this.segs; i++) {
      const t = i / this.segs;
      const swayX = Math.sin(time * sp + this.phase + i * 0.45) * sway * t * t
                   + Math.sin(time * sp * 0.6 + this.phase + i * 0.8) * sway * 0.3 * t;
      pts.push({ x: this.x + swayX, y: this.baseY - i * segH });
    }

    // Draw as filled leaf shape (tapered)
    ctx.beginPath();
    ctx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i++) {
      const t = i / this.segs;
      const w = this.leafW * (1 - t * 0.7) * 0.5; // taper toward tip
      ctx.lineTo(pts[i].x - w, pts[i].y);
    }
    // Tip
    ctx.lineTo(pts[pts.length - 1].x, pts[pts.length - 1].y - 3);
    // Return down the other side
    for (let i = pts.length - 1; i >= 1; i--) {
      const t = i / this.segs;
      const w = this.leafW * (1 - t * 0.7) * 0.5;
      ctx.lineTo(pts[i].x + w, pts[i].y);
    }
    ctx.closePath();

    const alpha = 0.25 * this.depth;
    ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha})`;
    ctx.fill();

    // Midrib line
    ctx.beginPath();
    ctx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i++) {
      ctx.lineTo(pts[i].x, pts[i].y);
    }
    ctx.strokeStyle = `rgba(${Math.max(0,c[0]-30)},${Math.max(0,c[1]-30)},${Math.max(0,c[2]-20)},${alpha * 0.8})`;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

// ════════════════════════════════════════════
// ██  PARTICLE / ROCK
// ════════════════════════════════════════════
class Particle {
  constructor() { this.reset(); }
  reset() {
    this.x = rand(0, width); this.y = rand(10, height - CONFIG.sandHeight - 10);
    this.size = rand(0.8, 2.2); this.vx = rand(-0.08, 0.08); this.vy = rand(-0.1, 0.04);
    this.phase = rand(0, Math.PI * 2);
  }
  update() {
    this.phase += 0.008;
    this.x += this.vx + Math.sin(this.phase) * 0.04;
    this.y += this.vy;
    if (this.y < -5 || this.y > height - CONFIG.sandHeight || this.x < -5 || this.x > width + 5) this.reset();
  }
  draw() {
    ctx.beginPath(); ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(160,190,150,0.1)'; ctx.fill();
  }
}

function makeRock(x) {
  const w = rand(8, 22), h = rand(5, 14);
  const shade = rand(40, 70);
  return { x, y: height - CONFIG.sandHeight + rand(-3, 3), w, h,
    color: `rgba(${shade},${shade - 5},${shade - 15},0.5)`,
    highlight: `rgba(${shade + 30},${shade + 25},${shade + 15},0.2)` };
}

// ════════════════════════════════════════════
// ██  INIT & RENDER
// ════════════════════════════════════════════
function initScene() {
  allFish = []; for (let i = 0; i < CONFIG.fishCount; i++) allFish.push(new Fish());
  bubbles = []; for (let i = 0; i < CONFIG.bubbleCount; i++) { const b = new Bubble(); b.y = rand(10, height); bubbles.push(b); }
  plants = []; for (let i = 0; i < CONFIG.plantCount; i++) plants.push(new Plant(rand(15, width - 15)));
  particles = []; for (let i = 0; i < CONFIG.particleCount; i++) particles.push(new Particle());
  rocks = []; for (let i = 0; i < CONFIG.rockCount; i++) rocks.push(makeRock(rand(10, width - 10)));
  aerators = []; for (let i = 0; i < CONFIG.aeratorCount; i++) aerators.push({ x: width * (i + 1) / (CONFIG.aeratorCount + 1), timer: 0 });
  foodPellets = [];
  feedTimer = 0;
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 0.016;

    // ── Water background ──
    const tc = CONFIG.waterTopColor, wbc = CONFIG.waterBottomColor;
    const wg = ctx.createLinearGradient(0, 0, 0, height);
    wg.addColorStop(0, `rgb(${tc[0]},${tc[1]},${tc[2]})`);
    wg.addColorStop(1, `rgb(${wbc[0]},${wbc[1]},${wbc[2]})`);
    ctx.fillStyle = wg;
    ctx.fillRect(0, 0, width, height);

    // ── Light rays ──
    if (CONFIG.lightRaysEnabled) {
      for (let i = 0; i < CONFIG.lightRayCount; i++) {
        const bx = width * (i + 0.5) / CONFIG.lightRayCount;
        const sw = Math.sin(time * 0.25 + i * 2.1) * 35;
        const sp = 45 + Math.sin(time * 0.18 + i * 1.3) * 18;
        ctx.beginPath();
        ctx.moveTo(bx + sw - 6, 0); ctx.lineTo(bx + sw + 6, 0);
        ctx.lineTo(bx + sp + sw * 0.4, height); ctx.lineTo(bx - sp + sw * 0.4, height);
        ctx.closePath();
        ctx.fillStyle = `rgba(140,210,255,${CONFIG.lightRayOpacity})`;
        ctx.fill();
      }
    }

    // ── Caustics ──
    if (CONFIG.causticsEnabled) {
      const sandTop = height - CONFIG.sandHeight;
      const cs = CONFIG.causticsSpeed;
      for (let x = 0; x < width; x += 10) {
        for (let y = sandTop - 15; y < height; y += 10) {
          const v = Math.sin(x * 0.028 + time * cs) * Math.cos(y * 0.035 + time * cs * 0.65)
                  + Math.sin(x * 0.018 - time * cs * 0.4 + y * 0.012) * 0.5;
          if (v > 0.35) {
            ctx.fillStyle = `rgba(100,200,255,${(v - 0.35) * 0.06})`;
            ctx.fillRect(x, y, 10, 10);
          }
        }
      }
    }

    // ── Sand ──
    const sc = CONFIG.sandColor;
    const sandBase = height - CONFIG.sandHeight;
    const sg = ctx.createLinearGradient(0, sandBase, 0, height);
    sg.addColorStop(0, `rgba(${sc[0]},${sc[1]},${sc[2]},0.65)`);
    sg.addColorStop(0.35, `rgba(${sc[0]},${sc[1]},${sc[2]},0.85)`);
    sg.addColorStop(1, `rgba(${Math.max(0,sc[0]-20)},${Math.max(0,sc[1]-18)},${Math.max(0,sc[2]-12)},0.92)`);
    ctx.fillStyle = sg;
    ctx.beginPath(); ctx.moveTo(0, height); ctx.lineTo(0, sandBase);
    for (let x = 0; x <= width; x += 3) {
      ctx.lineTo(x, sandBase + Math.sin(x * 0.02 + time * 0.25) * 3 + Math.sin(x * 0.055 + 0.8) * 1.5);
    }
    ctx.lineTo(width, height); ctx.closePath(); ctx.fill();

    // Sand speckles
    ctx.fillStyle = `rgba(${Math.min(255,sc[0]+25)},${Math.min(255,sc[1]+20)},${Math.min(255,sc[2]+12)},0.12)`;
    for (let i = 0; i < 50; i++) {
      ctx.fillRect((i * 41 + i * i * 11) % width, sandBase + 6 + ((i * 59 + i * 17) % Math.max(1, CONFIG.sandHeight - 8)), rand(1, 2.5), 1);
    }

    // ── Rocks ──
    for (const r of rocks) {
      ctx.beginPath();
      ctx.ellipse(r.x, r.y, r.w * 0.5, r.h * 0.5, 0, 0, Math.PI * 2);
      ctx.fillStyle = r.color; ctx.fill();
      ctx.beginPath();
      ctx.ellipse(r.x - r.w * 0.1, r.y - r.h * 0.15, r.w * 0.3, r.h * 0.25, -0.3, 0, Math.PI * 2);
      ctx.fillStyle = r.highlight; ctx.fill();
    }

    // ── Plants ──
    plants.sort((a, b) => a.depth - b.depth);
    for (const p of plants) p.draw();

    // ── Particles ──
    for (const p of particles) { p.update(); p.draw(); }

    // ── Food ──
    // Drop food when mouse is in feed zone
    if (CONFIG.feedingEnabled && mouse.x > 0 && mouse.y >= 0 && mouse.y < height * CONFIG.feedZoneHeight) {
      feedTimer++;
      if (feedTimer % CONFIG.foodDropRate === 0 && foodPellets.length < CONFIG.maxFood) {
        foodPellets.push(new Food(mouse.x));
      }
    }
    // Update and draw food
    for (let i = foodPellets.length - 1; i >= 0; i--) {
      if (!foodPellets[i].update() || foodPellets[i].eaten) { foodPellets.splice(i, 1); }
      else { foodPellets[i].draw(); }
    }

    // ── Fish shadows ──
    for (const f of allFish) f.drawShadow();

    // ── Fish ──
    for (const f of allFish) f.update();
    allFish.sort((a, b) => a.depth - b.depth);
    for (const f of allFish) f.draw();

    // ── Bubbles ──
    // Aerator streams
    for (const a of aerators) {
      a.timer++;
      if (a.timer % CONFIG.aeratorRate === 0) {
        bubbles.push(new Bubble(a.x, height - CONFIG.sandHeight - 2, 0.6));
      }
    }
    while (bubbles.length < CONFIG.bubbleCount) bubbles.push(new Bubble());
    for (let i = bubbles.length - 1; i >= 0; i--) {
      if (!bubbles[i].update()) bubbles.splice(i, 1);
      else bubbles[i].draw();
    }
    if (bubbles.length > CONFIG.bubbleCount * 4) bubbles.splice(0, bubbles.length - CONFIG.bubbleCount * 2);

    // ── Surface ripple ──
    if (CONFIG.surfaceRipple) {
      ctx.beginPath();
      ctx.moveTo(0, 0);
      for (let x = 0; x <= width; x += 3) {
        const wave = Math.sin(x * 0.015 + time * 1.2) * 2.5
                   + Math.sin(x * 0.04 + time * 0.8) * 1
                   + Math.cos(x * 0.025 - time * 0.6) * 1.5;
        ctx.lineTo(x, 4 + wave);
      }
      ctx.lineTo(width, 0); ctx.closePath();
      ctx.fillStyle = 'rgba(120,200,255,0.07)';
      ctx.fill();
      // Bright line
      ctx.beginPath();
      for (let x = 0; x <= width; x += 2) {
        const wave = Math.sin(x * 0.015 + time * 1.2) * 2.5
                   + Math.sin(x * 0.04 + time * 0.8) * 1
                   + Math.cos(x * 0.025 - time * 0.6) * 1.5;
        if (x === 0) ctx.moveTo(x, 4 + wave); else ctx.lineTo(x, 4 + wave);
      }
      ctx.strokeStyle = 'rgba(180,230,255,0.15)';
      ctx.lineWidth = 1;
      ctx.stroke();
    }

    // ── Feed zone indicator ──
    if (CONFIG.feedingEnabled && mouse.x > 0 && mouse.y >= 0 && mouse.y < height * CONFIG.feedZoneHeight) {
      const zoneH = height * CONFIG.feedZoneHeight;
      const ig = ctx.createLinearGradient(0, 0, 0, zoneH);
      ig.addColorStop(0, 'rgba(255,220,100,0.04)');
      ig.addColorStop(1, 'rgba(255,220,100,0)');
      ctx.fillStyle = ig;
      ctx.fillRect(0, 0, width, zoneH);
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initScene(); startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initScene();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: DNA Double Helix
 * Description: A rotating double-helix DNA strand rendered in 3D perspective with
 *   base-pair rungs, phosphate backbone nodes, and ambient bio-glow particles.
 *   Mouse Y modulates rotation speed; mouse X shifts the helix horizontally.
 */

// ─── CONFIG ──────────────────────────────────────────────────────────────────
const CONFIG = {
	helixRadius: 80, // px – radius of each helical strand
	helixPitch: 300, // px – vertical distance per full 360° turn
	basePairCount: 60, // number of base-pair rungs visible
	basePairWidth: 3, // px – thickness of each rung bar
	basePairGap: 6, // px – gap in the centre of each rung
	rotationSpeed: 0.4, // radians/s – base rotation speed
	verticalScroll: 30, // px/s – upward scroll speed of the helix
	depthFade: 0.55, // 0-1 – alpha multiplier for furthest depth
	backboneNodeRadius: 4, // px – radius of phosphate backbone spheres
	backboneNodeCount: 120, // total backbone nodes per strand
	glowParticleCount: 90, // ambient glow particles floating around
	glowParticleRadius: 2.5, // px – max radius of glow particles
	glowParticleAlpha: 0.35, // base alpha of glow particles
	glowParticleDrift: 20, // px/s – max drift speed
	perspectiveScale: 0.4, // depth scale factor (0 = flat, 1 = extreme)
	strandWidth: 2.5, // px – width of the backbone line
	strandAlpha: 0.85, // base alpha of backbone strands
	glowPasses: 3, // number of additive glow blur passes
	glowExpand: 6, // px expansion per glow pass
	glowAlpha: 0.07, // alpha per glow pass
	trailAlpha: 0.12, // motion trail overlay alpha (lower = longer trails)
	colors: {
		a: '#ff4466', // Adenine
		t: '#4488ff', // Thymine
		g: '#44dd88', // Guanine
		c: '#ffcc44', // Cytosine
		strand1: '#88ccff', // strand 1 backbone colour
		strand2: '#ff88cc', // strand 2 backbone colour
		glow: '#66ddff' // ambient glow particle colour
	}
};

// ─── GLOBALS ─────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;
let phase = 0; // current rotation phase in radians
let scrollOffset = 0; // vertical scroll accumulator

// Typed arrays for glow particles (x, y, z, vx, vy, radius, hueShift)
const GLOW_STRIDE = 7;
let glowData = null; // Float32Array

// Base pair sequence cache
let basePairSequence = null; // Uint8Array: 0=AT, 1=TA, 2=GC, 3=CG

// Heartbeat
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function hexToRgb(hex) {
	const v = parseInt(hex.slice(1), 16);
	return [(v >> 16) & 255, (v >> 8) & 255, v & 255];
}

function lerpColor(r, g, b, a) {
	return `rgba(${r},${g},${b},${a.toFixed(3)})`;
}

function seededRandom(i) {
	let x = Math.sin(i * 127.1 + 311.7) * 43758.5453;
	return x - Math.floor(x);
}

// ─── INIT ────────────────────────────────────────────────────────────────────
function initGlowParticles() {
	const count = CONFIG.glowParticleCount;
	glowData = new Float32Array(count * GLOW_STRIDE);
	for (let i = 0; i < count; i++) {
		const off = i * GLOW_STRIDE;
		glowData[off + 0] = Math.random() * width; // x
		glowData[off + 1] = Math.random() * height; // y
		glowData[off + 2] = Math.random(); // z (0=far, 1=near)
		glowData[off + 3] = (Math.random() - 0.5) * CONFIG.glowParticleDrift; // vx
		glowData[off + 4] = (Math.random() - 0.5) * CONFIG.glowParticleDrift; // vy
		glowData[off + 5] = Math.random() * CONFIG.glowParticleRadius; // radius
		glowData[off + 6] = Math.random() * 60 - 30; // hue shift
	}
}

function initBasePairs() {
	basePairSequence = new Uint8Array(CONFIG.basePairCount);
	for (let i = 0; i < CONFIG.basePairCount; i++) {
		basePairSequence[i] = Math.floor(Math.random() * 4);
	}
}

function initAll() {
	initGlowParticles();
	initBasePairs();
	lastTime = 0;
}

// ─── BASE PAIR COLORS ───────────────────────────────────────────────────────
const pairMap = [
	{ left: 'a', right: 't' },
	{ left: 't', right: 'a' },
	{ left: 'g', right: 'c' },
	{ left: 'c', right: 'g' }
];

const colorCache = {};
function getRgb(key) {
	if (!colorCache[key]) colorCache[key] = hexToRgb(CONFIG.colors[key]);
	return colorCache[key];
}

// ─── RENDER ──────────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) {
			requestAnimationFrame(render);
			return;
		}
		now *= 0.001; // ms → s
		const dt = lastTime ? Math.min(now - lastTime, 0.05) : 0.016;
		lastTime = now;

		// Mouse influence
		const mouseNormY =
			mouse.y >= 0 && mouse.y <= height
				? (mouse.y / height - 0.5) * 2 // -1 to 1
				: 0;
		const mouseShiftX =
			mouse.x >= 0 && mouse.x <= width ? (mouse.x / width - 0.5) * width * 0.3 : 0;

		const effectiveRotSpeed = CONFIG.rotationSpeed * (1 + mouseNormY * 1.5);
		phase += effectiveRotSpeed * dt;
		scrollOffset += CONFIG.verticalScroll * dt;

		// ── Motion trail (semi-transparent overlay instead of full clear) ──
		ctx.fillStyle = `rgba(0,0,0,${CONFIG.trailAlpha})`;
		ctx.fillRect(0, 0, width, height);

		const cx = width / 2 + mouseShiftX;
		const cy = height / 2;

		// ── Draw ambient glow particles ──
		updateAndDrawGlow(dt);

		// ── Collect all helix elements, sort by depth, then draw ──
		const elements = buildHelixElements(cx, cy);
		elements.sort((a, b) => a.z - b.z); // painter's order: far first

		// Pass 1: glow (additive)
		ctx.globalCompositeOperation = 'lighter';
		for (let pass = 0; pass < CONFIG.glowPasses; pass++) {
			const expand = (pass + 1) * CONFIG.glowExpand;
			const alpha = CONFIG.glowAlpha / (pass + 1);
			for (const el of elements) {
				drawElementGlow(el, expand, alpha);
			}
		}

		// Pass 2: solid
		ctx.globalCompositeOperation = 'source-over';
		for (const el of elements) {
			drawElement(el);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── BUILD HELIX ELEMENTS ───────────────────────────────────────────────────
function buildHelixElements(cx, cy) {
	const elements = [];
	const {
		helixRadius,
		helixPitch,
		basePairCount,
		basePairGap,
		backboneNodeRadius,
		perspectiveScale,
		depthFade,
		strandWidth,
		strandAlpha
	} = CONFIG;
	const spacing = helixPitch / basePairCount;

	for (let i = 0; i < basePairCount; i++) {
		const vertPos = i * spacing - (scrollOffset % helixPitch);
		const y = cy + vertPos - (basePairCount * spacing) / 2;

		// Skip off-screen
		if (y < -60 || y > height + 60) continue;

		const angle = phase + (i / basePairCount) * Math.PI * 2;
		const cosA = Math.cos(angle);
		const sinA = Math.sin(angle);

		// Strand 1 and Strand 2 positions (offset by π)
		const x1 = cx + cosA * helixRadius;
		const z1 = sinA; // -1 to 1 normalised depth
		const x2 = cx - cosA * helixRadius;
		const z2 = -sinA;

		const scale1 = 1 + z1 * perspectiveScale;
		const scale2 = 1 + z2 * perspectiveScale;
		const alpha1 = strandAlpha * (1 - (1 - depthFade) * (1 - (z1 + 1) / 2));
		const alpha2 = strandAlpha * (1 - (1 - depthFade) * (1 - (z2 + 1) / 2));

		// Base pair rung
		const pair = pairMap[basePairSequence[i % basePairSequence.length]];
		const leftRgb = getRgb(pair.left);
		const rightRgb = getRgb(pair.right);
		const avgZ = (z1 + z2) / 2;
		const rungAlpha = strandAlpha * (1 - (1 - depthFade) * (1 - (avgZ + 1) / 2));

		// Push rung (two halves)
		elements.push({
			type: 'rung',
			x1,
			y,
			x2,
			y2: y,
			gap: basePairGap * ((scale1 + scale2) / 2),
			width: CONFIG.basePairWidth * ((scale1 + scale2) / 2),
			leftColor: leftRgb,
			rightColor: rightRgb,
			alpha: rungAlpha * 0.8,
			z: avgZ
		});

		// Backbone nodes
		elements.push({
			type: 'node',
			x: x1,
			y,
			r: backboneNodeRadius * scale1,
			color: getRgb(CONFIG.colors.strand1.replace('#', '').length ? 'strand1' : 'a'),
			colorHex: CONFIG.colors.strand1,
			alpha: alpha1,
			z: z1
		});
		elements.push({
			type: 'node',
			x: x2,
			y,
			r: backboneNodeRadius * scale2,
			color: hexToRgb(CONFIG.colors.strand2),
			colorHex: CONFIG.colors.strand2,
			alpha: alpha2,
			z: z2
		});
	}

	return elements;
}

function drawElementGlow(el, expand, alpha) {
	const a = el.alpha * alpha;
	if (a < 0.005) return;

	if (el.type === 'node') {
		ctx.beginPath();
		ctx.arc(el.x, el.y, el.r + expand, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(el.color[0], el.color[1], el.color[2], a);
		ctx.fill();
	} else if (el.type === 'rung') {
		const midX = (el.x1 + el.x2) / 2;
		ctx.lineWidth = el.width + expand;
		ctx.lineCap = 'round';
		// Left half
		ctx.beginPath();
		ctx.moveTo(el.x1, el.y);
		ctx.lineTo(midX - el.gap / 2, el.y);
		ctx.strokeStyle = lerpColor(el.leftColor[0], el.leftColor[1], el.leftColor[2], a);
		ctx.stroke();
		// Right half
		ctx.beginPath();
		ctx.moveTo(midX + el.gap / 2, el.y);
		ctx.lineTo(el.x2, el.y);
		ctx.strokeStyle = lerpColor(el.rightColor[0], el.rightColor[1], el.rightColor[2], a);
		ctx.stroke();
	}
}

function drawElement(el) {
	if (el.type === 'node') {
		// Phosphate backbone sphere
		const r = el.r;
		const col = el.color;
		ctx.beginPath();
		ctx.arc(el.x, el.y, r, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(col[0], col[1], col[2], el.alpha);
		ctx.fill();
		// Highlight
		ctx.beginPath();
		ctx.arc(el.x - r * 0.25, el.y - r * 0.25, r * 0.4, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(255, 255, 255, el.alpha * 0.4);
		ctx.fill();
	} else if (el.type === 'rung') {
		const midX = (el.x1 + el.x2) / 2;
		ctx.lineWidth = el.width;
		ctx.lineCap = 'round';
		// Left half
		ctx.beginPath();
		ctx.moveTo(el.x1, el.y);
		ctx.lineTo(midX - el.gap / 2, el.y);
		ctx.strokeStyle = lerpColor(el.leftColor[0], el.leftColor[1], el.leftColor[2], el.alpha);
		ctx.stroke();
		// Right half
		ctx.beginPath();
		ctx.moveTo(midX + el.gap / 2, el.y);
		ctx.lineTo(el.x2, el.y);
		ctx.strokeStyle = lerpColor(el.rightColor[0], el.rightColor[1], el.rightColor[2], el.alpha);
		ctx.stroke();
	}
}

// ─── GLOW PARTICLES ─────────────────────────────────────────────────────────
function updateAndDrawGlow(dt) {
	const count = CONFIG.glowParticleCount;
	const rgb = hexToRgb(CONFIG.colors.glow);

	ctx.globalCompositeOperation = 'lighter';
	for (let i = 0; i < count; i++) {
		const off = i * GLOW_STRIDE;
		let x = glowData[off + 0];
		let y = glowData[off + 1];
		const z = glowData[off + 2];
		const vx = glowData[off + 3];
		const vy = glowData[off + 4];
		const r = glowData[off + 5];
		const hueShift = glowData[off + 6];

		x += vx * dt;
		y += vy * dt;

		// Wrap
		if (x < -20) x += width + 40;
		if (x > width + 20) x -= width + 40;
		if (y < -20) y += height + 40;
		if (y > height + 20) y -= height + 40;

		glowData[off + 0] = x;
		glowData[off + 1] = y;

		const alpha = CONFIG.glowParticleAlpha * (0.3 + z * 0.7);
		const scaledR = r * (0.5 + z * 0.5);

		// Soft glow circle
		ctx.beginPath();
		ctx.arc(x, y, scaledR * 3, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(rgb[0], rgb[1], rgb[2], alpha * 0.15);
		ctx.fill();

		ctx.beginPath();
		ctx.arc(x, y, scaledR, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(rgb[0], rgb[1], rgb[2], alpha);
		ctx.fill();
	}
	ctx.globalCompositeOperation = 'source-over';
}

// ─── MESSAGE HANDLER ─────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Electric Tendrils
 * Description: Branching electric arcs reach from screen edge anchors toward your
 *   mouse cursor. Bolts fork recursively with configurable depth, render in 3
 *   glow layers, and flash with impact circles. Proximity makes anchors fire
 *   faster. Ambient mini-arcs crackle between anchors.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Anchors --
  anchorCount: 8,                         // Edge anchor points (3-12)
  proximityBoost: true,                   // Fire faster when mouse is close

  // -- Bolt Appearance --
  boltColor: '#00ccff',                   // Primary bolt color
  boltCoreColor: '#ffffff',               // White-hot center color
  boltSegments: 16,                       // Segments per bolt (8-30)
  boltJitter: 22,                         // Random displacement per segment px (5-40)
  boltWidth: 4,                           // Outer glow width (2-8)
  boltCoreWidth: 1.5,                     // Center line width (0.5-3)

  // -- Bolt Behavior --
  boltDuration: 8,                        // Frames a bolt stays visible (3-15)
  boltFrequency: 28,                      // Base frames between bolts per anchor (10-60)

  // -- Forking --
  forkProbability: 0.25,                  // Branch chance at each segment (0-0.5)
  forkMaxDepth: 3,                        // Max branch recursion depth (1-4)
  forkLengthRatio: 0.45,                  // Branch length relative to remaining (0.2-0.7)

  // -- Flash --
  flashRadius: 40,                        // Impact flash circle radius (15-80)
  flashOpacity: 0.3,                      // Impact flash brightness (0.1-0.6)

  // -- Ambient --
  ambientArcs: true,                      // Random mini-arcs between anchors
  ambientArcFrequency: 35,               // Frames between ambient arcs (15-120)
  fieldGlow: true,                        // Background electric field gradient
  fieldGlowColor: '#001a33',             // Field gradient color
  fieldGlowIntensity: 0.04,              // Field gradient opacity (0.01-0.1)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let time = 0;
let anchors = [];
let activeBolts = [];
let ambientTimer = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }
function rand(a, b) { return Math.random() * (b - a) + a; }

function initAnchors() {
  anchors = [];
  const n = CONFIG.anchorCount;
  const perimeter = (width + height) * 2;
  for (let i = 0; i < n; i++) {
    const p = (i / n) * perimeter;
    let x, y;
    if (p < width) { x = p; y = 0; }
    else if (p < width + height) { x = width; y = p - width; }
    else if (p < width * 2 + height) { x = width - (p - width - height); y = height; }
    else { x = 0; y = height - (p - width * 2 - height); }
    anchors.push({ x, y, timer: Math.floor(rand(0, CONFIG.boltFrequency)) });
  }
}

function generateBolt(x0, y0, x1, y1, segments, jitter, depth) {
  const points = [{ x: x0, y: y0 }];
  const forks = [];

  for (let i = 1; i < segments; i++) {
    const t = i / segments;
    const bx = x0 + (x1 - x0) * t + (Math.random() - 0.5) * jitter * 2;
    const by = y0 + (y1 - y0) * t + (Math.random() - 0.5) * jitter * 2;
    points.push({ x: bx, y: by });

    // Fork chance
    if (depth < CONFIG.forkMaxDepth && Math.random() < CONFIG.forkProbability && i > 2 && i < segments - 2) {
      const remaining = segments - i;
      const forkSegs = Math.max(3, Math.floor(remaining * CONFIG.forkLengthRatio));
      const angle = Math.atan2(y1 - y0, x1 - x0) + (Math.random() - 0.5) * 1.2;
      const forkLen = Math.hypot(x1 - bx, y1 - by) * CONFIG.forkLengthRatio;
      const fx = bx + Math.cos(angle) * forkLen;
      const fy = by + Math.sin(angle) * forkLen;
      forks.push(generateBolt(bx, by, fx, fy, forkSegs, jitter * 0.7, depth + 1));
    }
  }
  points.push({ x: x1, y: y1 });

  return { points, forks, depth };
}

function drawBoltPath(bolt, alpha) {
  const pts = bolt.points;
  if (pts.length < 2) return;
  const c = hexRgb(CONFIG.boltColor);
  const depthFade = Math.pow(0.6, bolt.depth);

  // Build path once
  ctx.beginPath();
  ctx.moveTo(pts[0].x, pts[0].y);
  for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);

  // Layer 1: outer glow
  ctx.strokeStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha * 0.12 * depthFade})`;
  ctx.lineWidth = CONFIG.boltWidth * 3 * depthFade;
  ctx.lineJoin = 'round';
  ctx.stroke();

  // Layer 2: colored core
  ctx.strokeStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha * 0.5 * depthFade})`;
  ctx.lineWidth = CONFIG.boltWidth * depthFade;
  ctx.stroke();

  // Layer 3: white-hot center
  const cc = hexRgb(CONFIG.boltCoreColor);
  ctx.strokeStyle = `rgba(${cc[0]},${cc[1]},${cc[2]},${alpha * 0.8 * depthFade})`;
  ctx.lineWidth = CONFIG.boltCoreWidth * depthFade;
  ctx.stroke();

  // Draw forks recursively
  for (const fork of bolt.forks) {
    drawBoltPath(fork, alpha * 0.7);
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 1;

    // -- Clear with slight fade for afterimage --
    ctx.fillStyle = 'rgba(2,2,8,0.25)';
    ctx.fillRect(0, 0, width, height);

    // -- Background field glow toward mouse --
    if (CONFIG.fieldGlow && mouse.x >= 0) {
      const fc = hexRgb(CONFIG.fieldGlowColor);
      const g = ctx.createRadialGradient(mouse.x, mouse.y, 0, mouse.x, mouse.y, Math.max(width, height) * 0.6);
      g.addColorStop(0, `rgba(${fc[0]},${fc[1]},${fc[2]},${CONFIG.fieldGlowIntensity})`);
      g.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = g;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Fire bolts from anchors --
    if (mouse.x >= 0 && mouse.y >= 0) {
      for (const a of anchors) {
        a.timer--;
        let freq = CONFIG.boltFrequency;
        if (CONFIG.proximityBoost) {
          const d = Math.hypot(a.x - mouse.x, a.y - mouse.y);
          const boost = Math.max(0.3, d / Math.max(width, height));
          freq = Math.floor(freq * boost);
        }
        if (a.timer <= 0) {
          a.timer = Math.max(5, freq + Math.floor(rand(-5, 5)));
          const bolt = generateBolt(a.x, a.y, mouse.x + rand(-10, 10), mouse.y + rand(-10, 10),
            CONFIG.boltSegments, CONFIG.boltJitter, 0);
          activeBolts.push({ bolt, life: CONFIG.boltDuration, maxLife: CONFIG.boltDuration,
            anchorX: a.x, anchorY: a.y, targetX: mouse.x, targetY: mouse.y });
        }
      }
    }

    // -- Ambient arcs --
    if (CONFIG.ambientArcs && anchors.length > 1) {
      ambientTimer--;
      if (ambientTimer <= 0) {
        ambientTimer = CONFIG.ambientArcFrequency + Math.floor(rand(-8, 8));
        const i = Math.floor(rand(0, anchors.length));
        let j = (i + 1 + Math.floor(rand(0, 2))) % anchors.length;
        const a1 = anchors[i], a2 = anchors[j];
        const bolt = generateBolt(a1.x, a1.y, a2.x, a2.y, 8, CONFIG.boltJitter * 0.5, 1);
        activeBolts.push({ bolt, life: 4, maxLife: 4, anchorX: a1.x, anchorY: a1.y, targetX: a2.x, targetY: a2.y });
      }
    }

    // -- Draw active bolts --
    const bc = hexRgb(CONFIG.boltColor);
    for (let i = activeBolts.length - 1; i >= 0; i--) {
      const ab = activeBolts[i];
      ab.life--;
      if (ab.life <= 0) { activeBolts.splice(i, 1); continue; }

      const alpha = ab.life / ab.maxLife;

      // Flash at initial frame
      if (ab.life === ab.maxLife - 1) {
        // Anchor flash
        ctx.beginPath();
        ctx.arc(ab.anchorX, ab.anchorY, CONFIG.flashRadius * 0.6, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${bc[0]},${bc[1]},${bc[2]},${CONFIG.flashOpacity * 0.5})`;
        ctx.fill();
        // Target flash
        ctx.beginPath();
        ctx.arc(ab.targetX, ab.targetY, CONFIG.flashRadius, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${bc[0]},${bc[1]},${bc[2]},${CONFIG.flashOpacity})`;
        ctx.fill();
      }

      drawBoltPath(ab.bolt, alpha);
    }

    // -- Anchor point indicators --
    for (const a of anchors) {
      ctx.beginPath();
      ctx.arc(a.x, a.y, 3, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${bc[0]},${bc[1]},${bc[2]},0.15)`;
      ctx.fill();
    }

    // Cap bolts
    if (activeBolts.length > 50) activeBolts.splice(0, activeBolts.length - 40);

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      ctx.fillStyle = '#020208'; ctx.fillRect(0, 0, width, height);
      initAnchors();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      ctx.fillStyle = '#020208'; ctx.fillRect(0, 0, width, height);
      initAnchors();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Falling Leaves
 * Description: Leaves of various sizes and muted autumn colors (amber, rust, gold, olive)
 *   tumble and spiral downward with realistic rotation and swaying. They drift horizontally.
 *   Mouse creates an updraft that blows nearby leaves upward.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let leaves = [];
let time = 0;

const MAX_LEAVES = 50;

// Autumn palette — muted, warm tones
const LEAF_COLORS = [
	{ fill: [200, 120, 40], stroke: [170, 90, 30] }, // Amber
	{ fill: [180, 70, 40], stroke: [150, 50, 30] }, // Rust
	{ fill: [210, 170, 50], stroke: [180, 140, 40] }, // Gold
	{ fill: [130, 140, 50], stroke: [100, 110, 40] }, // Olive
	{ fill: [190, 90, 35], stroke: [160, 65, 25] }, // Burnt orange
	{ fill: [160, 50, 35], stroke: [130, 35, 25] } // Deep rust
];

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Leaf {
	constructor() {
		this.reset(true);
	}

	reset(randomY = false) {
		this.x = Math.random() * (width || 800);
		this.y = randomY ? Math.random() * (height || 600) : -20 - Math.random() * 80;
		this.size = 4 + Math.random() * 10;
		this.rotation = Math.random() * Math.PI * 2;
		this.rotationSpeed = (Math.random() - 0.5) * 0.03;
		this.vx = (Math.random() - 0.5) * 0.5;
		this.vy = 0.3 + Math.random() * 0.8;
		// Sway parameters — sinusoidal horizontal drift
		this.swayAmplitude = 0.3 + Math.random() * 0.8;
		this.swayFrequency = 0.01 + Math.random() * 0.02;
		this.swayPhase = Math.random() * Math.PI * 2;
		// Tumble — 3D rotation effect via scale modulation
		this.tumblePhase = Math.random() * Math.PI * 2;
		this.tumbleSpeed = 0.015 + Math.random() * 0.025;
		// Visual
		const palette = LEAF_COLORS[Math.floor(Math.random() * LEAF_COLORS.length)];
		this.fillColor = palette.fill;
		this.strokeColor = palette.stroke;
		this.opacity = 0.12 + Math.random() * 0.18;
		// Leaf shape variant
		this.shapeType = Math.floor(Math.random() * 3); // 0: simple, 1: pointed, 2: round
		this.stemLength = this.size * (0.4 + Math.random() * 0.3);
	}

	update(t) {
		// Horizontal sway
		const sway = Math.sin(t * this.swayFrequency + this.swayPhase) * this.swayAmplitude;
		this.vx += (sway - this.vx) * 0.02;

		// Mouse updraft effect
		const dx = this.x - mouse.x;
		const dy = this.y - mouse.y;
		const distSq = dx * dx + dy * dy;
		const updraftRadius = 180;
		if (distSq < updraftRadius * updraftRadius && distSq > 0) {
			const dist = Math.sqrt(distSq);
			const strength = 1 - dist / updraftRadius;
			// Blow upward and outward
			this.vy -= strength * 0.4;
			this.vx += (dx / dist) * strength * 0.3;
			// Spin faster near mouse
			this.rotationSpeed += strength * 0.005 * Math.sign(this.rotationSpeed);
		}

		// Gravity
		this.vy += 0.005;
		// Terminal velocity
		this.vy = Math.min(this.vy, 2);
		this.vx *= 0.995;

		this.x += this.vx;
		this.y += this.vy;

		// Rotation and tumble
		this.rotation += this.rotationSpeed;
		this.tumblePhase += this.tumbleSpeed;

		// Off-screen reset
		if (this.y > (height || 600) + 30 || this.x < -50 || this.x > (width || 800) + 50) {
			this.reset(false);
		}
	}

	draw(ctx) {
		const s = this.size;
		// 3D tumble effect — scale X by cosine to simulate rotation in depth
		const tumbleScale = 0.3 + 0.7 * Math.abs(Math.cos(this.tumblePhase));

		ctx.save();
		ctx.translate(this.x, this.y);
		ctx.rotate(this.rotation);
		ctx.scale(tumbleScale, 1);

		const [fr, fg, fb] = this.fillColor;
		const [sr, sg, sb] = this.strokeColor;

		// Draw leaf body
		ctx.beginPath();
		if (this.shapeType === 0) {
			// Simple oval leaf
			ctx.ellipse(0, 0, s * 0.5, s, 0, 0, Math.PI * 2);
		} else if (this.shapeType === 1) {
			// Pointed leaf
			ctx.moveTo(0, -s);
			ctx.quadraticCurveTo(s * 0.6, -s * 0.3, s * 0.4, s * 0.3);
			ctx.quadraticCurveTo(0, s * 0.8, 0, s);
			ctx.quadraticCurveTo(0, s * 0.8, -s * 0.4, s * 0.3);
			ctx.quadraticCurveTo(-s * 0.6, -s * 0.3, 0, -s);
		} else {
			// Round maple-ish leaf
			ctx.moveTo(0, -s * 0.9);
			ctx.bezierCurveTo(s * 0.8, -s * 0.6, s * 0.5, s * 0.2, s * 0.3, s * 0.5);
			ctx.quadraticCurveTo(0, s * 0.9, -s * 0.3, s * 0.5);
			ctx.bezierCurveTo(-s * 0.5, s * 0.2, -s * 0.8, -s * 0.6, 0, -s * 0.9);
		}
		ctx.closePath();
		ctx.fillStyle = `rgba(${fr}, ${fg}, ${fb}, ${this.opacity})`;
		ctx.fill();
		ctx.strokeStyle = `rgba(${sr}, ${sg}, ${sb}, ${this.opacity * 0.6})`;
		ctx.lineWidth = 0.5;
		ctx.stroke();

		// Center vein
		ctx.beginPath();
		ctx.moveTo(0, -s * 0.7);
		ctx.lineTo(0, s * 0.6);
		ctx.strokeStyle = `rgba(${sr}, ${sg}, ${sb}, ${this.opacity * 0.4})`;
		ctx.lineWidth = 0.4;
		ctx.stroke();

		// Stem
		ctx.beginPath();
		ctx.moveTo(0, s * 0.6);
		ctx.lineTo(0, s * 0.6 + this.stemLength);
		ctx.strokeStyle = `rgba(${sr}, ${sg}, ${sb}, ${this.opacity * 0.5})`;
		ctx.lineWidth = 0.6;
		ctx.stroke();

		ctx.restore();
	}
}

function initLeaves() {
	leaves = [];
	for (let i = 0; i < MAX_LEAVES; i++) {
		leaves.push(new Leaf());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initLeaves();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initLeaves();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time++;

		for (const leaf of leaves) {
			leaf.update(time);
			leaf.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Firefly Meadow
 * Description: Softly glowing firefly particles drifting with organic, non-linear
 *   movement. They pulse brighter occasionally with warm yellow/green glow.
 *   Mouse creates a gentle attraction zone that fireflies investigate.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let fireflies = [];
let time = 0;

const MAX_FIREFLIES = 60;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Firefly {
	constructor() {
		this.x = Math.random() * (width || 800);
		this.y = Math.random() * (height || 600);
		this.vx = 0;
		this.vy = 0;
		this.radius = 1.5 + Math.random() * 2;
		this.baseGlow = 0.08 + Math.random() * 0.12;
		this.glow = this.baseGlow;
		this.glowTarget = this.baseGlow;
		this.pulseTimer = Math.random() * 400;
		this.pulseInterval = 200 + Math.random() * 500;
		// Organic movement: use angular wandering
		this.angle = Math.random() * Math.PI * 2;
		this.angularVelocity = 0;
		this.speed = 0.2 + Math.random() * 0.4;
		// Color warmth — yellow to green spectrum
		this.hue = 50 + Math.random() * 80; // 50 (yellow) to 130 (green)
		this.saturation = 70 + Math.random() * 30;
		// Phase offset for individual timing
		this.phase = Math.random() * Math.PI * 2;
	}

	update(t) {
		// Organic angular wandering (like a random walk in angle space)
		this.angularVelocity += (Math.random() - 0.5) * 0.08;
		this.angularVelocity *= 0.92; // dampen
		this.angle += this.angularVelocity;

		// Gentle sinusoidal modulation of speed
		const speedMod = 0.7 + 0.3 * Math.sin(t * 0.005 + this.phase);
		const targetVx = Math.cos(this.angle) * this.speed * speedMod;
		const targetVy = Math.sin(this.angle) * this.speed * speedMod;

		// Smooth velocity transition
		this.vx += (targetVx - this.vx) * 0.05;
		this.vy += (targetVy - this.vy) * 0.05;

		// Mouse attraction — gentle investigation behavior
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const distSq = dx * dx + dy * dy;
		const attractRadius = 200;
		if (distSq < attractRadius * attractRadius && distSq > 400) {
			const dist = Math.sqrt(distSq);
			const force = 0.15 * (1 - dist / attractRadius);
			this.vx += (dx / dist) * force;
			this.vy += (dy / dist) * force;
		}
		// Very close to mouse — shy away slightly
		if (distSq < 400 && distSq > 0) {
			const dist = Math.sqrt(distSq);
			this.vx -= (dx / dist) * 0.3;
			this.vy -= (dy / dist) * 0.3;
		}

		this.x += this.vx;
		this.y += this.vy;

		// Wrap around edges with padding
		const pad = 30;
		if (this.x < -pad) this.x = width + pad;
		if (this.x > width + pad) this.x = -pad;
		if (this.y < -pad) this.y = height + pad;
		if (this.y > height + pad) this.y = -pad;

		// Pulsing glow
		this.pulseTimer++;
		if (this.pulseTimer > this.pulseInterval) {
			this.pulseTimer = 0;
			this.pulseInterval = 200 + Math.random() * 500;
			this.glowTarget = this.baseGlow + 0.2 + Math.random() * 0.3;
		}
		// Smooth glow transition
		this.glow += (this.glowTarget - this.glow) * 0.03;
		// Decay glow back to base
		this.glowTarget += (this.baseGlow - this.glowTarget) * 0.01;
	}

	draw(ctx) {
		const r = this.radius;
		const g = this.glow;

		// Outer soft glow (large radius, very transparent)
		const gradient = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r * 12);
		gradient.addColorStop(0, `hsla(${this.hue}, ${this.saturation}%, 70%, ${g * 0.6})`);
		gradient.addColorStop(0.3, `hsla(${this.hue}, ${this.saturation}%, 60%, ${g * 0.25})`);
		gradient.addColorStop(1, `hsla(${this.hue}, ${this.saturation}%, 50%, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, r * 12, 0, Math.PI * 2);
		ctx.fillStyle = gradient;
		ctx.fill();

		// Inner bright core
		const coreGrad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r * 2);
		coreGrad.addColorStop(0, `hsla(${this.hue}, ${this.saturation}%, 90%, ${g * 1.5})`);
		coreGrad.addColorStop(1, `hsla(${this.hue}, ${this.saturation}%, 70%, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, r * 2, 0, Math.PI * 2);
		ctx.fillStyle = coreGrad;
		ctx.fill();
	}
}

function initFireflies() {
	fireflies = [];
	for (let i = 0; i < MAX_FIREFLIES; i++) {
		fireflies.push(new Firefly());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initFireflies();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initFireflies();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		// Slight trail for dreamy effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.15)';
		ctx.fillRect(0, 0, width, height);

		time++;
		for (const ff of fireflies) {
			ff.update(time);
			ff.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Fluid Dye
 * Description: Simplified fluid dynamics — mouse movement injects colored dye and
 *   pushes a velocity field. Dye swirls, disperses, and creates mesmerizing patterns
 *   like ink dropped in water. Features grid-based velocity with diffusion, advection,
 *   and optional vorticity confinement. Rendered via ImageData for per-pixel color.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Dye --
  dyeColors: [                            // Dye injection colors [r,g,b] — cycles through
    [255, 40, 120],                       // Pink
    [40, 180, 255],                       // Cyan
    [255, 200, 40],                       // Gold
    [120, 255, 80],                       // Lime
    [180, 60, 255],                       // Purple
    [255, 120, 40],                       // Orange
  ],
  colorCycleSpeed: 100,                   // Frames between color shifts (30-300)
  dyeIntensity: 3.0,                      // Injection strength (0.5-8)
  dyeRadius: 4,                           // Injection radius in grid cells (2-12)

  // -- Fluid Physics --
  diffusion: 0.0002,                      // Velocity diffusion rate (0-0.001)
  viscosity: 0.997,                       // Damping per frame (0.99-0.9999)
  velocityScale: 25,                      // Mouse push strength (5-60)
  gridResolution: 5,                      // Cell size in px (3-8, lower=sharper)

  // -- Vorticity --
  vorticityEnabled: true,                 // Enhanced curl/swirl behavior
  vorticityStrength: 2.0,                 // Swirl enhancement (0.5-8)

  // -- Dye Fade --
  dyeFade: 0.996,                         // How fast dye fades (0.99-0.9999)

  // -- Rendering --
  pressureIterations: 6,                  // Jacobi pressure solve steps (2-20)
  backgroundColor: [5, 5, 15],            // Background tint [r,g,b]
  glowEnabled: true,                      // Bloom on bright areas
  glowIntensity: 1.2,                     // Bloom strength (0.5-3)
  blendMode: 'additive',                  // 'additive' or 'normal'
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let prevMouse = { x: -1, y: -1 };
let time = 0;
let cols, rows, size;
let vx, vy, vx0, vy0; // velocity fields
let dr, dg, db, dr0, dg0, db0; // dye density (RGB channels)
let imageData, pixels;
let colorIndex = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function idx(x, y) { return y * cols + x; }

function initFields() {
  size = CONFIG.gridResolution;
  cols = Math.ceil(width / size) + 2;
  rows = Math.ceil(height / size) + 2;
  const n = cols * rows;

  vx = new Float32Array(n); vy = new Float32Array(n);
  vx0 = new Float32Array(n); vy0 = new Float32Array(n);
  dr = new Float32Array(n); dg = new Float32Array(n); db = new Float32Array(n);
  dr0 = new Float32Array(n); dg0 = new Float32Array(n); db0 = new Float32Array(n);

  imageData = ctx.createImageData(width, height);
  pixels = imageData.data;
}

// Diffuse: spread values to neighbors (Gauss-Seidel relaxation)
function diffuse(x, x0, diff) {
  if (diff <= 0) { x.set(x0); return; }
  const a = diff * cols * rows;
  const inv = 1 / (1 + 4 * a);
  for (let iter = 0; iter < CONFIG.pressureIterations; iter++) {
    for (let j = 1; j < rows - 1; j++) {
      for (let i = 1; i < cols - 1; i++) {
        const id = idx(i, j);
        x[id] = (x0[id] + a * (x[id-1] + x[id+1] + x[id-cols] + x[id+cols])) * inv;
      }
    }
  }
}

// Advect: move quantities along velocity field (semi-Lagrangian)
function advect(d, d0, u, v) {
  for (let j = 1; j < rows - 1; j++) {
    for (let i = 1; i < cols - 1; i++) {
      const id = idx(i, j);
      // Trace back
      let x = i - u[id];
      let y = j - v[id];
      // Clamp
      if (x < 0.5) x = 0.5; if (x > cols - 1.5) x = cols - 1.5;
      if (y < 0.5) y = 0.5; if (y > rows - 1.5) y = rows - 1.5;
      // Bilinear interpolation
      const i0 = x | 0, j0 = y | 0;
      const i1 = i0 + 1, j1 = j0 + 1;
      const sx = x - i0, sy = y - j0;
      d[id] = (1-sx) * ((1-sy) * d0[idx(i0,j0)] + sy * d0[idx(i0,j1)])
            +    sx  * ((1-sy) * d0[idx(i1,j0)] + sy * d0[idx(i1,j1)]);
    }
  }
}

// Project: make velocity field divergence-free (mass conservation)
function project() {
  const p = vx0, div = vy0; // reuse buffers
  const hx = 1.0 / cols, hy = 1.0 / rows;

  // Compute divergence
  for (let j = 1; j < rows - 1; j++) {
    for (let i = 1; i < cols - 1; i++) {
      const id = idx(i, j);
      div[id] = -0.5 * (vx[id+1] - vx[id-1] + vy[id+cols] - vy[id-cols]);
      p[id] = 0;
    }
  }

  // Solve pressure (Jacobi)
  for (let iter = 0; iter < CONFIG.pressureIterations; iter++) {
    for (let j = 1; j < rows - 1; j++) {
      for (let i = 1; i < cols - 1; i++) {
        const id = idx(i, j);
        p[id] = (div[id] + p[id-1] + p[id+1] + p[id-cols] + p[id+cols]) * 0.25;
      }
    }
  }

  // Subtract pressure gradient
  for (let j = 1; j < rows - 1; j++) {
    for (let i = 1; i < cols - 1; i++) {
      const id = idx(i, j);
      vx[id] -= 0.5 * (p[id+1] - p[id-1]);
      vy[id] -= 0.5 * (p[id+cols] - p[id-cols]);
    }
  }
}

// Vorticity confinement: amplify existing curls
function addVorticity() {
  if (!CONFIG.vorticityEnabled) return;
  const str = CONFIG.vorticityStrength * 0.0005;

  // Compute curl (ω = dvx/dy - dvy/dx)
  const curl = dr0; // reuse buffer
  for (let j = 1; j < rows - 1; j++) {
    for (let i = 1; i < cols - 1; i++) {
      const id = idx(i, j);
      curl[id] = (vx[id+cols] - vx[id-cols]) - (vy[id+1] - vy[id-1]);
    }
  }

  // Apply confinement force
  for (let j = 2; j < rows - 2; j++) {
    for (let i = 2; i < cols - 2; i++) {
      const id = idx(i, j);
      // Gradient of |curl|
      const dcdx = Math.abs(curl[id+1]) - Math.abs(curl[id-1]);
      const dcdy = Math.abs(curl[id+cols]) - Math.abs(curl[id-cols]);
      const len = Math.sqrt(dcdx * dcdx + dcdy * dcdy) + 0.00001;
      // Normalized curl gradient × curl = confinement force direction
      const nx = dcdx / len, ny = dcdy / len;
      vx[id] += str * (ny * curl[id]);
      vy[id] -= str * (nx * curl[id]);
    }
  }
}

function velocityStep() {
  // Add mouse force
  if (mouse.x >= 0 && prevMouse.x >= 0) {
    const dx = mouse.x - prevMouse.x;
    const dy = mouse.y - prevMouse.y;
    const mx = Math.floor(mouse.x / size);
    const my = Math.floor(mouse.y / size);
    const r = CONFIG.dyeRadius;
    const scale = CONFIG.velocityScale * 0.1;

    for (let j = -r; j <= r; j++) {
      for (let i = -r; i <= r; i++) {
        const gx = mx + i, gy = my + j;
        if (gx < 1 || gx >= cols - 1 || gy < 1 || gy >= rows - 1) continue;
        const d = Math.sqrt(i * i + j * j);
        if (d > r) continue;
        const falloff = 1 - d / r;
        const id2 = idx(gx, gy);
        vx[id2] += dx * scale * falloff;
        vy[id2] += dy * scale * falloff;
      }
    }
  }

  // Diffuse
  vx0.set(vx); vy0.set(vy);
  diffuse(vx, vx0, CONFIG.diffusion);
  diffuse(vy, vy0, CONFIG.diffusion);
  project();

  // Advect
  vx0.set(vx); vy0.set(vy);
  advect(vx, vx0, vx0, vy0);
  advect(vy, vy0, vx0, vy0);
  project();

  // Vorticity
  addVorticity();

  // Damping
  const visc = CONFIG.viscosity;
  for (let i = 0; i < vx.length; i++) { vx[i] *= visc; vy[i] *= visc; }
}

function dyeStep() {
  // Inject dye at mouse
  if (mouse.x >= 0 && prevMouse.x >= 0) {
    const speed = Math.hypot(mouse.x - prevMouse.x, mouse.y - prevMouse.y);
    if (speed > 0.5) {
      const mx = Math.floor(mouse.x / size);
      const my = Math.floor(mouse.y / size);
      const r = CONFIG.dyeRadius;
      const c = CONFIG.dyeColors[colorIndex];
      const intensity = CONFIG.dyeIntensity;

      for (let j = -r; j <= r; j++) {
        for (let i = -r; i <= r; i++) {
          const gx = mx + i, gy = my + j;
          if (gx < 1 || gx >= cols - 1 || gy < 1 || gy >= rows - 1) continue;
          const d = Math.sqrt(i * i + j * j);
          if (d > r) continue;
          const f = (1 - d / r) * intensity * Math.min(1, speed * 0.1);
          const id2 = idx(gx, gy);
          dr[id2] += c[0] * f * 0.004;
          dg[id2] += c[1] * f * 0.004;
          db[id2] += c[2] * f * 0.004;
        }
      }
    }
  }

  // Diffuse dye
  dr0.set(dr); dg0.set(dg); db0.set(db);
  diffuse(dr, dr0, CONFIG.diffusion * 0.5);
  diffuse(dg, dg0, CONFIG.diffusion * 0.5);
  diffuse(db, db0, CONFIG.diffusion * 0.5);

  // Advect dye
  dr0.set(dr); dg0.set(dg); db0.set(db);
  advect(dr, dr0, vx, vy);
  advect(dg, dg0, vx, vy);
  advect(db, db0, vx, vy);

  // Fade
  const fade = CONFIG.dyeFade;
  for (let i = 0; i < dr.length; i++) {
    dr[i] *= fade; dg[i] *= fade; db[i] *= fade;
  }
}

function renderToPixels() {
  const bg = CONFIG.backgroundColor;
  const additive = CONFIG.blendMode === 'additive';
  const glow = CONFIG.glowEnabled ? CONFIG.glowIntensity : 1;

  for (let py = 0; py < height; py++) {
    const gy = (py / size) | 0;
    const fy = py / size - gy;
    const gy1 = Math.min(gy + 1, rows - 1);

    for (let px = 0; px < width; px++) {
      const gx = (px / size) | 0;
      const fx = px / size - gx;
      const gx1 = Math.min(gx + 1, cols - 1);

      // Bilinear interp of dye at this pixel
      const i00 = gy * cols + gx;
      const i10 = gy * cols + gx1;
      const i01 = gy1 * cols + gx;
      const i11 = gy1 * cols + gx1;

      let r = (1-fx)*(1-fy)*dr[i00] + fx*(1-fy)*dr[i10] + (1-fx)*fy*dr[i01] + fx*fy*dr[i11];
      let g = (1-fx)*(1-fy)*dg[i00] + fx*(1-fy)*dg[i10] + (1-fx)*fy*dg[i01] + fx*fy*dg[i11];
      let b = (1-fx)*(1-fy)*db[i00] + fx*(1-fy)*db[i10] + (1-fx)*fy*db[i01] + fx*fy*db[i11];

      // Tonemap
      r = Math.min(1, r * glow);
      g = Math.min(1, g * glow);
      b = Math.min(1, b * glow);

      const pidx = (py * width + px) << 2;
      if (additive) {
        pixels[pidx]     = Math.min(255, bg[0] + r * 255);
        pixels[pidx + 1] = Math.min(255, bg[1] + g * 255);
        pixels[pidx + 2] = Math.min(255, bg[2] + b * 255);
      } else {
        pixels[pidx]     = bg[0] + (255 - bg[0]) * r;
        pixels[pidx + 1] = bg[1] + (255 - bg[1]) * g;
        pixels[pidx + 2] = bg[2] + (255 - bg[2]) * b;
      }
      pixels[pidx + 3] = 255;
    }
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time++;

    // Color cycling
    if (time % CONFIG.colorCycleSpeed === 0) {
      colorIndex = (colorIndex + 1) % CONFIG.dyeColors.length;
    }

    velocityStep();
    dyeStep();
    renderToPixels();
    ctx.putImageData(imageData, 0, 0);

    prevMouse.x = mouse.x;
    prevMouse.y = mouse.y;

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initFields();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initFields();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Fluid Ribbons
 * Description: Graceful, flowing silk-like ribbons that trail across the screen in smooth
 *   sine/bezier curves. Ribbons taper from thick centers to thin edges, carry color gradients
 *   along their length, attract toward the mouse cursor, and glow at intersection points.
 *   Uses ring-buffer position history, Float32Array bulk storage, and delta-time animation.
 */

// ─── CONFIG ────────────────────────────────────────────────────────────────────
const CONFIG = {
	ribbonCount: 10, // Number of independent ribbons
	ribbonLength: 120, // History points per ribbon (ring buffer depth)
	ribbonWidth: 18, // Maximum width at the ribbon's center
	taperAmount: 0.92, // How sharply ribbon tapers at edges (0 = none, 1 = full)
	flowSpeed: 0.6, // Base movement speed (px per frame at 60fps)
	flowAmplitude: 150, // Sine-wave amplitude for vertical undulation (px)
	flowFrequency: 0.008, // Sine-wave frequency (lower = wider waves)
	attractRadius: 280, // Distance within which mouse attracts ribbons (px)
	attractStrength: 0.035, // How strongly ribbons curve toward the cursor
	colorSaturation: 72, // HSL saturation for ribbon color (%)
	colorLightness: 62, // HSL lightness for ribbon color (%)
	intersectionGlow: 0.35, // Glow intensity at ribbon crossings (0-1)
	trailAlpha: 0.06, // Base alpha for the oldest trail points
	glowPasses: 3, // Number of multi-pass glow layers
	glowWidthStep: 4, // Extra width added per glow pass
	glowAlphaDecay: 0.35 // Alpha multiplier per successive glow pass
};

// ─── STATE ─────────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;
let ribbons = [];

// ─── HEARTBEAT ─────────────────────────────────────────────────────────────────
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── RIBBON CLASS (pooled, zero-alloc render loop) ─────────────────────────────
class Ribbon {
	constructor(index) {
		this.index = index;
		const len = CONFIG.ribbonLength;

		// Ring buffer for x, y positions — Float32Array for performance
		this.xBuf = new Float32Array(len);
		this.yBuf = new Float32Array(len);
		this.head = 0; // Current write position in ring buffer
		this.filled = 0; // How many slots are filled (up to len)

		// Movement state
		this.x = 0;
		this.y = 0;
		this.vx = 0;
		this.vy = 0;
		this.angle = 0; // Current heading angle
		this.phase = 0; // Sine-wave phase offset
		this.baseHue = 0; // Starting hue for this ribbon

		// Precomputed taper widths — avoids per-frame allocation
		this.taperWidths = new Float32Array(len);
	}

	init(w, h) {
		const len = CONFIG.ribbonLength;
		this.x = Math.random() * w;
		this.y = Math.random() * h;
		this.angle = Math.random() * Math.PI * 2;
		this.phase = Math.random() * Math.PI * 2;
		this.baseHue = (this.index / CONFIG.ribbonCount) * 360 + Math.random() * 40;
		this.vx = Math.cos(this.angle) * CONFIG.flowSpeed;
		this.vy = Math.sin(this.angle) * CONFIG.flowSpeed;
		this.head = 0;
		this.filled = 0;

		// Fill the entire buffer with the starting position
		for (let i = 0; i < len; i++) {
			this.xBuf[i] = this.x;
			this.yBuf[i] = this.y;
		}
		this.filled = 1;

		// Precompute taper widths (bell-curve shape)
		for (let i = 0; i < len; i++) {
			const t = i / (len - 1); // 0 at head, 1 at tail
			const bell = Math.sin(t * Math.PI); // 0→1→0 bell
			const taper = 1 - CONFIG.taperAmount * (1 - bell);
			this.taperWidths[i] = CONFIG.ribbonWidth * taper;
		}
	}

	update(dt) {
		const speed = CONFIG.flowSpeed * dt;

		// Sine-wave undulation perpendicular to heading
		this.phase += CONFIG.flowFrequency * dt * 60;
		const perpAngle = this.angle + Math.PI * 0.5;
		const sineOffset = Math.sin(this.phase) * CONFIG.flowAmplitude * CONFIG.flowFrequency;

		// Base velocity
		this.vx = Math.cos(this.angle) * speed + Math.cos(perpAngle) * sineOffset * dt;
		this.vy = Math.sin(this.angle) * speed + Math.sin(perpAngle) * sineOffset * dt;

		// Mouse attraction
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < CONFIG.attractRadius && dist > 1) {
			const force = CONFIG.attractStrength * (1 - dist / CONFIG.attractRadius);
			this.vx += (dx / dist) * force * dt * 60;
			this.vy += (dy / dist) * force * dt * 60;
		}

		// Slowly drift the heading angle (smooth wandering)
		this.angle += (Math.random() - 0.5) * 0.04 * dt * 60;

		// Apply velocity
		this.x += this.vx;
		this.y += this.vy;

		// Soft edge wrapping with margin
		const margin = 100;
		if (this.x < -margin) this.x = width + margin;
		if (this.x > width + margin) this.x = -margin;
		if (this.y < -margin) this.y = height + margin;
		if (this.y > height + margin) this.y = -margin;

		// Push position into ring buffer
		this.xBuf[this.head] = this.x;
		this.yBuf[this.head] = this.y;
		this.head = (this.head + 1) % CONFIG.ribbonLength;
		if (this.filled < CONFIG.ribbonLength) this.filled++;
	}

	// Get the i-th oldest point (0 = oldest visible, filled-1 = newest/head)
	getPoint(i) {
		const idx = (this.head - this.filled + i + CONFIG.ribbonLength) % CONFIG.ribbonLength;
		return { x: this.xBuf[idx], y: this.yBuf[idx] };
	}

	draw(ctx, pass) {
		if (this.filled < 4) return;

		const count = this.filled;
		const isGlow = pass > 0;
		const extraWidth = isGlow ? pass * CONFIG.glowWidthStep : 0;
		const alphaScale = isGlow ? Math.pow(CONFIG.glowAlphaDecay, pass) : 1;

		// Draw as a sequence of quadratic bezier segments
		for (let i = 1; i < count - 1; i++) {
			const prev = this.getPoint(i - 1);
			const curr = this.getPoint(i);
			const next = this.getPoint(i + 1);

			// Midpoints for smooth bezier connections
			const mx0 = (prev.x + curr.x) * 0.5;
			const my0 = (prev.y + curr.y) * 0.5;
			const mx1 = (curr.x + next.x) * 0.5;
			const my1 = (curr.y + next.y) * 0.5;

			// Age factor: 0 at tail, 1 at head
			const t = i / (count - 1);
			const alpha = (CONFIG.trailAlpha + (1 - CONFIG.trailAlpha) * t) * alphaScale;
			const w = this.taperWidths[Math.min(i, CONFIG.ribbonLength - 1)] + extraWidth;

			// Color gradient along ribbon length
			const hue = (this.baseHue + t * 60) % 360;

			ctx.beginPath();
			ctx.moveTo(mx0, my0);
			ctx.quadraticCurveTo(curr.x, curr.y, mx1, my1);
			ctx.lineWidth = Math.max(0.5, w);
			ctx.strokeStyle = `hsla(${hue}, ${CONFIG.colorSaturation}%, ${CONFIG.colorLightness}%, ${alpha * 0.4})`;
			ctx.lineCap = 'round';
			ctx.lineJoin = 'round';
			ctx.stroke();
		}
	}
}

// ─── INTERSECTION DETECTION ────────────────────────────────────────────────────
// Lightweight: only check head positions of each ribbon pair for glow
function drawIntersectionGlows(ctx) {
	if (CONFIG.intersectionGlow <= 0) return;

	const checkRadius = CONFIG.ribbonWidth * 2;
	for (let a = 0; a < ribbons.length; a++) {
		for (let b = a + 1; b < ribbons.length; b++) {
			const ra = ribbons[a];
			const rb = ribbons[b];

			// Sample a few points along each ribbon for crossing detection
			const samplesA = Math.min(ra.filled, 30);
			const samplesB = Math.min(rb.filled, 30);
			const stepA = Math.max(1, Math.floor(ra.filled / samplesA));
			const stepB = Math.max(1, Math.floor(rb.filled / samplesB));

			for (let i = 0; i < ra.filled; i += stepA) {
				const pa = ra.getPoint(i);
				for (let j = 0; j < rb.filled; j += stepB) {
					const pb = rb.getPoint(j);
					const dx = pa.x - pb.x;
					const dy = pa.y - pb.y;
					const distSq = dx * dx + dy * dy;
					if (distSq < checkRadius * checkRadius) {
						const dist = Math.sqrt(distSq);
						const intensity = (1 - dist / checkRadius) * CONFIG.intersectionGlow;
						const midX = (pa.x + pb.x) * 0.5;
						const midY = (pa.y + pb.y) * 0.5;
						const hue = (ra.baseHue + rb.baseHue) * 0.5;

						const grad = ctx.createRadialGradient(midX, midY, 0, midX, midY, checkRadius);
						grad.addColorStop(0, `hsla(${hue}, 80%, 80%, ${intensity * 0.5})`);
						grad.addColorStop(1, `hsla(${hue}, 80%, 80%, 0)`);
						ctx.fillStyle = grad;
						ctx.fillRect(midX - checkRadius, midY - checkRadius, checkRadius * 2, checkRadius * 2);
					}
				}
			}
		}
	}
}

// ─── INITIALIZATION ────────────────────────────────────────────────────────────
function initRibbons() {
	ribbons = [];
	for (let i = 0; i < CONFIG.ribbonCount; i++) {
		const r = new Ribbon(i);
		r.init(width, height);
		ribbons.push(r);
	}
}

// ─── MESSAGE HANDLER ───────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			ctx.lineCap = 'round';
			ctx.lineJoin = 'round';
			initRibbons();
			lastTime = performance.now();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			// Don't reinitialize — ribbons will naturally drift into the new area
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

// ─── RENDER LOOP ───────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) return;

		// Delta time in seconds, capped to prevent spiral-of-death
		const dt = Math.min((now - lastTime) / 16.667, 3);
		lastTime = now;

		// Semi-transparent clear for motion trail effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.08)';
		ctx.fillRect(0, 0, width, height);

		// Update all ribbons
		for (let i = 0; i < ribbons.length; i++) {
			ribbons[i].update(dt);
		}

		// Multi-pass glow rendering (widest/faintest first)
		for (let pass = CONFIG.glowPasses; pass >= 0; pass--) {
			for (let i = 0; i < ribbons.length; i++) {
				ribbons[i].draw(ctx, pass);
			}
		}

		// Intersection glows
		drawIntersectionGlows(ctx);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Fog Drift
 * Description: Layered rolling fog and mist that drifts across the canvas with
 *   organic turbulence. Mouse pushes fog away, creating a parting-mist effect.
 *   Extremely atmospheric.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Fog Layers --
  layerCount: 6,                           // Number of independent fog layers
  fogColor: '180, 190, 210',               // RGB base fog color (no alpha — added dynamically)
  minOpacity: 0.03,                        // Minimum layer opacity (0-1)
  maxOpacity: 0.14,                        // Maximum layer opacity (0-1)

  // -- Layer Geometry --
  layerHeight: 0.45,                       // Layer height as fraction of canvas height (0-1)
  verticalSpread: 0.7,                     // How much layers spread vertically (0-1)
  verticalOffset: 0.3,                     // Base vertical position (0 = top, 1 = bottom)
  density: 5,                              // Number of fog blobs per layer

  // -- Motion --
  driftSpeed: 0.4,                         // Base horizontal drift speed
  driftSpeedVariance: 0.3,                 // ± random speed variation between layers
  turbulence: 0.35,                        // Perlin-like vertical turbulence intensity
  turbulenceSpeed: 0.003,                  // How fast turbulence oscillates
  speed: 1.0,                              // Global speed multiplier

  // -- Appearance --
  blobMinWidth: 0.3,                       // Minimum blob width as fraction of canvas width
  blobMaxWidth: 0.7,                       // Maximum blob width as fraction of canvas width
  blurRadius: 60,                          // Gaussian blur radius for softness in px

  // -- Mouse Interaction --
  mouseClearRadius: 200,                   // Radius where mouse pushes fog away in px
  mouseClearStrength: 0.9,                 // How much fog is cleared at center (0-1)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let layers = [];
let time = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initLayers();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initLayers();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function initLayers() {
  layers = [];
  for (let i = 0; i < CONFIG.layerCount; i++) {
    const t = i / Math.max(1, CONFIG.layerCount - 1);
    const opacity = CONFIG.minOpacity + (CONFIG.maxOpacity - CONFIG.minOpacity) * (0.5 + Math.random() * 0.5);
    const baseY = (CONFIG.verticalOffset + t * CONFIG.verticalSpread) * height;
    const layerH = CONFIG.layerHeight * height;
    const driftDir = i % 2 === 0 ? 1 : -1;
    const driftSpd = (CONFIG.driftSpeed + (Math.random() - 0.5) * CONFIG.driftSpeedVariance * 2) * driftDir;

    const blobs = [];
    for (let j = 0; j < CONFIG.density; j++) {
      blobs.push({
        xOffset: Math.random() * width * 2 - width * 0.5,
        yOffset: (Math.random() - 0.5) * layerH * 0.5,
        blobWidth: (CONFIG.blobMinWidth + Math.random() * (CONFIG.blobMaxWidth - CONFIG.blobMinWidth)) * width,
        blobHeight: layerH * (0.5 + Math.random() * 0.5),
        turbPhase: Math.random() * Math.PI * 2,
        turbAmp: CONFIG.turbulence * layerH * (0.3 + Math.random() * 0.7),
      });
    }

    layers.push({
      baseY,
      opacity,
      driftSpeed: driftSpd,
      blobs,
      xScroll: Math.random() * width,
    });
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += CONFIG.speed;

    ctx.clearRect(0, 0, width, height);

    for (let i = 0; i < layers.length; i++) {
      const layer = layers[i];

      layer.xScroll += layer.driftSpeed * CONFIG.speed;

      // Wrap scroll
      if (layer.xScroll > width * 2) layer.xScroll -= width * 3;
      if (layer.xScroll < -width) layer.xScroll += width * 3;

      for (const blob of layer.blobs) {
        const turbY = Math.sin(time * CONFIG.turbulenceSpeed + blob.turbPhase) * blob.turbAmp;
        const bx = blob.xOffset + layer.xScroll;
        const by = layer.baseY + blob.yOffset + turbY;

        // Wrap the blob horizontally
        const wrappedX = ((bx % (width + blob.blobWidth)) + width + blob.blobWidth) % (width + blob.blobWidth) - blob.blobWidth * 0.5;

        // Mouse interaction — reduce opacity near mouse
        let alphaMultiplier = 1;
        const dx = wrappedX + blob.blobWidth * 0.5 - mouse.x;
        const dy = by - mouse.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < CONFIG.mouseClearRadius + blob.blobWidth * 0.3) {
          const clearDist = CONFIG.mouseClearRadius + blob.blobWidth * 0.3;
          const factor = Math.max(0, 1 - dist / clearDist);
          alphaMultiplier = 1 - factor * CONFIG.mouseClearStrength;
        }

        const finalAlpha = layer.opacity * alphaMultiplier;
        if (finalAlpha < 0.002) continue;

        // Draw fog blob as a radial gradient ellipse
        ctx.save();
        ctx.globalAlpha = finalAlpha;
        ctx.filter = `blur(${CONFIG.blurRadius}px)`;

        const grad = ctx.createRadialGradient(
          wrappedX + blob.blobWidth * 0.5, by, 0,
          wrappedX + blob.blobWidth * 0.5, by, blob.blobWidth * 0.5
        );
        grad.addColorStop(0, `rgba(${CONFIG.fogColor}, 1)`);
        grad.addColorStop(0.5, `rgba(${CONFIG.fogColor}, 0.6)`);
        grad.addColorStop(1, `rgba(${CONFIG.fogColor}, 0)`);

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.ellipse(
          wrappedX + blob.blobWidth * 0.5,
          by,
          blob.blobWidth * 0.5,
          blob.blobHeight * 0.5,
          0, 0, Math.PI * 2
        );
        ctx.fill();
        ctx.restore();
      }
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Fractal Tree
 * Description: An animated recursive fractal tree with natural sway, seasonal
 *   color modes, growth animation, falling leaf particles, and mouse-driven
 *   wind interaction. Uses typed arrays for branch and leaf data, delta-time
 *   animation, off-screen culling, multi-pass glow, and motion trails.
 */

/* ───────────────────── CONFIG ───────────────────── */
const CONFIG = {
	maxDepth: 11, // max recursion depth for branching
	trunkLength: 140, // initial trunk segment length (px)
	branchRatio: 0.72, // child length as fraction of parent
	branchAngle: 0.45, // base branching angle (radians)
	branchAngleVariance: 0.15, // random variance added per branch (radians)
	swayAmplitude: 0.04, // max sway rotation (radians)
	swayFrequency: 1.2, // sway oscillation speed (Hz)
	swayDamping: 0.78, // sway amplitude multiplier per depth level
	trunkWidth: 14, // width of the trunk at base (px)
	widthRatio: 0.68, // child width as fraction of parent
	trunkColor: '100,70,40', // RGB for trunk base
	tipColor: '30,160,60', // RGB for branch tips (summer)
	leafCount: 3, // leaves spawned per terminal branch
	leafSize: 4, // radius of leaf particles (px)
	leafFallChance: 0.0004, // probability per frame per leaf to detach
	leafFallSpeed: 40, // falling speed (px/s)
	leafDriftSpeed: 20, // horizontal drift while falling (px/s)
	season: 'summer', // 'summer' | 'autumn' | 'winter' | 'spring'
	growthDuration: 180, // frames to grow from sapling to full size
	mouseWindRadius: 200, // radius of mouse wind influence (px)
	mouseWindForce: 0.6, // max wind angle from mouse proximity (radians)
	glowPasses: 2, // number of glow post-process passes
	glowAlpha: 0.1, // alpha per glow pass
	trailAlpha: 0.12 // motion trail opacity
};

/* ───────────────────── SEASON PALETTES ───────────────────── */
const SEASON_PALETTES = {
	summer: { tip: '30,160,60', leaf: '50,180,70', leafAlt: '30,140,50' },
	autumn: { tip: '200,100,20', leaf: '220,120,30', leafAlt: '180,40,20' },
	winter: { tip: '140,140,160', leaf: '200,210,230', leafAlt: '180,190,210' },
	spring: { tip: '220,140,180', leaf: '240,170,200', leafAlt: '255,200,220' }
};

/* ───────────────────── STATE ───────────────────── */
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;
let growthFrame = 0;

// Branch pool — pre-allocated
const MAX_BRANCHES = 4096;
let branchX0 = new Float32Array(MAX_BRANCHES); // start x
let branchY0 = new Float32Array(MAX_BRANCHES); // start y
let branchX1 = new Float32Array(MAX_BRANCHES); // end x
let branchY1 = new Float32Array(MAX_BRANCHES); // end y
let branchAngle = new Float32Array(MAX_BRANCHES); // base angle
let branchWidth = new Float32Array(MAX_BRANCHES); // line width
let branchDepth = new Uint8Array(MAX_BRANCHES); // recursion depth
let branchLen = new Float32Array(MAX_BRANCHES); // segment length
let branchSway = new Float32Array(MAX_BRANCHES); // sway phase offset
let branchParent = new Int16Array(MAX_BRANCHES); // parent index (-1 for root)
let branchCount = 0;

// Leaf pool
const MAX_LEAVES = 2048;
let leafX = new Float32Array(MAX_LEAVES);
let leafY = new Float32Array(MAX_LEAVES);
let leafHomeX = new Float32Array(MAX_LEAVES);
let leafHomeY = new Float32Array(MAX_LEAVES);
let leafFalling = new Uint8Array(MAX_LEAVES); // 0 = attached, 1 = falling
let leafDriftX = new Float32Array(MAX_LEAVES); // drift direction
let leafColor = new Uint8Array(MAX_LEAVES); // 0 or 1 for palette variation
let leafAlpha = new Float32Array(MAX_LEAVES);
let leafBranch = new Int16Array(MAX_LEAVES); // which branch this leaf belongs to
let leafCount = 0;

// Glow offscreen
let glowCanvas, glowCtx;

/* ───────────────────── HELPERS ───────────────────── */
function rand(a, b) {
	return a + Math.random() * (b - a);
}
function clamp(v, lo, hi) {
	return v < lo ? lo : v > hi ? hi : v;
}
function lerpColor(c1, c2, t) {
	const p1 = c1.split(',').map(Number);
	const p2 = c2.split(',').map(Number);
	const r = (p1[0] + (p2[0] - p1[0]) * t) | 0;
	const g = (p1[1] + (p2[1] - p1[1]) * t) | 0;
	const b = (p1[2] + (p2[2] - p1[2]) * t) | 0;
	return `${r},${g},${b}`;
}

/* ───────────────────── TREE GENERATION ───────────────────── */
function generateTree() {
	branchCount = 0;
	leafCount = 0;

	const baseX = width * 0.5;
	const baseY = height * 0.88;

	function addBranch(x0, y0, angle, len, w, depth, parent) {
		if (depth > CONFIG.maxDepth || branchCount >= MAX_BRANCHES) return;
		if (len < 3) return;

		const idx = branchCount++;
		branchX0[idx] = x0;
		branchY0[idx] = y0;
		branchAngle[idx] = angle;
		branchLen[idx] = len;
		branchWidth[idx] = w;
		branchDepth[idx] = depth;
		branchSway[idx] = rand(0, Math.PI * 2);
		branchParent[idx] = parent;

		// Compute end position (will be updated in render for sway)
		const x1 = x0 + Math.cos(angle) * len;
		const y1 = y0 + Math.sin(angle) * len;
		branchX1[idx] = x1;
		branchY1[idx] = y1;

		if (depth >= CONFIG.maxDepth - 1 || len < 8) {
			// Terminal — add leaves
			if (CONFIG.season !== 'winter') {
				for (let l = 0; l < CONFIG.leafCount && leafCount < MAX_LEAVES; l++) {
					const li = leafCount++;
					leafHomeX[li] = x1 + rand(-6, 6);
					leafHomeY[li] = y1 + rand(-6, 6);
					leafX[li] = leafHomeX[li];
					leafY[li] = leafHomeY[li];
					leafFalling[li] = 0;
					leafDriftX[li] = rand(-1, 1);
					leafColor[li] = Math.random() < 0.5 ? 0 : 1;
					leafAlpha[li] = rand(0.4, 0.8);
					leafBranch[li] = idx;
				}
			}
		}

		// Recurse
		const childLen = len * CONFIG.branchRatio;
		const childW = w * CONFIG.widthRatio;
		const variance1 = rand(-CONFIG.branchAngleVariance, CONFIG.branchAngleVariance);
		const variance2 = rand(-CONFIG.branchAngleVariance, CONFIG.branchAngleVariance);

		addBranch(x1, y1, angle - CONFIG.branchAngle + variance1, childLen, childW, depth + 1, idx);
		addBranch(x1, y1, angle + CONFIG.branchAngle + variance2, childLen, childW, depth + 1, idx);

		// Extra branch occasionally
		if (depth > 2 && Math.random() < 0.2) {
			const variance3 = rand(-CONFIG.branchAngleVariance * 2, CONFIG.branchAngleVariance * 2);
			addBranch(x1, y1, angle + variance3, childLen * 0.8, childW * 0.9, depth + 1, idx);
		}
	}

	addBranch(baseX, baseY, -Math.PI / 2, CONFIG.trunkLength, CONFIG.trunkWidth, 0, -1);
}

function initGlow() {
	glowCanvas = new OffscreenCanvas(width >> 1, height >> 1);
	glowCtx = glowCanvas.getContext('2d');
}

/* ───────────────────── UPDATE ───────────────────── */
function updateBranches(time, dt) {
	const growthScale = clamp(growthFrame / CONFIG.growthDuration, 0, 1);
	const baseX = width * 0.5;
	const baseY = height * 0.88;

	for (let i = 0; i < branchCount; i++) {
		const depth = branchDepth[i];
		const parent = branchParent[i];

		// Update start position from parent's end
		if (parent >= 0) {
			branchX0[i] = branchX1[parent];
			branchY0[i] = branchY1[parent];
		} else {
			branchX0[i] = baseX;
			branchY0[i] = baseY;
		}

		// Sway
		const swayDamp = Math.pow(CONFIG.swayDamping, depth);
		const sway =
			Math.sin(time * CONFIG.swayFrequency * Math.PI * 2 + branchSway[i]) *
			CONFIG.swayAmplitude *
			swayDamp;

		// Mouse wind
		let windAngle = 0;
		const mx = branchX0[i] - mouse.x;
		const my = branchY0[i] - mouse.y;
		const md = Math.sqrt(mx * mx + my * my);
		if (md < CONFIG.mouseWindRadius && md > 1) {
			const windStr = (1 - md / CONFIG.mouseWindRadius) * CONFIG.mouseWindForce;
			// Push away from mouse
			windAngle = (mx > 0 ? 1 : -1) * windStr * (depth / CONFIG.maxDepth);
		}

		const angle = branchAngle[i] + sway + windAngle;
		const len = branchLen[i] * growthScale;

		branchX1[i] = branchX0[i] + Math.cos(angle) * len;
		branchY1[i] = branchY0[i] + Math.sin(angle) * len;
	}
}

function updateLeaves(dt) {
	for (let i = 0; i < leafCount; i++) {
		if (leafFalling[i]) {
			// Fall
			leafY[i] += CONFIG.leafFallSpeed * dt;
			leafX[i] += leafDriftX[i] * CONFIG.leafDriftSpeed * dt;
			leafDriftX[i] += rand(-0.5, 0.5) * dt; // wobble
			leafAlpha[i] -= 0.15 * dt;

			// Reset if off screen or faded
			if (leafY[i] > height + 20 || leafAlpha[i] <= 0) {
				leafFalling[i] = 0;
				const bi = leafBranch[i];
				if (bi >= 0 && bi < branchCount) {
					leafHomeX[i] = branchX1[bi] + rand(-6, 6);
					leafHomeY[i] = branchY1[bi] + rand(-6, 6);
				}
				leafX[i] = leafHomeX[i];
				leafY[i] = leafHomeY[i];
				leafAlpha[i] = rand(0.4, 0.8);
				leafDriftX[i] = rand(-1, 1);
			}
		} else {
			// Update home position from branch
			const bi = leafBranch[i];
			if (bi >= 0 && bi < branchCount) {
				leafHomeX[i] = branchX1[bi] + (leafHomeX[i] - branchX1[bi]) * 0.5;
				leafHomeY[i] = branchY1[bi] + (leafHomeY[i] - branchY1[bi]) * 0.5;
			}
			leafX[i] = leafHomeX[i] + rand(-1.5, 1.5);
			leafY[i] = leafHomeY[i] + rand(-1.5, 1.5);

			// Chance to detach
			if (Math.random() < CONFIG.leafFallChance) {
				leafFalling[i] = 1;
			}
		}
	}
}

/* ───────────────────── DRAW ───────────────────── */
function drawBranches() {
	const palette = SEASON_PALETTES[CONFIG.season] || SEASON_PALETTES.summer;
	const growthScale = clamp(growthFrame / CONFIG.growthDuration, 0, 1);

	ctx.lineCap = 'round';

	// Batch by depth for fewer style changes
	for (let d = 0; d <= CONFIG.maxDepth; d++) {
		const t = d / CONFIG.maxDepth;
		const color = lerpColor(CONFIG.trunkColor, palette.tip, t);
		const alpha = clamp(0.6 + (1 - t) * 0.4, 0, 1);
		ctx.strokeStyle = `rgba(${color},${alpha.toFixed(3)})`;

		ctx.beginPath();
		for (let i = 0; i < branchCount; i++) {
			if (branchDepth[i] !== d) continue;
			const w = branchWidth[i] * growthScale;
			if (w < 0.3) continue;

			// Off-screen culling
			const minX = Math.min(branchX0[i], branchX1[i]);
			const maxX = Math.max(branchX0[i], branchX1[i]);
			const minY = Math.min(branchY0[i], branchY1[i]);
			const maxY = Math.max(branchY0[i], branchY1[i]);
			if (maxX < -20 || minX > width + 20 || maxY < -20 || minY > height + 20) continue;

			ctx.lineWidth = w;
			ctx.moveTo(branchX0[i], branchY0[i]);
			ctx.lineTo(branchX1[i], branchY1[i]);
		}
		ctx.stroke();
	}
}

function drawLeaves() {
	if (CONFIG.season === 'winter') return;
	const palette = SEASON_PALETTES[CONFIG.season] || SEASON_PALETTES.summer;
	const size = CONFIG.leafSize;

	ctx.beginPath();
	const colors = [palette.leaf, palette.leafAlt];

	for (let c = 0; c < 2; c++) {
		ctx.fillStyle = `rgba(${colors[c]},0.6)`;
		ctx.beginPath();
		for (let i = 0; i < leafCount; i++) {
			if (leafColor[i] !== c) continue;
			if (leafX[i] < -20 || leafX[i] > width + 20 || leafY[i] < -20 || leafY[i] > height + 20)
				continue;
			const a = leafAlpha[i];
			if (a < 0.02) continue;
			ctx.moveTo(leafX[i] + size, leafY[i]);
			ctx.arc(leafX[i], leafY[i], size * a, 0, Math.PI * 2);
		}
		ctx.fill();
	}
}

function drawGlow() {
	if (!glowCtx) return;
	const gw = glowCanvas.width;
	const gh = glowCanvas.height;
	glowCtx.clearRect(0, 0, gw, gh);
	glowCtx.drawImage(canvas, 0, 0, gw, gh);

	for (let p = 0; p < CONFIG.glowPasses; p++) {
		ctx.save();
		ctx.globalAlpha = CONFIG.glowAlpha;
		ctx.globalCompositeOperation = 'lighter';
		ctx.drawImage(glowCanvas, 0, 0, width, height);
		ctx.restore();
	}
}

/* ───────────────────── ANIMATION ───────────────────── */
function startAnimation() {
	lastTime = performance.now();
	growthFrame = 0;

	function render(now) {
		if (!ctx) return;
		const dt = Math.min((now - lastTime) / 1000, 0.05);
		lastTime = now;
		const time = now / 1000;

		if (growthFrame < CONFIG.growthDuration) growthFrame++;

		// Motion trail layer
		ctx.fillStyle = `rgba(0,0,0,${CONFIG.trailAlpha})`;
		ctx.fillRect(0, 0, width, height);

		// Update
		updateBranches(time, dt);
		updateLeaves(dt);

		// Draw layers
		drawBranches();
		drawLeaves();

		// Glow pass
		drawGlow();

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/* ───────────────────── HEARTBEAT ───────────────────── */
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

/* ───────────────────── MESSAGES ───────────────────── */
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initGlow();
			generateTree();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initGlow();
			generateTree();
			growthFrame = CONFIG.growthDuration; // skip growth on resize
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Galaxy Forge
 * Description: A spiral galaxy with thousands of orbiting stars. Mouse creates a
 *   gravitational well that warps star orbits, pulling tidal streams. Stars have
 *   color variation by distance, orbital trails, and a pulsing central core.
 *   Move the mouse to sculpt the galaxy in real-time.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Stars --
  starCount: 2200,                        // Total stars (500-5000)
  starMinSize: 0.5,                       // Smallest star radius (0.3-2)
  starMaxSize: 2.5,                       // Largest star radius (1.5-5)
  starGlow: true,                         // Soft glow on bright stars
  trailEnabled: true,                     // Stars leave brief orbital trails
  trailLength: 4,                         // Trail persistence (2-8)
  trailOpacity: 0.08,                     // Trail opacity (0.02-0.2)

  // -- Galaxy Structure --
  armCount: 3,                            // Number of spiral arms (2-6)
  armSpread: 0.35,                        // How tightly wound (0.1-1, lower=tighter)
  armWidth: 0.45,                         // Angular spread of each arm (0.1-0.8)
  rotationSpeed: 0.0018,                  // Base orbital speed (0.0005-0.005)

  // -- Core --
  coreRadius: 45,                         // Central bright region radius (20-80)
  coreColor: '#ffe0a0',                   // Core glow color
  corePulseSpeed: 0.8,                    // Core brightness pulse (0-3)

  // -- Dust & Nebula --
  dustLanes: true,                        // Dark bands between arms
  dustOpacity: 0.2,                       // Dust lane darkness (0.05-0.5)
  nebulaEnabled: true,                    // Colored nebula patches
  nebulaColors: ['#331155', '#113355', '#553311', '#115533'],

  // -- Mouse Gravity --
  mouseGravityStrength: 4,                // Pull force (0.5-15)
  mouseGravityRadius: 250,               // Influence radius in px (80-500)

  // -- Background --
  backgroundColor: '#030308',             // Deep space color
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let time = 0;
let stars = [];
let cx, cy;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }

function initStars() {
  cx = width / 2;
  cy = height / 2;
  stars = [];
  const maxR = Math.min(width, height) * 0.42;

  for (let i = 0; i < CONFIG.starCount; i++) {
    // Distribute in spiral arms with some scatter
    const arm = Math.floor(rand(0, CONFIG.armCount));
    const armAngle = (arm / CONFIG.armCount) * Math.PI * 2;
    const dist = Math.pow(Math.random(), 0.6) * maxR; // more stars near center
    const spiralAngle = armAngle + dist * CONFIG.armSpread * 0.03;
    const scatter = (Math.random() - 0.5) * CONFIG.armWidth * 2;
    const angle = spiralAngle + scatter;

    const x = cx + Math.cos(angle) * dist;
    const y = cy + Math.sin(angle) * dist;

    // Color by distance — blue-white near core, amber/red at edges
    const distNorm = dist / maxR;
    let r, g, b;
    if (distNorm < 0.3) {
      r = 200 + rand(30, 55); g = 210 + rand(20, 45); b = 240 + rand(10, 15);
    } else if (distNorm < 0.6) {
      r = 240 + rand(0, 15); g = 220 + rand(0, 30); b = 180 + rand(0, 50);
    } else {
      r = 220 + rand(0, 35); g = 160 + rand(0, 60); b = 100 + rand(0, 60);
    }

    stars.push({
      x, y,
      ox: x, oy: y, // original position for trail
      dist,
      angle,
      orbitSpeed: (1 / (dist + 20)) * CONFIG.rotationSpeed * 60 * rand(0.8, 1.2),
      size: rand(CONFIG.starMinSize, CONFIG.starMaxSize) * (1 - distNorm * 0.4),
      color: [Math.min(255, r), Math.min(255, g), Math.min(255, b)],
      brightness: rand(0.5, 1),
    });
  }
}

function startAnimation() {
  const coreRgb = hexRgb(CONFIG.coreColor);
  const bgRgb = hexRgb(CONFIG.backgroundColor);

  function render() {
    if (!ctx) return;
    time += 0.016;

    // -- Background with trail fade --
    if (CONFIG.trailEnabled) {
      ctx.fillStyle = `rgba(${bgRgb[0]},${bgRgb[1]},${bgRgb[2]},${CONFIG.trailOpacity})`;
      ctx.fillRect(0, 0, width, height);
    } else {
      ctx.fillStyle = CONFIG.backgroundColor;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Nebula clouds --
    if (CONFIG.nebulaEnabled) {
      for (let i = 0; i < CONFIG.nebulaColors.length; i++) {
        const nc = hexRgb(CONFIG.nebulaColors[i]);
        const na = 0.6 + i * 1.2;
        const nx = cx + Math.cos(na + time * 0.03) * 120;
        const ny = cy + Math.sin(na * 1.3 + time * 0.02) * 100;
        const ng = ctx.createRadialGradient(nx, ny, 0, nx, ny, 100);
        ng.addColorStop(0, `rgba(${nc[0]},${nc[1]},${nc[2]},0.02)`);
        ng.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = ng;
        ctx.fillRect(nx - 100, ny - 100, 200, 200);
      }
    }

    // -- Dust lanes --
    if (CONFIG.dustLanes) {
      const maxR = Math.min(width, height) * 0.42;
      for (let arm = 0; arm < CONFIG.armCount; arm++) {
        const baseAngle = (arm + 0.5) / CONFIG.armCount * Math.PI * 2;
        for (let d = 20; d < maxR; d += 15) {
          const angle = baseAngle + d * CONFIG.armSpread * 0.03 + time * CONFIG.rotationSpeed * 8;
          const dx = cx + Math.cos(angle) * d;
          const dy = cy + Math.sin(angle) * d;
          ctx.beginPath();
          ctx.arc(dx, dy, 12 + d * 0.04, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(0,0,0,${CONFIG.dustOpacity * 0.04})`;
          ctx.fill();
        }
      }
    }

    // -- Update and draw stars --
    const mActive = mouse.x >= 0 && mouse.y >= 0;
    const mgr = CONFIG.mouseGravityRadius;
    const mgs = CONFIG.mouseGravityStrength;

    for (const s of stars) {
      // Orbital rotation around center
      s.angle += s.orbitSpeed;
      s.x = cx + Math.cos(s.angle) * s.dist;
      s.y = cy + Math.sin(s.angle) * s.dist;

      // Mouse gravity pull
      if (mActive) {
        const dx = mouse.x - s.x;
        const dy = mouse.y - s.y;
        const d = Math.sqrt(dx * dx + dy * dy);
        if (d < mgr && d > 5) {
          const force = (1 - d / mgr) * mgs * 0.5;
          s.x += (dx / d) * force;
          s.y += (dy / d) * force;
        }
      }

      // Draw star
      const c = s.color;
      const alpha = s.brightness * (0.6 + Math.sin(time * 3 + s.angle * 5) * 0.1);
      ctx.beginPath();
      ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha})`;
      ctx.fill();

      // Star glow
      if (CONFIG.starGlow && s.size > 1.5) {
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size * 3, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha * 0.04})`;
        ctx.fill();
      }
    }

    // -- Core glow --
    const corePulse = 0.8 + Math.sin(time * CONFIG.corePulseSpeed * 3) * 0.2;
    for (let i = 3; i >= 0; i--) {
      const r = CONFIG.coreRadius * (0.3 + i * 0.6) * corePulse;
      const cg = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
      cg.addColorStop(0, `rgba(${coreRgb[0]},${coreRgb[1]},${coreRgb[2]},${0.08 / (i + 1)})`);
      cg.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = cg;
      ctx.beginPath();
      ctx.arc(cx, cy, r, 0, Math.PI * 2);
      ctx.fill();
    }
    // Bright core center
    ctx.beginPath();
    ctx.arc(cx, cy, 3, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(255,255,240,${0.5 * corePulse})`;
    ctx.fill();

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initStars();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initStars();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Glitch Grid
 * Description: A subtle grid overlay that occasionally glitches — random cells flash,
 *   scan lines appear and disappear, small sections shift position briefly.
 *   Restrained HUD aesthetic with intermittent interference.
 *   Mouse proximity increases glitch frequency nearby.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

const CELL_SIZE = 40;
let cols, rows;
let glitches = []; // active glitch effects
let scanLines = []; // horizontal scan line distortions
let shiftBlocks = []; // section shifts

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function init() {
	cols = Math.ceil(width / CELL_SIZE);
	rows = Math.ceil(height / CELL_SIZE);
	glitches = [];
	scanLines = [];
	shiftBlocks = [];
}

// Glitch types
function spawnCellFlash(nearMouse) {
	let col, row;
	if (nearMouse && mouse.x > 0) {
		// Spawn near mouse
		col = Math.floor(mouse.x / CELL_SIZE) + Math.floor((Math.random() - 0.5) * 6);
		row = Math.floor(mouse.y / CELL_SIZE) + Math.floor((Math.random() - 0.5) * 6);
	} else {
		col = Math.floor(Math.random() * cols);
		row = Math.floor(Math.random() * rows);
	}

	col = Math.max(0, Math.min(cols - 1, col));
	row = Math.max(0, Math.min(rows - 1, row));

	const hue = Math.random() < 0.5 ? 180 : 120; // cyan or green
	glitches.push({
		type: 'cell',
		col: col,
		row: row,
		life: 0.3 + Math.random() * 0.5, // seconds
		maxLife: 0.3 + Math.random() * 0.5,
		hue: hue,
		alpha: 0.05 + Math.random() * 0.1
	});
}

function spawnScanLine() {
	scanLines.push({
		y: Math.random() * height,
		speed: (1 + Math.random() * 3) * (Math.random() < 0.5 ? 1 : -1),
		width: 1 + Math.random() * 2,
		life: 0.5 + Math.random() * 1.5,
		alpha: 0.03 + Math.random() * 0.07
	});
}

function spawnShiftBlock(nearMouse) {
	let x, y;
	if (nearMouse && mouse.x > 0) {
		x = mouse.x + (Math.random() - 0.5) * 200;
		y = mouse.y + (Math.random() - 0.5) * 200;
	} else {
		x = Math.random() * width;
		y = Math.random() * height;
	}

	const blockW = CELL_SIZE * (1 + Math.floor(Math.random() * 4));
	const blockH = CELL_SIZE * (1 + Math.floor(Math.random() * 2));

	shiftBlocks.push({
		x: x,
		y: y,
		w: blockW,
		h: blockH,
		shiftX: (Math.random() - 0.5) * 8,
		shiftY: 0,
		life: 0.05 + Math.random() * 0.15, // very brief
		maxLife: 0.05 + Math.random() * 0.15,
		alpha: 0.04 + Math.random() * 0.06
	});
}

function startAnimation() {
	let lastTime = 0;
	let spawnAccum = 0;

	function render(time) {
		if (!ctx) return;
		const dt = lastTime ? (time - lastTime) / 1000 : 0.016;
		lastTime = time;

		ctx.clearRect(0, 0, width, height);

		// === Draw the base grid ===
		ctx.strokeStyle = 'rgba(100, 200, 180, 0.03)';
		ctx.lineWidth = 0.5;

		// Vertical lines
		for (let c = 0; c <= cols; c++) {
			const x = c * CELL_SIZE;
			ctx.beginPath();
			ctx.moveTo(x, 0);
			ctx.lineTo(x, height);
			ctx.stroke();
		}
		// Horizontal lines
		for (let r = 0; r <= rows; r++) {
			const y = r * CELL_SIZE;
			ctx.beginPath();
			ctx.moveTo(0, y);
			ctx.lineTo(width, y);
			ctx.stroke();
		}

		// === Mouse proximity — glow nearby grid intersections ===
		if (mouse.x > 0 && mouse.y > 0) {
			const mc = Math.floor(mouse.x / CELL_SIZE);
			const mr = Math.floor(mouse.y / CELL_SIZE);
			const range = 3;

			for (let dc = -range; dc <= range; dc++) {
				for (let dr = -range; dr <= range; dr++) {
					const c = mc + dc;
					const r = mr + dr;
					if (c < 0 || c > cols || r < 0 || r > rows) continue;

					const px = c * CELL_SIZE;
					const py = r * CELL_SIZE;
					const dx = px - mouse.x;
					const dy = py - mouse.y;
					const dist = Math.sqrt(dx * dx + dy * dy);
					const maxDist = range * CELL_SIZE;

					if (dist < maxDist) {
						const glow = (1 - dist / maxDist) * 0.12;
						ctx.beginPath();
						ctx.arc(px, py, 2, 0, Math.PI * 2);
						ctx.fillStyle = `rgba(0, 220, 180, ${glow})`;
						ctx.fill();
					}
				}
			}
		}

		// === Spawn glitches ===
		spawnAccum += dt;

		// Mouse proximity increases spawn rate
		const mouseOnScreen = mouse.x > 0 && mouse.x < width && mouse.y > 0 && mouse.y < height;
		const baseRate = 0.15; // seconds between spawns
		const mouseRate = mouseOnScreen ? 0.05 : baseRate;

		if (spawnAccum > mouseRate) {
			spawnAccum = 0;

			// Cell flashes
			if (Math.random() < 0.5) {
				spawnCellFlash(mouseOnScreen && Math.random() < 0.7);
			}

			// Scan lines (less frequent)
			if (Math.random() < 0.15) {
				spawnScanLine();
			}

			// Shift blocks (rare)
			if (Math.random() < 0.1) {
				spawnShiftBlock(mouseOnScreen && Math.random() < 0.6);
			}
		}

		// === Update and draw cell flashes ===
		for (let i = glitches.length - 1; i >= 0; i--) {
			const g = glitches[i];
			g.life -= dt;

			if (g.life <= 0) {
				glitches.splice(i, 1);
				continue;
			}

			const fadeIn = Math.min(1, (g.maxLife - g.life) / 0.05);
			const fadeOut = Math.min(1, g.life / 0.1);
			const fade = fadeIn * fadeOut;

			const x = g.col * CELL_SIZE;
			const y = g.row * CELL_SIZE;

			// Flickering effect
			const flicker = Math.random() < 0.3 ? 0 : 1;

			ctx.fillStyle = `rgba(0, ${g.hue === 180 ? '200, 220' : '220, 150'}, ${g.alpha * fade * flicker})`;
			ctx.fillRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);

			// Cell border highlight
			ctx.strokeStyle = `rgba(0, ${g.hue === 180 ? '220, 240' : '240, 180'}, ${g.alpha * fade * 1.5 * flicker})`;
			ctx.lineWidth = 0.5;
			ctx.strokeRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);
		}

		// === Update and draw scan lines ===
		for (let i = scanLines.length - 1; i >= 0; i--) {
			const s = scanLines[i];
			s.y += s.speed;
			s.life -= dt;

			if (s.life <= 0 || s.y < -10 || s.y > height + 10) {
				scanLines.splice(i, 1);
				continue;
			}

			// Draw the scan line
			ctx.fillStyle = `rgba(0, 200, 180, ${s.alpha})`;
			ctx.fillRect(0, s.y, width, s.width);

			// Slight chromatic aberration
			ctx.fillStyle = `rgba(200, 0, 100, ${s.alpha * 0.3})`;
			ctx.fillRect(0, s.y - 1, width, 0.5);
			ctx.fillStyle = `rgba(0, 100, 200, ${s.alpha * 0.3})`;
			ctx.fillRect(0, s.y + s.width, width, 0.5);
		}

		// === Update and draw shift blocks ===
		for (let i = shiftBlocks.length - 1; i >= 0; i--) {
			const b = shiftBlocks[i];
			b.life -= dt;

			if (b.life <= 0) {
				shiftBlocks.splice(i, 1);
				continue;
			}

			// Copy and shift a region (simulated with colored overlay)
			const fadeOut = b.life / b.maxLife;

			// Draw a slightly shifted duplicate overlay
			ctx.save();
			ctx.globalAlpha = b.alpha * fadeOut;
			ctx.fillStyle = 'rgba(0, 180, 160, 1)';
			ctx.fillRect(b.x + b.shiftX, b.y + b.shiftY, b.w, b.h);
			ctx.restore();

			// Draw corruption lines within the block
			const lineCount = 2 + Math.floor(Math.random() * 3);
			for (let l = 0; l < lineCount; l++) {
				const ly = b.y + Math.random() * b.h;
				ctx.fillStyle = `rgba(0, 255, 200, ${b.alpha * fadeOut * 0.5})`;
				ctx.fillRect(b.x, ly, b.w, 1);
			}
		}

		// === Occasional full-screen micro-glitch (very rare) ===
		if (Math.random() < 0.002) {
			ctx.fillStyle = 'rgba(0, 200, 180, 0.01)';
			ctx.fillRect(0, 0, width, height);
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Gravity Wells
 * Description: Multiple gravity wells pull orbiting particles into swirling
 *   paths. Particles trail behind them, transfer between wells when they
 *   gain enough velocity, and the mouse can act as an additional gravity source.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Wells --
  wellCount: 4,                           // Number of gravity wells (2-8 recommended)
  wellStrength: 800,                      // Gravitational pull constant (higher = stronger)
  wellColor: 'rgba(100, 180, 255, 0.8)',  // Color of well center glow
  wellGlowRadius: 60,                     // Radius of the well glow effect in px

  // -- Particles --
  particleCount: 300,                     // Total orbiting particles
  particleColor: 'rgba(0, 220, 255, 0.9)', // Base particle color
  particleSize: 2,                        // Particle radius in px

  // -- Trails --
  trailLength: 20,                        // Number of past positions stored (longer = longer tail)
  trailOpacity: 0.4,                      // Starting opacity of the trail (fades to 0)

  // -- Physics --
  orbitDamping: 0.998,                    // Velocity damping per frame (0.99-1.0, lower = more friction)
  escapeVelocityThreshold: 12,            // Speed above which particles can escape a well
  backgroundFadeRate: 0.08,               // Background fade alpha per frame (0-1, lower = longer trails)

  // -- Mouse Interaction --
  mouseWellEnabled: true,                 // Whether the mouse acts as a gravity well
  mouseWellStrength: 1200,                // Gravitational strength of the mouse well
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let wells = [];
let particles = [];

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function parseRGBA(str) {
  const m = str.match(/rgba?\(\s*([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)\s*(?:,\s*([\d.]+))?\)/);
  if (m) return { r: +m[1], g: +m[2], b: +m[3], a: m[4] !== undefined ? +m[4] : 1 };
  return { r: 0, g: 220, b: 255, a: 0.9 };
}

class Well {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.vx = (Math.random() - 0.5) * 0.3;
    this.vy = (Math.random() - 0.5) * 0.3;
  }

  update() {
    this.x += this.vx;
    this.y += this.vy;
    if (this.x < 80 || this.x > width - 80) this.vx *= -1;
    if (this.y < 80 || this.y > height - 80) this.vy *= -1;
  }

  draw(ctx) {
    const col = parseRGBA(CONFIG.wellColor);
    const grad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, CONFIG.wellGlowRadius);
    grad.addColorStop(0, `rgba(${col.r}, ${col.g}, ${col.b}, ${col.a})`);
    grad.addColorStop(0.4, `rgba(${col.r}, ${col.g}, ${col.b}, ${col.a * 0.3})`);
    grad.addColorStop(1, `rgba(${col.r}, ${col.g}, ${col.b}, 0)`);
    ctx.beginPath();
    ctx.arc(this.x, this.y, CONFIG.wellGlowRadius, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
  }
}

class GravParticle {
  constructor() {
    this.x = Math.random() * (width || 800);
    this.y = Math.random() * (height || 600);
    this.vx = (Math.random() - 0.5) * 4;
    this.vy = (Math.random() - 0.5) * 4;
    this.trail = [];
    this.hueOffset = Math.random() * 40 - 20;
  }

  update(allWells) {
    for (const well of allWells) {
      const dx = well.x - this.x;
      const dy = well.y - this.y;
      const distSq = dx * dx + dy * dy;
      const dist = Math.sqrt(distSq);
      if (dist < 5) continue;

      const strength = well.strength || CONFIG.wellStrength;
      const force = strength / (distSq + 500);
      this.vx += (dx / dist) * force;
      this.vy += (dy / dist) * force;
    }

    this.vx *= CONFIG.orbitDamping;
    this.vy *= CONFIG.orbitDamping;

    this.x += this.vx;
    this.y += this.vy;

    // Trail
    this.trail.push({ x: this.x, y: this.y });
    if (this.trail.length > CONFIG.trailLength) {
      this.trail.shift();
    }

    // Wrap around
    if (this.x < -50) this.x = width + 50;
    if (this.x > width + 50) this.x = -50;
    if (this.y < -50) this.y = height + 50;
    if (this.y > height + 50) this.y = -50;
  }

  draw(ctx, color) {
    // Draw trail
    if (this.trail.length > 1) {
      ctx.beginPath();
      ctx.moveTo(this.trail[0].x, this.trail[0].y);
      for (let i = 1; i < this.trail.length; i++) {
        ctx.lineTo(this.trail[i].x, this.trail[i].y);
      }
      ctx.strokeStyle = `rgba(${Math.min(255, color.r + this.hueOffset)}, ${color.g}, ${color.b}, ${CONFIG.trailOpacity})`;
      ctx.lineWidth = CONFIG.particleSize * 0.6;
      ctx.stroke();
    }

    // Draw particle
    ctx.beginPath();
    ctx.arc(this.x, this.y, CONFIG.particleSize, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${Math.min(255, color.r + this.hueOffset)}, ${color.g}, ${color.b}, ${color.a})`;
    ctx.fill();
  }
}

function initSimulation() {
  wells = [];
  particles = [];

  const margin = 120;
  for (let i = 0; i < CONFIG.wellCount; i++) {
    const x = margin + Math.random() * (width - margin * 2);
    const y = margin + Math.random() * (height - margin * 2);
    wells.push(new Well(x, y));
  }

  for (let i = 0; i < CONFIG.particleCount; i++) {
    const p = new GravParticle();
    p.x = Math.random() * width;
    p.y = Math.random() * height;
    // Give initial orbital velocity around nearest well
    let nearestWell = wells[0];
    let nearestDist = Infinity;
    for (const w of wells) {
      const d = Math.hypot(w.x - p.x, w.y - p.y);
      if (d < nearestDist) { nearestDist = d; nearestWell = w; }
    }
    const angle = Math.atan2(p.y - nearestWell.y, p.x - nearestWell.x) + Math.PI / 2;
    const speed = 1.5 + Math.random() * 2.5;
    p.vx = Math.cos(angle) * speed;
    p.vy = Math.sin(angle) * speed;
    particles.push(p);
  }
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initSimulation();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initSimulation();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function startAnimation() {
  const color = parseRGBA(CONFIG.particleColor);

  function render() {
    if (!ctx) return;

    // Fade background
    ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.backgroundFadeRate})`;
    ctx.fillRect(0, 0, width, height);

    // Build active wells list
    const activeWells = [...wells];
    if (CONFIG.mouseWellEnabled && mouse.x > -1000) {
      activeWells.push({
        x: mouse.x,
        y: mouse.y,
        strength: CONFIG.mouseWellStrength
      });
    }

    // Update and draw wells
    for (const well of wells) {
      well.update();
      well.draw(ctx);
    }

    // Mouse well glow
    if (CONFIG.mouseWellEnabled && mouse.x > -1000) {
      const col = parseRGBA(CONFIG.wellColor);
      const grad = ctx.createRadialGradient(mouse.x, mouse.y, 0, mouse.x, mouse.y, CONFIG.wellGlowRadius * 0.7);
      grad.addColorStop(0, `rgba(${Math.min(255, col.r + 50)}, ${Math.min(255, col.g + 50)}, ${col.b}, 0.6)`);
      grad.addColorStop(1, `rgba(${col.r}, ${col.g}, ${col.b}, 0)`);
      ctx.beginPath();
      ctx.arc(mouse.x, mouse.y, CONFIG.wellGlowRadius * 0.7, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
    }

    // Update and draw particles
    for (const p of particles) {
      p.update(activeWells);
      p.draw(ctx, color);
    }

    requestAnimationFrame(render);
  }

  requestAnimationFrame(render);
}

/**
 * Title: Hexagonal Pulse
 * Description: A grid of hexagons that pulse with a ripple effect emanating from
 * the mouse position. Each hex glows with a subtle accent color that fades with
 * distance from the ripple origin. Clean, geometric feel.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

// Hex grid config
const HEX_RADIUS = 28;
const HEX_GAP = 4;
const RIPPLE_SPEED = 180; // pixels per second
const RIPPLE_LIFETIME = 3.0; // seconds
const MAX_RIPPLES = 5;

let hexagons = [];
let ripples = [];
let lastTime = 0;
let lastClickTime = 0;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			buildGrid();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			buildGrid();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			// Spawn ripples on movement (throttled)
			const now = performance.now() / 1000;
			if (now - lastClickTime > 0.6) {
				lastClickTime = now;
				ripples.push({ x: mouse.x, y: mouse.y, time: now, radius: 0 });
				if (ripples.length > MAX_RIPPLES) ripples.shift();
			}
			break;
	}
};

function buildGrid() {
	hexagons = [];
	const hexW = (HEX_RADIUS + HEX_GAP) * Math.sqrt(3);
	const hexH = (HEX_RADIUS + HEX_GAP) * 1.5;
	const cols = Math.ceil(width / hexW) + 2;
	const rows = Math.ceil(height / hexH) + 2;

	for (let row = -1; row < rows; row++) {
		for (let col = -1; col < cols; col++) {
			const offsetX = (row % 2) * (hexW / 2);
			hexagons.push({
				x: col * hexW + offsetX,
				y: row * hexH,
				pulse: 0
			});
		}
	}
}

function hexPath(cx, cy, r) {
	ctx.beginPath();
	for (let i = 0; i < 6; i++) {
		const angle = (Math.PI / 3) * i - Math.PI / 6;
		const px = cx + r * Math.cos(angle);
		const py = cy + r * Math.sin(angle);
		if (i === 0) ctx.moveTo(px, py);
		else ctx.lineTo(px, py);
	}
	ctx.closePath();
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;

		ctx.clearRect(0, 0, width, height);

		// Update ripples
		for (let i = ripples.length - 1; i >= 0; i--) {
			const r = ripples[i];
			r.radius += RIPPLE_SPEED * dt;
			if (now - r.time > RIPPLE_LIFETIME) {
				ripples.splice(i, 1);
			}
		}

		// Calculate mouse distance influence for ambient glow
		const mouseInfluenceRadius = 250;

		for (let i = 0; i < hexagons.length; i++) {
			const hex = hexagons[i];
			let pulseIntensity = 0;

			// Ripple influence
			for (let j = 0; j < ripples.length; j++) {
				const rip = ripples[j];
				const dist = Math.hypot(hex.x - rip.x, hex.y - rip.y);
				const rippleAge = now - rip.time;
				const rippleFront = rip.radius;
				const ringWidth = 80;
				const distFromFront = Math.abs(dist - rippleFront);

				if (distFromFront < ringWidth) {
					const ringFade = 1 - distFromFront / ringWidth;
					const ageFade = 1 - rippleAge / RIPPLE_LIFETIME;
					pulseIntensity = Math.max(pulseIntensity, ringFade * ageFade);
				}
			}

			// Ambient mouse proximity glow
			const mouseDist = Math.hypot(hex.x - mouse.x, hex.y - mouse.y);
			if (mouseDist < mouseInfluenceRadius) {
				const proximity = 1 - mouseDist / mouseInfluenceRadius;
				pulseIntensity = Math.max(pulseIntensity, proximity * 0.3);
			}

			// Smooth the pulse
			hex.pulse += (pulseIntensity - hex.pulse) * 0.15;

			// Draw hexagon
			const scale = 1 + hex.pulse * 0.12;
			const drawRadius = HEX_RADIUS * scale;

			// Base hex outline
			const baseAlpha = 0.06 + hex.pulse * 0.25;
			hexPath(hex.x, hex.y, drawRadius);
			ctx.strokeStyle = `rgba(255, 255, 255, ${baseAlpha})`;
			ctx.lineWidth = 1;
			ctx.stroke();

			// Pulse fill with accent color (subtle cyan-blue)
			if (hex.pulse > 0.01) {
				hexPath(hex.x, hex.y, drawRadius);
				const fillAlpha = hex.pulse * 0.1;
				ctx.fillStyle = `rgba(100, 180, 255, ${fillAlpha})`;
				ctx.fill();

				// Inner glow ring
				hexPath(hex.x, hex.y, drawRadius * 0.7);
				ctx.strokeStyle = `rgba(140, 200, 255, ${hex.pulse * 0.15})`;
				ctx.lineWidth = 0.5;
				ctx.stroke();
			}
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Hyperspace Warp Drive
 * Description: A 3D starfield with speed lines. Move the mouse to steer the warp tunnel!
 */

const CONFIG = {
    starCount: 600,
    baseSpeed: 2.5,       // Forward speed
    fov: 300,             // Field of view (stretches the Z axis)
    starColor: '255, 255, 255', // RGB components (must be comma separated for opacity logic)
    tailLength: 1.5       // Multiplier for the speed line trails
};

let canvas, ctx, width, height;
let stars =[];
let mouse = { x: 0, y: 0 };
let centerX, centerY;

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            mouse = { x: width / 2, y: height / 2 };
            startAnimation();
            break;
        case 'resize': resize(e.data.width, e.data.height); break;
        case 'mousemove': mouse.x = e.data.x; mouse.y = e.data.y; break;
    }
};

function resize(w, h) {
    width = w; height = h;
    centerX = width / 2; centerY = height / 2;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initStars();
}

class Star {
    constructor() {
        this.reset();
        this.z = Math.random() * width; 
    }
    reset() {
        this.x = (Math.random() - 0.5) * width * 2;
        this.y = (Math.random() - 0.5) * height * 2;
        this.z = width; 
        this.pz = this.z;
    }
    update() {
        this.pz = this.z; 
        this.z -= CONFIG.baseSpeed;
        if (this.z < 1) this.reset();
    }
    draw() {
        let targetX = centerX + (mouse.x - centerX) * 0.3;
        let targetY = centerY + (mouse.y - centerY) * 0.3;

        let px = (this.x / this.pz) * CONFIG.fov + targetX;
        let py = (this.y / this.pz) * CONFIG.fov + targetY;
        let nx = (this.x / this.z) * CONFIG.fov + targetX;
        let ny = (this.y / this.z) * CONFIG.fov + targetY;

        let opacity = 1 - (this.z / width);

        ctx.beginPath();
        ctx.moveTo(px, py);

        let tailX = nx + (nx - px) * CONFIG.tailLength;
        let tailY = ny + (ny - py) * CONFIG.tailLength;
        ctx.lineTo(tailX, tailY);

        // Respecting the starColor from config while applying dynamic opacity
        ctx.strokeStyle = `rgba(${CONFIG.starColor}, ${opacity})`;
        ctx.lineWidth = (1 - (this.z / width)) * 2.5; 
        ctx.stroke();
    }
}

function initStars() {
    stars =[];
    for (let i = 0; i < CONFIG.starCount; i++) {
        stars.push(new Star());
    }
}

function startAnimation() {
    function render() {
        if (!ctx) return;

        // ClearRect is the gold standard for transparency. 
        // It ensures the Chat Background Image set in Open WebUI is fully visible.
        ctx.clearRect(0, 0, width, height);

        for (let i = 0; i < stars.length; i++) {
            stars[i].update();
            stars[i].draw();
        }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/*
  HypnoSpiral – Web-Worker edition
  Name: HypnoSpiral
  Description: A slowly fading, hypnotic spiral made of concentric coloured rings that rotate and drift outward.
  All behaviour is controlled by the CONFIG block below – tweak only there.
*/

// =========================================================================
// CONFIG ––––––––––––––––––––––––––––––––––––––––––––––––––––––––––––––––
const CONFIG = {
  TRAIL_ALPHA: 0.04,      // Controls fade speed to transparency (0.01 - 0.1)
  RING_SPACING: 4,        // px between rings
  RING_THICKNESS: 15,     // divisor for ring radius → stroke thickness
  ROTATION_SPEED: 0.02,   // rad/frame
  HUE_SHIFT: 2,           // hue += HUE_SHIFT per frame
  HUE_RANGE: 360,        // 360 = full spectrum
  SATURATION: '90%',       // CSS saturation string
  LIGHTNESS: '60%',        // CSS lightness string
};
// =========================================================================

let c, ctx, w, h, t = 0, frames = 0;

self.onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;
    animate();
  }
  if (e.data.type === 'resize') {
    w = c.width = e.data.width;
    h = c.height = e.data.height;
  }
};

function animate() {
  // 1. Erase previous frame into transparency instead of layering black paint
  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.TRAIL_ALPHA})`;
  ctx.fillRect(0, 0, w, h);

  // 2. Set back to normal drawing mode
  ctx.globalCompositeOperation = 'source-over';

  const cx = w / 2;
  const cy = h / 2;
  const rMax = Math.hypot(cx, cy);

  for (let r = 1; r < rMax; r += CONFIG.RING_SPACING) {
    const a = r * 0.04 + t;
    const x = cx + Math.cos(a) * r;
    const y = cy + Math.sin(a) * r;
    ctx.strokeStyle = `hsl(${(frames * CONFIG.HUE_SHIFT + r / 4) % CONFIG.HUE_RANGE},${CONFIG.SATURATION},${CONFIG.LIGHTNESS})`;
    ctx.beginPath();
    ctx.arc(x, y, r / CONFIG.RING_THICKNESS, 0, Math.PI * 2);
    ctx.stroke();
  }

  t += CONFIG.ROTATION_SPEED;
  frames++;
  requestAnimationFrame(animate);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Ice Crystals
 * Description: Hexagonal crystal growth with 6-fold symmetry, prismatic highlights, and mouse-warmth melting.
 */
const CONFIG = {
	maxCrystals: 8,
	growthSpeed: 0.8,
	branchProb: 0.3,
	branchAngle: Math.PI / 3,
	maxDepth: 4,
	symmetry: 6,
	color: 'rgba(180,220,255,',
	prismIntensity: 0.6,
	meltRadius: 120,
	meltSpeed: 0.02,
	regrowDelay: 90,
	edgeFrost: 40,
	seedInterval: 200
};
let canvas,
	ctx,
	W,
	H,
	mouse = { x: -5e3, y: -5e3 },
	crystals = [],
	time = 0;
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1e3);
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			startAnim();
			break;
		case 'resize':
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			crystals = [];
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};
class Crystal {
	constructor(x, y) {
		this.x = x;
		this.y = y;
		this.segs = [];
		this.queue = [{ x, y, angle: 0, depth: 0, len: 0, maxLen: 20 + Math.random() * 30 }];
		for (let i = 1; i < CONFIG.symmetry; i++)
			this.queue.push({
				x,
				y,
				angle: ((Math.PI * 2) / CONFIG.symmetry) * i,
				depth: 0,
				len: 0,
				maxLen: 20 + Math.random() * 30
			});
		this.melted = 0;
		this.meltTimer = 0;
	}
	grow(dt) {
		if (this.melted > 0) {
			this.meltTimer++;
			if (this.meltTimer > CONFIG.regrowDelay) this.melted = Math.max(0, this.melted - 0.01 * dt);
			return;
		}
		let newQ = [];
		for (let q of this.queue) {
			if (q.len < q.maxLen) {
				q.len += CONFIG.growthSpeed * dt;
				let ex = q.x + Math.cos(q.angle) * q.len,
					ey = q.y + Math.sin(q.angle) * q.len;
				this.segs.push({
					x1: q.x,
					y1: q.y,
					x2: ex,
					y2: ey,
					d: q.depth,
					hue: ((q.angle * 180) / Math.PI + time * 0.5) % 360
				});
				if (q.len >= q.maxLen && q.depth < CONFIG.maxDepth && Math.random() < CONFIG.branchProb) {
					let a1 = q.angle + CONFIG.branchAngle * (0.8 + Math.random() * 0.4),
						a2 = q.angle - CONFIG.branchAngle * (0.8 + Math.random() * 0.4);
					let ml = q.maxLen * 0.65;
					newQ.push({ x: ex, y: ey, angle: a1, depth: q.depth + 1, len: 0, maxLen: ml });
					newQ.push({ x: ex, y: ey, angle: a2, depth: q.depth + 1, len: 0, maxLen: ml });
				} else if (q.len < q.maxLen) {
					newQ.push(q);
				}
			}
		}
		this.queue = newQ;
	}
	draw() {
		let s = 1 - this.melted;
		for (let seg of this.segs) {
			let a = Math.max(0.05, (0.6 - seg.d * 0.1) * s);
			ctx.strokeStyle =
				CONFIG.prismIntensity > 0
					? `hsla(${seg.hue},70%,80%,${a * CONFIG.prismIntensity})`
					: CONFIG.color + a + ')';
			ctx.lineWidth = Math.max(0.5, (3 - seg.d * 0.5) * s);
			ctx.beginPath();
			ctx.moveTo(seg.x1, seg.y1);
			ctx.lineTo(seg.x2, seg.y2);
			ctx.stroke();
		}
	}
	melt(amt) {
		this.melted = Math.min(1, this.melted + amt);
		this.meltTimer = 0;
	}
}
function drawFrost() {
	ctx.globalAlpha = 0.08;
	let g = ctx.createLinearGradient(0, 0, CONFIG.edgeFrost, 0);
	g.addColorStop(0, 'rgba(200,230,255,0.4)');
	g.addColorStop(1, 'transparent');
	ctx.fillStyle = g;
	ctx.fillRect(0, 0, CONFIG.edgeFrost, H);
	let g2 = ctx.createLinearGradient(W, 0, W - CONFIG.edgeFrost, 0);
	g2.addColorStop(0, 'rgba(200,230,255,0.4)');
	g2.addColorStop(1, 'transparent');
	ctx.fillStyle = g2;
	ctx.fillRect(W - CONFIG.edgeFrost, 0, CONFIG.edgeFrost, H);
	let g3 = ctx.createLinearGradient(0, 0, 0, CONFIG.edgeFrost);
	g3.addColorStop(0, 'rgba(200,230,255,0.4)');
	g3.addColorStop(1, 'transparent');
	ctx.fillStyle = g3;
	ctx.fillRect(0, 0, W, CONFIG.edgeFrost);
	ctx.globalAlpha = 1;
}
function startAnim() {
	let last = performance.now();
	function render(now) {
		if (!ctx) return;
		let dt = Math.min((now - last) / 16.67, 3);
		last = now;
		time++;
		ctx.clearRect(0, 0, W, H);
		if (time % CONFIG.seedInterval === 0 && crystals.length < CONFIG.maxCrystals) {
			crystals.push(new Crystal(Math.random() * W, Math.random() * H));
		}
		for (let c of crystals) {
			let dx = c.x - mouse.x,
				dy = c.y - mouse.y,
				d = Math.sqrt(dx * dx + dy * dy);
			if (d < CONFIG.meltRadius) c.melt(CONFIG.meltSpeed * dt * (1 - d / CONFIG.meltRadius));
			c.grow(dt);
			c.draw();
		}
		drawFrost();
		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Ink Bloom
 * Description: Ink-drop-like blooms that slowly expand and diffuse at random
 *   locations, fading out as they grow. Deep, rich colors (indigo, crimson,
 *   emerald) with low opacity. Mouse position influences where new blooms appear.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let blooms = [];
let time = 0;
let lastBloomTime = 0;

const MAX_BLOOMS = 25;
const BLOOM_INTERVAL = 80; // frames between new blooms
const MOUSE_BLOOM_CHANCE = 0.4; // chance a bloom spawns near mouse

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Deep, rich color palette
const COLORS = [
	{ r: 40, g: 20, b: 120 }, // deep indigo
	{ r: 150, g: 15, b: 30 }, // crimson
	{ r: 10, g: 100, b: 60 }, // emerald
	{ r: 80, g: 10, b: 110 }, // dark violet
	{ r: 20, g: 60, b: 120 }, // navy blue
	{ r: 120, g: 30, b: 80 }, // plum
	{ r: 10, g: 80, b: 90 } // teal
];

class Bloom {
	constructor(x, y) {
		this.x = x;
		this.y = y;
		this.radius = 2;
		this.maxRadius = 80 + Math.random() * 160;
		this.growthRate = 0.3 + Math.random() * 0.5;
		this.color = COLORS[Math.floor(Math.random() * COLORS.length)];
		this.alpha = 0.08 + Math.random() * 0.05;
		this.maxAlpha = this.alpha;
		this.alive = true;
		this.age = 0;
		this.rotation = Math.random() * Math.PI * 2;
		this.rotationSpeed = (Math.random() - 0.5) * 0.002;
		// Slight organic drift
		this.driftX = (Math.random() - 0.5) * 0.15;
		this.driftY = (Math.random() - 0.5) * 0.15;
		// Number of tendrils for the ink bloom shape
		this.tendrils = 5 + Math.floor(Math.random() * 4);
		this.tendrilPhases = [];
		this.tendrilAmps = [];
		for (let i = 0; i < this.tendrils; i++) {
			this.tendrilPhases.push(Math.random() * Math.PI * 2);
			this.tendrilAmps.push(0.15 + Math.random() * 0.25);
		}
	}

	update() {
		this.age++;
		this.radius += this.growthRate * (1 - this.radius / this.maxRadius);
		this.rotation += this.rotationSpeed;
		this.x += this.driftX;
		this.y += this.driftY;

		// Fade as bloom approaches max size
		const progress = this.radius / this.maxRadius;
		if (progress > 0.5) {
			this.alpha = this.maxAlpha * (1 - (progress - 0.5) * 2);
		}

		if (this.alpha <= 0.001 || this.radius >= this.maxRadius * 0.98) {
			this.alive = false;
		}
	}

	draw() {
		const { r, g, b } = this.color;

		ctx.save();
		ctx.translate(this.x, this.y);
		ctx.rotate(this.rotation);

		// Draw multiple concentric bloom layers for depth
		for (let layer = 0; layer < 4; layer++) {
			const layerScale = 0.4 + layer * 0.2;
			const layerAlpha = this.alpha * (1 - layer * 0.2);
			const rad = this.radius * layerScale;

			if (layerAlpha <= 0) continue;

			// Organic ink shape using overlapping radial gradients with offset
			const offsetX = Math.sin(this.age * 0.02 + layer) * rad * 0.1;
			const offsetY = Math.cos(this.age * 0.02 + layer * 1.5) * rad * 0.1;

			const gradient = ctx.createRadialGradient(offsetX, offsetY, 0, offsetX, offsetY, rad);
			gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${layerAlpha})`);
			gradient.addColorStop(0.3, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.7})`);
			gradient.addColorStop(0.6, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.3})`);
			gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			// Draw an organic, ink-like shape
			ctx.beginPath();
			const steps = 60;
			for (let i = 0; i <= steps; i++) {
				const angle = (i / steps) * Math.PI * 2;
				let r2 = rad;
				// Add tendril distortion
				for (let t = 0; t < this.tendrils; t++) {
					r2 +=
						Math.sin(angle * (t + 2) + this.tendrilPhases[t] + this.age * 0.008) *
						rad *
						this.tendrilAmps[t] *
						layerScale;
				}
				const px = Math.cos(angle) * r2;
				const py = Math.sin(angle) * r2;
				if (i === 0) {
					ctx.moveTo(px, py);
				} else {
					ctx.lineTo(px, py);
				}
			}
			ctx.closePath();
			ctx.fillStyle = gradient;
			ctx.fill();
		}

		ctx.restore();
	}
}

function spawnBloom() {
	let x, y;
	const nearMouse = mouse.x > 0 && mouse.y > 0 && Math.random() < MOUSE_BLOOM_CHANCE;

	if (nearMouse) {
		// Spawn near mouse with some scatter
		x = mouse.x + (Math.random() - 0.5) * 200;
		y = mouse.y + (Math.random() - 0.5) * 200;
	} else {
		x = Math.random() * width;
		y = Math.random() * height;
	}

	blooms.push(new Bloom(x, y));
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			blooms = [];
			// Seed initial blooms
			for (let i = 0; i < 5; i++) {
				spawnBloom();
			}
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;

		// Slow fade for trailing ink effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.015)';
		ctx.fillRect(0, 0, width, height);

		time++;

		// Spawn new blooms periodically
		if (time - lastBloomTime > BLOOM_INTERVAL && blooms.length < MAX_BLOOMS) {
			spawnBloom();
			lastBloomTime = time;
		}

		// Update and draw blooms
		for (const bloom of blooms) {
			bloom.update();
			bloom.draw();
		}

		// Remove dead blooms
		blooms = blooms.filter((b) => b.alive);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Isometric Terrain
 * Description: An isometric grid of diamond-shaped tiles that undulate like rolling
 * hills using sine waves. Height is represented by shade/opacity. Mouse creates a
 * wave disturbance. Uses a subtle monochrome palette.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let lastTime = 0;
let cols, rows;

const TILE_WIDTH = 40;
const TILE_HEIGHT = 20;
const WAVE_AMPLITUDE = 12;
const WAVE_FREQUENCY = 0.08;
const WAVE_SPEED = 0.8;
const MOUSE_WAVE_RADIUS = 250;
const MOUSE_WAVE_AMP = 18;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			recalcGrid();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			recalcGrid();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function recalcGrid() {
	// Extra tiles beyond screen edges to prevent pop-in
	cols = Math.ceil(width / (TILE_WIDTH / 2)) + 4;
	rows = Math.ceil(height / (TILE_HEIGHT / 2)) + 8;
}

/**
 * Convert grid coordinates to isometric screen coordinates.
 * The grid origin is offset so tiles fill the screen.
 */
function gridToIso(gx, gy) {
	const halfW = TILE_WIDTH / 2;
	const halfH = TILE_HEIGHT / 2;
	return {
		x: (gx - gy) * halfW + width / 2,
		y: (gx + gy) * halfH - (rows * halfH) / 2 + height / 2
	};
}

/**
 * Calculate the height offset for a tile at grid position (gx, gy).
 * Combines multiple sine waves for organic terrain, plus mouse disturbance.
 */
function getHeight(gx, gy) {
	// Layered sine waves for natural undulation
	let h = 0;
	h += Math.sin(gx * WAVE_FREQUENCY + time * WAVE_SPEED) * WAVE_AMPLITUDE;
	h += Math.sin(gy * WAVE_FREQUENCY * 1.3 + time * WAVE_SPEED * 0.7) * WAVE_AMPLITUDE * 0.6;
	h += Math.sin((gx + gy) * WAVE_FREQUENCY * 0.5 + time * WAVE_SPEED * 1.2) * WAVE_AMPLITUDE * 0.4;

	// Mouse wave disturbance
	const iso = gridToIso(gx, gy);
	const mouseDist = Math.hypot(iso.x - mouse.x, iso.y - mouse.y);
	if (mouseDist < MOUSE_WAVE_RADIUS) {
		const influence = 1 - mouseDist / MOUSE_WAVE_RADIUS;
		const mouseWave = Math.sin(mouseDist * 0.04 - time * 3) * influence;
		h += mouseWave * MOUSE_WAVE_AMP;
	}

	return h;
}

/** Draw an isometric diamond tile */
function drawTile(cx, cy, heightOffset, brightness) {
	const halfW = TILE_WIDTH / 2;
	const halfH = TILE_HEIGHT / 2;
	const y = cy - heightOffset;

	// Top face of the tile
	ctx.beginPath();
	ctx.moveTo(cx, y - halfH); // top
	ctx.lineTo(cx + halfW, y); // right
	ctx.lineTo(cx, y + halfH); // bottom
	ctx.lineTo(cx - halfW, y); // left
	ctx.closePath();

	// Fill with height-based brightness
	const gray = Math.floor(180 + brightness * 60);
	const alpha = 0.03 + brightness * 0.06;
	ctx.fillStyle = `rgba(${gray}, ${gray}, ${Math.floor(gray * 1.05)}, ${alpha})`;
	ctx.fill();

	// Stroke
	const strokeAlpha = 0.04 + brightness * 0.05;
	ctx.strokeStyle = `rgba(200, 205, 215, ${strokeAlpha})`;
	ctx.lineWidth = 0.6;
	ctx.stroke();
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;
		time += dt;

		ctx.clearRect(0, 0, width, height);

		// Track min/max height for normalization
		let minH = Infinity;
		let maxH = -Infinity;

		// Pre-compute heights
		const heights = [];
		for (let gy = 0; gy < rows; gy++) {
			heights[gy] = [];
			for (let gx = 0; gx < cols; gx++) {
				const h = getHeight(gx - cols / 2, gy - rows / 2);
				heights[gy][gx] = h;
				if (h < minH) minH = h;
				if (h > maxH) maxH = h;
			}
		}

		const heightRange = maxH - minH || 1;

		// Draw tiles back to front (painter's algorithm via row order)
		for (let gy = 0; gy < rows; gy++) {
			for (let gx = 0; gx < cols; gx++) {
				const adjustedGx = gx - cols / 2;
				const adjustedGy = gy - rows / 2;
				const iso = gridToIso(adjustedGx, adjustedGy);
				const h = heights[gy][gx];

				// Normalize brightness 0-1
				const brightness = (h - minH) / heightRange;

				// Only draw tiles that are potentially visible
				if (
					iso.x > -TILE_WIDTH &&
					iso.x < width + TILE_WIDTH &&
					iso.y - h > -TILE_HEIGHT * 3 &&
					iso.y - h < height + TILE_HEIGHT * 3
				) {
					drawTile(iso.x, iso.y, h, brightness);
				}
			}
		}

		// Subtle mouse indicator glow
		if (mouse.x > 0 && mouse.y > 0) {
			const gradient = ctx.createRadialGradient(mouse.x, mouse.y, 0, mouse.x, mouse.y, 100);
			gradient.addColorStop(0, 'rgba(200, 210, 230, 0.03)');
			gradient.addColorStop(1, 'rgba(200, 210, 230, 0)');
			ctx.fillStyle = gradient;
			ctx.fillRect(mouse.x - 100, mouse.y - 100, 200, 200);
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

// ---------- CONFIGURABLE VARIABLES ----------
const FPS            = 60;          // target frames per second (approx)
const ROTATION_SPEED = 0.01;        // radians per frame
const WEDGES         = 12;          // number of radial wedges
const WAVE_SPEED     = 2;           // speed of the scale “wobble”
const WAVE_AMP       = 0.3;         // amplitude of the scale wobble (0–1)
const HUE_BASE       = 30;          // hue step per wedge
const HUE_SPEED      = 180;         // hue shift per second
const SATURATION     = 100;         // HSL saturation %
const LIGHTNESS      = 55;          // HSL lightness %
const NOISE_MIN      = 0.03;        // minimum overlay opacity
const NOISE_RANGE    = 0.02;        // additional overlay range
// ------------------------------------------

let c, ctx, w, h, angle = 0;

self.onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;
    loop();
  }
};

function loop() {
  angle += ROTATION_SPEED;

  // Clear to transparency every frame
  ctx.clearRect(0, 0, w, h);

  // draw radial wedges
  for (let i = 0; i < WEDGES; i++) {
    ctx.save();
    ctx.translate(w / 2, h / 2);
    ctx.rotate((i * 2 * Math.PI) / WEDGES + angle);
    ctx.scale(
      1 + WAVE_AMP * Math.sin(WAVE_SPEED * angle + i),
      1 + WAVE_AMP * Math.cos(WAVE_SPEED * angle + i)
    );
    ctx.beginPath();
    ctx.moveTo(0, 0);
    ctx.arc(0, 0, w, 0, Math.PI / WEDGES);
    ctx.closePath();
    ctx.fillStyle = `hsl(${(i * HUE_BASE + angle * HUE_SPEED) % 360},${SATURATION}%,${LIGHTNESS}%)`;
    ctx.fill();
    ctx.restore();
  }

  // noisy overlay - using source-atop to ensure the noise only affects 
  // the wedges and does not 'fog' the transparent chat background gap
  ctx.globalCompositeOperation = 'source-atop';
  ctx.fillStyle = `rgba(255,255,255,${NOISE_MIN + NOISE_RANGE * Math.abs(Math.sin(angle))})`;
  ctx.fillRect(0, 0, w, h);
  ctx.globalCompositeOperation = 'source-over';

  requestAnimationFrame(loop);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Kaleidoscope
 * Description: Mesmerizing kaleidoscope pattern with mirrored segments and
 *   interactive mouse-driven seed point control.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Symmetry --
  segmentCount: 8,                 // Mirror segments (4, 6, 8, 12)
  rotationSpeed: 0.003,            // Rotation speed in radians/frame (0.001-0.02)
  reflectionEnabled: true,         // Enable reflection within segments

  // -- Source Pattern --
  sourcePattern: 'mixed',          // Pattern type: 'circles', 'lines', 'mixed'
  patternElementCount: 30,         // Number of pattern elements per segment (10-80)
  patternSpeed: 0.008,             // Element animation speed (0.001-0.05)
  elementSizeRange: [4, 28],       // Min/max element size in px
  lineWidth: 1.5,                  // Stroke width for line elements (0.5-4)

  // -- Colors --
  colorPalette: [                  // Colors cycled across elements
    '#ff006e', '#fb5607', '#ffbe0b',
    '#8338ec', '#3a86ff', '#06d6a0',
    '#118ab2', '#ef476f'
  ],
  backgroundColor: 'rgba(0,0,0,0.08)', // Trail fade color (lower alpha = longer trails)

  // -- Geometry --
  centerRadius: 30,                // Blank zone at center in px (0-100)
  outerFade: 0.85,                 // Fade start as fraction of radius (0.5-1.0)

  // -- Mouse Interaction --
  // Mouse position shifts the pattern seed point for the source drawing
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let elements = [];
let cx, cy, maxR;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initElements() {
  cx = width / 2;
  cy = height / 2;
  maxR = Math.min(cx, cy);
  elements = [];
  for (let i = 0; i < CONFIG.patternElementCount; i++) {
    elements.push(createRandomElement(i));
  }
}

function createRandomElement(index) {
  const types = CONFIG.sourcePattern === 'mixed'
    ? ['circle', 'line']
    : [CONFIG.sourcePattern === 'circles' ? 'circle' : 'line'];
  const type = types[index % types.length];
  const colorIdx = index % CONFIG.colorPalette.length;
  const [minS, maxS] = CONFIG.elementSizeRange;
  return {
    type,
    angle: Math.random() * Math.PI * 2,
    radius: CONFIG.centerRadius + Math.random() * (maxR - CONFIG.centerRadius) * 0.8,
    size: minS + Math.random() * (maxS - minS),
    speed: (0.5 + Math.random()) * CONFIG.patternSpeed,
    radiusSpeed: (Math.random() - 0.5) * CONFIG.patternSpeed * 0.5,
    phase: Math.random() * Math.PI * 2,
    color: CONFIG.colorPalette[colorIdx],
    opacity: 0.4 + Math.random() * 0.6,
  };
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initElements();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initElements();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function parseColor(hex, alpha) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `rgba(${r},${g},${b},${alpha})`;
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 1;

    // Trail fade
    ctx.fillStyle = CONFIG.backgroundColor;
    ctx.fillRect(0, 0, width, height);

    const segments = CONFIG.segmentCount;
    const sliceAngle = (Math.PI * 2) / segments;
    const rotation = time * CONFIG.rotationSpeed;

    // Mouse-driven seed offset
    let seedX = 0, seedY = 0;
    if (mouse.x > 0 && mouse.y > 0) {
      seedX = (mouse.x - cx) * 0.002;
      seedY = (mouse.y - cy) * 0.002;
    }

    // Update elements
    for (const el of elements) {
      el.angle += el.speed + seedX * 0.05;
      el.radius += el.radiusSpeed;
      el.phase += CONFIG.patternSpeed;

      // Bounce radius
      if (el.radius < CONFIG.centerRadius || el.radius > maxR * 0.85) {
        el.radiusSpeed *= -1;
        el.radius = Math.max(CONFIG.centerRadius, Math.min(maxR * 0.85, el.radius));
      }
    }

    ctx.save();
    ctx.translate(cx, cy);

    for (let s = 0; s < segments; s++) {
      ctx.save();
      ctx.rotate(rotation + s * sliceAngle);

      // Clip to segment
      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.arc(0, 0, maxR, 0, sliceAngle);
      ctx.closePath();
      ctx.clip();

      // Draw elements in this segment
      for (const el of elements) {
        const a = el.angle + seedY * 0.1;
        const px = Math.cos(a) * el.radius;
        const py = Math.sin(a) * el.radius;

        // Fade near edges
        const distRatio = el.radius / maxR;
        let fade = 1;
        if (distRatio > CONFIG.outerFade) {
          fade = 1 - (distRatio - CONFIG.outerFade) / (1 - CONFIG.outerFade);
        }

        const alpha = el.opacity * fade;
        if (alpha <= 0) continue;

        ctx.fillStyle = parseColor(el.color, alpha);
        ctx.strokeStyle = parseColor(el.color, alpha * 0.8);
        ctx.lineWidth = CONFIG.lineWidth;

        if (el.type === 'circle') {
          const pulsedSize = el.size * (0.7 + 0.3 * Math.sin(el.phase));
          ctx.beginPath();
          ctx.arc(px, py, pulsedSize, 0, Math.PI * 2);
          ctx.fill();
        } else {
          const len = el.size * 1.5;
          const la = a + Math.sin(el.phase) * 0.5;
          ctx.beginPath();
          ctx.moveTo(px - Math.cos(la) * len, py - Math.sin(la) * len);
          ctx.lineTo(px + Math.cos(la) * len, py + Math.sin(la) * len);
          ctx.stroke();
        }

        // Reflection
        if (CONFIG.reflectionEnabled) {
          const ry = -py;
          ctx.fillStyle = parseColor(el.color, alpha * 0.5);
          ctx.strokeStyle = parseColor(el.color, alpha * 0.4);
          if (el.type === 'circle') {
            const pulsedSize = el.size * (0.7 + 0.3 * Math.sin(el.phase));
            ctx.beginPath();
            ctx.arc(px, ry, pulsedSize, 0, Math.PI * 2);
            ctx.fill();
          } else {
            const len = el.size * 1.5;
            const la = -a + Math.sin(el.phase) * 0.5;
            ctx.beginPath();
            ctx.moveTo(px - Math.cos(la) * len, ry - Math.sin(la) * len);
            ctx.lineTo(px + Math.cos(la) * len, ry + Math.sin(la) * len);
            ctx.stroke();
          }
        }
      }

      ctx.restore();
    }

    // Center mask
    if (CONFIG.centerRadius > 0) {
      const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, CONFIG.centerRadius);
      grad.addColorStop(0, 'rgba(0,0,0,0.9)');
      grad.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(0, 0, CONFIG.centerRadius, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.restore();
    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Lava Lamp
 * Description: Large, soft, amorphous blobs that slowly rise, merge, split,
 *   and sink like a lava lamp. Warm colors (deep reds, oranges, magentas)
 *   with very low opacity and heavy blur. Mouse attracts nearby blobs.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let blobs = [];
let time = 0;

const BLOB_COUNT = 12;
const MOUSE_ATTRACT_RADIUS = 250;
const MOUSE_ATTRACT_STRENGTH = 0.4;

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Warm color palette: deep reds, oranges, magentas
const COLORS = [
	{ r: 180, g: 30, b: 20 }, // deep red
	{ r: 200, g: 60, b: 10 }, // burnt orange
	{ r: 160, g: 20, b: 80 }, // magenta
	{ r: 220, g: 80, b: 20 }, // orange
	{ r: 140, g: 10, b: 50 }, // dark crimson
	{ r: 190, g: 40, b: 60 } // rose red
];

class Blob {
	constructor() {
		this.reset();
	}

	reset() {
		this.x = Math.random() * width;
		this.y = Math.random() * height;
		this.radius = 60 + Math.random() * 100;
		this.baseRadius = this.radius;
		this.vx = (Math.random() - 0.5) * 0.3;
		this.vy = -0.2 - Math.random() * 0.5; // drift upward
		this.color = COLORS[Math.floor(Math.random() * COLORS.length)];
		this.phase = Math.random() * Math.PI * 2;
		this.pulseSpeed = 0.005 + Math.random() * 0.01;
		this.wobbleAmpX = 0.3 + Math.random() * 0.5;
		this.wobbleAmpY = 0.2 + Math.random() * 0.3;
		this.wobbleFreqX = 0.008 + Math.random() * 0.006;
		this.wobbleFreqY = 0.006 + Math.random() * 0.008;
		this.alpha = 0.04 + Math.random() * 0.06;
	}

	update() {
		// Slow organic drift
		this.x += this.vx + Math.sin(time * this.wobbleFreqX + this.phase) * this.wobbleAmpX;
		this.y += this.vy + Math.cos(time * this.wobbleFreqY + this.phase) * this.wobbleAmpY;

		// Pulsing radius
		this.radius = this.baseRadius + Math.sin(time * this.pulseSpeed + this.phase) * 20;

		// Mouse attraction
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < MOUSE_ATTRACT_RADIUS && dist > 1) {
			const force = (1 - dist / MOUSE_ATTRACT_RADIUS) * MOUSE_ATTRACT_STRENGTH;
			this.x += (dx / dist) * force;
			this.y += (dy / dist) * force;
		}

		// Wrap around vertically — blobs that rise off top reappear at bottom
		if (this.y + this.radius < -50) {
			this.y = height + this.radius + 50;
			this.x = Math.random() * width;
		}
		// Occasionally sink back down (some blobs drift downward)
		if (this.y - this.radius > height + 100) {
			this.y = -this.radius - 50;
			this.x = Math.random() * width;
		}

		// Soft horizontal bounds
		if (this.x < -this.radius * 2) this.x = width + this.radius;
		if (this.x > width + this.radius * 2) this.x = -this.radius;
	}

	draw() {
		const { r, g, b } = this.color;

		// Draw multiple layered radial gradients for a soft, blurred look
		for (let layer = 0; layer < 3; layer++) {
			const layerScale = 1 + layer * 0.4;
			const layerAlpha = this.alpha / (layer + 1);
			const rad = this.radius * layerScale;

			const gradient = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, rad);
			gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${layerAlpha})`);
			gradient.addColorStop(0.4, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.6})`);
			gradient.addColorStop(0.7, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.2})`);
			gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			ctx.beginPath();
			ctx.arc(this.x, this.y, rad, 0, Math.PI * 2);
			ctx.fillStyle = gradient;
			ctx.fill();
		}
	}
}

function initBlobs() {
	blobs = [];
	for (let i = 0; i < BLOB_COUNT; i++) {
		blobs.push(new Blob());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initBlobs();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initBlobs();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;

		// Soft fade instead of full clear for trailing effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.08)';
		ctx.fillRect(0, 0, width, height);

		time++;

		// Update and draw blobs
		for (const blob of blobs) {
			blob.update();
		}
		for (const blob of blobs) {
			blob.draw();
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// =========================================================================
// Configurable Parameters
// =========================================================================
const CFG = {
  // Visuals
  GRADIENT_TOP: '#fff',           // top of fill gradient
  GRADIENT_MID: '#888',           // mid-point of fill gradient
  GRADIENT_BOTTOM: '#000',        // bottom of fill gradient
  POINT_COUNT: 24,                // number of points (np)
  POINT_MIN_R: 20,                // min random radius (unused in logic, kept for compatibility)
  POINT_MAX_R: 60,                // max random radius (unused in logic, kept for compatibility)
  SMOOTHING: 0.08,                 // lerp factor for point movement
  WAVE_AMPLITUDE: 20,              // sin wave height offset
  WAVE_FREQ: 0.5,                  // sin wave frequency per point
  TIME_SPEED: 0.01,                // delta-t per frame
};

// =========================================================================
// Worker
// =========================================================================
let c, ctx, w, h, t = 0, rid = 0, pts = [];

function rand(a, b) { return a + (b - a) * Math.random(); }

onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;
    for (let i = 0; i < CFG.POINT_COUNT; i++) {
      pts.push({ x: rand(0, w), y: rand(0, h), r: rand(CFG.POINT_MIN_R, CFG.POINT_MAX_R) });
    }
    draw();
  }
  if (e.data.type === 'resize') {
    w = c.width = e.data.width;
    h = c.height = e.data.height;
  }
  if (e.data.type === 'mousemove') {
    pts[0].x = e.data.x;
    pts[0].y = e.data.y;
  }
};

function draw() {
  rid = requestAnimationFrame(draw);
  t += CFG.TIME_SPEED;

  // Clear the canvas to transparency instead of filling with a solid color
  ctx.clearRect(0, 0, w, h);

  // Smooth follow
  for (let i = 1; i < CFG.POINT_COUNT; i++) {
    let p = pts[i], prev = pts[i - 1];
    p.x += (prev.x - p.x) * CFG.SMOOTHING;
    p.y += (prev.y - p.y) * CFG.SMOOTHING;
  }

  // Draw filled wave
  ctx.beginPath();
  ctx.moveTo(0, h);
  for (let i = 0; i < CFG.POINT_COUNT; i++) {
    let p = pts[i], y = p.y + Math.sin(t + i * CFG.WAVE_FREQ) * CFG.WAVE_AMPLITUDE;
    ctx.lineTo(p.x, y);
  }
  ctx.lineTo(w, h);
  ctx.closePath();

  let g = ctx.createLinearGradient(0, 0, 0, h);
  g.addColorStop(0, CFG.GRADIENT_TOP);
  g.addColorStop(0.5, CFG.GRADIENT_MID);
  g.addColorStop(1, CFG.GRADIENT_BOTTOM);
  ctx.fillStyle = g;
  ctx.fill();
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Magnetic Field
 * Description: Magnetic field line visualization with multiple dipoles. Field lines are traced
 *   via Euler integration from N to S poles with color mapped to field strength. Thousands of
 *   iron filing segments orient along the local field direction. Dipoles orbit slowly, causing
 *   dynamic topology reconfiguration. Mouse acts as a strong dipole.
 *   Uses Float32Array bulk storage, spatial hashing for filings, and delta-time animation.
 */

// ─── CONFIG ────────────────────────────────────────────────────────────────────
const CONFIG = {
	dipoleCount: 4, // Number of magnetic dipoles
	dipoleSeparation: 30, // Distance between N and S poles of each dipole (px)
	dipoleStrength: 6000, // Magnetic moment strength of each dipole
	fieldLineCount: 14, // Number of field lines traced per N pole
	fieldLineSteps: 300, // Maximum integration steps per field line
	fieldLineStepSize: 3, // Step size for Euler integration (px)
	ironFilingCount: 2500, // Number of iron filing segments scattered across canvas
	ironFilingLength: 8, // Length of each iron filing segment (px)
	ironFilingAlpha: 0.25, // Base opacity of iron filings
	fieldColorHue: 200, // Base hue for field visualization
	fieldColorIntensity: 1.2, // Multiplier for brightness mapping from field strength
	dipoleOrbitSpeed: 0.003, // Angular velocity of dipole orbital drift (rad/frame)
	dipoleOrbitRadius: 120, // Radius of the slow orbital path of each dipole
	mouseDipoleStrength: 10000, // Strength of the mouse-controlled dipole
	lineWidth: 1.2, // Width of field lines
	lineAlphaBase: 0.35, // Base alpha for field lines
	filingResetRate: 0.002, // Fraction of filings repositioned per frame (keeps it fresh)
	glowPasses: 2, // Multi-pass glow layers for field lines
	glowWidthStep: 3, // Width increase per glow pass
	glowAlphaDecay: 0.3, // Alpha decay per glow pass
	poleGlowRadius: 25 // Visual glow radius around pole markers
};

// ─── STATE ─────────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;

// Dipole storage: each dipole has a center, angle, and generates two poles
let dipoles = [];

// Iron filing positions — Float32Array for performance
let filingX, filingY;

// Precomputed pole positions (N and S for each dipole + mouse dipole)
// Updated each frame
let poleX, poleY, poleSign, poleStrength;
let poleCount = 0;

// ─── HEARTBEAT ─────────────────────────────────────────────────────────────────
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── DIPOLE CLASS ──────────────────────────────────────────────────────────────
class Dipole {
	constructor(cx, cy, angle, strength) {
		this.cx = cx;
		this.cy = cy;
		this.angle = angle;
		this.strength = strength;
		this.orbitAngle = Math.random() * Math.PI * 2;
		this.orbitCx = cx;
		this.orbitCy = cy;
		this.hue = Math.random() * 60 + CONFIG.fieldColorHue - 30;
	}

	update(dt) {
		this.orbitAngle += CONFIG.dipoleOrbitSpeed * dt;
		this.cx = this.orbitCx + Math.cos(this.orbitAngle) * CONFIG.dipoleOrbitRadius;
		this.cy = this.orbitCy + Math.sin(this.orbitAngle) * CONFIG.dipoleOrbitRadius;
		// Slowly rotate the dipole itself
		this.angle += CONFIG.dipoleOrbitSpeed * 0.5 * dt;
	}

	getNPole() {
		const half = CONFIG.dipoleSeparation * 0.5;
		return {
			x: this.cx + Math.cos(this.angle) * half,
			y: this.cy + Math.sin(this.angle) * half
		};
	}

	getSPole() {
		const half = CONFIG.dipoleSeparation * 0.5;
		return {
			x: this.cx - Math.cos(this.angle) * half,
			y: this.cy - Math.sin(this.angle) * half
		};
	}
}

// ─── FIELD COMPUTATION ─────────────────────────────────────────────────────────
// Returns { bx, by } — the magnetic field vector at point (x, y)
// Each pole contributes a monopole-like field: B = strength * sign / r^2, direction = r_hat * sign
function computeField(x, y) {
	let bx = 0,
		by = 0;

	for (let i = 0; i < poleCount; i++) {
		const dx = x - poleX[i];
		const dy = y - poleY[i];
		const dist2 = dx * dx + dy * dy + 100; // Softening to prevent singularities
		const dist = Math.sqrt(dist2);
		const factor = (poleStrength[i] * poleSign[i]) / (dist2 * dist);
		bx += dx * factor;
		by += dy * factor;
	}

	return { bx, by };
}

function fieldMagnitude(bx, by) {
	return Math.sqrt(bx * bx + by * by);
}

// ─── INITIALIZATION ────────────────────────────────────────────────────────────
function initDipoles() {
	dipoles = [];
	const cx = width * 0.5;
	const cy = height * 0.5;
	const spread = Math.min(width, height) * 0.25;

	for (let i = 0; i < CONFIG.dipoleCount; i++) {
		const angle = (i / CONFIG.dipoleCount) * Math.PI * 2;
		const x = cx + Math.cos(angle) * spread;
		const y = cy + Math.sin(angle) * spread;
		const dipAngle = angle + Math.PI * 0.5 + (Math.random() - 0.5) * 1;
		dipoles.push(new Dipole(x, y, dipAngle, CONFIG.dipoleStrength));
	}

	// Allocate pole arrays: each dipole = 2 poles + mouse dipole (2 poles)
	const maxPoles = (CONFIG.dipoleCount + 1) * 2;
	poleX = new Float32Array(maxPoles);
	poleY = new Float32Array(maxPoles);
	poleSign = new Float32Array(maxPoles);
	poleStrength = new Float32Array(maxPoles);
}

function initFilings() {
	const n = CONFIG.ironFilingCount;
	filingX = new Float32Array(n);
	filingY = new Float32Array(n);

	for (let i = 0; i < n; i++) {
		filingX[i] = Math.random() * width;
		filingY[i] = Math.random() * height;
	}
}

function updatePolePositions() {
	poleCount = 0;

	for (let i = 0; i < dipoles.length; i++) {
		const d = dipoles[i];
		const np = d.getNPole();
		const sp = d.getSPole();

		poleX[poleCount] = np.x;
		poleY[poleCount] = np.y;
		poleSign[poleCount] = 1;
		poleStrength[poleCount] = d.strength;
		poleCount++;

		poleX[poleCount] = sp.x;
		poleY[poleCount] = sp.y;
		poleSign[poleCount] = -1;
		poleStrength[poleCount] = d.strength;
		poleCount++;
	}

	// Mouse dipole (horizontal orientation)
	if (mouse.x > -1000) {
		const sep = CONFIG.dipoleSeparation * 0.5;
		poleX[poleCount] = mouse.x + sep;
		poleY[poleCount] = mouse.y;
		poleSign[poleCount] = 1;
		poleStrength[poleCount] = CONFIG.mouseDipoleStrength;
		poleCount++;

		poleX[poleCount] = mouse.x - sep;
		poleY[poleCount] = mouse.y;
		poleSign[poleCount] = -1;
		poleStrength[poleCount] = CONFIG.mouseDipoleStrength;
		poleCount++;
	}
}

// ─── RENDERING ─────────────────────────────────────────────────────────────────
function traceFieldLine(ctx, startX, startY, direction, pass) {
	const steps = CONFIG.fieldLineSteps;
	const stepSize = CONFIG.fieldLineStepSize * direction;
	const isGlow = pass > 0;
	const extraWidth = isGlow ? pass * CONFIG.glowWidthStep : 0;
	const alphaScale = isGlow ? Math.pow(CONFIG.glowAlphaDecay, pass) : 1;

	let x = startX;
	let y = startY;

	ctx.beginPath();
	ctx.moveTo(x, y);

	let prevStrength = 0;
	let segmentCount = 0;

	for (let s = 0; s < steps; s++) {
		const { bx, by } = computeField(x, y);
		const mag = fieldMagnitude(bx, by);
		if (mag < 0.0001) break;

		// Normalize and step
		const nx = bx / mag;
		const ny = by / mag;
		x += nx * stepSize;
		y += ny * stepSize;

		// Off-screen culling — stop tracing
		if (x < -50 || x > width + 50 || y < -50 || y > height + 50) break;

		// Check if we've reached a pole (close to any S pole)
		let hitPole = false;
		for (let p = 0; p < poleCount; p++) {
			if (poleSign[p] !== -direction) continue;
			const dx = x - poleX[p];
			const dy = y - poleY[p];
			if (dx * dx + dy * dy < 100) {
				hitPole = true;
				break;
			}
		}

		ctx.lineTo(x, y);
		segmentCount++;

		if (hitPole) break;
		prevStrength = mag;
	}

	if (segmentCount < 3) return;

	// Color based on average field strength
	const intensity = Math.min(prevStrength * CONFIG.fieldColorIntensity * 500, 1);
	const hue = CONFIG.fieldColorHue + intensity * 40;
	const lightness = 40 + intensity * 30;
	const alpha = (CONFIG.lineAlphaBase + intensity * 0.3) * alphaScale;

	ctx.strokeStyle = `hsla(${hue}, 70%, ${lightness}%, ${alpha})`;
	ctx.lineWidth = CONFIG.lineWidth + extraWidth;
	ctx.lineCap = 'round';
	ctx.stroke();
}

function drawFieldLines(ctx) {
	// Trace field lines from each N pole
	for (let p = 0; p < poleCount; p++) {
		if (poleSign[p] !== 1) continue; // Only start from N poles

		const cx = poleX[p];
		const cy = poleY[p];

		for (let i = 0; i < CONFIG.fieldLineCount; i++) {
			const angle = (i / CONFIG.fieldLineCount) * Math.PI * 2;
			const startR = 8;
			const sx = cx + Math.cos(angle) * startR;
			const sy = cy + Math.sin(angle) * startR;

			// Multi-pass glow
			for (let pass = CONFIG.glowPasses; pass >= 0; pass--) {
				traceFieldLine(ctx, sx, sy, 1, pass);
			}
		}
	}
}

function drawIronFilings(ctx) {
	const halfLen = CONFIG.ironFilingLength * 0.5;
	const resetCount = Math.ceil(CONFIG.ironFilingCount * CONFIG.filingResetRate);

	// Randomly reposition a few filings each frame for visual freshness
	for (let i = 0; i < resetCount; i++) {
		const idx = Math.floor(Math.random() * CONFIG.ironFilingCount);
		filingX[idx] = Math.random() * width;
		filingY[idx] = Math.random() * height;
	}

	ctx.lineWidth = 1;
	ctx.lineCap = 'round';

	// Batch by starting a single path and drawing all filings
	for (let i = 0; i < CONFIG.ironFilingCount; i++) {
		const x = filingX[i];
		const y = filingY[i];

		// Off-screen culling
		if (x < -10 || x > width + 10 || y < -10 || y > height + 10) continue;

		const { bx, by } = computeField(x, y);
		const mag = fieldMagnitude(bx, by);
		if (mag < 0.0001) continue;

		const nx = bx / mag;
		const ny = by / mag;
		const intensity = Math.min(mag * 600, 1);
		const alpha = CONFIG.ironFilingAlpha * (0.3 + intensity * 0.7);

		ctx.beginPath();
		ctx.moveTo(x - nx * halfLen, y - ny * halfLen);
		ctx.lineTo(x + nx * halfLen, y + ny * halfLen);
		ctx.strokeStyle = `hsla(${CONFIG.fieldColorHue + intensity * 30}, 50%, ${50 + intensity * 30}%, ${alpha})`;
		ctx.stroke();
	}
}

function drawPoles(ctx) {
	for (let i = 0; i < poleCount; i++) {
		const x = poleX[i];
		const y = poleY[i];
		const isN = poleSign[i] > 0;
		const r = CONFIG.poleGlowRadius;

		// Glow
		const grad = ctx.createRadialGradient(x, y, 0, x, y, r);
		const hue = isN ? 0 : 220;
		grad.addColorStop(0, `hsla(${hue}, 80%, 70%, 0.3)`);
		grad.addColorStop(0.5, `hsla(${hue}, 80%, 50%, 0.1)`);
		grad.addColorStop(1, `hsla(${hue}, 80%, 30%, 0)`);
		ctx.fillStyle = grad;
		ctx.fillRect(x - r, y - r, r * 2, r * 2);

		// Core dot
		ctx.beginPath();
		ctx.arc(x, y, 4, 0, Math.PI * 2);
		ctx.fillStyle = isN ? 'rgba(255, 100, 100, 0.8)' : 'rgba(100, 150, 255, 0.8)';
		ctx.fill();
	}
}

// ─── MESSAGE HANDLER ───────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initDipoles();
			initFilings();
			lastTime = performance.now();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initFilings();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

// ─── RENDER LOOP ───────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) return;

		const dt = Math.min((now - lastTime) / 16.667, 3);
		lastTime = now;

		// Clear with slight trail
		ctx.fillStyle = 'rgba(0, 0, 0, 0.12)';
		ctx.fillRect(0, 0, width, height);

		// Update dipole positions
		for (let i = 0; i < dipoles.length; i++) {
			dipoles[i].update(dt);
		}
		updatePolePositions();

		// Render layers
		drawIronFilings(ctx);
		drawFieldLines(ctx);
		drawPoles(ctx);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Magnetic Sand
 * Description: Iron filings simulation — hundreds of elongated particles align along
 *   magnetic field lines from your mouse (north pole) and a configurable second pole.
 *   Filings drift toward poles, rotate smoothly, and shimmer with metallic sheen.
 *   Optional field line overlay shows the computed dipole field paths.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Filings --
  filingCount: 1500,                      // Number of iron filings (300-3000)
  filingLength: 6,                        // Filing length in px (3-12)
  filingWidth: 1.2,                       // Filing thickness in px (0.5-2.5)
  filingColor: '#8a8a8a',                 // Base metallic gray
  filingOpacity: 0.7,                     // Filing opacity (0.3-0.95)
  alignSpeed: 0.1,                        // Rotation alignment speed (0.02-0.3)
  attractionStrength: 2,                  // Drift toward poles (0-8)
  attractionDamping: 0.96,                // Movement damping (0.9-0.99)

  // -- Second Pole --
  secondPoleEnabled: true,                // Show a south pole
  secondPoleX: 0.75,                      // X position (fraction 0-1 of width)
  secondPoleY: 0.75,                      // Y position (fraction 0-1 of height)
  secondPoleStrength: 1.0,                // Relative strength vs mouse pole (0.3-3)

  // -- Field Lines --
  fieldLinesEnabled: true,                // Show magnetic field line overlay
  fieldLineCount: 14,                     // Number of field lines (4-24)
  fieldLineColor: '#4488aa',              // Field line color
  fieldLineOpacity: 0.15,                 // Field line opacity (0.05-0.5)

  // -- Visual --
  sheenEnabled: true,                     // Metallic sheen on filings
  surfaceColor: '#f0ebe0',               // Background surface color
  surfaceTexture: true,                   // Subtle noise texture on background
  clusterDensity: 1.5,                    // Clustering near poles (0-4)
  mouseRadius: 300,                       // Mouse influence radius (100-500)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let filings = [];
let textureData = null;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }

// Compute magnetic field direction at point (px,py) from two poles
function fieldAngle(px, py, p1x, p1y, p2x, p2y, p2str) {
  let bx = 0, by = 0;

  // North pole (mouse) - field points away
  let dx = px - p1x, dy = py - p1y;
  let d2 = dx * dx + dy * dy + 100; // +100 to avoid singularity
  let d3 = Math.pow(d2, 1.5);
  bx += dx / d3 * 10000;
  by += dy / d3 * 10000;

  // South pole - field points toward
  if (CONFIG.secondPoleEnabled) {
    dx = px - p2x; dy = py - p2y;
    d2 = dx * dx + dy * dy + 100;
    d3 = Math.pow(d2, 1.5);
    bx -= dx / d3 * 10000 * p2str;
    by -= dy / d3 * 10000 * p2str;
  }

  return Math.atan2(by, bx);
}

function fieldStrength(px, py, p1x, p1y, p2x, p2y, p2str) {
  const d1 = Math.hypot(px - p1x, py - p1y) + 10;
  let s = 1000 / (d1 * d1);
  if (CONFIG.secondPoleEnabled) {
    const d2 = Math.hypot(px - p2x, py - p2y) + 10;
    s += (1000 / (d2 * d2)) * p2str;
  }
  return s;
}

class Filing {
  constructor() {
    this.x = rand(10, width - 10);
    this.y = rand(10, height - 10);
    this.angle = rand(0, Math.PI);
    this.vx = 0;
    this.vy = 0;
    this.len = CONFIG.filingLength * rand(0.7, 1.3);
  }

  update(p1x, p1y, p2x, p2y, p2str) {
    if (p1x < 0) return;

    // Target angle from field
    const target = fieldAngle(this.x, this.y, p1x, p1y, p2x, p2y, p2str);

    // Smooth angle alignment (filings align with field, not against)
    let da = target - this.angle;
    // Normalize to [-PI/2, PI/2] since filings are symmetric
    while (da > Math.PI / 2) da -= Math.PI;
    while (da < -Math.PI / 2) da += Math.PI;
    this.angle += da * CONFIG.alignSpeed;

    // Attraction toward poles
    const str = CONFIG.attractionStrength * 0.01;
    let dx = p1x - this.x, dy = p1y - this.y;
    let d = Math.sqrt(dx * dx + dy * dy) + 1;
    if (d < CONFIG.mouseRadius) {
      const f = (1 / (d * d)) * str * 500 * CONFIG.clusterDensity;
      this.vx += (dx / d) * f;
      this.vy += (dy / d) * f;
    }

    if (CONFIG.secondPoleEnabled) {
      dx = p2x - this.x; dy = p2y - this.y;
      d = Math.sqrt(dx * dx + dy * dy) + 1;
      const f = (1 / (d * d)) * str * 500 * p2str * CONFIG.clusterDensity;
      this.vx += (dx / d) * f;
      this.vy += (dy / d) * f;
    }

    this.vx *= CONFIG.attractionDamping;
    this.vy *= CONFIG.attractionDamping;
    this.x += this.vx;
    this.y += this.vy;

    // Boundary
    if (this.x < 5) { this.x = 5; this.vx *= -0.3; }
    if (this.x > width - 5) { this.x = width - 5; this.vx *= -0.3; }
    if (this.y < 5) { this.y = 5; this.vy *= -0.3; }
    if (this.y > height - 5) { this.y = height - 5; this.vy *= -0.3; }
  }

  draw() {
    const cos = Math.cos(this.angle);
    const sin = Math.sin(this.angle);
    const hl = this.len * 0.5;
    const x1 = this.x - cos * hl;
    const y1 = this.y - sin * hl;
    const x2 = this.x + cos * hl;
    const y2 = this.y + sin * hl;

    const c = hexRgb(CONFIG.filingColor);
    if (CONFIG.sheenEnabled) {
      // Metallic sheen: one end brighter based on angle to virtual light
      const lightAngle = Math.atan2(-1, 1); // light from top-right
      const angleDiff = Math.abs(this.angle - lightAngle);
      const sheen = Math.cos(angleDiff) * 0.3;

      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(this.x, this.y);
      ctx.strokeStyle = `rgba(${Math.min(255, c[0] + sheen * 80)|0},${Math.min(255, c[1] + sheen * 80)|0},${Math.min(255, c[2] + sheen * 80)|0},${CONFIG.filingOpacity})`;
      ctx.lineWidth = CONFIG.filingWidth;
      ctx.lineCap = 'round';
      ctx.stroke();

      ctx.beginPath();
      ctx.moveTo(this.x, this.y);
      ctx.lineTo(x2, y2);
      ctx.strokeStyle = `rgba(${Math.max(0, c[0] - sheen * 40)|0},${Math.max(0, c[1] - sheen * 40)|0},${Math.max(0, c[2] - sheen * 40)|0},${CONFIG.filingOpacity})`;
      ctx.stroke();
    } else {
      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.strokeStyle = `rgba(${c[0]},${c[1]},${c[2]},${CONFIG.filingOpacity})`;
      ctx.lineWidth = CONFIG.filingWidth;
      ctx.lineCap = 'round';
      ctx.stroke();
    }
  }
}

function drawFieldLines(p1x, p1y, p2x, p2y, p2str) {
  if (!CONFIG.fieldLinesEnabled || p1x < 0) return;
  const c = hexRgb(CONFIG.fieldLineColor);
  ctx.strokeStyle = `rgba(${c[0]},${c[1]},${c[2]},${CONFIG.fieldLineOpacity})`;
  ctx.lineWidth = 0.8;

  const n = CONFIG.fieldLineCount;
  for (let i = 0; i < n; i++) {
    const startAngle = (i / n) * Math.PI * 2;
    let x = p1x + Math.cos(startAngle) * 12;
    let y = p1y + Math.sin(startAngle) * 12;

    ctx.beginPath();
    ctx.moveTo(x, y);

    for (let step = 0; step < 200; step++) {
      const a = fieldAngle(x, y, p1x, p1y, p2x, p2y, p2str);
      x += Math.cos(a) * 4;
      y += Math.sin(a) * 4;

      // Stop if out of bounds or near south pole
      if (x < 0 || x > width || y < 0 || y > height) break;
      if (CONFIG.secondPoleEnabled && Math.hypot(x - p2x, y - p2y) < 15) break;

      ctx.lineTo(x, y);
    }
    ctx.stroke();
  }
}

function initFilings() {
  filings = [];
  for (let i = 0; i < CONFIG.filingCount; i++) filings.push(new Filing());
}

function generateTexture() {
  if (!CONFIG.surfaceTexture) return;
  const id = ctx.createImageData(width, height);
  const d = id.data;
  const sc = hexRgb(CONFIG.surfaceColor);
  for (let i = 0; i < d.length; i += 4) {
    const noise = (Math.random() - 0.5) * 12;
    d[i] = Math.max(0, Math.min(255, sc[0] + noise));
    d[i+1] = Math.max(0, Math.min(255, sc[1] + noise));
    d[i+2] = Math.max(0, Math.min(255, sc[2] + noise));
    d[i+3] = 255;
  }
  textureData = id;
}

function startAnimation() {
  const sc = hexRgb(CONFIG.surfaceColor);

  function render() {
    if (!ctx) return;

    // Background
    if (textureData) {
      ctx.putImageData(textureData, 0, 0);
    } else {
      ctx.fillStyle = CONFIG.surfaceColor;
      ctx.fillRect(0, 0, width, height);
    }

    const p1x = mouse.x, p1y = mouse.y;
    const p2x = width * CONFIG.secondPoleX;
    const p2y = height * CONFIG.secondPoleY;
    const p2str = CONFIG.secondPoleStrength;

    // Field lines (behind filings)
    drawFieldLines(p1x, p1y, p2x, p2y, p2str);

    // Pole indicators
    if (CONFIG.secondPoleEnabled) {
      ctx.beginPath();
      ctx.arc(p2x, p2y, 6, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(200,60,60,0.3)';
      ctx.fill();
      ctx.fillStyle = 'rgba(200,60,60,0.6)';
      ctx.font = '10px monospace';
      ctx.fillText('S', p2x - 3, p2y + 4);
    }
    if (p1x >= 0) {
      ctx.beginPath();
      ctx.arc(p1x, p1y, 6, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(60,60,200,0.3)';
      ctx.fill();
      ctx.fillStyle = 'rgba(60,60,200,0.6)';
      ctx.font = '10px monospace';
      ctx.fillText('N', p1x - 3, p1y + 4);
    }

    // Update and draw filings
    for (const f of filings) {
      f.update(p1x, p1y, p2x, p2y, p2str);
      f.draw();
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initFilings();
      generateTexture();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initFilings();
      generateTexture();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Matrix Rain
 * Description: Classic Matrix digital rain with columns of falling katakana, numbers,
 *   and latin characters. Green phosphor glow, brighter leading characters.
 *   Mouse proximity accelerates nearby columns.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

// Column state
let columns = [];
const FONT_SIZE = 14;
const CHAR_POOL =
	'アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワヲン' +
	'0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initColumns();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initColumns();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function initColumns() {
	const count = Math.ceil(width / FONT_SIZE);
	columns = [];
	for (let i = 0; i < count; i++) {
		columns.push({
			x: i * FONT_SIZE,
			y: Math.random() * height * -1, // start above screen
			speed: 0.3 + Math.random() * 0.7, // base speed multiplier
			chars: generateChars(Math.ceil(height / FONT_SIZE) + 10),
			length: 8 + Math.floor(Math.random() * 20), // visible trail length
			offset: 0 // fractional y offset for smooth scrolling
		});
	}
}

function generateChars(count) {
	const chars = [];
	for (let i = 0; i < count; i++) {
		chars.push(CHAR_POOL[Math.floor(Math.random() * CHAR_POOL.length)]);
	}
	return chars;
}

function randomChar() {
	return CHAR_POOL[Math.floor(Math.random() * CHAR_POOL.length)];
}

function startAnimation() {
	let lastTime = 0;

	function render(time) {
		if (!ctx) return;
		const dt = lastTime ? (time - lastTime) / 16.67 : 1; // normalize to ~60fps
		lastTime = time;

		// Fade the canvas instead of clearing — creates the trail effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
		ctx.fillRect(0, 0, width, height);

		ctx.font = `${FONT_SIZE}px monospace`;

		for (let i = 0; i < columns.length; i++) {
			const col = columns[i];

			// Mouse proximity check — speed boost for nearby columns
			const dx = col.x - mouse.x;
			const dist = Math.abs(dx);
			const mouseBoost = dist < 200 ? 1 + (1 - dist / 200) * 2.5 : 1;

			// Advance the column
			col.offset += col.speed * mouseBoost * dt;

			// When we've moved a full character height, shift everything
			if (col.offset >= FONT_SIZE) {
				col.offset -= FONT_SIZE;
				col.y += FONT_SIZE;

				// Randomly mutate a character in the trail
				const mutateIdx = Math.floor(Math.random() * col.chars.length);
				col.chars[mutateIdx] = randomChar();
			}

			// Calculate the head position (in cell units)
			const headRow = Math.floor(col.y / FONT_SIZE);

			// Draw visible characters
			for (let j = 0; j < col.length; j++) {
				const row = headRow - j;
				const py = row * FONT_SIZE + col.offset;

				// Skip if off-screen
				if (py < -FONT_SIZE || py > height + FONT_SIZE) continue;

				const charIdx = Math.abs(row) % col.chars.length;
				const ch = col.chars[charIdx];

				if (j === 0) {
					// Leading character — bright white-green
					ctx.fillStyle = 'rgba(180, 255, 180, 0.95)';
					ctx.shadowColor = 'rgba(0, 255, 70, 0.8)';
					ctx.shadowBlur = 12;
				} else if (j === 1) {
					// Second char — still bright
					ctx.fillStyle = 'rgba(0, 255, 70, 0.7)';
					ctx.shadowColor = 'rgba(0, 255, 70, 0.4)';
					ctx.shadowBlur = 6;
				} else {
					// Trail — fades out
					const fade = 1 - j / col.length;
					const alpha = fade * 0.4;
					ctx.fillStyle = `rgba(0, 200, 50, ${alpha})`;
					ctx.shadowBlur = 0;
				}

				ctx.fillText(ch, col.x, py);
			}

			// Reset shadow after each column
			ctx.shadowBlur = 0;

			// Reset column when it's fully off the bottom
			if ((headRow - col.length) * FONT_SIZE > height) {
				col.y = Math.random() * -height * 0.5 - FONT_SIZE * col.length;
				col.speed = 0.3 + Math.random() * 0.7;
				col.length = 8 + Math.floor(Math.random() * 20);
				col.chars = generateChars(Math.ceil(height / FONT_SIZE) + 10);
			}
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

// DigitalRain – transparency-optimized
let c,ctx,w,h,cols=[],font=15,glow=[]; 
self.onmessage=e=>{
  if(e.data.type==='init'){
    c=e.data.canvas;ctx=c.getContext('2d');
    w=c.width=e.data.width;h=c.height=e.data.height;
    ctx.font=font+'px monospace';
    let colCount=Math.floor(w/font);
    for(let i=0;i<colCount;i++){
      cols[i]=Math.random()*h;
      glow[i]=Math.random();
    }
    animate();
  }
  if(e.data.type==='resize'){
    w=c.width=e.data.width;h=c.height=e.data.height;
    ctx.font=font+'px monospace';
  }
};
function animate(){
  // 1. Erase a portion of the previous frame to transparency
  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle='rgba(0,0,0,0.1)';
  ctx.fillRect(0,0,w,h);

  // 2. Switch back to normal drawing mode for characters
  ctx.globalCompositeOperation = 'source-over';

  let colCount=Math.floor(w/font);
  for(let i=0;i<colCount;i++){
    let txt=String.fromCharCode(0x30A0+Math.random()*96|0);
    let y=cols[i];
    ctx.fillStyle='hsla(120,100%,'+glow[i]*70+'%,1)';
    ctx.fillText(txt,i*font,y);
    cols[i]+=font*0.8;
    glow[i]*=0.98;
    if(y>h&&Math.random()<0.02){cols[i]=0;glow[i]=1;}
  }
  requestAnimationFrame(animate);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Morphing Polygons
 * Description: Several large semi-transparent polygons that slowly morph between
 * different shapes (triangle → square → pentagon → hexagon → circle) using vertex
 * interpolation. They drift lazily and overlap with blend effects. Mouse proximity
 * speeds up the morphing.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let polygons = [];
let lastTime = 0;

// Shape definitions — number of vertices for each stage
const SHAPES = [3, 4, 5, 6, 12]; // triangle, square, pentagon, hexagon, ~circle
const MAX_VERTICES = 12; // Normalize all shapes to this vertex count
const NUM_POLYGONS = 6;
const BASE_MORPH_SPEED = 0.08; // Morphs per second
const MOUSE_INFLUENCE = 300;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initPolygons();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			// Reposition polygons within new bounds
			for (const p of polygons) {
				p.x = Math.min(p.x, width);
				p.y = Math.min(p.y, height);
			}
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Generate normalized vertices for a regular polygon with `sides` vertices,
 * upsampled to MAX_VERTICES points for smooth interpolation.
 */
function generateShape(sides) {
	const points = [];
	for (let i = 0; i < MAX_VERTICES; i++) {
		// Map each of the MAX_VERTICES points to a position on the polygon
		const t = i / MAX_VERTICES;
		const angle = t * Math.PI * 2 - Math.PI / 2;

		// For a regular polygon with `sides`, find the radius at this angle
		const sectorAngle = (Math.PI * 2) / sides;
		const localAngle = ((angle % sectorAngle) + sectorAngle) % sectorAngle;
		const halfSector = sectorAngle / 2;
		const r = Math.cos(halfSector) / Math.cos(localAngle - halfSector);

		points.push({
			x: Math.cos(angle) * r,
			y: Math.sin(angle) * r
		});
	}
	return points;
}

// Pre-generate all shape vertices
const shapeVertices = SHAPES.map((s) => generateShape(s));

function initPolygons() {
	polygons = [];
	const colors = [
		[120, 160, 255],
		[180, 120, 255],
		[100, 220, 200],
		[255, 150, 120],
		[200, 200, 100],
		[150, 180, 220]
	];

	for (let i = 0; i < NUM_POLYGONS; i++) {
		const radius = 80 + Math.random() * 120;
		polygons.push({
			x: Math.random() * width,
			y: Math.random() * height,
			vx: (Math.random() - 0.5) * 15,
			vy: (Math.random() - 0.5) * 15,
			radius,
			rotation: Math.random() * Math.PI * 2,
			rotationSpeed: (Math.random() - 0.5) * 0.15,
			shapeIndex: Math.floor(Math.random() * SHAPES.length),
			morphProgress: 0,
			color: colors[i % colors.length],
			opacity: 0.04 + Math.random() * 0.06
		});
	}
}

function lerp(a, b, t) {
	return a + (b - a) * t;
}

function lerpPoint(a, b, t) {
	return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
}

// Smooth easing
function easeInOut(t) {
	return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;

		ctx.clearRect(0, 0, width, height);

		// Use lighter composite for overlapping glow
		ctx.globalCompositeOperation = 'lighter';

		for (const poly of polygons) {
			// Mouse distance for speed boost
			const mouseDist = Math.hypot(poly.x - mouse.x, poly.y - mouse.y);
			const mouseBoost =
				mouseDist < MOUSE_INFLUENCE ? 1 + (1 - mouseDist / MOUSE_INFLUENCE) * 4 : 1;

			// Advance morph
			poly.morphProgress += BASE_MORPH_SPEED * mouseBoost * dt;

			if (poly.morphProgress >= 1) {
				poly.morphProgress -= 1;
				poly.shapeIndex = (poly.shapeIndex + 1) % SHAPES.length;
			}

			// Drift movement
			poly.x += poly.vx * dt;
			poly.y += poly.vy * dt;
			poly.rotation += poly.rotationSpeed * dt;

			// Wrap around edges with padding
			const pad = poly.radius * 1.5;
			if (poly.x < -pad) poly.x = width + pad;
			if (poly.x > width + pad) poly.x = -pad;
			if (poly.y < -pad) poly.y = height + pad;
			if (poly.y > height + pad) poly.y = -pad;

			// Get current and next shape vertices
			const currentShape = shapeVertices[poly.shapeIndex];
			const nextShape = shapeVertices[(poly.shapeIndex + 1) % SHAPES.length];
			const t = easeInOut(poly.morphProgress);

			// Draw interpolated shape
			ctx.save();
			ctx.translate(poly.x, poly.y);
			ctx.rotate(poly.rotation);

			ctx.beginPath();
			for (let i = 0; i < MAX_VERTICES; i++) {
				const pt = lerpPoint(currentShape[i], nextShape[i], t);
				const px = pt.x * poly.radius;
				const py = pt.y * poly.radius;
				if (i === 0) ctx.moveTo(px, py);
				else ctx.lineTo(px, py);
			}
			ctx.closePath();

			// Fill
			const [r, g, b] = poly.color;
			ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${poly.opacity})`;
			ctx.fill();

			// Stroke
			ctx.strokeStyle = `rgba(${r}, ${g}, ${b}, ${poly.opacity * 2.5})`;
			ctx.lineWidth = 1.2;
			ctx.stroke();

			ctx.restore();
		}

		// Reset composite
		ctx.globalCompositeOperation = 'source-over';

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Mycelium Network
 * Description: An organic fungal mycelium that grows outward from seed points,
 *   branching stochastically. Nutrient pulses race along established connections,
 *   mature nodes release spores, and the mouse acts as a nutrient source that
 *   accelerates nearby growth and attracts branching direction.
 */

// ─── CONFIG ──────────────────────────────────────────────────────────────────
const CONFIG = {
	seedCount: 4, // number of initial growth origin points
	growthSpeed: 40, // px/s – base tip extension speed
	growthAngleVariance: 0.35, // radians – max random wander per step
	branchProbability: 0.012, // per-frame chance of branching at a tip
	branchAngleRange: 0.8, // radians – max branch fork angle
	maxBranchDepth: 7, // maximum recursive branching depth
	maxSegments: 4000, // hard cap on total hypha segments
	hyphaWidth: 1.5, // px – base strand thickness
	hyphaAlpha: 0.6, // base alpha of hypha strands
	pulseSpeed: 120, // px/s – speed of nutrient pulses
	pulseFrequency: 0.3, // pulses spawned per second per seed
	pulseGlow: 8, // px – glow radius around a pulse dot
	pulseSize: 3, // px – core radius of pulse dot
	nodeGlowRadius: 12, // px – glow at branch intersection nodes
	nodeGlowAlpha: 0.15, // alpha of node glow
	fadeRate: 0.0008, // alpha decay per second for old segments
	sporeCount: 5, // spores per burst
	sporeSpeed: 25, // px/s – spore drift speed
	sporeLifetime: 3.0, // seconds before spore fades
	sporeBurstChance: 0.005, // per-frame chance a mature node bursts
	mouseNutrientRadius: 200, // px – radius of mouse nutrient influence
	mouseGrowthBoost: 2.5, // multiplier for growth speed near mouse
	mouseBranchBoost: 3.0, // multiplier for branch probability near mouse
	baseHue: 80, // HSL hue (80 = yellow-green)
	hueVariance: 30, // random hue offset range
	glowPasses: 2, // additive glow passes for the network
	glowExpand: 4, // px – extra width per glow pass
	glowAlpha: 0.04, // alpha per glow pass
	trailAlpha: 0.03, // motion trail decay alpha
	layerCount: 3, // parallax depth layers
	layerAlphaScale: 0.4 // alpha multiplier for the deepest layer
};

// ─── GLOBALS ─────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;

// Segment storage: Float32Array columns (x1,y1,x2,y2,age,branchDepth,layer,hue)
const SEG_STRIDE = 8;
let segments = null; // Float32Array
let segCount = 0;

// Active tips: objects with {x,y,angle,depth,layer,hue,active}
let tips = [];
const MAX_TIPS = 500;

// Pulses: {segIndex, t, speed, layer}
let pulses = [];
const MAX_PULSES = 200;

// Spores: Float32Array (x,y,vx,vy,life,maxLife,layer)
const SPORE_STRIDE = 7;
let spores = null;
let sporeCount = 0;
const MAX_SPORES = 300;

// Nodes (branch points): Float32Array (x,y,age,layer)
const NODE_STRIDE = 4;
let nodes = null;
let nodeCount = 0;
const MAX_NODES = 800;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── INIT ────────────────────────────────────────────────────────────────────
function initAll() {
	segments = new Float32Array(CONFIG.maxSegments * SEG_STRIDE);
	segCount = 0;
	tips = [];
	pulses = [];
	spores = new Float32Array(MAX_SPORES * SPORE_STRIDE);
	sporeCount = 0;
	nodes = new Float32Array(MAX_NODES * NODE_STRIDE);
	nodeCount = 0;
	lastTime = 0;

	// Seed points
	for (let i = 0; i < CONFIG.seedCount; i++) {
		const layer = i % CONFIG.layerCount;
		tips.push({
			x: width * 0.2 + Math.random() * width * 0.6,
			y: height * 0.2 + Math.random() * height * 0.6,
			angle: Math.random() * Math.PI * 2,
			depth: 0,
			layer,
			hue: CONFIG.baseHue + (Math.random() - 0.5) * CONFIG.hueVariance,
			active: true
		});
	}
}

// ─── SPATIAL HASH (for node proximity) ──────────────────────────────────────
const CELL_SIZE = 50;
let hashMap = new Map();

function hashKey(x, y) {
	return ((x / CELL_SIZE) | 0) * 100000 + ((y / CELL_SIZE) | 0);
}

function rebuildHash() {
	hashMap.clear();
	for (let i = 0; i < segCount; i++) {
		const off = i * SEG_STRIDE;
		const key = hashKey(segments[off + 2], segments[off + 3]);
		if (!hashMap.has(key)) hashMap.set(key, []);
		hashMap.get(key).push(i);
	}
}

function nearbySegCount(x, y, radius) {
	let count = 0;
	const cells = Math.ceil(radius / CELL_SIZE);
	const cx = (x / CELL_SIZE) | 0;
	const cy = (y / CELL_SIZE) | 0;
	for (let dx = -cells; dx <= cells; dx++) {
		for (let dy = -cells; dy <= cells; dy++) {
			const key = (cx + dx) * 100000 + (cy + dy);
			const bucket = hashMap.get(key);
			if (bucket) count += bucket.length;
		}
	}
	return count;
}

// ─── UPDATE ──────────────────────────────────────────────────────────────────
function update(dt) {
	// Grow tips
	const activeTips = [];
	for (const tip of tips) {
		if (!tip.active) continue;
		if (segCount >= CONFIG.maxSegments) {
			tip.active = false;
			continue;
		}

		// Mouse influence
		const dx = mouse.x - tip.x;
		const dy = mouse.y - tip.y;
		const distMouse = Math.sqrt(dx * dx + dy * dy);
		const mouseInfluence =
			distMouse < CONFIG.mouseNutrientRadius ? 1 - distMouse / CONFIG.mouseNutrientRadius : 0;

		const speed = CONFIG.growthSpeed * (1 + mouseInfluence * (CONFIG.mouseGrowthBoost - 1));

		// Steer toward mouse slightly
		if (mouseInfluence > 0) {
			const toMouse = Math.atan2(dy, dx);
			let angleDiff = toMouse - tip.angle;
			while (angleDiff > Math.PI) angleDiff -= Math.PI * 2;
			while (angleDiff < -Math.PI) angleDiff += Math.PI * 2;
			tip.angle += angleDiff * 0.1 * mouseInfluence;
		}

		// Wander
		tip.angle += (Math.random() - 0.5) * CONFIG.growthAngleVariance;

		const nx = tip.x + Math.cos(tip.angle) * speed * dt;
		const ny = tip.y + Math.sin(tip.angle) * speed * dt;

		// Cull if off-screen
		if (nx < -50 || nx > width + 50 || ny < -50 || ny > height + 50) {
			tip.active = false;
			continue;
		}

		// Store segment
		const off = segCount * SEG_STRIDE;
		segments[off + 0] = tip.x;
		segments[off + 1] = tip.y;
		segments[off + 2] = nx;
		segments[off + 3] = ny;
		segments[off + 4] = 0; // age
		segments[off + 5] = tip.depth;
		segments[off + 6] = tip.layer;
		segments[off + 7] = tip.hue;
		segCount++;

		tip.x = nx;
		tip.y = ny;

		// Branching
		const branchProb =
			CONFIG.branchProbability * (1 + mouseInfluence * (CONFIG.mouseBranchBoost - 1));
		if (Math.random() < branchProb && tip.depth < CONFIG.maxBranchDepth && tips.length < MAX_TIPS) {
			const branchAngle = tip.angle + (Math.random() - 0.5) * CONFIG.branchAngleRange;
			tips.push({
				x: nx,
				y: ny,
				angle: branchAngle,
				depth: tip.depth + 1,
				layer: tip.layer,
				hue: tip.hue + (Math.random() - 0.5) * 10,
				active: true
			});
			// Store branch node
			if (nodeCount < MAX_NODES) {
				const noff = nodeCount * NODE_STRIDE;
				nodes[noff + 0] = nx;
				nodes[noff + 1] = ny;
				nodes[noff + 2] = 0;
				nodes[noff + 3] = tip.layer;
				nodeCount++;
			}
		}

		activeTips.push(tip);
	}

	// Age segments
	for (let i = 0; i < segCount; i++) {
		segments[i * SEG_STRIDE + 4] += dt;
	}
	for (let i = 0; i < nodeCount; i++) {
		nodes[i * NODE_STRIDE + 2] += dt;
	}

	// Spawn pulses
	if (segCount > 10 && pulses.length < MAX_PULSES) {
		if (Math.random() < CONFIG.pulseFrequency * dt) {
			pulses.push({
				segIndex: Math.floor(Math.random() * segCount),
				t: 0,
				speed: CONFIG.pulseSpeed,
				layer: Math.floor(Math.random() * CONFIG.layerCount)
			});
		}
	}

	// Update pulses
	for (let i = pulses.length - 1; i >= 0; i--) {
		pulses[i].t += CONFIG.pulseSpeed * dt;
		const si = pulses[i].segIndex;
		if (si >= segCount || pulses[i].t > 1) {
			// Move to next segment or remove
			const nextSeg = si + 1;
			if (nextSeg < segCount) {
				pulses[i].segIndex = nextSeg;
				pulses[i].t = 0;
			} else {
				pulses.splice(i, 1);
			}
		}
	}

	// Spore bursts from mature nodes
	for (let i = 0; i < nodeCount; i++) {
		const noff = i * NODE_STRIDE;
		if (nodes[noff + 2] > 5 && Math.random() < CONFIG.sporeBurstChance) {
			for (let s = 0; s < CONFIG.sporeCount && sporeCount < MAX_SPORES; s++) {
				const soff = sporeCount * SPORE_STRIDE;
				const angle = Math.random() * Math.PI * 2;
				spores[soff + 0] = nodes[noff + 0];
				spores[soff + 1] = nodes[noff + 1];
				spores[soff + 2] = Math.cos(angle) * CONFIG.sporeSpeed * (0.5 + Math.random());
				spores[soff + 3] = Math.sin(angle) * CONFIG.sporeSpeed * (0.5 + Math.random());
				spores[soff + 4] = CONFIG.sporeLifetime;
				spores[soff + 5] = CONFIG.sporeLifetime;
				spores[soff + 6] = nodes[noff + 3]; // layer
				sporeCount++;
			}
		}
	}

	// Update spores
	let aliveSpores = 0;
	for (let i = 0; i < sporeCount; i++) {
		const soff = i * SPORE_STRIDE;
		spores[soff + 0] += spores[soff + 2] * dt;
		spores[soff + 1] += spores[soff + 3] * dt;
		spores[soff + 4] -= dt;
		if (spores[soff + 4] > 0) {
			if (aliveSpores !== i) {
				const doff = aliveSpores * SPORE_STRIDE;
				for (let j = 0; j < SPORE_STRIDE; j++) spores[doff + j] = spores[soff + j];
			}
			aliveSpores++;
		}
	}
	sporeCount = aliveSpores;
}

// ─── DRAW ────────────────────────────────────────────────────────────────────
function draw() {
	// Trail overlay
	ctx.fillStyle = `rgba(0,0,0,${CONFIG.trailAlpha})`;
	ctx.fillRect(0, 0, width, height);

	// Draw per layer (back to front)
	for (let layer = CONFIG.layerCount - 1; layer >= 0; layer--) {
		const layerAlpha = 1 - (layer / CONFIG.layerCount) * (1 - CONFIG.layerAlphaScale);

		// Glow passes
		ctx.globalCompositeOperation = 'lighter';
		for (let pass = 0; pass < CONFIG.glowPasses; pass++) {
			const extraW = (pass + 1) * CONFIG.glowExpand;
			const gAlpha = CONFIG.glowAlpha / (pass + 1);
			drawSegments(layer, layerAlpha * gAlpha, CONFIG.hyphaWidth + extraW);
		}

		// Solid pass
		ctx.globalCompositeOperation = 'source-over';
		drawSegments(layer, layerAlpha, CONFIG.hyphaWidth);

		// Nodes
		drawNodes(layer, layerAlpha);

		// Pulses
		drawPulses(layer, layerAlpha);

		// Spores
		drawSpores(layer, layerAlpha);
	}
}

function drawSegments(layer, alphaScale, lineWidth) {
	ctx.lineWidth = lineWidth;
	ctx.lineCap = 'round';

	// Batch by similar hue for fewer style changes
	for (let i = 0; i < segCount; i++) {
		const off = i * SEG_STRIDE;
		if (segments[off + 6] !== layer) continue;

		const age = segments[off + 4];
		const depth = segments[off + 5];
		const hue = segments[off + 7];
		const fade = Math.max(0, 1 - age * CONFIG.fadeRate);
		const depthFade = 1 / (1 + depth * 0.15);
		const alpha = CONFIG.hyphaAlpha * fade * depthFade * alphaScale;

		if (alpha < 0.005) continue;

		ctx.beginPath();
		ctx.moveTo(segments[off + 0], segments[off + 1]);
		ctx.lineTo(segments[off + 2], segments[off + 3]);
		ctx.strokeStyle = `hsla(${hue | 0},70%,60%,${alpha.toFixed(3)})`;
		ctx.stroke();
	}
}

function drawNodes(layer, alphaScale) {
	ctx.globalCompositeOperation = 'lighter';
	for (let i = 0; i < nodeCount; i++) {
		const noff = i * NODE_STRIDE;
		if (nodes[noff + 3] !== layer) continue;

		const alpha = CONFIG.nodeGlowAlpha * alphaScale;
		if (alpha < 0.005) continue;

		ctx.beginPath();
		ctx.arc(nodes[noff + 0], nodes[noff + 1], CONFIG.nodeGlowRadius, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue},80%,70%,${alpha.toFixed(3)})`;
		ctx.fill();
	}
	ctx.globalCompositeOperation = 'source-over';
}

function drawPulses(layer, alphaScale) {
	ctx.globalCompositeOperation = 'lighter';
	for (const pulse of pulses) {
		if (pulse.layer !== layer) continue;
		const si = pulse.segIndex;
		if (si >= segCount) continue;
		const off = si * SEG_STRIDE;
		const t = pulse.t;
		const px = segments[off + 0] + (segments[off + 2] - segments[off + 0]) * t;
		const py = segments[off + 1] + (segments[off + 3] - segments[off + 1]) * t;

		// Outer glow
		ctx.beginPath();
		ctx.arc(px, py, CONFIG.pulseGlow, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue + 30},90%,80%,${(0.15 * alphaScale).toFixed(3)})`;
		ctx.fill();

		// Core
		ctx.beginPath();
		ctx.arc(px, py, CONFIG.pulseSize, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue + 30},90%,90%,${(0.7 * alphaScale).toFixed(3)})`;
		ctx.fill();
	}
	ctx.globalCompositeOperation = 'source-over';
}

function drawSpores(layer, alphaScale) {
	for (let i = 0; i < sporeCount; i++) {
		const soff = i * SPORE_STRIDE;
		if (spores[soff + 6] !== layer) continue;
		const life = spores[soff + 4];
		const maxLife = spores[soff + 5];
		const alpha = (life / maxLife) * 0.5 * alphaScale;
		if (alpha < 0.005) continue;
		const r = 1.5 * (life / maxLife);

		ctx.beginPath();
		ctx.arc(spores[soff + 0], spores[soff + 1], r, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue + 40},60%,80%,${alpha.toFixed(3)})`;
		ctx.fill();
	}
}

// ─── ANIMATION LOOP ─────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) {
			requestAnimationFrame(render);
			return;
		}
		now *= 0.001;
		const dt = lastTime ? Math.min(now - lastTime, 0.05) : 0.016;
		lastTime = now;

		update(dt);
		draw();

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── MESSAGE HANDLER ─────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Nebula Clouds
 * Description: Soft, slowly drifting colored cloud formations using layered circles with very low
 *              opacity and large radii. Colors are deep purples, blues, and pinks.
 *              Mouse proximity causes nearby clouds to gently disperse.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let clouds = [];
let time = 0;

const CLOUD_COUNT = 45;
const MOUSE_RADIUS = 200;
const MOUSE_FORCE = 0.8;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Nebula palette: deep purples, blues, pinks
const NEBULA_COLORS = [
	{ r: 80, g: 40, b: 160 }, // deep purple
	{ r: 40, g: 60, b: 180 }, // deep blue
	{ r: 160, g: 50, b: 120 }, // magenta-pink
	{ r: 60, g: 30, b: 140 }, // violet
	{ r: 100, g: 60, b: 200 }, // lavender
	{ r: 30, g: 80, b: 160 }, // royal blue
	{ r: 180, g: 60, b: 160 }, // hot pink
	{ r: 50, g: 50, b: 120 } // dark indigo
];

class Cloud {
	constructor() {
		this.reset(true);
	}

	reset(initial = false) {
		this.x = Math.random() * width;
		this.y = Math.random() * height;
		this.radius = 80 + Math.random() * 200;
		this.baseRadius = this.radius;
		this.vx = (Math.random() - 0.5) * 0.15;
		this.vy = (Math.random() - 0.5) * 0.1;
		this.color = NEBULA_COLORS[Math.floor(Math.random() * NEBULA_COLORS.length)];
		this.opacity = 0.015 + Math.random() * 0.03;
		this.phase = Math.random() * Math.PI * 2;
		this.pulseSpeed = 0.005 + Math.random() * 0.01;
		this.layers = 2 + Math.floor(Math.random() * 3); // 2-4 sub-layers
		// Dispersion offset from mouse interaction
		this.offsetX = 0;
		this.offsetY = 0;
	}

	update() {
		// Gentle drift
		this.x += this.vx;
		this.y += this.vy;

		// Breathing pulse
		this.radius = this.baseRadius + Math.sin(time * this.pulseSpeed + this.phase) * 15;

		// Wrap around edges with buffer
		const buffer = this.radius * 2;
		if (this.x < -buffer) this.x = width + buffer;
		if (this.x > width + buffer) this.x = -buffer;
		if (this.y < -buffer) this.y = height + buffer;
		if (this.y > height + buffer) this.y = -buffer;

		// Mouse dispersal
		const dx = this.x + this.offsetX - mouse.x;
		const dy = this.y + this.offsetY - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);

		if (dist < MOUSE_RADIUS && dist > 0) {
			const force = (1 - dist / MOUSE_RADIUS) * MOUSE_FORCE;
			this.offsetX += (dx / dist) * force;
			this.offsetY += (dy / dist) * force;
		}

		// Smoothly return offset to zero
		this.offsetX *= 0.97;
		this.offsetY *= 0.97;
	}

	draw() {
		const drawX = this.x + this.offsetX;
		const drawY = this.y + this.offsetY;
		const { r, g, b } = this.color;

		// Draw multiple concentric layers for soft cloud effect
		for (let i = this.layers; i >= 0; i--) {
			const layerRadius = this.radius * (0.4 + i * 0.25);
			const layerOpacity = this.opacity * (1 - i * 0.2);

			const gradient = ctx.createRadialGradient(drawX, drawY, 0, drawX, drawY, layerRadius);
			gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${layerOpacity})`);
			gradient.addColorStop(0.4, `rgba(${r}, ${g}, ${b}, ${layerOpacity * 0.6})`);
			gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			ctx.beginPath();
			ctx.arc(drawX, drawY, layerRadius, 0, Math.PI * 2);
			ctx.fillStyle = gradient;
			ctx.fill();
		}
	}
}

function initClouds() {
	clouds = [];
	for (let i = 0; i < CLOUD_COUNT; i++) {
		clouds.push(new Cloud());
	}
}

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time += 1;

		// Sort by radius for depth ordering (smaller = further back)
		clouds.sort((a, b) => a.baseRadius - b.baseRadius);

		for (const cloud of clouds) {
			cloud.update();
			cloud.draw();
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initClouds();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initClouds();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Neon Dreamscape
 * Description: Paint persistent glowing neon tube trails by moving your mouse.
 *   Trails pulse with light, slowly fade leaving ghost impressions, and cast an
 *   ambient fog glow. Mouse speed affects stroke width. Color cycles through a
 *   configurable palette. Cyberpunk neon sign energy.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Trail Color --
  trailColor: '#ff00ff',                  // Primary neon color (when not cycling)
  colorCycle: true,                       // Cycle through palette over time
  colorPalette: [                         // Colors to cycle through
    '#ff00ff', '#00ffff', '#ff3366',
    '#33ff99', '#ff9900', '#6633ff',
  ],
  colorCycleSpeed: 0.4,                   // Palette cycle speed (0.1-3)

  // -- Glow Rendering --
  glowRadius: 28,                         // Outer aura size in px (10-60)
  glowIntensity: 1.4,                     // Glow brightness multiplier (0.5-3)
  coreWidth: 2.5,                         // Bright center line width in px (1-6)

  // -- Trail Behavior --
  trailFadeSpeed: 0.006,                  // How fast trails disappear (0.001-0.05)
  trailGhostOpacity: 0.02,               // Minimum opacity of faded trails (0-0.1)
  maxTrailPoints: 600,                    // Max points stored per active trail

  // -- Pulse & Flicker --
  pulseSpeed: 1.2,                        // Brightness pulse frequency (0-5)
  pulseAmount: 0.18,                      // Pulse amplitude (0-0.5)
  flickerEnabled: true,                   // Random brightness drops
  flickerIntensity: 0.35,                 // Flicker depth (0-0.8)

  // -- Ambient --
  ambientFog: true,                       // Background fog tinted by neon
  fogColor: '#1a0030',                    // Fog base tint
  fogOpacity: 0.025,                      // Fog density per frame (0.005-0.1)
  speedWidthEffect: 1.0,                  // Speed \u2192 width mapping (0-2, 0=constant width)
  backgroundColor: '#050510',             // Deep background color
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let prevMouse = { x: -1, y: -1 };
let time = 0;
let trails = []; // array of completed trails
let activeTrail = null; // currently being drawn
let isDrawing = false;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function hexToRgb(hex) {
  return [parseInt(hex.slice(1, 3), 16), parseInt(hex.slice(3, 5), 16), parseInt(hex.slice(5, 7), 16)];
}

function getCurrentColor() {
  if (!CONFIG.colorCycle) return hexToRgb(CONFIG.trailColor);
  const pal = CONFIG.colorPalette;
  const t = (time * CONFIG.colorCycleSpeed) % pal.length;
  const i0 = Math.floor(t) % pal.length;
  const i1 = (i0 + 1) % pal.length;
  const f = t - Math.floor(t);
  const c0 = hexToRgb(pal[i0]), c1 = hexToRgb(pal[i1]);
  return [
    c0[0] + (c1[0] - c0[0]) * f,
    c0[1] + (c1[1] - c0[1]) * f,
    c0[2] + (c1[2] - c0[2]) * f,
  ];
}

class Trail {
  constructor() {
    this.points = []; // {x, y, color, width}
    this.opacity = 1;
    this.birthTime = time;
  }

  addPoint(x, y, color, w) {
    this.points.push({ x, y, color, width: w });
    if (this.points.length > CONFIG.maxTrailPoints) this.points.shift();
  }

  draw(globalFlicker) {
    if (this.points.length < 2) return;
    const pts = this.points;
    const pulse = 1 + Math.sin(time * CONFIG.pulseSpeed * 6 + this.birthTime * 3) * CONFIG.pulseAmount;
    const alpha = this.opacity * pulse * globalFlicker;
    if (alpha < 0.001) return;

    // Pass 1: Outer aura glow
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    const gr = CONFIG.glowRadius * CONFIG.glowIntensity;

    ctx.beginPath();
    ctx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i++) {
      if (i < pts.length - 1) {
        const mx = (pts[i].x + pts[i + 1].x) * 0.5;
        const my = (pts[i].y + pts[i + 1].y) * 0.5;
        ctx.quadraticCurveTo(pts[i].x, pts[i].y, mx, my);
      } else {
        ctx.lineTo(pts[i].x, pts[i].y);
      }
    }

    // Outer glow (widest, dimmest)
    const c = pts[Math.floor(pts.length / 2)].color;
    ctx.strokeStyle = `rgba(${c[0]|0},${c[1]|0},${c[2]|0},${alpha * 0.06})`;
    ctx.lineWidth = gr;
    ctx.stroke();

    // Mid glow
    ctx.strokeStyle = `rgba(${c[0]|0},${c[1]|0},${c[2]|0},${alpha * 0.15})`;
    ctx.lineWidth = gr * 0.45;
    ctx.stroke();

    // Colored core
    ctx.strokeStyle = `rgba(${c[0]|0},${c[1]|0},${c[2]|0},${alpha * 0.6})`;
    ctx.lineWidth = CONFIG.coreWidth * 2.5;
    ctx.stroke();

    // White-hot center
    ctx.strokeStyle = `rgba(255,255,255,${alpha * 0.7})`;
    ctx.lineWidth = CONFIG.coreWidth;
    ctx.stroke();
  }
}

function startAnimation() {
  const bgRgb = hexToRgb(CONFIG.backgroundColor);
  const fogRgb = hexToRgb(CONFIG.fogColor);

  function render() {
    if (!ctx) return;
    time += 0.016;

    // -- Background fade (creates trail persistence) --
    ctx.fillStyle = `rgba(${bgRgb[0]},${bgRgb[1]},${bgRgb[2]},${CONFIG.trailFadeSpeed * 3})`;
    ctx.fillRect(0, 0, width, height);

    // -- Ambient fog --
    if (CONFIG.ambientFog) {
      ctx.fillStyle = `rgba(${fogRgb[0]},${fogRgb[1]},${fogRgb[2]},${CONFIG.fogOpacity})`;
      ctx.fillRect(0, 0, width, height);

      // Fog glow around active trail tip
      if (activeTrail && activeTrail.points.length > 0) {
        const tip = activeTrail.points[activeTrail.points.length - 1];
        const c = tip.color;
        const fogGlow = ctx.createRadialGradient(tip.x, tip.y, 0, tip.x, tip.y, 120);
        fogGlow.addColorStop(0, `rgba(${c[0]|0},${c[1]|0},${c[2]|0},0.03)`);
        fogGlow.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = fogGlow;
        ctx.fillRect(tip.x - 120, tip.y - 120, 240, 240);
      }
    }

    // -- Flicker calculation --
    let flicker = 1;
    if (CONFIG.flickerEnabled) {
      if (Math.random() < 0.06) {
        flicker = 1 - CONFIG.flickerIntensity * Math.random();
      }
    }

    // -- Detect drawing --
    const mouseValid = mouse.x >= 0 && mouse.y >= 0 && mouse.x <= width && mouse.y <= height;
    const moved = mouseValid && (Math.abs(mouse.x - prevMouse.x) > 0.5 || Math.abs(mouse.y - prevMouse.y) > 0.5);

    if (moved) {
      const dx = mouse.x - prevMouse.x;
      const dy = mouse.y - prevMouse.y;
      const speed = Math.sqrt(dx * dx + dy * dy);

      // Width inversely proportional to speed
      const maxW = CONFIG.coreWidth * 4;
      const minW = CONFIG.coreWidth * 0.8;
      const speedFactor = Math.min(1, speed / 30) * CONFIG.speedWidthEffect;
      const w = maxW - (maxW - minW) * speedFactor;

      if (!isDrawing) {
        // Start new trail
        activeTrail = new Trail();
        isDrawing = true;
      }

      const color = getCurrentColor();
      activeTrail.addPoint(mouse.x, mouse.y, color, w);
    } else if (isDrawing && !moved) {
      // Mouse stopped — finalize trail
      if (activeTrail && activeTrail.points.length > 1) {
        trails.push(activeTrail);
      }
      activeTrail = null;
      isDrawing = false;
    }

    prevMouse.x = mouse.x;
    prevMouse.y = mouse.y;

    // -- Fade and draw old trails --
    for (let i = trails.length - 1; i >= 0; i--) {
      trails[i].opacity -= CONFIG.trailFadeSpeed * 0.3;
      if (trails[i].opacity <= CONFIG.trailGhostOpacity) {
        trails[i].opacity = CONFIG.trailGhostOpacity;
        // Remove truly dead trails
        if (trails[i].opacity < 0.005) {
          trails.splice(i, 1);
          continue;
        }
      }
      trails[i].draw(flicker);
    }

    // -- Draw active trail --
    if (activeTrail) {
      activeTrail.draw(flicker);
    }

    // -- Trim old trails to prevent memory buildup --
    if (trails.length > 40) {
      trails.splice(0, trails.length - 30);
    }

    requestAnimationFrame(render);
  }

  // Initial background fill
  ctx.fillStyle = CONFIG.backgroundColor;
  ctx.fillRect(0, 0, width, height);

  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      ctx.fillStyle = CONFIG.backgroundColor;
      ctx.fillRect(0, 0, width, height);
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Neural Network
 * Description: Visualization of connected nodes in layers with pulses of light traveling
 *   along connections. Nodes glow when activated. The network slowly reorganizes.
 *   Mouse adds energy to the nearest node, triggering cascading activations.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

let layers = [];
let connections = [];
let pulses = [];

const LAYER_COUNT = 5;
const NODE_RADIUS = 4;
const MAX_PULSES = 80;
const REORGANIZE_SPEED = 0.002;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initNetwork();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initNetwork();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function initNetwork() {
	layers = [];
	connections = [];
	pulses = [];

	// Create layers with varying node counts
	const nodeCounts = [];
	for (let l = 0; l < LAYER_COUNT; l++) {
		if (l === 0 || l === LAYER_COUNT - 1) {
			nodeCounts.push(3 + Math.floor(Math.random() * 3));
		} else {
			nodeCounts.push(5 + Math.floor(Math.random() * 5));
		}
	}

	const layerSpacing = width / (LAYER_COUNT + 1);

	for (let l = 0; l < LAYER_COUNT; l++) {
		const layer = [];
		const count = nodeCounts[l];
		const nodeSpacing = height / (count + 1);
		const baseX = layerSpacing * (l + 1);

		for (let n = 0; n < count; n++) {
			const baseY = nodeSpacing * (n + 1);
			layer.push({
				x: baseX,
				y: baseY,
				targetX: baseX + (Math.random() - 0.5) * 30,
				targetY: baseY + (Math.random() - 0.5) * 20,
				energy: 0, // 0-1 glow intensity
				layer: l,
				index: n,
				driftPhase: Math.random() * Math.PI * 2
			});
		}
		layers.push(layer);
	}

	// Create connections between adjacent layers (not fully connected — sparse)
	for (let l = 0; l < LAYER_COUNT - 1; l++) {
		const fromLayer = layers[l];
		const toLayer = layers[l + 1];

		for (const from of fromLayer) {
			// Connect to 1-3 nodes in the next layer
			const connectCount = 1 + Math.floor(Math.random() * Math.min(3, toLayer.length));
			const targets = shuffleArray([...toLayer]).slice(0, connectCount);

			for (const to of targets) {
				connections.push({
					from: from,
					to: to,
					weight: 0.3 + Math.random() * 0.7,
					opacity: 0.06 + Math.random() * 0.08
				});
			}
		}
	}
}

function shuffleArray(arr) {
	for (let i = arr.length - 1; i > 0; i--) {
		const j = Math.floor(Math.random() * (i + 1));
		[arr[i], arr[j]] = [arr[j], arr[i]];
	}
	return arr;
}

function spawnPulse(connection) {
	if (pulses.length >= MAX_PULSES) return;
	pulses.push({
		conn: connection,
		progress: 0,
		speed: 0.008 + Math.random() * 0.012,
		brightness: 0.4 + Math.random() * 0.6
	});
}

function startAnimation() {
	let lastMouseActivation = 0;
	let spontaneousTimer = 0;

	function render(time) {
		if (!ctx) return;

		ctx.clearRect(0, 0, width, height);

		// Slow reorganization — nodes drift toward new targets
		for (const layer of layers) {
			for (const node of layer) {
				// Gentle sine-based drift
				node.driftPhase += REORGANIZE_SPEED;
				const drift = Math.sin(node.driftPhase) * 15;
				const driftY = Math.cos(node.driftPhase * 0.7) * 10;

				node.x += (node.targetX + drift - node.x) * 0.01;
				node.y += (node.targetY + driftY - node.y) * 0.01;

				// Decay energy
				node.energy *= 0.97;
			}
		}

		// Mouse interaction — energize nearest node
		if (time - lastMouseActivation > 200) {
			let nearest = null;
			let nearestDist = Infinity;

			for (const layer of layers) {
				for (const node of layer) {
					const dx = node.x - mouse.x;
					const dy = node.y - mouse.y;
					const dist = dx * dx + dy * dy;
					if (dist < nearestDist) {
						nearestDist = dist;
						nearest = node;
					}
				}
			}

			if (nearest && nearestDist < 200 * 200) {
				nearest.energy = Math.min(1, nearest.energy + 0.5);
				// Fire pulses along outgoing connections
				for (const conn of connections) {
					if (conn.from === nearest && Math.random() < 0.6) {
						spawnPulse(conn);
					}
				}
				lastMouseActivation = time;
			}
		}

		// Spontaneous firing
		spontaneousTimer++;
		if (spontaneousTimer > 60) {
			spontaneousTimer = 0;
			// Pick a random input node to fire
			const inputLayer = layers[0];
			const node = inputLayer[Math.floor(Math.random() * inputLayer.length)];
			node.energy = Math.min(1, node.energy + 0.3);

			for (const conn of connections) {
				if (conn.from === node && Math.random() < 0.4) {
					spawnPulse(conn);
				}
			}
		}

		// Draw connections
		for (const conn of connections) {
			ctx.beginPath();
			ctx.moveTo(conn.from.x, conn.from.y);
			ctx.lineTo(conn.to.x, conn.to.y);

			// Brighter if either node is energized
			const energyBoost = Math.max(conn.from.energy, conn.to.energy) * 0.2;
			ctx.strokeStyle = `rgba(100, 160, 255, ${conn.opacity + energyBoost})`;
			ctx.lineWidth = 0.8 + conn.weight * 0.5;
			ctx.stroke();
		}

		// Update and draw pulses
		for (let i = pulses.length - 1; i >= 0; i--) {
			const p = pulses[i];
			p.progress += p.speed;

			if (p.progress >= 1) {
				// Pulse arrived — energize target node and cascade
				p.conn.to.energy = Math.min(1, p.conn.to.energy + 0.3 * p.brightness);

				// Cascade: fire from the target node (with diminishing probability)
				if (p.brightness > 0.2) {
					for (const conn of connections) {
						if (conn.from === p.conn.to && Math.random() < 0.35) {
							if (pulses.length < MAX_PULSES) {
								pulses.push({
									conn: conn,
									progress: 0,
									speed: 0.008 + Math.random() * 0.012,
									brightness: p.brightness * 0.7
								});
							}
						}
					}
				}

				pulses.splice(i, 1);
				continue;
			}

			// Interpolate position
			const px = p.conn.from.x + (p.conn.to.x - p.conn.from.x) * p.progress;
			const py = p.conn.from.y + (p.conn.to.y - p.conn.from.y) * p.progress;

			ctx.beginPath();
			ctx.arc(px, py, 2.5, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(140, 200, 255, ${p.brightness * 0.7})`;
			ctx.shadowColor = `rgba(100, 180, 255, ${p.brightness * 0.5})`;
			ctx.shadowBlur = 8;
			ctx.fill();
			ctx.shadowBlur = 0;
		}

		// Draw nodes
		for (const layer of layers) {
			for (const node of layer) {
				const glow = node.energy;

				// Outer glow
				if (glow > 0.05) {
					ctx.beginPath();
					ctx.arc(node.x, node.y, NODE_RADIUS + 6, 0, Math.PI * 2);
					ctx.fillStyle = `rgba(100, 180, 255, ${glow * 0.15})`;
					ctx.fill();
				}

				// Node body
				ctx.beginPath();
				ctx.arc(node.x, node.y, NODE_RADIUS, 0, Math.PI * 2);
				const baseAlpha = 0.15 + glow * 0.6;
				ctx.fillStyle = `rgba(120, 180, 255, ${baseAlpha})`;
				ctx.fill();

				// Bright center when energized
				if (glow > 0.1) {
					ctx.beginPath();
					ctx.arc(node.x, node.y, NODE_RADIUS * 0.5, 0, Math.PI * 2);
					ctx.fillStyle = `rgba(200, 230, 255, ${glow * 0.5})`;
					ctx.shadowColor = `rgba(120, 200, 255, ${glow * 0.4})`;
					ctx.shadowBlur = 10;
					ctx.fill();
					ctx.shadowBlur = 0;
				}
			}
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Northern Lights Curtain
 * Description: Vertical curtains of shimmering aurora light that sway horizontally.
 *   Layered vertical bands with colors shifting between green, cyan, and magenta.
 *   They shimmer with varying brightness. Mouse position pushes curtains aside.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let curtains = [];
let shimmerPoints = [];

const NUM_CURTAINS = 8;
const SHIMMER_POINTS = 25;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class AuroraCurtain {
	constructor(index, total) {
		this.index = index;
		this.total = total;
		// Base X position spread across the screen
		this.baseX = 0;
		this.recalc();
		// Sway parameters
		this.swayPhase = Math.random() * Math.PI * 2;
		this.swaySpeed = 0.003 + Math.random() * 0.004;
		this.swayAmplitude = 30 + Math.random() * 50;
		// Secondary sway for organic movement
		this.sway2Phase = Math.random() * Math.PI * 2;
		this.sway2Speed = 0.007 + Math.random() * 0.005;
		this.sway2Amplitude = 10 + Math.random() * 20;
		// Color cycling
		this.colorPhase = (index / total) * Math.PI * 2;
		this.colorSpeed = 0.002 + Math.random() * 0.003;
		// Brightness
		this.baseBrightness = 0.06 + Math.random() * 0.06;
		this.brightness = this.baseBrightness;
		this.brightTarget = this.baseBrightness;
		this.shimmerTimer = Math.random() * 200;
		// Width of this curtain band
		this.bandWidth = 40 + Math.random() * 60;
		// Vertical extent — most curtains don't reach the bottom
		this.topY = 0;
		this.bottomFraction = 0.4 + Math.random() * 0.45; // extends 40-85% down
		// Number of control points for the curtain shape
		this.numPoints = 12 + Math.floor(Math.random() * 6);
	}

	recalc() {
		const spacing = (width || 800) / (this.total + 1);
		this.baseX = spacing * (this.index + 1);
	}

	getSwayOffset(y, t) {
		// Sway increases toward the bottom (curtain drapes from top)
		const yFactor = y / (height || 600);
		const sway1 = Math.sin(t * this.swaySpeed + this.swayPhase + y * 0.003) * this.swayAmplitude;
		const sway2 = Math.sin(t * this.sway2Speed + this.sway2Phase + y * 0.005) * this.sway2Amplitude;
		return (sway1 + sway2) * yFactor;
	}

	getMousePush(x, y) {
		const dx = x - mouse.x;
		const dy = y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		const pushRadius = 200;
		if (dist < pushRadius && dist > 0) {
			const strength = 1 - dist / pushRadius;
			return (dx / dist) * strength * strength * 80;
		}
		return 0;
	}

	update(t) {
		// Shimmer — occasional brightness pulse
		this.shimmerTimer++;
		if (this.shimmerTimer > 100 + Math.random() * 200) {
			this.shimmerTimer = 0;
			this.brightTarget = this.baseBrightness + 0.04 + Math.random() * 0.08;
		}
		this.brightness += (this.brightTarget - this.brightness) * 0.02;
		this.brightTarget += (this.baseBrightness - this.brightTarget) * 0.005;
	}

	draw(ctx, t) {
		const bottomY = height * this.bottomFraction;
		const step = bottomY / this.numPoints;

		// Aurora colors: cycle between green (120), cyan (180), magenta (300)
		const colorT = t * this.colorSpeed + this.colorPhase;
		// Use sine to smoothly cycle through 3 hue anchors
		const hueBase = this.getAuroraHue(colorT);

		// Build left and right edges of the curtain
		const leftPoints = [];
		const rightPoints = [];

		for (let i = 0; i <= this.numPoints; i++) {
			const y = this.topY + i * step;
			const sway = this.getSwayOffset(y, t);
			const push = this.getMousePush(this.baseX + sway, y);
			const x = this.baseX + sway + push;

			// Width varies along height for organic shape
			const widthMod = 0.6 + 0.4 * Math.sin(i * 0.8 + t * 0.005);
			const halfW = (this.bandWidth * widthMod) / 2;

			leftPoints.push({ x: x - halfW, y });
			rightPoints.push({ x: x + halfW, y });
		}

		// Draw curtain as a filled shape with gradient
		ctx.beginPath();
		// Left edge (top to bottom)
		ctx.moveTo(leftPoints[0].x, leftPoints[0].y);
		for (let i = 1; i < leftPoints.length; i++) {
			const prev = leftPoints[i - 1];
			const curr = leftPoints[i];
			const cpx = (prev.x + curr.x) / 2;
			const cpy = (prev.y + curr.y) / 2;
			ctx.quadraticCurveTo(prev.x, prev.y, cpx, cpy);
		}
		ctx.lineTo(leftPoints[leftPoints.length - 1].x, leftPoints[leftPoints.length - 1].y);

		// Right edge (bottom to top)
		for (let i = rightPoints.length - 1; i >= 0; i--) {
			const curr = rightPoints[i];
			const next = i > 0 ? rightPoints[i - 1] : rightPoints[0];
			const cpx = (curr.x + next.x) / 2;
			const cpy = (curr.y + next.y) / 2;
			ctx.quadraticCurveTo(curr.x, curr.y, cpx, cpy);
		}
		ctx.closePath();

		// Vertical gradient — bright at top, fading out at bottom
		const midX = this.baseX + this.getSwayOffset(bottomY / 2, t);
		const grad = ctx.createLinearGradient(midX, this.topY, midX, bottomY);
		const alpha = this.brightness;
		const hue1 = hueBase;
		const hue2 = hueBase + 30;
		grad.addColorStop(0, `hsla(${hue1}, 80%, 65%, ${alpha * 1.2})`);
		grad.addColorStop(0.3, `hsla(${hue1}, 70%, 55%, ${alpha})`);
		grad.addColorStop(0.6, `hsla(${hue2}, 60%, 45%, ${alpha * 0.6})`);
		grad.addColorStop(1, `hsla(${hue2}, 50%, 35%, 0)`);

		ctx.fillStyle = grad;
		ctx.fill();

		// Inner glow line for shimmer
		ctx.beginPath();
		for (let i = 0; i <= this.numPoints; i++) {
			const y = this.topY + i * step;
			const sway = this.getSwayOffset(y, t);
			const push = this.getMousePush(this.baseX + sway, y);
			const x = this.baseX + sway + push;
			if (i === 0) {
				ctx.moveTo(x, y);
			} else {
				const prevY = this.topY + (i - 1) * step;
				const prevSway = this.getSwayOffset(prevY, t);
				const prevPush = this.getMousePush(this.baseX + prevSway, prevY);
				const prevX = this.baseX + prevSway + prevPush;
				ctx.quadraticCurveTo(prevX, prevY, (prevX + x) / 2, (prevY + y) / 2);
			}
		}
		ctx.strokeStyle = `hsla(${hue1}, 90%, 75%, ${alpha * 0.5})`;
		ctx.lineWidth = 1.5;
		ctx.stroke();
	}

	getAuroraHue(t) {
		// Cycle between green (120), cyan (180), magenta (300)
		const hues = [120, 180, 300, 120];
		const idx = ((t % (Math.PI * 2)) / (Math.PI * 2)) * 3;
		const i = Math.floor(idx) % 3;
		const frac = idx - Math.floor(idx);
		return hues[i] + (hues[i + 1] - hues[i]) * frac;
	}
}

class ShimmerPoint {
	constructor() {
		this.reset();
	}

	reset() {
		this.x = Math.random() * (width || 800);
		this.y = Math.random() * (height || 600) * 0.6;
		this.radius = 1 + Math.random() * 2;
		this.opacity = 0;
		this.maxOpacity = 0.05 + Math.random() * 0.1;
		this.fadeIn = true;
		this.speed = 0.002 + Math.random() * 0.004;
	}

	update() {
		if (this.fadeIn) {
			this.opacity += this.speed;
			if (this.opacity >= this.maxOpacity) {
				this.fadeIn = false;
			}
		} else {
			this.opacity -= this.speed;
			if (this.opacity <= 0) {
				this.reset();
			}
		}
	}

	draw(ctx) {
		if (this.opacity <= 0) return;
		const grad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.radius * 4);
		grad.addColorStop(0, `rgba(200, 255, 220, ${this.opacity})`);
		grad.addColorStop(1, 'rgba(200, 255, 220, 0)');
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.radius * 4, 0, Math.PI * 2);
		ctx.fillStyle = grad;
		ctx.fill();
	}
}

function initCurtains() {
	curtains = [];
	for (let i = 0; i < NUM_CURTAINS; i++) {
		curtains.push(new AuroraCurtain(i, NUM_CURTAINS));
	}
	shimmerPoints = [];
	for (let i = 0; i < SHIMMER_POINTS; i++) {
		shimmerPoints.push(new ShimmerPoint());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initCurtains();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			for (const c of curtains) {
				c.recalc();
			}
			shimmerPoints.forEach((s) => s.reset());
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time++;

		// Draw curtains
		for (const curtain of curtains) {
			curtain.update(time);
			curtain.draw(ctx, time);
		}

		// Draw shimmer points (star-like sparkles in the aurora)
		for (const sp of shimmerPoints) {
			sp.update();
			sp.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Ocean Waves
 * Description: Layered horizontal wave patterns at different depths, creating an
 *   ocean surface viewed from below. Deep blues and teals with varying opacity.
 *   Mouse position creates a swell/disturbance in the nearest wave layer.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let layers = [];

const NUM_LAYERS = 5;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class WaveLayer {
	constructor(index, total) {
		// Depth: 0 = deepest/back, total-1 = shallowest/front
		this.depth = index / (total - 1); // 0..1
		this.yBase = 0;
		this.amplitude = 0;
		this.frequency = 0;
		this.speed = 0;
		this.phase = Math.random() * Math.PI * 2;
		this.secondaryFreq = 0;
		this.secondaryAmp = 0;
		this.recalc(index, total);
	}

	recalc(index, total) {
		// Position layers from top ~30% to bottom ~80% of screen
		const t = index / (total - 1);
		this.yBase = height * (0.25 + t * 0.55);
		this.amplitude = 15 + t * 25;
		this.frequency = 0.003 + (1 - t) * 0.004;
		this.speed = 0.008 + (1 - t) * 0.012;
		this.secondaryFreq = this.frequency * 2.3;
		this.secondaryAmp = this.amplitude * 0.3;
		// Color — deep layers are darker and more blue, shallow are lighter and teal
		const hue = 200 + t * 20; // 200 (deep blue) to 220 (teal-ish)
		const lightness = 15 + t * 20;
		const alpha = 0.08 + t * 0.12;
		this.color = `hsla(${hue}, 70%, ${lightness}%, ${alpha})`;
		this.highlightColor = `hsla(${hue - 10}, 60%, ${lightness + 15}%, ${alpha * 0.5})`;
	}

	getY(x, t, mouseInfluence) {
		// Primary wave
		let y =
			this.yBase + Math.sin(x * this.frequency + t * this.speed + this.phase) * this.amplitude;
		// Secondary harmonic
		y +=
			Math.sin(x * this.secondaryFreq + t * this.speed * 1.5 + this.phase * 2) * this.secondaryAmp;
		// Tertiary ripple for realism
		y += Math.sin(x * this.frequency * 4.7 + t * this.speed * 0.7) * this.amplitude * 0.08;
		// Mouse swell disturbance
		y += mouseInfluence;
		return y;
	}

	getMouseInfluence(x) {
		const dx = x - mouse.x;
		const dy = this.yBase - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		const influenceRadius = 250;
		if (dist < influenceRadius) {
			const strength = 1 - dist / influenceRadius;
			// Push wave away from mouse — creates a swell
			return -strength * strength * 40 * (1 - this.depth * 0.5);
		}
		return 0;
	}

	draw(ctx, t) {
		const step = 4; // pixel step for performance
		ctx.beginPath();
		ctx.moveTo(0, height);

		for (let x = 0; x <= width; x += step) {
			const mi = this.getMouseInfluence(x);
			const y = this.getY(x, t, mi);
			ctx.lineTo(x, y);
		}

		ctx.lineTo(width, height);
		ctx.closePath();
		ctx.fillStyle = this.color;
		ctx.fill();

		// Draw highlight line along the wave crest
		ctx.beginPath();
		for (let x = 0; x <= width; x += step) {
			const mi = this.getMouseInfluence(x);
			const y = this.getY(x, t, mi);
			if (x === 0) {
				ctx.moveTo(x, y);
			} else {
				ctx.lineTo(x, y);
			}
		}
		ctx.strokeStyle = this.highlightColor;
		ctx.lineWidth = 1.5;
		ctx.stroke();
	}
}

// Foam/bubble particles for surface detail
class Bubble {
	constructor() {
		this.reset();
	}

	reset() {
		this.x = Math.random() * (width || 800);
		this.y = (height || 600) * (0.2 + Math.random() * 0.6);
		this.radius = 0.5 + Math.random() * 1.5;
		this.opacity = 0.03 + Math.random() * 0.06;
		this.vx = (Math.random() - 0.5) * 0.3;
		this.vy = -0.1 - Math.random() * 0.3;
		this.life = 1;
		this.decay = 0.001 + Math.random() * 0.003;
	}

	update() {
		this.x += this.vx;
		this.y += this.vy;
		this.life -= this.decay;
		if (this.life <= 0 || this.y < 0) {
			this.reset();
		}
	}

	draw(ctx) {
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(150, 200, 220, ${this.opacity * this.life})`;
		ctx.fill();
	}
}

let bubbles = [];
const MAX_BUBBLES = 30;

function initLayers() {
	layers = [];
	for (let i = 0; i < NUM_LAYERS; i++) {
		layers.push(new WaveLayer(i, NUM_LAYERS));
	}
	bubbles = [];
	for (let i = 0; i < MAX_BUBBLES; i++) {
		bubbles.push(new Bubble());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initLayers();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			// Recalculate layer positions
			for (let i = 0; i < layers.length; i++) {
				layers[i].recalc(i, NUM_LAYERS);
			}
			bubbles.forEach((b) => b.reset());
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time++;

		// Draw layers back to front (deep first)
		for (const layer of layers) {
			layer.draw(ctx, time);
		}

		// Draw bubbles
		for (const b of bubbles) {
			b.update();
			b.draw(ctx);
		}

		// Subtle caustic light pattern overlay
		drawCaustics(time);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

function drawCaustics(t) {
	// Very subtle shifting light patches
	const count = 6;
	for (let i = 0; i < count; i++) {
		const cx = width * (0.15 + 0.7 * (i / count)) + Math.sin(t * 0.003 + i * 1.5) * 80;
		const cy = height * 0.4 + Math.cos(t * 0.004 + i * 2.1) * 60;
		const r = 60 + Math.sin(t * 0.005 + i) * 20;
		const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
		const alpha = 0.015 + 0.01 * Math.sin(t * 0.006 + i * 3);
		grad.addColorStop(0, `rgba(120, 200, 220, ${alpha})`);
		grad.addColorStop(1, 'rgba(120, 200, 220, 0)');
		ctx.beginPath();
		ctx.arc(cx, cy, r, 0, Math.PI * 2);
		ctx.fillStyle = grad;
		ctx.fill();
	}
}

/**
 * Title: Particle Vortex
 * Description: Particles orbiting a central point in spiral/vortex patterns.
 *   Different rings at different speeds. Mouse becomes a secondary gravitational
 *   center, creating figure-8 or chaotic orbital patterns. Warm white/gold particles.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let particles = [];
let time = 0;
let center = { x: 0, y: 0 };

const PARTICLE_COUNT = 200;
const CENTER_GRAVITY = 0.0003;
const MOUSE_GRAVITY = 0.00015;
const DAMPING = 0.9995;
const TRAIL_ALPHA = 0.04;

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Warm white/gold color palette
const COLORS = [
	{ r: 255, g: 240, b: 200 }, // warm white
	{ r: 255, g: 215, b: 100 }, // gold
	{ r: 255, g: 200, b: 130 }, // light amber
	{ r: 255, g: 230, b: 160 }, // pale gold
	{ r: 240, g: 200, b: 180 }, // warm beige
	{ r: 255, g: 180, b: 80 } // deep gold
];

class Particle {
	constructor(ringIndex, totalRings) {
		this.ringIndex = ringIndex;
		this.totalRings = totalRings;
		this.reset();
	}

	reset() {
		// Distribute in rings around center
		const ringRadius = 50 + (this.ringIndex / this.totalRings) * Math.min(width, height) * 0.4;
		const angle = Math.random() * Math.PI * 2;

		this.x = center.x + Math.cos(angle) * ringRadius;
		this.y = center.y + Math.sin(angle) * ringRadius;

		// Tangential velocity for orbiting (perpendicular to radius)
		const speed = 0.8 + (1 - this.ringIndex / this.totalRings) * 1.5;
		this.vx = -Math.sin(angle) * speed;
		this.vy = Math.cos(angle) * speed;

		this.color = COLORS[Math.floor(Math.random() * COLORS.length)];
		this.size = 1 + Math.random() * 2;
		this.alpha = 0.3 + Math.random() * 0.5;
		this.trail = [];
		this.maxTrail = 8 + Math.floor(Math.random() * 8);
	}

	update() {
		// Store trail position
		this.trail.push({ x: this.x, y: this.y });
		if (this.trail.length > this.maxTrail) {
			this.trail.shift();
		}

		// Gravitational pull toward center
		let dx = center.x - this.x;
		let dy = center.y - this.y;
		let dist = Math.sqrt(dx * dx + dy * dy);
		if (dist > 1) {
			const force = CENTER_GRAVITY * dist;
			this.vx += (dx / dist) * force;
			this.vy += (dy / dist) * force;
		}

		// Mouse as secondary gravitational center
		if (mouse.x > 0 && mouse.y > 0) {
			dx = mouse.x - this.x;
			dy = mouse.y - this.y;
			dist = Math.sqrt(dx * dx + dy * dy);
			if (dist > 5 && dist < 400) {
				const force = MOUSE_GRAVITY * dist;
				this.vx += (dx / dist) * force;
				this.vy += (dy / dist) * force;
			}
		}

		// Apply velocity with damping
		this.vx *= DAMPING;
		this.vy *= DAMPING;
		this.x += this.vx;
		this.y += this.vy;

		// Soft boundary — if particle escapes too far, gently pull back
		const maxDist = Math.max(width, height) * 0.6;
		const distFromCenter = Math.sqrt((this.x - center.x) ** 2 + (this.y - center.y) ** 2);
		if (distFromCenter > maxDist) {
			this.x += (center.x - this.x) * 0.01;
			this.y += (center.y - this.y) * 0.01;
		}
	}

	draw() {
		const { r, g, b } = this.color;

		// Draw trail
		for (let i = 0; i < this.trail.length; i++) {
			const t = this.trail[i];
			const trailAlpha = (i / this.trail.length) * this.alpha * 0.3;
			const trailSize = this.size * (i / this.trail.length) * 0.6;
			ctx.beginPath();
			ctx.arc(t.x, t.y, trailSize, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${trailAlpha})`;
			ctx.fill();
		}

		// Draw particle with glow
		// Outer glow
		const glowGrad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.size * 4);
		glowGrad.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${this.alpha * 0.3})`);
		glowGrad.addColorStop(0.5, `rgba(${r}, ${g}, ${b}, ${this.alpha * 0.1})`);
		glowGrad.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size * 4, 0, Math.PI * 2);
		ctx.fillStyle = glowGrad;
		ctx.fill();

		// Core
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${this.alpha})`;
		ctx.fill();
	}
}

function initParticles() {
	center.x = width / 2;
	center.y = height / 2;
	particles = [];

	const rings = 5;
	const perRing = Math.floor(PARTICLE_COUNT / rings);

	for (let ring = 0; ring < rings; ring++) {
		for (let i = 0; i < perRing; i++) {
			particles.push(new Particle(ring, rings));
		}
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initParticles();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initParticles();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;

		// Semi-transparent overlay for motion trails
		ctx.fillStyle = `rgba(0, 0, 0, ${TRAIL_ALPHA})`;
		ctx.fillRect(0, 0, width, height);

		time++;

		// Update and draw all particles
		for (const p of particles) {
			p.update();
		}
		for (const p of particles) {
			p.draw();
		}

		// Draw subtle center glow
		const centerGlow = ctx.createRadialGradient(center.x, center.y, 0, center.x, center.y, 60);
		centerGlow.addColorStop(0, 'rgba(255, 220, 150, 0.06)');
		centerGlow.addColorStop(0.5, 'rgba(255, 200, 100, 0.02)');
		centerGlow.addColorStop(1, 'rgba(255, 180, 80, 0)');
		ctx.beginPath();
		ctx.arc(center.x, center.y, 60, 0, Math.PI * 2);
		ctx.fillStyle = centerGlow;
		ctx.fill();

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Pendulum Waves
 * Description: A row of pendulums with incrementally different lengths
 *   creates mesmerizing wave patterns as they swing in and out of phase.
 *   Optional trailing arcs show the bob paths. Mouse drags the nearest pendulum.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Pendulum Array --
  pendulumCount: 24,                      // Number of pendulums in the row (12-40 look great)
  lengthRatioStart: 0.25,                 // Length of shortest pendulum as fraction of canvas height
  lengthIncrement: 0.015,                 // Length increase per pendulum (fraction of height)

  // -- Bob Appearance --
  bobSize: 8,                             // Bob circle radius in px
  bobColor: 'rgba(0, 230, 180, 1)',       // Bob fill color
  stringColor: 'rgba(180, 180, 200, 0.5)', // Pendulum string/rod color
  stringWidth: 1.5,                       // String stroke width in px

  // -- Motion --
  swingAmplitude: 0.7,                    // Max swing angle in radians (0.5-1.2 recommended)
  speedMultiplier: 1.0,                   // Global speed multiplier (0.5 = half speed)
  phaseOffset: 0,                         // Starting phase offset in radians
  gravity: 9.81,                          // Gravity constant (affects period calculation)

  // -- Trails --
  trailEnabled: true,                     // Whether to draw trailing arcs behind bobs
  trailColor: 'rgba(0, 230, 180, 0.15)', // Trail arc color
  trailOpacity: 0.15,                     // Trail opacity (0-1)
  trailLength: 40,                        // Number of past positions to draw (10-80)

  // -- Mouse Interaction --
  mouseInteractionRadius: 120,            // Radius within which mouse affects pendulums (px)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000, down: false };
let pendulums = [];
let time = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function parseRGBA(str) {
  const m = str.match(/rgba?\(\s*([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)\s*(?:,\s*([\d.]+))?\)/);
  if (m) return { r: +m[1], g: +m[2], b: +m[3], a: m[4] !== undefined ? +m[4] : 1 };
  return { r: 0, g: 230, b: 180, a: 1 };
}

class Pendulum {
  constructor(anchorX, anchorY, length, index) {
    this.anchorX = anchorX;
    this.anchorY = anchorY;
    this.length = length;
    this.index = index;
    this.trail = [];
    // Each pendulum has slightly different period via length
    this.period = 2 * Math.PI * Math.sqrt(length / (CONFIG.gravity * 50));
  }

  getAngle(t) {
    const omega = (2 * Math.PI) / this.period;
    return CONFIG.swingAmplitude * Math.sin(omega * t + CONFIG.phaseOffset);
  }

  getBobPos(t) {
    const angle = this.getAngle(t);
    return {
      x: this.anchorX + Math.sin(angle) * this.length,
      y: this.anchorY + Math.cos(angle) * this.length,
    };
  }

  update(t) {
    const pos = this.getBobPos(t);

    // Mouse interaction — push the bob away
    const dx = pos.x - mouse.x;
    const dy = pos.y - mouse.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < CONFIG.mouseInteractionRadius && dist > 1) {
      const pushForce = (1 - dist / CONFIG.mouseInteractionRadius) * 15;
      pos.x += (dx / dist) * pushForce;
      pos.y += (dy / dist) * pushForce;
    }

    this.trail.push({ x: pos.x, y: pos.y });
    if (this.trail.length > CONFIG.trailLength) {
      this.trail.shift();
    }

    this.bobX = pos.x;
    this.bobY = pos.y;
  }

  draw(ctx) {
    const bobCol = parseRGBA(CONFIG.bobColor);
    const strCol = parseRGBA(CONFIG.stringColor);
    const trailCol = parseRGBA(CONFIG.trailColor);

    // Draw trail
    if (CONFIG.trailEnabled && this.trail.length > 1) {
      for (let i = 1; i < this.trail.length; i++) {
        const alpha = (i / this.trail.length) * CONFIG.trailOpacity;
        ctx.beginPath();
        ctx.arc(this.trail[i].x, this.trail[i].y, CONFIG.bobSize * 0.4, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${trailCol.r}, ${trailCol.g}, ${trailCol.b}, ${alpha})`;
        ctx.fill();
      }
    }

    // Draw string
    ctx.beginPath();
    ctx.moveTo(this.anchorX, this.anchorY);
    ctx.lineTo(this.bobX, this.bobY);
    ctx.strokeStyle = `rgba(${strCol.r}, ${strCol.g}, ${strCol.b}, ${strCol.a})`;
    ctx.lineWidth = CONFIG.stringWidth;
    ctx.stroke();

    // Draw bob with glow
    const grad = ctx.createRadialGradient(this.bobX, this.bobY, 0, this.bobX, this.bobY, CONFIG.bobSize * 2);
    grad.addColorStop(0, `rgba(${bobCol.r}, ${bobCol.g}, ${bobCol.b}, 0.3)`);
    grad.addColorStop(1, `rgba(${bobCol.r}, ${bobCol.g}, ${bobCol.b}, 0)`);
    ctx.beginPath();
    ctx.arc(this.bobX, this.bobY, CONFIG.bobSize * 2, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();

    ctx.beginPath();
    ctx.arc(this.bobX, this.bobY, CONFIG.bobSize, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${bobCol.r}, ${bobCol.g}, ${bobCol.b}, ${bobCol.a})`;
    ctx.fill();

    // Highlight
    ctx.beginPath();
    ctx.arc(this.bobX - CONFIG.bobSize * 0.25, this.bobY - CONFIG.bobSize * 0.25, CONFIG.bobSize * 0.35, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(255, 255, 255, 0.3)`;
    ctx.fill();
  }
}

function initPendulums() {
  pendulums = [];
  const spacing = width / (CONFIG.pendulumCount + 1);
  const anchorY = height * 0.08;

  for (let i = 0; i < CONFIG.pendulumCount; i++) {
    const anchorX = spacing * (i + 1);
    const lengthFrac = CONFIG.lengthRatioStart + CONFIG.lengthIncrement * i;
    const length = lengthFrac * height;
    pendulums.push(new Pendulum(anchorX, anchorY, length, i));
  }
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initPendulums();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initPendulums();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function startAnimation() {
  function render() {
    if (!ctx) return;

    ctx.clearRect(0, 0, width, height);

    // Draw anchor bar
    const anchorY = height * 0.08;
    ctx.beginPath();
    ctx.moveTo(0, anchorY);
    ctx.lineTo(width, anchorY);
    ctx.strokeStyle = 'rgba(100, 100, 120, 0.3)';
    ctx.lineWidth = 3;
    ctx.stroke();

    // Connecting line between all bobs
    if (pendulums.length > 1) {
      ctx.beginPath();
      ctx.moveTo(pendulums[0].bobX, pendulums[0].bobY);
      for (let i = 1; i < pendulums.length; i++) {
        ctx.lineTo(pendulums[i].bobX, pendulums[i].bobY);
      }
      ctx.strokeStyle = 'rgba(0, 230, 180, 0.12)';
      ctx.lineWidth = 1;
      ctx.stroke();
    }

    for (const p of pendulums) {
      p.update(time);
      p.draw(ctx);
    }

    time += 0.016 * CONFIG.speedMultiplier;
    requestAnimationFrame(render);
  }

  requestAnimationFrame(render);
}

/**
 * Title: Pixel Rain
 * Description: Pixel-art style rain with blocky, grid-snapped drops, optional
 *   splash particles, and glowing trails. Mouse creates pixel splash ripples.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Grid --
  pixelSize: 4,                             // Grid snap size in pixels (2-10)

  // -- Drops --
  dropCount: 180,                           // Number of active rain drops (50-500)
  fallSpeed: 3.5,                           // Base fall speed in pixels per frame (1-10)
  fallSpeedVariance: 1.5,                   // Random speed variance added per drop (0-5)
  dropLength: 4,                            // Drop trail length in grid cells (1-10)

  // -- Colors --
  colorPalette: [                           // Array of drop colors — picked randomly
    'rgba(80, 180, 255, 0.9)',              //   Light blue
    'rgba(100, 200, 255, 0.7)',             //   Cyan-ish
    'rgba(60, 140, 220, 0.8)',              //   Steel blue
    'rgba(120, 220, 255, 0.6)',             //   Pale cyan
  ],

  // -- Trail --
  trailFadeSpeed: 0.88,                     // Per-frame opacity retention for trails (0.8-0.98)

  // -- Wind --
  windAngle: 5,                             // Wind slant in degrees (0=straight, -30 to 30)

  // -- Splash --
  splashEnabled: true,                      // Enable splash particles when drops hit bottom
  splashRadius: 3,                          // Splash particle spread in grid cells (1-8)
  splashParticleCount: 4,                   // Number of splash particles per drop (1-8)

  // -- Glow --
  backgroundGlowEnabled: true,              // Subtle ambient glow behind rain
  glowColor: 'rgba(60, 160, 255, 0.015)',   // Ambient glow tint color
  glowRadius: 60,                           // Glow circle radius around drops (20-100)

  // -- Mouse --
  mouseRippleRadius: 100,                   // Mouse splash ripple radius in px
  mouseRippleIntensity: 6,                  // How many splash particles the mouse generates (1-15)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let drops = [];
let splashes = [];
let trailCanvas, trailCtx;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initTrailBuffer();
      initDrops();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initTrailBuffer();
      initDrops();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      spawnMouseRipple();
      break;
  }
};

function initTrailBuffer() {
  trailCanvas = new OffscreenCanvas(width, height);
  trailCtx = trailCanvas.getContext('2d');
}

function snap(val) {
  return Math.floor(val / CONFIG.pixelSize) * CONFIG.pixelSize;
}

function randomColor() {
  const palette = CONFIG.colorPalette;
  return palette[Math.floor(Math.random() * palette.length)];
}

function initDrops() {
  drops = [];
  for (let i = 0; i < CONFIG.dropCount; i++) {
    drops.push(createDrop(true));
  }
}

function createDrop(randomY) {
  const windRad = (CONFIG.windAngle * Math.PI) / 180;
  return {
    x: snap(Math.random() * width),
    y: randomY ? snap(Math.random() * height) : snap(-CONFIG.pixelSize * CONFIG.dropLength),
    speed: CONFIG.fallSpeed + Math.random() * CONFIG.fallSpeedVariance,
    color: randomColor(),
    windDx: Math.tan(windRad),
  };
}

function spawnMouseRipple() {
  if (!CONFIG.splashEnabled) return;
  if (mouse.x < 0 || mouse.y < 0) return;

  for (let i = 0; i < CONFIG.mouseRippleIntensity; i++) {
    const angle = Math.random() * Math.PI * 2;
    const speed = 0.5 + Math.random() * 2;
    splashes.push({
      x: snap(mouse.x),
      y: snap(mouse.y),
      vx: Math.cos(angle) * speed * CONFIG.pixelSize,
      vy: Math.sin(angle) * speed * CONFIG.pixelSize - 1,
      life: 1,
      decay: 0.03 + Math.random() * 0.04,
      color: randomColor(),
    });
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;

    // Fade the trail buffer
    trailCtx.globalAlpha = CONFIG.trailFadeSpeed;
    trailCtx.globalCompositeOperation = 'source-over';
    trailCtx.fillStyle = 'rgba(0, 0, 0, 0.1)';
    // Use destination-in to fade existing content
    trailCtx.globalCompositeOperation = 'destination-in';
    trailCtx.fillStyle = `rgba(0, 0, 0, ${CONFIG.trailFadeSpeed})`;
    trailCtx.fillRect(0, 0, width, height);
    trailCtx.globalCompositeOperation = 'source-over';
    trailCtx.globalAlpha = 1;

    // Update and draw drops onto trail buffer
    const ps = CONFIG.pixelSize;
    for (let i = 0; i < drops.length; i++) {
      const d = drops[i];

      // Draw drop pixel column
      for (let j = 0; j < CONFIG.dropLength; j++) {
        const py = d.y - j * ps;
        if (py < 0 || py >= height) continue;
        const alpha = 1 - j / CONFIG.dropLength;
        trailCtx.globalAlpha = alpha;
        trailCtx.fillStyle = d.color;
        trailCtx.fillRect(snap(d.x), snap(py), ps, ps);
      }
      trailCtx.globalAlpha = 1;

      // Background glow
      if (CONFIG.backgroundGlowEnabled) {
        trailCtx.save();
        trailCtx.globalAlpha = 0.02;
        trailCtx.fillStyle = CONFIG.glowColor;
        trailCtx.beginPath();
        trailCtx.arc(d.x + ps / 2, d.y + ps / 2, CONFIG.glowRadius, 0, Math.PI * 2);
        trailCtx.fill();
        trailCtx.restore();
      }

      // Move
      d.y += d.speed * ps * 0.25;
      d.x += d.windDx * d.speed * 0.5;

      // Reset if off screen
      if (d.y > height + ps * CONFIG.dropLength) {
        if (CONFIG.splashEnabled) {
          spawnSplash(d.x, height);
        }
        Object.assign(d, createDrop(false));
      }
      if (d.x < -ps * 5 || d.x > width + ps * 5) {
        Object.assign(d, createDrop(false));
      }
    }

    // Update splashes
    for (let i = splashes.length - 1; i >= 0; i--) {
      const s = splashes[i];
      s.x += s.vx;
      s.y += s.vy;
      s.vy += 0.15 * ps * 0.25; // Gravity
      s.life -= s.decay;

      if (s.life <= 0) {
        splashes.splice(i, 1);
        continue;
      }

      trailCtx.globalAlpha = s.life;
      trailCtx.fillStyle = s.color;
      trailCtx.fillRect(snap(s.x), snap(s.y), ps, ps);
    }
    trailCtx.globalAlpha = 1;

    // Composite trail buffer to main canvas
    ctx.clearRect(0, 0, width, height);
    ctx.drawImage(trailCanvas, 0, 0);

    requestAnimationFrame(render);
  }

  requestAnimationFrame(render);
}

function spawnSplash(x, y) {
  for (let i = 0; i < CONFIG.splashParticleCount; i++) {
    const angle = -Math.PI * (0.15 + Math.random() * 0.7);
    const speed = 0.5 + Math.random() * CONFIG.splashRadius;
    const ps = CONFIG.pixelSize;
    splashes.push({
      x: snap(x),
      y: snap(y - ps),
      vx: Math.cos(angle) * speed * ps * 0.5,
      vy: Math.sin(angle) * speed * ps * 0.5,
      life: 1,
      decay: 0.04 + Math.random() * 0.05,
      color: randomColor(),
    });
  }
}

/**
 * Title: Plasma Field
 * Description: Classic plasma effect using overlapping sine functions to create
 *   flowing, colorful plasma patterns. Rich but subtle color palette that slowly
 *   evolves. Mouse position warps the plasma field locally.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let imageData;

const PIXEL_STEP = 2; // render every Nth pixel for performance
const TIME_SPEED = 0.008;
const MOUSE_WARP_RADIUS = 200;
const MOUSE_WARP_STRENGTH = 40;

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Precompute a color palette for the plasma
const PALETTE_SIZE = 256;
const palette = new Array(PALETTE_SIZE);

function buildPalette() {
	for (let i = 0; i < PALETTE_SIZE; i++) {
		const t = i / PALETTE_SIZE;

		// Multi-layered sine color generation for rich, evolving hues
		const r = Math.floor(
			128 + 64 * Math.sin(Math.PI * 2 * t * 1.0 + 0.0) + 32 * Math.sin(Math.PI * 2 * t * 2.5 + 1.2)
		);
		const g = Math.floor(
			80 + 50 * Math.sin(Math.PI * 2 * t * 1.3 + 2.0) + 30 * Math.sin(Math.PI * 2 * t * 3.0 + 0.8)
		);
		const b = Math.floor(
			140 + 80 * Math.sin(Math.PI * 2 * t * 0.8 + 4.0) + 40 * Math.sin(Math.PI * 2 * t * 1.8 + 2.5)
		);

		palette[i] = {
			r: Math.max(0, Math.min(255, r)),
			g: Math.max(0, Math.min(255, g)),
			b: Math.max(0, Math.min(255, b))
		};
	}
}

// Precompute sine lookup table for performance
const SIN_TABLE_SIZE = 4096;
const sinTable = new Float32Array(SIN_TABLE_SIZE);
function buildSinTable() {
	for (let i = 0; i < SIN_TABLE_SIZE; i++) {
		sinTable[i] = Math.sin((i / SIN_TABLE_SIZE) * Math.PI * 2);
	}
}

function fastSin(x) {
	// Normalize to [0, SIN_TABLE_SIZE)
	const idx = ((x % (Math.PI * 2)) + Math.PI * 2) % (Math.PI * 2);
	return sinTable[Math.floor((idx / (Math.PI * 2)) * SIN_TABLE_SIZE) % SIN_TABLE_SIZE];
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			buildPalette();
			buildSinTable();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;

		time += TIME_SPEED;
		imageData = ctx.createImageData(width, height);
		const data = imageData.data;

		const cx = width * 0.5;
		const cy = height * 0.5;
		const hasMouse = mouse.x > 0 && mouse.y > 0;

		for (let y = 0; y < height; y += PIXEL_STEP) {
			for (let x = 0; x < width; x += PIXEL_STEP) {
				// Normalized coordinates
				let px = x;
				let py = y;

				// Mouse warp — distort coordinates near mouse
				if (hasMouse) {
					const mdx = x - mouse.x;
					const mdy = y - mouse.y;
					const mDist = Math.sqrt(mdx * mdx + mdy * mdy);
					if (mDist < MOUSE_WARP_RADIUS && mDist > 1) {
						const warpFactor = 1 - mDist / MOUSE_WARP_RADIUS;
						const warpAmount = warpFactor * warpFactor * MOUSE_WARP_STRENGTH;
						px += fastSin(mdy * 0.05 + time * 3) * warpAmount;
						py += fastSin(mdx * 0.05 + time * 3) * warpAmount;
					}
				}

				// Classic plasma: sum of several sine functions
				const scale = 0.01;
				const sx = px * scale;
				const sy = py * scale;

				// Layer 1: horizontal waves
				let v = fastSin(sx * 10 + time);

				// Layer 2: vertical waves
				v += fastSin(sy * 8 + time * 1.3);

				// Layer 3: diagonal waves
				v += fastSin((sx + sy) * 6 + time * 0.7);

				// Layer 4: circular ripple from center
				const dx = px - cx;
				const dy = py - cy;
				const dist = Math.sqrt(dx * dx + dy * dy) * scale;
				v += fastSin(dist * 8 - time * 2);

				// Layer 5: secondary circular ripple (offset)
				const dx2 = px - cx * 0.6;
				const dy2 = py - cy * 1.3;
				const dist2 = Math.sqrt(dx2 * dx2 + dy2 * dy2) * scale;
				v += fastSin(dist2 * 6 + time * 1.5);

				// Layer 6: complex interference
				v += fastSin(sx * 4 * fastSin(time * 0.5) + sy * 5 * fastSin(time * 0.3));

				// Normalize v from [-6, 6] to [0, 1]
				v = (v + 6) / 12;

				// Shift palette over time for evolving colors
				const paletteIdx =
					Math.floor(((((v + time * 0.1) % 1) + 1) % 1) * PALETTE_SIZE) % PALETTE_SIZE;
				const color = palette[paletteIdx];

				// Apply subtle alpha
				const alpha = 50 + Math.floor(v * 40);

				// Fill the pixel block
				for (let dy2 = 0; dy2 < PIXEL_STEP && y + dy2 < height; dy2++) {
					for (let dx2 = 0; dx2 < PIXEL_STEP && x + dx2 < width; dx2++) {
						const idx = ((y + dy2) * width + (x + dx2)) * 4;
						data[idx] = color.r;
						data[idx + 1] = color.g;
						data[idx + 2] = color.b;
						data[idx + 3] = alpha;
					}
				}
			}
		}

		ctx.putImageData(imageData, 0, 0);
		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// QuantumFoam – transparency-optimized
// ------------------------------------------------------------------
// CONFIGURATION CONSTANTS
// ------------------------------------------------------------------
const PARTICLE_COUNT   = 2500; 
const MIN_RADIUS       = 0.5;  
const MAX_RADIUS       = 2;    
const GROWTH_SPEED     = 1.003;
const MIN_LIFE_DECAY   = 0.01; 
const MAX_LIFE_DECAY   = 0.02; 
const TRAIL_OPACITY    = 0.1;  // Controls how fast trails erase to transparency
const HUE_RANGE        = 360;   
const SATURATION       = '80%';
const LIGHTNESS        = '60%';
// ------------------------------------------------------------------

let c, ctx, w, h, foam = [];

self.onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;

    foam = Array.from({ length: PARTICLE_COUNT }, _ => ({
      x: Math.random() * w,
      y: Math.random() * h,
      r: Math.random() * (MAX_RADIUS - MIN_RADIUS) + MIN_RADIUS,
      life: 1,
      decay: Math.random() * (MAX_LIFE_DECAY - MIN_LIFE_DECAY) + MIN_LIFE_DECAY,
      hue: Math.random() * HUE_RANGE
    }));
    animate();
  }

  if (e.data.type === 'resize') {
    w = c.width = e.data.width;
    h = c.height = e.data.height;
  }
};

function animate() {
  // 1. Erase a portion of the previous frame to transparency
  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle = `rgba(0,0,0,${TRAIL_OPACITY})`;
  ctx.fillRect(0, 0, w, h);

  // 2. Switch back to normal drawing mode for particles
  ctx.globalCompositeOperation = 'source-over';

  foam = foam.filter(f => {
    f.life -= f.decay;
    f.r *= GROWTH_SPEED;

    ctx.beginPath();
    ctx.arc(f.x, f.y, f.r, 0, Math.PI * 2);
    ctx.fillStyle = `hsla(${f.hue},${SATURATION},${LIGHTNESS},${f.life})`;
    ctx.fill();

    return f.life > 0;
  });

  while (foam.length < PARTICLE_COUNT) {
    foam.push({
      x: Math.random() * w,
      y: Math.random() * h,
      r: MIN_RADIUS,
      life: 1,
      decay: Math.random() * (MAX_LIFE_DECAY - MIN_LIFE_DECAY) + MIN_LIFE_DECAY,
      hue: Math.random() * HUE_RANGE
    });
  }
  requestAnimationFrame(animate);
}

