/**
 * Title: Rain on Glass
 * Description: Raindrops falling with realistic physics — acceleration, subtle streaks,
 *   occasional pausing and merging. Larger drops fall slower. Mouse position creates
 *   a wind effect that angles the rain.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let drops = [];
let streaks = [];

const MAX_DROPS = 180;
const MAX_STREAKS = 40;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Raindrop {
	constructor() {
		this.reset(true);
	}

	reset(randomY = false) {
		this.x = Math.random() * width;
		this.y = randomY ? Math.random() * height : -10 - Math.random() * 60;
		this.radius = 1 + Math.random() * 2.5;
		this.vy = 0.5 + Math.random() * 1.5;
		this.vx = 0;
		this.acceleration = 0.02 + Math.random() * 0.04;
		this.maxSpeed = 3 + Math.random() * 4;
		this.opacity = 0.15 + Math.random() * 0.25;
		this.paused = false;
		this.pauseTimer = 0;
		this.pauseThreshold = 200 + Math.random() * 600;
		this.streakLength = 0;
		// Larger drops are slower
		if (this.radius > 2) {
			this.maxSpeed *= 0.6;
			this.acceleration *= 0.7;
			this.opacity += 0.05;
		}
	}

	update(windX) {
		// Chance to pause briefly (simulates surface tension on glass)
		this.pauseTimer++;
		if (!this.paused && this.pauseTimer > this.pauseThreshold && Math.random() < 0.003) {
			this.paused = true;
			this.pauseTimer = 0;
			this.pauseThreshold = 40 + Math.random() * 120;
		}
		if (this.paused) {
			this.pauseTimer++;
			if (this.pauseTimer > this.pauseThreshold) {
				this.paused = false;
				this.pauseTimer = 0;
				this.pauseThreshold = 200 + Math.random() * 600;
			}
			// Even when paused, slight wind drift
			this.x += windX * 0.1;
			this.streakLength *= 0.9;
			return;
		}

		// Accelerate
		this.vy = Math.min(this.vy + this.acceleration, this.maxSpeed);
		this.vx += (windX - this.vx) * 0.02;

		this.x += this.vx;
		this.y += this.vy;

		// Streak length proportional to speed
		this.streakLength = this.vy * 3;

		// Off-screen reset
		if (this.y > height + 20 || this.x < -20 || this.x > width + 20) {
			this.reset(false);
		}
	}

	draw(ctx) {
		// Draw streak behind the drop
		if (this.streakLength > 1) {
			ctx.beginPath();
			ctx.moveTo(this.x, this.y);
			ctx.lineTo(this.x - this.vx * 2, this.y - this.streakLength);
			ctx.strokeStyle = `rgba(180, 210, 240, ${this.opacity * 0.3})`;
			ctx.lineWidth = this.radius * 0.5;
			ctx.stroke();
		}

		// Draw the drop itself — slightly elongated when moving fast
		ctx.beginPath();
		const stretch = 1 + this.vy * 0.08;
		ctx.save();
		ctx.translate(this.x, this.y);
		ctx.scale(1, stretch);
		ctx.arc(0, 0, this.radius, 0, Math.PI * 2);
		ctx.restore();
		ctx.fillStyle = `rgba(180, 210, 240, ${this.opacity})`;
		ctx.fill();

		// Tiny highlight on top of drop for glass refraction look
		ctx.beginPath();
		ctx.arc(
			this.x - this.radius * 0.3,
			this.y - this.radius * 0.3,
			this.radius * 0.35,
			0,
			Math.PI * 2
		);
		ctx.fillStyle = `rgba(220, 240, 255, ${this.opacity * 0.5})`;
		ctx.fill();
	}
}

// Residual streak left behind by fast drops
class Streak {
	constructor(x, y, len) {
		this.x = x;
		this.y = y;
		this.length = len;
		this.opacity = 0.08;
		this.life = 1;
		this.decay = 0.003 + Math.random() * 0.005;
	}

	update() {
		this.life -= this.decay;
		this.opacity = 0.08 * this.life;
	}

	draw(ctx) {
		if (this.life <= 0) return;
		ctx.beginPath();
		ctx.moveTo(this.x, this.y);
		ctx.lineTo(this.x, this.y + this.length);
		ctx.strokeStyle = `rgba(180, 210, 240, ${this.opacity})`;
		ctx.lineWidth = 0.5;
		ctx.stroke();
	}
}

function initDrops() {
	drops = [];
	streaks = [];
	for (let i = 0; i < MAX_DROPS; i++) {
		drops.push(new Raindrop());
	}
}

function getWind() {
	// Wind based on mouse X position relative to center
	const centerX = width / 2;
	const dx = mouse.x - centerX;
	// Normalize to -1..1, scale for effect
	return (dx / centerX) * 1.5;
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initDrops();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initDrops();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		const wind = getWind();

		// Check for merging — nearby drops absorb smaller ones
		for (let i = 0; i < drops.length; i++) {
			for (let j = i + 1; j < drops.length; j++) {
				const dx = drops[i].x - drops[j].x;
				const dy = drops[i].y - drops[j].y;
				const dist = Math.sqrt(dx * dx + dy * dy);
				const mergeThresh = drops[i].radius + drops[j].radius;
				if (dist < mergeThresh) {
					// Merge: bigger drop absorbs smaller
					if (drops[i].radius >= drops[j].radius) {
						drops[i].radius = Math.min(drops[i].radius + drops[j].radius * 0.3, 4);
						drops[i].vy = Math.max(drops[i].vy, drops[j].vy);
						drops[j].reset(false);
					} else {
						drops[j].radius = Math.min(drops[j].radius + drops[i].radius * 0.3, 4);
						drops[j].vy = Math.max(drops[i].vy, drops[j].vy);
						drops[i].reset(false);
					}
					break;
				}
			}
		}

		// Occasional residual streaks
		if (Math.random() < 0.02 && streaks.length < MAX_STREAKS) {
			const d = drops[Math.floor(Math.random() * drops.length)];
			if (d.vy > 3) {
				streaks.push(new Streak(d.x, d.y, d.streakLength * 2));
			}
		}

		// Update and draw streaks
		for (let i = streaks.length - 1; i >= 0; i--) {
			streaks[i].update();
			streaks[i].draw(ctx);
			if (streaks[i].life <= 0) {
				streaks.splice(i, 1);
			}
		}

		// Update and draw drops
		for (const drop of drops) {
			drop.update(wind);
			drop.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Retro Sun
 * Description: Synthwave sunset with a glowing semi-circle sun, animated horizontal
 *   stripe cutouts, twinkling stars, and a rich gradient sky. Mouse proximity
 *   intensifies the sun's glow.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Sun --
  sunColorTop: '#ff6ec7',                 // Top gradient color of the sun
  sunColorBottom: '#ffb347',              // Bottom gradient color of the sun
  sunRadius: 120,                         // Sun radius in pixels
  sunPositionY: 0.55,                     // Sun vertical position (0=top, 1=bottom)
  glowIntensity: 1.2,                     // Base glow brightness (0-3)
  glowPulseSpeed: 0.8,                    // Glow pulse animation speed (0-5)

  // -- Stripes --
  stripeCount: 8,                         // Number of horizontal stripe cutouts
  stripeSpacing: 6,                       // Spacing between stripes in pixels
  stripeWidth: 4,                         // Width of each stripe in pixels
  stripeScrollSpeed: 0.3,                 // Speed stripes scroll upward

  // -- Horizon --
  horizonEnabled: true,                   // Show a horizon line
  horizonColor: '#ff6ec7',                // Horizon line color

  // -- Background --
  bgGradientTop: '#0a001a',              // Sky gradient top color (deep purple/black)
  bgGradientBottom: '#1a0033',           // Sky gradient bottom color

  // -- Stars --
  starCount: 80,                          // Number of twinkling stars
  starColor: 'rgba(255, 255, 255, 0.8)', // Star color

  // -- Mouse --
  mouseGlowRadius: 300,                  // Mouse influence radius for glow boost
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let stars = [];
let time = 0;
let stripeOffset = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function hexToRgb(hex) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return { r, g, b };
}

function initStars() {
  stars = [];
  const sunY = height * CONFIG.sunPositionY;
  for (let i = 0; i < CONFIG.starCount; i++) {
    stars.push({
      x: Math.random() * width,
      y: Math.random() * sunY * 0.9,
      size: Math.random() * 1.8 + 0.5,
      twinkleSpeed: Math.random() * 0.03 + 0.01,
      twinkleOffset: Math.random() * Math.PI * 2,
    });
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 0.016;
    stripeOffset = (stripeOffset + CONFIG.stripeScrollSpeed) % (CONFIG.stripeSpacing + CONFIG.stripeWidth);

    const sunY = height * CONFIG.sunPositionY;
    const sunX = width / 2;

    // -- Background gradient --
    const bgGrad = ctx.createLinearGradient(0, 0, 0, height);
    bgGrad.addColorStop(0, CONFIG.bgGradientTop);
    bgGrad.addColorStop(0.6, CONFIG.bgGradientBottom);
    bgGrad.addColorStop(1, '#000000');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, width, height);

    // -- Stars --
    for (const star of stars) {
      const twinkle = 0.3 + 0.7 * Math.abs(Math.sin(time * star.twinkleSpeed * 60 + star.twinkleOffset));
      ctx.beginPath();
      ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.starColor.replace(/[\d.]+\)$/, (twinkle * 0.8).toFixed(2) + ')');
      ctx.fill();
    }

    // -- Sun glow (behind sun) --
    const dx = mouse.x - sunX;
    const dy = mouse.y - sunY;
    const mouseDist = Math.sqrt(dx * dx + dy * dy);
    const mouseBoost = Math.max(0, 1 - mouseDist / CONFIG.mouseGlowRadius) * 0.6;
    const pulse = Math.sin(time * CONFIG.glowPulseSpeed) * 0.15 + 0.85;
    const glowAlpha = CONFIG.glowIntensity * pulse * 0.15 + mouseBoost * 0.1;

    const topRgb = hexToRgb(CONFIG.sunColorTop);
    for (let i = 3; i >= 1; i--) {
      const r = CONFIG.sunRadius * (1 + i * 0.8);
      const glow = ctx.createRadialGradient(sunX, sunY, CONFIG.sunRadius * 0.5, sunX, sunY, r);
      glow.addColorStop(0, `rgba(${topRgb.r}, ${topRgb.g}, ${topRgb.b}, ${glowAlpha * (0.4 / i)})`);
      glow.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = glow;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Sun body (semi-circle above horizon) --
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, width, sunY);
    ctx.clip();

    const sunGrad = ctx.createLinearGradient(sunX, sunY - CONFIG.sunRadius, sunX, sunY + CONFIG.sunRadius * 0.3);
    sunGrad.addColorStop(0, CONFIG.sunColorTop);
    sunGrad.addColorStop(1, CONFIG.sunColorBottom);
    ctx.fillStyle = sunGrad;
    ctx.beginPath();
    ctx.arc(sunX, sunY, CONFIG.sunRadius, 0, Math.PI * 2);
    ctx.fill();

    // -- Stripe cutouts on sun --
    ctx.globalCompositeOperation = 'destination-out';
    const stripeStart = sunY - CONFIG.sunRadius;
    const stripeEnd = sunY;
    for (let y = stripeStart + stripeOffset; y < stripeEnd; y += CONFIG.stripeSpacing + CONFIG.stripeWidth) {
      if (y > stripeStart + CONFIG.sunRadius * 0.3) {
        ctx.fillStyle = 'rgba(0, 0, 0, 1)';
        ctx.fillRect(sunX - CONFIG.sunRadius - 10, y, CONFIG.sunRadius * 2 + 20, CONFIG.stripeWidth);
      }
    }
    ctx.globalCompositeOperation = 'source-over';
    ctx.restore();

    // -- Horizon line --
    if (CONFIG.horizonEnabled) {
      ctx.strokeStyle = CONFIG.horizonColor;
      ctx.lineWidth = 2;
      ctx.globalAlpha = 0.6;
      ctx.beginPath();
      ctx.moveTo(0, sunY);
      ctx.lineTo(width, sunY);
      ctx.stroke();
      ctx.globalAlpha = 1;
    }

    // -- Ground reflection glow --
    const groundGrad = ctx.createLinearGradient(0, sunY, 0, height);
    const bottomRgb = hexToRgb(CONFIG.sunColorBottom);
    groundGrad.addColorStop(0, `rgba(${bottomRgb.r}, ${bottomRgb.g}, ${bottomRgb.b}, 0.08)`);
    groundGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
    ctx.fillStyle = groundGrad;
    ctx.fillRect(0, sunY, width, height - sunY);

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initStars();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initStars();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Ripple Pond
 * Description: Water ripple interference simulation using a 2D wave equation.
 *   Periodic drops create expanding circular ripples that interfere with each other.
 *   Mouse acts as a continuous drop source. Optional rain mode for ambient drops.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Wave Physics --
  dropFrequency: 90,                      // Frames between random drops
  rippleSpeed: 0.4,                       // Wave propagation speed (0-0.5, higher=faster)
  rippleDamping: 0.985,                   // Wave energy decay per frame (0.95-0.999)
  waveHeightMultiplier: 2.5,              // Visual amplitude multiplier (0-10)

  // -- Appearance --
  rippleColor: 'rgba(100, 180, 255, 1)',  // Base ripple highlight color
  rippleWidth: 1,                         // Not used directly — waves are pixel-based
  maxRipples: 15,                         // Max concurrent drop sources
  gridResolution: 4,                      // Pixel step for wave grid (lower=sharper, higher=faster)

  // -- Reflection --
  reflectionEnabled: true,                // Enable bright reflection highlights
  reflectionColor: 'rgba(200, 230, 255, 0.6)', // Reflection highlight color

  // -- Background --
  backgroundTint: 'rgba(10, 20, 40, 0.03)', // Subtle background overlay each frame

  // -- Mouse --
  mouseDropEnabled: true,                 // Mouse acts as a drop source
  mouseDropStrength: 3.0,                 // Mouse drop amplitude (0-10)

  // -- Rain Mode --
  rainMode: false,                        // Continuous random drops everywhere
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let grid, prevGrid;
let cols, rows;
let frameCount = 0;
let lastMouseDrop = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initGrid() {
  cols = Math.ceil(width / CONFIG.gridResolution) + 1;
  rows = Math.ceil(height / CONFIG.gridResolution) + 1;
  grid = new Float32Array(cols * rows);
  prevGrid = new Float32Array(cols * rows);
}

function addDrop(gx, gy, strength) {
  if (gx < 1 || gx >= cols - 1 || gy < 1 || gy >= rows - 1) return;
  const idx = gy * cols + gx;
  grid[idx] = strength;
}

function addDropAtPixel(px, py, strength) {
  const gx = Math.round(px / CONFIG.gridResolution);
  const gy = Math.round(py / CONFIG.gridResolution);
  // Add a small cluster for a more visible ripple
  for (let dy = -1; dy <= 1; dy++) {
    for (let dx = -1; dx <= 1; dx++) {
      const cx = gx + dx;
      const cy = gy + dy;
      if (cx >= 1 && cx < cols - 1 && cy >= 1 && cy < rows - 1) {
        const dist = Math.sqrt(dx * dx + dy * dy);
        grid[cy * cols + cx] += strength * (1 - dist * 0.3);
      }
    }
  }
}

function stepWave() {
  const speed = CONFIG.rippleSpeed;
  const damping = CONFIG.rippleDamping;
  const temp = prevGrid;

  for (let y = 1; y < rows - 1; y++) {
    for (let x = 1; x < cols - 1; x++) {
      const idx = y * cols + x;
      const val = (
        grid[idx - 1] +
        grid[idx + 1] +
        grid[(y - 1) * cols + x] +
        grid[(y + 1) * cols + x]
      ) * 0.5 - prevGrid[idx];
      temp[idx] = val * damping;
    }
  }

  prevGrid = grid;
  grid = temp;
}

function parseRgba(str) {
  const m = str.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  if (m) return { r: parseInt(m[1]), g: parseInt(m[2]), b: parseInt(m[3]) };
  return { r: 100, g: 180, b: 255 };
}

function startAnimation() {
  const baseColor = parseRgba(CONFIG.rippleColor);
  const reflColor = parseRgba(CONFIG.reflectionColor);

  function render() {
    if (!ctx) return;
    frameCount++;

    // Background
    ctx.fillStyle = CONFIG.backgroundTint;
    ctx.fillRect(0, 0, width, height);
    // Fade slightly to keep it clean
    ctx.fillStyle = 'rgba(0, 0, 0, 0.04)';
    ctx.fillRect(0, 0, width, height);

    // Random drops
    if (frameCount % CONFIG.dropFrequency === 0) {
      const gx = Math.floor(Math.random() * (cols - 4)) + 2;
      const gy = Math.floor(Math.random() * (rows - 4)) + 2;
      addDrop(gx, gy, 4);
    }

    // Rain mode
    if (CONFIG.rainMode && frameCount % 12 === 0) {
      const gx = Math.floor(Math.random() * (cols - 4)) + 2;
      const gy = Math.floor(Math.random() * (rows - 4)) + 2;
      addDrop(gx, gy, 2);
    }

    // Mouse drops
    if (CONFIG.mouseDropEnabled && mouse.x > 0 && mouse.y > 0) {
      if (frameCount - lastMouseDrop > 8) {
        addDropAtPixel(mouse.x, mouse.y, CONFIG.mouseDropStrength);
        lastMouseDrop = frameCount;
      }
    }

    // Step physics
    stepWave();

    // Render waves
    const res = CONFIG.gridResolution;
    const mult = CONFIG.waveHeightMultiplier;

    for (let y = 1; y < rows - 1; y++) {
      for (let x = 1; x < cols - 1; x++) {
        const val = grid[y * cols + x] * mult;
        if (Math.abs(val) > 0.15) {
          const px = x * res;
          const py = y * res;
          const alpha = Math.min(0.5, Math.abs(val) * 0.08);

          if (val > 0) {
            ctx.fillStyle = `rgba(${baseColor.r}, ${baseColor.g}, ${baseColor.b}, ${alpha})`;
          } else {
            ctx.fillStyle = `rgba(${baseColor.r * 0.5 | 0}, ${baseColor.g * 0.5 | 0}, ${baseColor.b}, ${alpha * 0.6})`;
          }
          ctx.fillRect(px, py, res, res);

          // Reflection highlights
          if (CONFIG.reflectionEnabled && val > 1.5) {
            const refAlpha = Math.min(0.3, (val - 1.5) * 0.1);
            ctx.fillStyle = `rgba(${reflColor.r}, ${reflColor.g}, ${reflColor.b}, ${refAlpha})`;
            ctx.fillRect(px, py, res, res);
          }
        }
      }
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initGrid();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initGrid();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Sacred Geometry
 * Description: Slowly rotating, nested geometric shapes — circles inscribed in
 * squares, inscribed in circles, etc. Uses the golden ratio for sizing. Thin lines
 * with low opacity in white/gold tones. Mouse position shifts the rotation center.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let lastTime = 0;
let centerX, centerY, baseRadius;

const PHI = (1 + Math.sqrt(5)) / 2; // Golden ratio ≈ 1.618
const LAYERS = 8;
const ROTATION_SPEED = 0.06; // radians per second base

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			recalcCenter();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			recalcCenter();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function recalcCenter() {
	centerX = width / 2;
	centerY = height / 2;
	baseRadius = Math.min(width, height) * 0.38;
}

/** Draw a regular polygon inscribed in a circle of given radius */
function drawPolygon(cx, cy, radius, sides, rotation) {
	ctx.beginPath();
	for (let i = 0; i <= sides; i++) {
		const angle = ((Math.PI * 2) / sides) * i + rotation;
		const px = cx + radius * Math.cos(angle);
		const py = cy + radius * Math.sin(angle);
		if (i === 0) ctx.moveTo(px, py);
		else ctx.lineTo(px, py);
	}
	ctx.stroke();
}

/** Draw a circle */
function drawCircle(cx, cy, radius) {
	ctx.beginPath();
	ctx.arc(cx, cy, radius, 0, Math.PI * 2);
	ctx.stroke();
}

/** Draw the Flower of Life pattern (6 circles around center) */
function drawFlowerOfLife(cx, cy, radius, rotation) {
	drawCircle(cx, cy, radius);
	for (let i = 0; i < 6; i++) {
		const angle = (Math.PI / 3) * i + rotation;
		const px = cx + radius * Math.cos(angle);
		const py = cy + radius * Math.sin(angle);
		drawCircle(px, py, radius);
	}
}

/** Draw a Vesica Piscis (two overlapping circles) */
function drawVesicaPiscis(cx, cy, radius, rotation) {
	const offset = radius / 2;
	const dx = Math.cos(rotation) * offset;
	const dy = Math.sin(rotation) * offset;
	drawCircle(cx - dx, cy - dy, radius);
	drawCircle(cx + dx, cy + dy, radius);
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;
		time += dt;

		ctx.clearRect(0, 0, width, height);

		// Mouse influence on center — gentle offset
		let drawCX = centerX;
		let drawCY = centerY;
		if (mouse.x > 0 && mouse.y > 0) {
			const maxOffset = 60;
			const dx = (mouse.x - centerX) / width;
			const dy = (mouse.y - centerY) / height;
			drawCX += dx * maxOffset;
			drawCY += dy * maxOffset;
		}

		ctx.lineCap = 'round';
		ctx.lineJoin = 'round';

		// Draw nested layers from outside in, alternating shapes
		for (let i = 0; i < LAYERS; i++) {
			const factor = Math.pow(1 / PHI, i);
			const radius = baseRadius * factor;
			const rotation = time * ROTATION_SPEED * (i % 2 === 0 ? 1 : -1) * (1 + i * 0.3);

			// Breathing pulse
			const breathe = 1 + Math.sin(time * 0.5 + i * 0.7) * 0.02;
			const r = radius * breathe;

			// Alpha fades toward inner layers slightly
			const alpha = 0.08 + (1 - i / LAYERS) * 0.06;

			// Alternate between white and gold tones
			const isGold = i % 3 === 1;
			if (isGold) {
				ctx.strokeStyle = `rgba(220, 190, 120, ${alpha})`;
			} else {
				ctx.strokeStyle = `rgba(220, 225, 235, ${alpha})`;
			}
			ctx.lineWidth = 0.8;

			// Alternate shape types for visual variety
			const shapeType = i % 5;
			switch (shapeType) {
				case 0: // Circle
					drawCircle(drawCX, drawCY, r);
					break;
				case 1: // Square (4-gon)
					drawPolygon(drawCX, drawCY, r, 4, rotation);
					break;
				case 2: // Circle
					drawCircle(drawCX, drawCY, r);
					break;
				case 3: // Hexagon
					drawPolygon(drawCX, drawCY, r, 6, rotation);
					break;
				case 4: // Triangle
					drawPolygon(drawCX, drawCY, r, 3, rotation);
					break;
			}

			// Draw inscribed connecting lines for some layers
			if (i < LAYERS - 1 && i % 2 === 0) {
				const sides = [3, 4, 6][i % 3];
				ctx.strokeStyle = `rgba(200, 200, 220, ${alpha * 0.4})`;
				ctx.lineWidth = 0.4;
				drawPolygon(drawCX, drawCY, r * 0.85, sides, rotation + Math.PI / sides);
			}
		}

		// Flower of Life in the center
		const flowerRadius = baseRadius * Math.pow(1 / PHI, 4);
		ctx.strokeStyle = 'rgba(220, 190, 120, 0.05)';
		ctx.lineWidth = 0.5;
		drawFlowerOfLife(drawCX, drawCY, flowerRadius, time * 0.03);

		// Outer Vesica Piscis
		ctx.strokeStyle = 'rgba(220, 225, 235, 0.04)';
		ctx.lineWidth = 0.6;
		drawVesicaPiscis(drawCX, drawCY, baseRadius * 0.6, time * 0.02);

		// Radial guide lines (very subtle)
		ctx.strokeStyle = 'rgba(255, 255, 255, 0.02)';
		ctx.lineWidth = 0.3;
		for (let i = 0; i < 12; i++) {
			const angle = (Math.PI / 6) * i + time * 0.01;
			ctx.beginPath();
			ctx.moveTo(drawCX, drawCY);
			ctx.lineTo(
				drawCX + Math.cos(angle) * baseRadius * 1.1,
				drawCY + Math.sin(angle) * baseRadius * 1.1
			);
			ctx.stroke();
		}

		// Center dot
		ctx.fillStyle = 'rgba(220, 200, 150, 0.12)';
		ctx.beginPath();
		ctx.arc(drawCX, drawCY, 2.5, 0, Math.PI * 2);
		ctx.fill();

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Sandstorm
 * Description: Desert sandstorm with particles blowing horizontally through
 *   turbulent gusts. Mouse creates a calm shelter zone where particles deflect
 *   away. Very atmospheric with layered sand colors and variable opacity.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Particle Count & Size --
  particleCount: 350,                      // Total number of sand particles
  minParticleSize: 1,                      // Smallest particle radius in px
  maxParticleSize: 3.5,                    // Largest particle radius in px

  // -- Sand Colors --
  colorPalette: [                          // Array of sand particle colors (RGBA)
    'rgba(210, 180, 130, 1)',              //   Light tan
    'rgba(190, 155, 100, 1)',              //   Warm sand
    'rgba(170, 140, 90, 1)',               //   Dark sand
    'rgba(220, 195, 155, 1)',              //   Pale cream
    'rgba(160, 130, 80, 1)',               //   Deep ochre
    'rgba(230, 210, 170, 1)',              //   Bleached bone
  ],
  minOpacity: 0.25,                        // Minimum particle opacity (0-1)
  maxOpacity: 0.85,                        // Maximum particle opacity (0-1)

  // -- Wind --
  windSpeed: 5,                            // Base horizontal wind speed in px/frame
  windDirection: 0,                        // Wind angle in degrees (0 = left-to-right)
  turbulence: 2.5,                         // Vertical random turbulence amplitude in px
  turbulenceFrequency: 0.04,               // How fast turbulence oscillates

  // -- Gusts --
  gustFrequency: 3000,                     // Average ms between wind gusts
  gustFrequencyVariance: 2000,             // ± random ms added to gust timing
  gustStrength: 3.5,                       // Speed multiplier during a gust
  gustDuration: 800,                       // How long a gust lasts in ms
  gustRampUp: 200,                         // Ms to ramp up to full gust strength

  // -- Visual Atmosphere --
  hazeOpacity: 0.04,                       // Background haze overlay opacity (0-1)
  hazeColor: 'rgba(200, 175, 130, 1)',     // Color of the atmospheric haze

  // -- Mouse Interaction --
  mouseShelterRadius: 180,                 // Radius of the calm shelter zone in px
  mouseShelterStrength: 6,                 // How hard particles are deflected from mouse
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let particles = [];
let time = 0;
let gustActive = false;
let gustFactor = 0;
let lastGustTime = 0;
let nextGustDelay = 0;
let gustStartTime = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initParticles();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initParticles();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function parseRGBA(str) {
  const m = str.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  if (m) return { r: +m[1], g: +m[2], b: +m[3] };
  return { r: 200, g: 180, b: 130 };
}

function initParticles() {
  particles = [];
  const windRad = CONFIG.windDirection * Math.PI / 180;

  for (let i = 0; i < CONFIG.particleCount; i++) {
    particles.push(createParticle(true, windRad));
  }
}

function createParticle(randomPos, windRad) {
  const colorStr = CONFIG.colorPalette[Math.floor(Math.random() * CONFIG.colorPalette.length)];
  const color = parseRGBA(colorStr);
  const size = CONFIG.minParticleSize + Math.random() * (CONFIG.maxParticleSize - CONFIG.minParticleSize);
  const opacity = CONFIG.minOpacity + Math.random() * (CONFIG.maxOpacity - CONFIG.minOpacity);
  // Smaller particles move slower (depth illusion)
  const depthFactor = 0.4 + (size / CONFIG.maxParticleSize) * 0.6;

  let x, y;
  if (randomPos) {
    x = Math.random() * width;
    y = Math.random() * height;
  } else {
    // Spawn from upwind edge
    const wx = Math.cos(windRad);
    if (wx >= 0) {
      x = -size * 2;
    } else {
      x = width + size * 2;
    }
    y = Math.random() * height;
  }

  return {
    x, y, size, color, opacity, depthFactor,
    turbPhase: Math.random() * Math.PI * 2,
    vx: 0, vy: 0,
  };
}

function startAnimation() {
  const windRad = CONFIG.windDirection * Math.PI / 180;
  const windDirX = Math.cos(windRad);
  const windDirY = Math.sin(windRad);

  function render() {
    if (!ctx) return;
    const now = performance.now();
    time++;

    ctx.clearRect(0, 0, width, height);

    // Background haze
    ctx.save();
    ctx.globalAlpha = CONFIG.hazeOpacity;
    ctx.fillStyle = CONFIG.hazeColor;
    ctx.fillRect(0, 0, width, height);
    ctx.restore();

    // Gust logic
    if (!gustActive) {
      if (now - lastGustTime > nextGustDelay) {
        gustActive = true;
        gustStartTime = now;
        lastGustTime = now;
      }
    } else {
      const elapsed = now - gustStartTime;
      if (elapsed >= CONFIG.gustDuration) {
        gustActive = false;
        gustFactor = 0;
        nextGustDelay = CONFIG.gustFrequency + (Math.random() - 0.5) * 2 * CONFIG.gustFrequencyVariance;
      } else if (elapsed < CONFIG.gustRampUp) {
        gustFactor = (elapsed / CONFIG.gustRampUp) * (CONFIG.gustStrength - 1);
      } else {
        const fadeStart = CONFIG.gustDuration * 0.6;
        if (elapsed > fadeStart) {
          gustFactor = (CONFIG.gustStrength - 1) * (1 - (elapsed - fadeStart) / (CONFIG.gustDuration - fadeStart));
        } else {
          gustFactor = CONFIG.gustStrength - 1;
        }
      }
    }

    const currentSpeedMult = 1 + gustFactor;

    // Update and draw particles
    for (let i = 0; i < particles.length; i++) {
      const p = particles[i];

      // Turbulence
      p.turbPhase += CONFIG.turbulenceFrequency;
      const turbX = Math.sin(p.turbPhase * 1.3 + i) * CONFIG.turbulence * 0.3;
      const turbY = Math.sin(p.turbPhase + i * 0.7) * CONFIG.turbulence;

      // Wind force
      const windForce = CONFIG.windSpeed * p.depthFactor * currentSpeedMult;
      p.vx = windDirX * windForce + turbX;
      p.vy = windDirY * windForce + turbY;

      // Mouse shelter — deflect particles
      const dx = p.x - mouse.x;
      const dy = p.y - mouse.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONFIG.mouseShelterRadius && dist > 1) {
        const factor = Math.pow(1 - dist / CONFIG.mouseShelterRadius, 2);
        const nx = dx / dist;
        const ny = dy / dist;
        p.vx += nx * CONFIG.mouseShelterStrength * factor;
        p.vy += ny * CONFIG.mouseShelterStrength * factor;
      }

      p.x += p.vx;
      p.y += p.vy;

      // Recycle particles that leave the screen
      const margin = CONFIG.maxParticleSize * 3;
      if (p.x > width + margin || p.x < -margin ||
          p.y > height + margin || p.y < -margin) {
        const fresh = createParticle(false, windRad);
        particles[i] = fresh;
        continue;
      }

      // Draw particle
      ctx.globalAlpha = p.opacity;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fillStyle = `rgb(${p.color.r}, ${p.color.g}, ${p.color.b})`;
      ctx.fill();
    }

    // Draw haze streaks during gusts for visual emphasis
    if (gustFactor > 0.5) {
      const streakAlpha = Math.min(0.06, gustFactor * 0.02);
      ctx.save();
      ctx.globalAlpha = streakAlpha;
      ctx.strokeStyle = CONFIG.hazeColor;
      ctx.lineWidth = 1;
      for (let s = 0; s < 8; s++) {
        const sy = Math.random() * height;
        const sx = Math.random() * width * 0.3;
        const sl = 80 + Math.random() * 200;
        ctx.beginPath();
        ctx.moveTo(sx, sy);
        ctx.lineTo(sx + sl * windDirX, sy + sl * windDirY);
        ctx.stroke();
      }
      ctx.restore();
    }

    ctx.globalAlpha = 1;
    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Smoke Tendrils
 * Description: Organic rising smoke tendrils with Perlin-like turbulence,
 *   wind drift, and mouse-driven disturbance. Particles rise from the
 *   bottom, swirl through turbulence fields, and fade as they ascend.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Tendril Layout --
  tendrilCount: 6,                        // Number of smoke tendril sources across the bottom
  particlesPerTendril: 80,                // Active particles per tendril (total = count × this)

  // -- Particle Appearance --
  particleSizeMin: 2,                     // Minimum particle radius in px
  particleSizeMax: 8,                     // Maximum particle radius in px
  particleColor: 'rgba(200, 200, 220, 1)', // Base smoke color (alpha managed per-particle)
  particleOpacity: 0.35,                  // Starting opacity for new particles (0-1)
  fadeRate: 0.003,                        // Opacity lost per frame (higher = faster fade)

  // -- Motion --
  riseSpeed: 1.2,                         // Base upward speed in px/frame
  spreadRate: 0.4,                        // Horizontal drift magnitude per frame
  turbulenceFrequency: 0.008,             // Noise sample frequency (lower = smoother swirls)
  turbulenceAmplitude: 2.5,               // Strength of turbulence displacement in px

  // -- Wind --
  windSpeed: 0.3,                         // Constant horizontal wind in px/frame
  windDirection: 1,                       // 1 = rightward, -1 = leftward

  // -- Origin --
  originYFraction: 0.95,                  // Spawn Y as fraction of canvas height (0=top, 1=bottom)

  // -- Mouse Interaction --
  mouseTurbulenceRadius: 160,             // Radius of mouse disturbance in px
  mouseTurbulenceStrength: 4.0,           // Displacement force from mouse proximity
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let tendrils = [];
let frameCount = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

// --- Simple hash-based noise (no imports needed) ---
function hash(x, y) {
  let h = (x * 374761393 + y * 668265263 + 1013904223) | 0;
  h = Math.imul(h ^ (h >>> 13), 1274126177);
  h = h ^ (h >>> 16);
  return (h & 0x7fffffff) / 0x7fffffff; // 0-1
}

function smoothNoise(x, y) {
  const ix = Math.floor(x);
  const iy = Math.floor(y);
  const fx = x - ix;
  const fy = y - iy;
  const sx = fx * fx * (3 - 2 * fx);
  const sy = fy * fy * (3 - 2 * fy);
  const a = hash(ix, iy);
  const b = hash(ix + 1, iy);
  const c = hash(ix, iy + 1);
  const d = hash(ix + 1, iy + 1);
  return a + (b - a) * sx + (c - a) * sy + (a - b - c + d) * sx * sy;
}

function noise2D(x, y) {
  return smoothNoise(x, y) * 2 - 1; // -1 to 1
}

function parseRGBA(str) {
  const m = str.match(/rgba?\(\s*([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)/);
  if (m) return { r: +m[1], g: +m[2], b: +m[3] };
  return { r: 200, g: 200, b: 220 };
}

class Particle {
  constructor(originX, originY) {
    this.reset(originX, originY);
  }

  reset(originX, originY) {
    this.x = originX + (Math.random() - 0.5) * 20;
    this.y = originY + (Math.random() - 0.5) * 10;
    this.vx = 0;
    this.vy = 0;
    this.size = CONFIG.particleSizeMin + Math.random() * (CONFIG.particleSizeMax - CONFIG.particleSizeMin);
    this.opacity = CONFIG.particleOpacity * (0.6 + Math.random() * 0.4);
    this.life = 1;
    this.seed = Math.random() * 1000;
  }

  update(originX, originY) {
    const freq = CONFIG.turbulenceFrequency;
    const amp = CONFIG.turbulenceAmplitude;

    const nx = noise2D(this.x * freq + this.seed, this.y * freq + frameCount * 0.01);
    const ny = noise2D(this.x * freq + 100 + this.seed, this.y * freq + frameCount * 0.01 + 100);

    this.vx += nx * amp * 0.1 + CONFIG.windSpeed * CONFIG.windDirection * 0.05;
    this.vy -= CONFIG.riseSpeed * 0.05;
    this.vx += (Math.random() - 0.5) * CONFIG.spreadRate * 0.3;

    // Mouse turbulence
    const dx = this.x - mouse.x;
    const dy = this.y - mouse.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < CONFIG.mouseTurbulenceRadius && dist > 1) {
      const force = (1 - dist / CONFIG.mouseTurbulenceRadius) * CONFIG.mouseTurbulenceStrength;
      this.vx += (dx / dist) * force * 0.1;
      this.vy += (dy / dist) * force * 0.1;
    }

    this.vx *= 0.96;
    this.vy *= 0.96;

    this.x += this.vx;
    this.y += this.vy;

    this.opacity -= CONFIG.fadeRate;
    this.size += 0.02;

    if (this.opacity <= 0 || this.y < -50) {
      this.reset(originX, originY);
    }
  }

  draw(ctx, color) {
    if (this.opacity <= 0) return;
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${color.r}, ${color.g}, ${color.b}, ${this.opacity})`;
    ctx.fill();
  }
}

function initTendrils() {
  tendrils = [];
  const originY = height * CONFIG.originYFraction;
  const spacing = width / (CONFIG.tendrilCount + 1);

  for (let t = 0; t < CONFIG.tendrilCount; t++) {
    const originX = spacing * (t + 1);
    const particles = [];
    for (let p = 0; p < CONFIG.particlesPerTendril; p++) {
      const particle = new Particle(originX, originY);
      particle.opacity = CONFIG.particleOpacity * Math.random();
      particle.y = originY - Math.random() * height;
      particles.push(particle);
    }
    tendrils.push({ originX, particles });
  }
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initTendrils();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initTendrils();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function startAnimation() {
  const color = parseRGBA(CONFIG.particleColor);

  function render() {
    if (!ctx) return;

    ctx.clearRect(0, 0, width, height);

    ctx.globalCompositeOperation = 'lighter';

    const originY = height * CONFIG.originYFraction;

    for (const tendril of tendrils) {
      for (const particle of tendril.particles) {
        particle.update(tendril.originX, originY);
        particle.draw(ctx, color);
      }
    }

    ctx.globalCompositeOperation = 'source-over';

    frameCount++;
    requestAnimationFrame(render);
  }

  requestAnimationFrame(render);
}

/**
 * Title: Snow Globe
 * Description: Gentle snowfall with drifting flakes, shimmer sparkles,
 *   bottom-edge accumulation, and a mouse-driven swirl wind effect.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Flake Appearance --
  flakeCount: 180,                        // Total number of snowflakes
  minFlakeSize: 1.5,                      // Smallest flake radius in px
  maxFlakeSize: 5,                        // Largest flake radius in px
  flakeColor: 'rgba(255, 255, 255, 1)',   // Base flake color
  flakeOpacity: 0.85,                     // Global flake opacity (0-1)
  shimmerChance: 0.02,                    // Per-frame chance a flake sparkles (0-1)
  shimmerGlowRadius: 12,                  // Glow radius when a flake shimmers in px
  shimmerColor: 'rgba(200, 230, 255, 0.9)', // Color of the shimmer glow

  // -- Motion --
  gravity: 0.35,                          // Downward acceleration per frame
  windDirection: 1,                       // Horizontal wind bias (-1 left, 1 right)
  windStrength: 0.4,                      // Base horizontal wind force
  driftRandomness: 0.6,                   // Per-frame random horizontal jitter
  speed: 1.0,                             // Global speed multiplier

  // -- Accumulation --
  accumulationHeight: 18,                 // Max snow buildup height at bottom in px
  accumulationRate: 0.012,                // How fast snow accumulates (0-1)

  // -- Mouse Interaction --
  mouseRadius: 160,                       // Radius of mouse swirl influence in px
  mouseSwirl: 3.5,                        // Tangential swirl force strength
  mouseRepel: 1.2,                        // Radial push-away force strength
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let flakes = [];
let accumulation = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initFlakes();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initFlakes();
      accumulation = 0;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function initFlakes() {
  flakes = [];
  for (let i = 0; i < CONFIG.flakeCount; i++) {
    flakes.push(createFlake(true));
  }
}

function createFlake(randomY) {
  const size = CONFIG.minFlakeSize + Math.random() * (CONFIG.maxFlakeSize - CONFIG.minFlakeSize);
  return {
    x: Math.random() * width,
    y: randomY ? Math.random() * height : -size * 2,
    size,
    vx: 0,
    vy: 0.5 + Math.random() * 1.5,
    wobblePhase: Math.random() * Math.PI * 2,
    wobbleSpeed: 0.01 + Math.random() * 0.03,
    opacity: 0.4 + Math.random() * 0.6,
  };
}

function startAnimation() {
  function render() {
    if (!ctx) return;

    ctx.clearRect(0, 0, width, height);

    const floorY = height - accumulation;

    // Update and draw flakes
    for (let i = 0; i < flakes.length; i++) {
      const f = flakes[i];

      // Wobble drift
      f.wobblePhase += f.wobbleSpeed * CONFIG.speed;
      const wobble = Math.sin(f.wobblePhase) * CONFIG.driftRandomness;

      // Wind
      f.vx += (CONFIG.windDirection * CONFIG.windStrength + wobble) * 0.02 * CONFIG.speed;
      f.vy += CONFIG.gravity * 0.02 * CONFIG.speed;

      // Mouse swirl
      const dx = f.x - mouse.x;
      const dy = f.y - mouse.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONFIG.mouseRadius && dist > 1) {
        const factor = 1 - dist / CONFIG.mouseRadius;
        const nx = dx / dist;
        const ny = dy / dist;
        // Tangential swirl
        f.vx += (-ny * CONFIG.mouseSwirl * factor) * 0.1;
        f.vy += (nx * CONFIG.mouseSwirl * factor) * 0.1;
        // Radial repel
        f.vx += nx * CONFIG.mouseRepel * factor * 0.1;
        f.vy += ny * CONFIG.mouseRepel * factor * 0.1;
      }

      // Damping
      f.vx *= 0.96;
      f.vy *= 0.98;

      // Clamp terminal velocity
      f.vy = Math.min(f.vy, 3 * CONFIG.speed);

      f.x += f.vx;
      f.y += f.vy;

      // Reached bottom — recycle and add to accumulation
      if (f.y >= floorY) {
        accumulation = Math.min(accumulation + CONFIG.accumulationRate * f.size, CONFIG.accumulationHeight);
        flakes[i] = createFlake(false);
        continue;
      }

      // Wrap horizontally
      if (f.x < -10) f.x = width + 10;
      if (f.x > width + 10) f.x = -10;

      // Draw flake
      const alpha = f.opacity * CONFIG.flakeOpacity;

      // Shimmer check
      const isShimmering = Math.random() < CONFIG.shimmerChance;
      if (isShimmering) {
        ctx.save();
        ctx.shadowBlur = CONFIG.shimmerGlowRadius;
        ctx.shadowColor = CONFIG.shimmerColor;
        ctx.beginPath();
        ctx.arc(f.x, f.y, f.size * 1.3, 0, Math.PI * 2);
        ctx.fillStyle = CONFIG.shimmerColor;
        ctx.globalAlpha = alpha;
        ctx.fill();
        ctx.restore();
      }

      ctx.beginPath();
      ctx.arc(f.x, f.y, f.size, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.flakeColor;
      ctx.globalAlpha = alpha;
      ctx.fill();
    }

    // Draw accumulation mound
    if (accumulation > 0.5) {
      ctx.globalAlpha = 0.9;
      ctx.fillStyle = 'rgba(240, 245, 255, 0.6)';
      ctx.beginPath();
      ctx.moveTo(0, height);
      const segments = 24;
      for (let i = 0; i <= segments; i++) {
        const sx = (i / segments) * width;
        const waveOffset = Math.sin(i * 0.8) * accumulation * 0.2;
        ctx.lineTo(sx, height - accumulation + waveOffset);
      }
      ctx.lineTo(width, height);
      ctx.closePath();
      ctx.fill();
    }

    ctx.globalAlpha = 1;
    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Solar Wind Embers
 * Description: Floating amber particles that drift upward and react to the sun (mouse).
 */

const CONFIG = {
    particleCount: 80,
    minSize: 1,
    maxSize: 4,
    baseColor: 'rgba(255, 180, 50, 0.2)',
    glowColor: 'rgba(255, 255, 200, 0.5)',
    driftSpeed: 0.4,
    mouseRadius: 200
};

let canvas, ctx, width, height;
let particles = [];
let mouse = { x: -5000, y: -5000 };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas;
        ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x;
        mouse.y = e.data.y;
    }
};

function resize(w, h) {
    width = w; height = h;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initParticles();
}

function initParticles() {
    particles = [];
    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push({
            x: Math.random() * width,
            y: Math.random() * height,
            vx: (Math.random() - 0.5) * 0.5,
            vy: -(Math.random() * CONFIG.driftSpeed + 0.2),
            size: Math.random() * (CONFIG.maxSize - CONFIG.minSize) + CONFIG.minSize,
            angle: Math.random() * Math.PI * 2
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, width, height);

    for (let p of particles) {
        p.y += p.vy;
        p.x += p.vx + Math.sin(p.angle) * 0.2;
        p.angle += 0.01;

        // Screen wrap
        if (p.y < -10) p.y = height + 10;
        if (p.x < -10) p.x = width + 10;
        if (p.x > width + 10) p.x = -10;

        // Mouse reaction
        let dx = mouse.x - p.x;
        let dy = mouse.y - p.y;
        let dist = Math.hypot(dx, dy);

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);

        if (dist < CONFIG.mouseRadius) {
            ctx.fillStyle = CONFIG.glowColor;
            p.x -= dx * 0.01;
            p.y -= dy * 0.01;
        } else {
            ctx.fillStyle = CONFIG.baseColor;
        }

        ctx.fill();
    }

    requestAnimationFrame(render);
}

/**
 * Title: Stained Glass
 * Description: Animated stained glass mosaic with Voronoi cells, glowing
 *   lead joints, color shifting, and refraction shimmer. Mouse creates a
