 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Cell Layout --
  cellCount: 80,                   // Number of Voronoi cells (20-200)

  // -- Colors --
  cellColors: [                    // Palette for glass cell fills
    '#c2185b', '#e65100', '#f9a825',
    '#2e7d32', '#0277bd', '#4a148c',
