/**
 * Title: Fireflies (Emerald Canopy)
 * Description: Bioluminescent forest spores drifting lazily.
 */
let canvas, ctx, w, h;
let particles = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    particles = [];
    for (let i = 0; i < 25; i++) {
        particles.push({
            x: Math.random() * w, y: Math.random() * h,
            vx: (Math.random() - 0.5) * 0.4,
            vy: (Math.random() - 0.5) * 0.4,
            r: Math.random() * 3 + 1,
            alpha: Math.random(),
            speed: 0.01 + Math.random() * 0.02
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    for (let p of particles) {
        p.x += p.vx;
        p.y += p.vy;
        p.alpha += p.speed;
        if (p.alpha > 1 || p.alpha < 0) p.speed = -p.speed;
        if (p.x < 0) p.x = w; if (p.x > w) p.x = 0;
        if (p.y < 0) p.y = h; if (p.y > h) p.y = 0;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(46, 204, 113, ${Math.abs(p.alpha)})`;
        ctx.shadowBlur = 10;
        ctx.shadowColor = '#2ecc71';
        ctx.fill();
    }
    ctx.shadowBlur = 0; // Reset
    requestAnimationFrame(render);
}

