    petals = [];
    for (let i = 0; i < 30; i++) {
        petals.push({
            x: Math.random() * w,
            y: Math.random() * h - h,
            r: Math.random() * 4 + 2,
            d: Math.random() * w,
            speed: Math.random() * 1.5 + 0.8,
            sway: Math.random() * 2
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = 'rgba(255, 179, 209, 0.7)';
    for (let p of petals) {
        p.y += p.speed;
        p.x += Math.sin(p.y / 30) * p.sway * 0.5;
        if (p.y > h) {
            p.y = -20;
            p.x = Math.random() * w;
        }
        ctx.beginPath();
        ctx.ellipse(p.x, p.y, p.r, p.r * 1.5, Math.PI / 4, 0, Math.PI * 2);
        ctx.fill();
    }
    requestAnimationFrame(render);
}

