dark.canvasScript:
/**
 * Title: Retro Synthwave Grid
 * Description: A classic outrun-style 3D moving grid with a stylized neon sun.
 */

let canvas, ctx, w, h;
let offset = 0;

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    const horizon = h * 0.55;
    const vpX = w / 2;

    // 1. Draw the Retro Sun
    ctx.save();
    ctx.beginPath();
    ctx.arc(vpX, horizon, 140, Math.PI, 0);
    let sunGradient = ctx.createLinearGradient(0, horizon - 140, 0, horizon);
    sunGradient.addColorStop(0, '#ffaa00');
    sunGradient.addColorStop(0.6, '#ff007f');
    sunGradient.addColorStop(1, '#66004d');
    ctx.fillStyle = sunGradient;
    ctx.fill();

    // Sun Slices (retro effect)
    ctx.globalCompositeOperation = 'destination-out';
    for(let i = 0; i < 6; i++) {
        let sliceY = horizon - (i * 18);
        let sliceH = 2 + (i * 1.5);
        ctx.fillRect(vpX - 150, sliceY, 300, sliceH);
    }
    ctx.restore();

    // 2. Draw the Grid
    ctx.strokeStyle = 'rgba(255, 0, 191, 0.6)';
    ctx.lineWidth = 2;

    // Vertical radiating lines
    ctx.beginPath();
    for (let i = -w * 2; i < w * 3; i += 100) {
        ctx.moveTo(vpX, horizon);
        ctx.lineTo(i, h);
    }
    ctx.stroke();

    // Horizontal moving lines (Perspective illusion)
    offset += 0.012;
    if (offset >= 1) offset = 0;

    ctx.beginPath();
    const linesCount = 20;
    for (let i = 0; i < linesCount; i++) {
        let z = (i + offset) / linesCount;
        // Cubic easing pushes lines faster towards the bottom
        let drawY = horizon + Math.pow(z, 3) * (h - horizon);

        if (drawY > horizon && drawY < h) {
            ctx.moveTo(0, drawY);
            ctx.lineTo(w, drawY);
        }
    }
    ctx.stroke();

    requestAnimationFrame(render);
}

